const $ = (id) => document.getElementById(id);

function showCoachTip(anchor, message, options = {}) {
  const target = typeof anchor === "string" ? $(anchor) || document.querySelector(anchor) : anchor;
  if (!target || !message) return;
  if (target.hidden || target.closest?.("[hidden]")) return;
  const key = options.key || String(anchor || message).slice(0, 80);
  const storageKey = `npsCoachTip:${key}`;
  if (!options.force) {
    try {
      if (sessionStorage.getItem(storageKey) === "1") return;
      sessionStorage.setItem(storageKey, "1");
    } catch (_) {
      /* sessionStorage may be unavailable in hardened browser contexts. */
    }
  }
  document.querySelectorAll(".guided-coach-tip").forEach((node) => node.remove());
  if (state.coachTipTimer) clearTimeout(state.coachTipTimer);
  const tip = document.createElement("div");
  const position = options.position || "bottom";
  tip.className = `guided-coach-tip guided-coach-tip-${position}`;
  tip.setAttribute("role", "status");
  tip.innerHTML = `<span>${escapeHtml(options.label || "Signal Coach")}</span><strong>${escapeHtml(message)}</strong>`;
  document.body.appendChild(tip);
  const place = () => {
    const rect = target.getBoundingClientRect();
    const tipRect = tip.getBoundingClientRect();
    const gap = 12;
    let left = rect.left + (rect.width / 2) - (tipRect.width / 2);
    let top = rect.bottom + gap;
    if (position === "top") top = rect.top - tipRect.height - gap;
    if (position === "right") {
      left = rect.right + gap;
      top = rect.top + (rect.height / 2) - (tipRect.height / 2);
    }
    if (position === "left") {
      left = rect.left - tipRect.width - gap;
      top = rect.top + (rect.height / 2) - (tipRect.height / 2);
    }
    const maxLeft = Math.max(12, window.innerWidth - tipRect.width - 12);
    const maxTop = Math.max(12, window.innerHeight - tipRect.height - 12);
    tip.style.left = `${Math.min(Math.max(12, left), maxLeft)}px`;
    tip.style.top = `${Math.min(Math.max(12, top), maxTop)}px`;
  };
  requestAnimationFrame(() => {
    place();
    tip.classList.add("show");
  });
  const dismiss = () => {
    tip.classList.remove("show");
    window.setTimeout(() => tip.remove(), 220);
  };
  tip.addEventListener("click", dismiss);
  state.coachTipTimer = window.setTimeout(dismiss, options.duration || 3200);
}

function showCoachTipSoon(anchor, message, options = {}) {
  window.setTimeout(() => showCoachTip(anchor, message, options), options.delay ?? 350);
}

function scrollGuidedElementIntoView(elementOrId, options = {}) {
  const target = typeof elementOrId === "string" ? $(elementOrId) : elementOrId;
  if (!target) return;
  const behavior = options.behavior || "smooth";
  const block = options.block || "start";
  const containers = [
    document.querySelector(".workspace"),
    document.querySelector(".guided-setup"),
    document.querySelector(".setup-main"),
    $("guidedAnalysisComplete"),
  ].filter(Boolean);
  containers.forEach((container) => {
    const targetTop = target.getBoundingClientRect().top;
    const containerTop = container.getBoundingClientRect().top;
    const nextTop = container.scrollTop + targetTop - containerTop - (options.offset || 14);
    if (Number.isFinite(nextTop) && typeof container.scrollTo === "function") {
      container.scrollTo({ top: Math.max(0, nextTop), behavior });
    }
  });
  target.scrollIntoView({ behavior, block });
}

function clearCoachTips() {
  if (state.coachTipTimer) clearTimeout(state.coachTipTimer);
  state.coachTipTimer = null;
  document.querySelectorAll(".guided-coach-tip").forEach((node) => node.remove());
}

function scheduleGuidedStageCoachTip() {
  if (state.guidedReleaseToApp === true) return;
  if (state.guidedStageCoachTimer) clearTimeout(state.guidedStageCoachTimer);
  state.guidedStageCoachTimer = window.setTimeout(() => {
    const hasBase = (state.baseColumns || []).length > 0 || state.baseUploadComplete === true;
    const analysisComplete = state.guidedAnalysisComplete === true;
    const completePanel = $("guidedAnalysisComplete");
    const briefingStarted = completePanel?.classList.contains("briefing-started");
    const fieldDiveVisible = $("guidedFieldDive") && !$("guidedFieldDive").hidden;
    const storyChooserVisible = $("guidedStoryChooser") && !$("guidedStoryChooser").hidden;
    const storyPanelVisible = $("guidedStoryPanel") && !$("guidedStoryPanel").hidden;
    const railVisible = $("guidedDeepDiveRail") && !$("guidedDeepDiveRail").hidden;
    const feedbackVisible = $("guidedInsightFeedback") && !$("guidedInsightFeedback").hidden;
    const stageNextVisible = $("guidedInsightStageNext") && !$("guidedInsightStageNext").hidden;
    let tip = null;
    if (!hasBase) {
      tip = ["upload", "baseUploadButton", "Start by uploading the Base File. I will read it and guide the next step.", "top"];
    } else if (state.guidedSetupStage === "coverage" && !state.setupCoverageChoice) {
      tip = ["coverage", "guidedCoverageStep", "Choose whether the Base File already has all fields or whether you want to add a lookup file.", "top"];
    } else if (state.setupCoverageChoice === "lookup" && !(state.lookupColumns || []).length) {
      tip = ["lookup", "lookupUploadButton", "Upload the lookup file, then I will help connect it using the unique key.", "top"];
    } else if (!state.guidedMappingConfirmed && (state.setupCoverageChoice === "complete" || (state.lookupColumns || []).length)) {
      tip = ["mapping", "confirmMappingBtn", "Review the mapped columns once, then confirm so I can prepare the analysis.", "top"];
    } else if (state.guidedMappingConfirmed && !analysisComplete) {
      tip = ["analysis", "confirmTargetScaleBtn", "Check the target and loyalty scale, then confirm this step.", "top"];
    } else if (analysisComplete && !briefingStarted) {
      tip = ["briefing-start", "guidedStartBriefing", "Click here to begin the guided readout before opening any dashboard.", "top"];
    } else if (analysisComplete && storyChooserVisible) {
      tip = ["route-chooser", "guidedRecommendedStart", "Start with the recommended path, or pick another route below if you want to explore differently.", "top"];
    } else if (analysisComplete && storyPanelVisible) {
      tip = [`story-${state.guidedStoryKey || "health"}`, "guidedStoryContinue", "If this route looks right, start the investigation. If not, choose a different signal.", "top"];
    } else if (analysisComplete && fieldDiveVisible && feedbackVisible) {
      tip = ["signal-feedback", "guidedInsightFeedback", "Tell me whether these signals are useful. I will either continue the story or help you try another field.", "left"];
    } else if (analysisComplete && fieldDiveVisible && stageNextVisible) {
      const stage = GUIDED_INSIGHT_STAGES[state.guidedInsightStage || "nps"] || GUIDED_INSIGHT_STAGES.nps;
      tip = [`stage-ready-${state.guidedInsightStage || "nps"}`, "guidedInsightStageNext", `You have enough signals for this stage. Click here to continue to ${stage.next.toLowerCase()}.`, "left"];
    } else if (analysisComplete && fieldDiveVisible && railVisible) {
      tip = ["rail-review", "guidedDeepDiveRail", "Review the table signals here. You can change fields to keep adding better evidence.", "left"];
    } else if (analysisComplete && fieldDiveVisible) {
      const field = $("guidedDeepDiveField")?.value || "";
      tip = [`field-dive-${state.guidedInsightIndex || 0}-${field}`, field ? "guidedDeepDiveAnalyze" : "guidedDeepDiveField", field ? "Click Analyze and I will group the insight by this field." : "Choose a field so I can group the insight for you.", "top"];
    } else if (analysisComplete && state.guidedAttackChooserVisible) {
      const firstInvestigate = document.querySelector("[data-guided-investigate]");
      tip = ["attack-deck", firstInvestigate || "guidedAttackDeck", "Use Investigate to open a signal, or double-click any card to see the decision logic.", "top"];
    } else if (analysisComplete && briefingStarted) {
      const insights = state.guidedCompletionInsights || [];
      const index = Number(state.guidedInsightIndex || 0);
      tip = [
        `insight-${index}`,
        "guidedInsightNext",
        index >= insights.length - 1
          ? "Click here to choose what to attack first. Use Back if you want to review the previous insight."
          : index > 0
            ? "Click Next insight to continue, or Back if you want to review the previous point."
            : "Click Next insight to continue the guided briefing.",
        "bottom",
      ];
    }
    if (!tip) return;
    const [key, anchor, message, position] = tip;
    if (state.guidedStageCoachKey === key) return;
    state.guidedStageCoachKey = key;
    showCoachTip(anchor, message, { key: `stage-${key}`, position, force: true, duration: 3600 });
  }, 900);
}

