function hydrateNavIcons() {
  document.querySelectorAll(".nav-item").forEach((button) => {
    if (button.querySelector(".nav-icon")) return;
    const icon = NAV_ICONS[button.dataset.icon] || NAV_ICONS.dashboard;
    button.insertAdjacentHTML("afterbegin", `<span class="nav-icon" aria-hidden="true">${icon}</span>`);
  });
  document.querySelectorAll(".nav-section-icon").forEach((iconEl) => {
    if (iconEl.innerHTML.trim()) return;
    iconEl.innerHTML = NAV_SECTION_ICONS[iconEl.dataset.sectionIcon] || NAV_SECTION_ICONS.command;
  });
}

function wireNavigationRibbons() {
  document.querySelectorAll(".nav-section-toggle").forEach((toggle) => {
    toggle.addEventListener("click", () => {
      const section = toggle.closest(".nav-section");
      if (section?.classList.contains("nav-section-static")) return;
      const isOpen = section.classList.toggle("open");
      toggle.setAttribute("aria-expanded", String(isOpen));
    });
  });
}

function openNavSectionForItem(button) {
  const section = button.closest(".nav-section");
  if (!section) return;
  section.classList.add("open");
  section.querySelector(".nav-section-toggle")?.setAttribute("aria-expanded", "true");
}

const ANALYSIS_REQUIRED_VIEWS = new Set([
  "datasetsummary", "performanceoverview", "executivesummary", "decisionguide", "dimensions", "results", "sentimentbriefing", "insightsreadout",
  "executive", "executivelens", "agent", "manager", "customdashboards", "boardpdf", "rawdata", "downloads",
  "performancequestions", "movingaverageslaunch", "movingaverages", "quartilelaunch", "quartile", "statistics", "customstatslaunch", "customstats",
  "feedback", "sentimentcompare", "themebuilder", "themecompare",
  "wave", "tenure", "dimensionlens", "customdims",
  "themesoverview", "acptoverview", "rootcause", "Promoterdna", "alerts", "analysis",
]);

const ANALYSIS_REQUIRED_ACTION_IDS = new Set([
  "exportAnalysisProject", "dateToggle", "genAiJsonOutput",
]);

const PROJECT_ACTIONS_ADVANCED_IDS = new Set([
  "executiveLensTop", "analysisSnapshotTop", "boardPdfTop", "genAiJsonTop", "downloadsTop", "customStatsHtmlExport",
]);

function analysisHasDashboardData(analysis = state.analysis || {}) {
  return executiveDashboardHasData(analysis)
    || Number(analysis.summary?.total || analysis.summary?.Total || analysis.counts?.Total || 0) > 0
    || ["feedbackRows", "feedbackTableRows", "themeRows", "weekly", "agents", "managers", "preview"].some((key) => Array.isArray(analysis[key]) && analysis[key].length > 0);
}

function isAnalysisRequiredView(viewId = "") {
  const resolved = VIEW_TARGET_ALIASES[viewId] || NAV_VIEW_ALIASES[viewId] || viewId;
  return ANALYSIS_REQUIRED_VIEWS.has(resolved);
}

function updateAnalysisAccessUi() {
  const hasData = analysisHasDashboardData();
  document.body.classList.toggle("analysis-data-ready", hasData);
  document.body.classList.toggle("analysis-data-pending", !hasData);
  document.querySelectorAll(".nav-item").forEach((item) => {
    if (PROJECT_ACTIONS_ADVANCED_IDS.has(item.id || "")) {
      item.hidden = true;
      return;
    }
    const view = item.dataset.view || "";
    const requiresAnalysis = (view && isAnalysisRequiredView(view)) || ANALYSIS_REQUIRED_ACTION_IDS.has(item.id || "");
    if (requiresAnalysis) item.hidden = !hasData;
  });
  document.querySelectorAll(".nav-section").forEach((section) => {
    const isSetupSection = Boolean(section.querySelector('[data-view="setuphome"]'));
    const isProjectActions = section.classList.contains("nav-section-project-actions");
    if (isSetupSection || isProjectActions || section.classList.contains("nav-section-hidden")) return;
    const items = Array.from(section.querySelectorAll(".nav-item"));
    section.hidden = !hasData && items.length > 0 && items.every((item) => item.hidden);
    if (section.hidden) {
      section.classList.remove("open");
      section.querySelector(".nav-section-toggle")?.setAttribute("aria-expanded", "false");
    }
  });
  const activeView = document.querySelector(".view.active")?.id || "";
  if (!hasData && isAnalysisRequiredView(activeView)) activateView("setuphome");
}

function activateView(viewId) {
  if (isAnalysisRequiredView(viewId) && !analysisHasDashboardData()) {
    viewId = "setuphome";
  }
  const resolvedViewId = VIEW_TARGET_ALIASES[viewId] || viewId;
  const view = $(resolvedViewId);
  if (!view) return;
  const workspace = document.querySelector(".workspace");
  const nav = document.querySelector(".nav");
  const navViewId = NAV_VIEW_ALIASES[viewId] || viewId;
  const button = document.querySelector(`.nav-item[data-view="${navViewId}"]`);
  document.querySelectorAll(".nav-item").forEach((item) => item.classList.remove("active"));
  document.querySelectorAll(".top-view-button").forEach((item) => item.classList.remove("active"));
  document.querySelectorAll(".view").forEach((item) => item.classList.remove("active"));
  if (button) {
    button.classList.add("active");
    openNavSectionForItem(button);
  }
  document.querySelector(`.top-view-button[data-view="${resolvedViewId}"]`)?.classList.add("active");
  view.classList.add("active");
  updateDashboardGuideForView(resolvedViewId);
  if (resolvedViewId === "boardpdf") renderBoardPdfOptionCards();
  if (resolvedViewId === "rawdata") renderAnalysisRawDataPage();
  if (resolvedViewId === "performancequestions") setMasterLensIntroVisible(true);
  workspace?.scrollTo({ top: 0, left: 0, behavior: "auto" });
  requestAnimationFrame(() => {
    window.scrollTo({ top: 0, left: 0, behavior: "auto" });

    if (!nav || !button) return;
    const navRect = nav.getBoundingClientRect();
    const buttonRect = button.getBoundingClientRect();
    const inset = 12;
    if (buttonRect.top < navRect.top + inset) {
      nav.scrollTop -= navRect.top + inset - buttonRect.top;
    } else if (buttonRect.bottom > navRect.bottom - inset) {
      nav.scrollTop += buttonRect.bottom - (navRect.bottom - inset);
    }
  });
}


