function wireDashboardGuideToggle() {
  const root = $("dashboardGuideAvatar");
  const robot = root?.querySelector(".dashboard-guide-person");
  if (!root || !robot || root.dataset.toggleWired === "1") return;
  root.dataset.toggleWired = "1";
  robot.setAttribute("role", "button");
  robot.setAttribute("tabindex", "0");
  robot.setAttribute("aria-label", "Show or hide dashboard guide");
  const toggle = (event) => {
    event.stopPropagation();
    if (root.classList.contains("hidden")) {
      root.classList.remove("hidden");
      updateDashboardGuideForView(document.querySelector(".view.active")?.id || "executive");
      return;
    }
    root.classList.toggle("guide-collapsed");
  };
  robot.addEventListener("click", toggle);
  robot.addEventListener("keydown", (event) => {
    if (event.key === "Enter" || event.key === " ") {
      event.preventDefault();
      toggle(event);
    }
  });
}
function addDashboardGuideHelpActions() {
  const root = $("dashboardGuideAvatar");
  const actions = root?.querySelector(".dashboard-guide-actions");
  const next = $("dashboardGuideNext");
  const close = $("dashboardGuideClose");
  if (!root || !actions || !next || !close) return;
  next.textContent = "Help Me";
  close.textContent = "Got it";
  let menu = $("dashboardGuideHelpMenu");
  if (!menu) {
    actions.insertAdjacentHTML("beforeend", `<div class="dashboard-guide-help-menu" id="dashboardGuideHelpMenu" hidden><button type="button" data-guide-view="executivesummary">Summary</button><button type="button" data-guide-view="executive">Executive</button><button type="button" data-guide-view="agent">Agent</button><button type="button" data-guide-view="manager">Manager</button><button type="button" data-guide-view="quartilelaunch">Quartile</button><button type="button" data-guide-view="feedback">Sentiment</button><button type="button" data-guide-view="boardpdf">PDF</button><button type="button" data-guide-view="downloads">Downloads</button></div>`);
    menu = $("dashboardGuideHelpMenu");
  }
  next.onclick = (event) => { event.stopPropagation(); if (menu) menu.hidden = !menu.hidden; };
  close.onclick = (event) => { event.stopPropagation(); if (menu) menu.hidden = true; root.classList.add("guide-collapsed"); };
  menu?.querySelectorAll("[data-guide-view]").forEach((button) => {
    button.onclick = (event) => { event.stopPropagation(); activateView(button.dataset.guideView); if (menu) menu.hidden = true; };
  });
}

function updateDashboardGuideForView(viewId = "") {
  const root = $("dashboardGuideAvatar");
  const text = $("dashboardGuideText");
  if (!root || !text) return;
  if (!state.guidedReleaseToApp && !dashboardGuideShouldRun() && root.classList.contains("hidden")) return;
  root.classList.remove("hidden", "signing-off", "guide-collapsed");
  text.textContent = dashboardGuideMessageForView(viewId);
  addDashboardGuideHelpActions();
  wireDashboardGuideToggle();
}

function runDashboardGuideTour() {
  const root = $("dashboardGuideAvatar");
  if (!root) return;
  root.classList.remove("hidden", "signing-off");
  clearDashboardGuideFlag();
  updateDashboardGuideForView(document.querySelector(".view.active")?.id || "executive");
}
function setDatePanelOpen(open) {
  const panel = $("datePanel");
  const toggle = $("dateToggle");
  if (!panel || !toggle) return;
  panel.classList.toggle("hidden", !open);
  toggle.classList.toggle("active", open);
  toggle.setAttribute("aria-expanded", String(open));
}

function syncDateFilterControls(filter = {}) {
  const mode = filter.mode || "All Time";
  if ($("customStart")) $("customStart").value = filter.start || "";
  if ($("customEnd")) $("customEnd").value = filter.end || "";
  document.querySelectorAll("#datePanel [data-range]").forEach((button) => {
    button.classList.toggle("active", button.dataset.range === mode);
  });
}

function updateDateToggleLabel(label = "All Time") {
  const text = String(label || "All Time").trim() || "All Time";
  const toggle = $("dateToggle");
  if (!toggle) return;
  toggle.title = `Date Range (${text})`;
  toggle.setAttribute("aria-label", `Date Range (${text})`);
}

async function applyDateFilter(mode, start = "", end = "") {
  if (mode === "Custom Range") {
    if (!start && !end) throw new Error("Select a start date, an end date, or both.");
    if (start && end && start > end) throw new Error("The start date must be on or before the end date.");
  }

  showLoading(`Applying ${mode} date filter...`, 20);
  try {
    const response = await fetch("/api/date-filter", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ mode, start, end }),
    });
    const payload = await response.json().catch(() => ({ ok: false, error: "The date filter returned an unreadable response." }));
    if (!response.ok || !payload.ok) throw new Error(payload.error || "Unable to apply the selected date range.");
    const analysis = payload.analysis || {};
    renderAnalysis(analysis);
    syncDateFilterControls(analysis.dateFilter || { mode, start, end });
    setDatePanelOpen(false);
  } finally {
    hideLoading();
  }
}

function setMasterLensIntroVisible(visible) {
  state.masterLensIntroVisible = Boolean(visible);
  const intro = $("masterLensIntro");
  const workspace = $("performanceLensWorkspace");
  const workbar = $("performanceWorkbar");
  const section = $("performancequestions");
  if (intro) intro.hidden = !state.masterLensIntroVisible;
  if (workspace) workspace.classList.toggle("intro-hidden", state.masterLensIntroVisible);
  if (workbar) workbar.hidden = state.masterLensIntroVisible;
  if (section) section.classList.toggle("master-lens-intro-active", state.masterLensIntroVisible);
}

function resetLaunchWorkspaceScroll(workspace) {
  const scrollers = [document.querySelector(".workspace"), document.scrollingElement, document.documentElement, document.body].filter(Boolean);
  const reset = () => {
    scrollers.forEach((scroller) => {
      scroller.scrollTop = 0;
      scroller.scrollLeft = 0;
      if (typeof scroller.scrollTo === "function") scroller.scrollTo({ top: 0, left: 0, behavior: "auto" });
    });
    workspace?.scrollIntoView({ block: "start", inline: "nearest", behavior: "auto" });
  };
  if (document.activeElement instanceof HTMLElement) document.activeElement.blur();
  reset();
  requestAnimationFrame(() => {
    reset();
    requestAnimationFrame(reset);
  });
  window.setTimeout(reset, 80);
}

function setLaunchPageVisible(key, visible) {
  const config = LAUNCH_PAGE_MAP[key];
  if (!config) return;
  state.launchPages = state.launchPages || {};
  state.launchPages[key] = Boolean(visible);
  const launch = $(config.launch);
  const workspace = $(config.workspace);
  if (launch) launch.hidden = !state.launchPages[key];
  if (workspace) workspace.classList.toggle("is-hidden", state.launchPages[key]);
  launch?.closest(".view")?.classList.toggle("launch-page-active", state.launchPages[key]);
  if (!state.launchPages[key]) {
    resetLaunchWorkspaceScroll(workspace);
  }
}

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function formatMetric(value, digits = 1) {
  const number = Number(value || 0);
  return Number.isInteger(number) ? number.toLocaleString() : number.toFixed(digits);
}

function formatDataPoint(value, digits = 2) {
  if (value == null || value === "") return "";
  const number = Number(value);
  if (!Number.isFinite(number) || String(value).trim() === "") return formatDisplayLabel(value);
  return number.toLocaleString(undefined, {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits,
  });
}

function formatDisplayLabel(value) {
  const text = String(value ?? "").trim();
  const isoDate = text.match(/^(\d{4}-\d{2}-\d{2})(?:[T\s]\d{2}:\d{2}:\d{2}(?:\.\d+)?(?:Z)?)?$/);
  if (isoDate) return isoDate[1];
  return text;
}

function displayCellValue(value) {
  return formatDataPoint(value, 2);
}

function quartileTooltip() {
  let tooltip = $("quartileTooltip");
  if (!tooltip) {
    tooltip = document.createElement("div");
    tooltip.id = "quartileTooltip";
    tooltip.className = "quartile-tooltip hidden";
    document.body.appendChild(tooltip);
  }
  return tooltip;
}

function showQuartileTooltip(event, text) {
  const tooltip = quartileTooltip();
  tooltip.innerHTML = String(text || "").split("|").map((part, index) => index ? `<span>${escapeHtml(part)}</span>` : `<strong>${escapeHtml(part)}</strong>`).join("");
  tooltip.classList.remove("hidden");
  moveQuartileTooltip(event);
}

function moveQuartileTooltip(event) {
  const tooltip = quartileTooltip();
  const offset = 14;
  const rect = tooltip.getBoundingClientRect();
  const x = Math.min(event.clientX + offset, window.innerWidth - rect.width - 16);
  const y = Math.min(event.clientY + offset, window.innerHeight - rect.height - 16);
  tooltip.style.left = `${Math.max(12, x)}px`;
  tooltip.style.top = `${Math.max(12, y)}px`;
}

function hideQuartileTooltip() {
  quartileTooltip().classList.add("hidden");
}

function loadingStageCaptions(status) {
  const normalized = String(status || "").toLowerCase();
  const activeRowStage = String(state.rowProgress?.stage || "").toLowerCase();
  if (normalized.includes("file read") || normalized.includes("upload:") || normalized.includes("workbook") || normalized.includes("profil")) {
    return [
      "The file transfer and workbook processing are separate steps. A completed transfer does not mean Excel parsing has finished.",
      "Large workbooks take longer while Python opens the sheet and scans every row for column types, blanks, and unique values.",
      "The current stage below comes from the local server. The elapsed timer will continue even when a workbook library cannot report row-by-row progress.",
    ];
  }
  if (normalized.includes("sparrow")) {
    const nextStage = state.activeAnalysisEngines?.theme === "local" ? "local theme rules" : "Owl theme classification";
    return [
      "Sparrow is running now: it is classifying each verbatim as Positive, Neutral, or Negative.",
      `Current stage: sentiment classification. Next stage: ${nextStage}.`,
      "Sparrow is working locally on this system. The row counter shows confirmed sentiment progress.",
    ];
  }
  if (activeRowStage === "local rules" || normalized.includes("local rules")) {
    return [
      "Local NPS rules are running now. The row counter shows how many rows have been confirmed by the rule-based analysis.",
      "This stage is using the local rule path selected for this run.",
      "Feedback is still being processed on this system while the app prepares the NPS outputs.",
    ];
  }
  if (normalized.includes("vulture")) {
    return [
      "Owl is running now: it is classifying verbatims into 9 theme fields including drivers, issue type, impact, and resolution status.",
      "Current stage: theme classification. Next stage: the app will build executive, agent, manager, quartile, and analysis summaries.",
      "Owl is working locally on this system. The row counter shows confirmed theme-classification progress.",
    ];
  }
  if (normalized.includes("summary") || normalized.includes("dashboard") || normalized.includes("export")) {
    return [
      "Model work is complete. The app is now building dashboard tables, charts, movement views, and export-ready outputs.",
      "Final assembly is active: weekly trend, agent, manager, driver, alert, custom dimension, and workbook-ready sections are being prepared.",
      "This stage can take longer on large files because the app is grouping every analyzed row into multiple leadership views.",
    ];
  }
  return [
    `Local analysis is running. Sentiment: ${state.activeAnalysisEngines?.sentiment === "local" ? "Local Rules" : "Sparrow"}. Themes: ${state.activeAnalysisEngines?.theme === "local" ? "Local Rules" : "Owl"}.`,
    "Everything is still on this system. No customer feedback is being sent outside the app.",
  ];
}

function loadingStageDetails(status, pct = 0) {
  const normalized = String(status || "").toLowerCase();
  const activeRowStage = String(state.rowProgress?.stage || "").toLowerCase();
  if (normalized.includes("file read") || normalized.includes("upload:") || normalized.includes("workbook") || normalized.includes("profil") || normalized.includes("decode")) {
    return [
      ["1. Browser read", "Read the selected file from disk"],
      ["2. Local transfer", "Send it to the Python server on this computer"],
      ["3. Workbook parsing", "Open Excel and count rows and columns"],
      ["4. Column profile", "Build Explorer metadata and a small preview"],
    ];
  }
  const isAssembly = Number(pct || 0) >= 80
    || normalized.includes("summary")
    || normalized.includes("dashboard")
    || normalized.includes("export")
    || normalized.includes("assembly")
    || normalized.includes("weekly");
  if (isAssembly) {
    return [
      ["Dashboard views", "Executive cards, NPS trend, sentiment mix"],
      ["People rollups", "Agent, manager/TL, and custom dimensions"],
      ["Driver intelligence", "Themes, alerts, complaints, and opportunity tables"],
      ["Output pack", "Tables, charts, downloads, and read-only views"],
    ];
  }
  if (activeRowStage === "local rules" || normalized.includes("local rules")) {
    return [
      ["Local rules", "Applying the selected rule-based NPS logic"],
      ["Row confirmation", "Checking each included row against the mapped fields"],
      ["Score alignment", "Preparing NPS bands from your confirmed scale"],
      ["Local processing", "Feedback stays on this system"],
    ];
  }
  if (normalized.includes("sparrow") || normalized.includes("sentiment")) {
    return [
      ["Sentiment review", "Positive, passive, and negative classification"],
      ["Blank handling", "Empty comments are treated as passive"],
      ["Score alignment", "NPS score and verbatim tone are prepared"],
      ["Local processing", "Feedback stays on this system"],
    ];
  }
  return [
    ["File preparation", "Validating uploaded rows and mapped columns"],
    ["Lookup merge", "Joining base and lookup fields where selected"],
    ["Data quality", "Checking dates, score fields, and blank comments"],
    ["Ready for analysis", "Preparing NPS intelligence outputs"],
  ];
}

function formatElapsed(seconds) {
  const safe = Math.max(0, Math.floor(seconds || 0));
  const minutes = Math.floor(safe / 60);
  const secs = safe % 60;
  return `${String(minutes).padStart(2, "0")}:${String(secs).padStart(2, "0")}`;
}

function friendlyDuration(seconds) {
  const safe = Math.max(0, Math.floor(seconds || 0));
  const minutes = Math.floor(safe / 60);
  if (safe < 75) return "a little while";
  if (minutes === 1) return "1 minute";
  return `${minutes} minutes`;
}

function estimateRemainingText(pct) {
  const percent = Math.max(0, Math.min(100, Number(pct) || 0));
  const rows = Number(state.setupBaseRowCount || state.statsRowCounts?.base || 0);
  if (percent >= 99) return "";
  if (percent >= 95) return "the final steps are underway";
  if (rows >= 50000) {
    if (percent < 40) return "roughly 8 to 12 minutes more";
    if (percent < 75) return "roughly 4 to 7 minutes more";
    return "roughly 1 to 3 minutes more";
  }
  if (rows >= 10000) {
    if (percent < 45) return "roughly 3 to 6 minutes more";
    if (percent < 80) return "roughly 1 to 3 minutes more";
    return "less than 2 minutes";
  }
  if (percent < 60) return "roughly 1 to 2 minutes more";
  return "less than a minute";
}

function currentWorkbookSizeNote() {
  const rows = Number(state.setupBaseRowCount || state.statsRowCounts?.base || 0);
  const uploadBytes = state.rowProgress?.total && ["Upload", "File Read"].includes(state.rowProgress.stage)
    ? Number(state.rowProgress.total || 0)
    : 0;
  const mb = uploadBytes / (1024 * 1024);
  if (rows >= 50000 || mb >= 40) {
    return "This is a large workbook, so this stage can take some time.";
  }
  if (rows >= 10000 || mb >= 10) {
    return "This workbook has a healthy amount of data, so I am moving carefully through it.";
  }
  if (rows > 0) {
    return "This is a smaller workbook, so the analysis should move quickly once Excel finishes reading it.";
  }
  return "I am still measuring the workbook, so I will avoid guessing its size until the row count is ready.";
}

function conversationalLoadingMessage(status, pct = 0) {
  const elapsedSeconds = state.loadingStartedAt ? Math.floor((Date.now() - state.loadingStartedAt) / 1000) : 0;
  const elapsed = friendlyDuration(elapsedSeconds);
  const remaining = estimateRemainingText(pct);
  const sizeNote = currentWorkbookSizeNote();
  const normalized = String(status || "").toLowerCase();
  const activeRowStage = String(state.rowProgress?.stage || "").toLowerCase();
  if (normalized.includes("file read")) {
    return "I am reading the workbook from this computer first. Once I finish reading it, I will hand it to the local analyzer.";
  }
  if (normalized.includes("upload:")) {
    return "I am sending the workbook to the local analyzer now. Nothing is being sent outside this system.";
  }
  if (normalized.includes("workbook") || normalized.includes("received:") || normalized.includes("profil")) {
    return `${sizeNote} I am checking the column structure, blanks, and unique values now. If this step takes a little while, it usually means the workbook is still being read safely.`;
  }
  if (normalized.includes("starting local nps analysis")) {
    return `I am starting the NPS analysis with the options you selected. Based on the file size, it may take ${remaining}.`;
  }
  if (normalized.includes("sparrow")) {
    return `Sparrow is reviewing sentiment now. I know it has been ${elapsed}; model-based review can take longer, but it is still running locally.`;
  }
  if (activeRowStage === "local rules" || normalized.includes("local rules")) {
    return `I am applying the local NPS rules now and confirming rows with the rule-based analysis you selected. Estimated time left: ${remaining}.`;
  }
  if (normalized.includes("vulture")) {
    return `Owl is reading themes now. This part can take a little while because it checks feedback line by line. Estimated time left: ${remaining}.`;
  }
  if (normalized.includes("dashboard") || normalized.includes("summary") || normalized.includes("assembly")) {
    if (Number(pct || 0) >= 99) {
      return elapsedSeconds >= 120
        ? "The analysis is complete. I am packaging a large set of summaries and output views, so this final handoff is taking longer than usual."
        : "The analysis is complete. I am packaging the summaries and output views now.";
    }
    return `The analysis work is mostly done. I am preparing the summaries and output views now. ${remaining ? `Estimated time left: ${remaining}.` : "I am on the final handoff."}`;
  }
  if (normalized.includes("browser handoff")) {
    if (elapsedSeconds >= 180) {
      return "The analysis engine has finished. I am still bringing a large result package into the browser and preparing the guided briefing. This can take a few minutes for large files.";
    }
    return "The analysis engine has finished. I am bringing the results into the browser and preparing the guided briefing now.";
  }
  if (normalized.includes("browser preparation")) {
    if (normalized.includes("statistics")) return "The analysis is complete. I am loading supporting statistics and column profiles so the next screens have the right context.";
    if (normalized.includes("rendering")) return "The analysis is complete. I am building the dashboard views and evidence tables in the browser now.";
    if (normalized.includes("guided insight")) return "The analysis is complete. I am turning the results into the short guided briefing.";
    return "The analysis is complete. I am preparing the results experience in the browser.";
  }
  if (elapsedSeconds >= 240) {
    return `I know it has been ${elapsed}. ${sizeNote} Please hold on; estimated time left is ${remaining}.`;
  }
  return `I am working on it. ${sizeNote} Estimated time left: ${remaining}.`;
}

function parseRowProgress(text) {
  const uploadMatch = String(text || "").match(/(?:Upload|Sending)[^:]*:?\s*([\d,]+)\s*\/\s*([\d,]+)\s*bytes/i);
  if (uploadMatch) {
    const done = Number(uploadMatch[1].replaceAll(",", "")) || 0;
    const total = Number(uploadMatch[2].replaceAll(",", "")) || 0;
    return { stage: "Upload", done, display: done, total };
  }
  const readMatch = String(text || "").match(/(?:File Read|Reading)[^:]*:?\s*([\d,]+)\s*\/\s*([\d,]+)\s*bytes/i);
  if (readMatch) {
    const done = Number(readMatch[1].replaceAll(",", "")) || 0;
    const total = Number(readMatch[2].replaceAll(",", "")) || 0;
    return { stage: "File Read", done, display: done, total };
  }
  const match = String(text || "").match(/(?:Sparrow|Owl|Theme Builder|Local Rules)[^:]*:?\s*([\d,]+)\s*\/\s*([\d,]+)\s*rows/i);
  if (!match) return null;
  const lower = String(text).toLowerCase();
  const stage = lower.includes("theme builder") ? "Theme Builder" : lower.includes("local rules") ? "Local Rules" : lower.includes("vulture") ? "Owl" : "Sparrow";
  return {
    stage,
    done: Number(match[1].replaceAll(",", "")) || 0,
    display: Number(match[1].replaceAll(",", "")) || 0,
    total: Number(match[2].replaceAll(",", "")) || 0,
  };
}

function renderLoadingUi() {
  const now = Date.now();
  const elapsedSeconds = state.loadingStartedAt ? Math.floor((now - state.loadingStartedAt) / 1000) : 0;
  const row = state.rowProgress;
  const elapsed = $("loadingElapsed");
  if (elapsed) elapsed.textContent = `Elapsed ${formatElapsed(elapsedSeconds)}`;
  const rowText = $("loadingRows");
  if (rowText) {
    const rowDisplay = Number(row?.display ?? row?.done ?? row?.target ?? 0);
    const rowTotal = Number(row?.total || 0);
    if (rowTotal && row.stage === "Upload") {
      rowText.textContent = `Upload transferred ${formatFileSize(rowDisplay)}/${formatFileSize(rowTotal)}`;
    } else if (rowTotal && row.stage === "File Read") {
      rowText.textContent = `Browser read ${formatFileSize(rowDisplay)}/${formatFileSize(rowTotal)}`;
    } else {
      rowText.textContent = rowTotal
        ? `${row.stage} confirmed rows ${rowDisplay.toLocaleString()}/${rowTotal.toLocaleString()}`
        : "Preparing rows...";
    }
  }
  if (!state.lastCaptionAt || now - state.lastCaptionAt >= 5000) {
    state.lastCaptionAt = now;
    const caption = $("loadingCaption");
    if (caption) {
      const captions = loadingStageCaptions(state.loadingBaseStatus);
      caption.textContent = captions[state.loadingCaptionIndex % captions.length];
      state.loadingCaptionIndex += 1;
    }
  }
  const detail = $("loadingDetail");
  if (detail) {
    const items = loadingStageDetails(state.loadingBaseStatus, state.loadingDisplayPct);
    detail.innerHTML = items.map(([label, note]) => `
      <div class="loading-detail-item">
        <span aria-hidden="true"></span>
        <div><b>${escapeHtml(label)}</b><small>${escapeHtml(note)}</small></div>
      </div>
    `).join("");
  }
  const conversation = $("loadingConversation");
  if (conversation) conversation.textContent = conversationalLoadingMessage(state.loadingBaseStatus, state.loadingDisplayPct);
}

function updateProgress(text, pct = 0) {
  const boundedPct = Math.max(0, Math.min(100, Number(pct) || 0));
  const baseStatus = text || "Processing locally...";
  const now = Date.now();
  state.loadingBaseStatus = baseStatus;
  state.loadingDisplayPct = boundedPct;
  const parsedRows = parseRowProgress(baseStatus);
  if (parsedRows && parsedRows.total) {
    if (state.rowProgress.stage !== parsedRows.stage || state.rowProgress.total !== parsedRows.total) {
      state.rowProgress = { stage: parsedRows.stage, display: parsedRows.done, target: parsedRows.done, total: parsedRows.total };
      state.loadingCaptionIndex = 0;
      state.lastCaptionAt = 0;
    } else {
      state.rowProgress.target = Math.max(state.rowProgress.target, parsedRows.done);
      state.rowProgress.display = state.rowProgress.target;
    }
  }
  const hasNewProgress = baseStatus !== state.lastProgressText || Math.abs(boundedPct - state.lastProgressPct) >= 0.1;
  if (hasNewProgress) {
    state.lastProgressAt = now;
    state.lastProgressText = baseStatus;
    state.lastProgressPct = boundedPct;
  }
  const elapsedSeconds = state.lastProgressAt ? Math.floor((now - state.lastProgressAt) / 1000) : 0;
  const status = elapsedSeconds >= 5
    ? `${baseStatus} On track locally - no new checkpoint for ${elapsedSeconds}s.`
    : baseStatus;
  const tickerStatus = document.body.classList.contains("nps-onboarding-active") ? friendlyTickerStatus(status, boundedPct) : status;
  $("loadingText").textContent = tickerStatus;
  const conversation = $("loadingConversation");
  if (conversation) conversation.textContent = conversationalLoadingMessage(status, boundedPct);
  $("loadingPct").textContent = `${boundedPct.toFixed(2)}%`;
  $("progressBar").style.width = `${boundedPct}%`;
  renderLoadingUi();

  const last = state.progressHistory[state.progressHistory.length - 1];
  if (hasNewProgress && (!last || last.text !== baseStatus || Math.abs(last.pct - boundedPct) >= 1)) {
    state.progressHistory.push({ text: baseStatus, pct: boundedPct });
    state.progressHistory = state.progressHistory.slice(-4);
  }
  const steps = $("loadingSteps");
  if (steps) {
    steps.innerHTML = "";
    state.progressHistory.forEach((item) => {
      const row = document.createElement("div");
      row.className = "loading-step";
      const percent = document.createElement("span");
      percent.textContent = `${item.pct.toFixed(0)}%`;
      const detail = document.createElement("div");
      detail.textContent = item.text;
      row.append(percent, detail);
      steps.appendChild(row);
    });
  }
}

function showLoading(text, pct = 10) {
  state.progressHistory = [];
  state.lastProgressAt = 0;
  state.lastProgressText = "";
  state.lastProgressPct = 0;
  state.loadingStartedAt = Date.now();
  state.loadingCaptionIndex = 0;
  state.lastCaptionAt = 0;
  state.rowProgress = { stage: "", display: 0, target: 0, total: 0 };
  if (state.loadingUiTimer) clearInterval(state.loadingUiTimer);
  state.loadingUiTimer = setInterval(renderLoadingUi, 250);
  updateProgress(text, pct);
  $("loading").classList.remove("hidden");
}

function hideLoading() {
  if (state.progressTimer) {
    clearInterval(state.progressTimer);
    state.progressTimer = null;
  }
  if (state.loadingUiTimer) {
    clearInterval(state.loadingUiTimer);
    state.loadingUiTimer = null;
  }
  $("loading").classList.add("hidden");
}

async function pollProgress() {
  try {
    const response = await fetch("/api/analysis/progress", { cache: "no-store" });
    const payload = await response.json();
    const analysis = payload.analysis || payload || {};
    const pct = Number(analysis.progress || 0);
    updateProgress(analysis.status || "Processing locally...", pct);
  } catch (err) {
    console.warn("Progress poll failed", err);
  }
}

function startProgressPolling() {
  if (state.progressTimer) clearInterval(state.progressTimer);
  pollProgress();
  state.progressTimer = setInterval(pollProgress, 1000);
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function waitForAnalysisCompletion(expectedAnalysisId) {
  const started = Date.now();
  let missedPolls = 0;
  let maxProgress = 0;
  while (Date.now() - started < 60 * 60 * 1000) {
    try {
      const response = await fetch("/api/analysis/progress", { cache: "no-store" });
      if (!response.ok) throw new Error(`Analysis status check failed (${response.status})`);
      const payload = await response.json();
      const analysis = payload.analysis || payload || {};
      const currentProgress = Number(analysis.progress || 0);
      const currentAnalysisId = analysis.analysisId || "";
      if (expectedAnalysisId && currentAnalysisId !== expectedAnalysisId) {
        throw new Error("The local backend restarted or returned a different analysis session. Please refresh, re-upload the files, and run analysis again.");
      }
      if (!analysis.running && currentProgress < 100) {
        throw new Error(`Analysis stopped before completion at ${currentProgress.toFixed(1)}%. Status: ${analysis.status || "Unknown"}. Please run analysis again.`);
      }
      missedPolls = 0;
      maxProgress = Math.max(maxProgress, currentProgress);
      updateProgress(analysis.status || "Processing locally...", Math.max(currentProgress, maxProgress));
      if (analysis.error) throw new Error(analysis.error);
      if (!analysis.running && currentProgress >= 100) {
        if (state.progressTimer) {
          clearInterval(state.progressTimer);
          state.progressTimer = null;
        }
        updateProgress("Browser handoff: analysis engine is complete. Bringing the final result package into the app...", 96);
        const finalResponse = await fetch("/api/status", { cache: "no-store" });
        if (!finalResponse.ok) throw new Error(`Final dashboard load failed (${finalResponse.status})`);
        updateProgress("Browser handoff: final result package received. Preparing dashboard data for this screen...", 97);
        const finalPayload = await finalResponse.json();
        updateProgress("Browser handoff: dashboard data is ready. Preparing the guided briefing...", 98);
        return finalPayload.analysis || {};
      }
    } catch (err) {
      missedPolls += 1;
      console.warn("Analysis status poll missed", err);
      if (err.message && (err.message.includes("different analysis session") || err.message.includes("stopped before completion"))) {
        throw err;
      }
      const elapsedMinutes = Math.max(1, Math.round((Date.now() - started) / 60000));
      updateProgress(
        `Still working locally. The analysis engine may be busy with a large file; reconnecting to the status check (${missedPolls} missed, ${elapsedMinutes} min elapsed)...`,
        Math.max(state.lastProgressPct || 0, maxProgress)
      );
    }
    await sleep(missedPolls ? Math.min(5000, 1500 + missedPolls * 250) : 1500);
  }
  throw new Error("Analysis is still running after 60 minutes. Please check the local backend window.");
}

function friendlyTickerStatus(status, pct = 0) {
  const text = String(status || "").replace(/\s*On track locally\s*-\s*no new checkpoint for \d+s\.?/i, "").trim();
  const normalized = text.toLowerCase();
  const activeRowStage = String(state.rowProgress?.stage || "").toLowerCase();
  if (normalized.includes("file read")) return "Reading your workbook";
  if (normalized.includes("upload:")) return "Preparing the local analysis";
  if (normalized.includes("workbook:")) return "Opening the Excel file";
  if (normalized.includes("received:")) return "Opening the Excel file";
  if (normalized.includes("profile:") || normalized.includes("profil")) return "Checking workbook structure";
  if (normalized.includes("complete: workbook")) return "Workbook is ready";
  if (normalized.includes("starting local nps analysis")) return "Starting the NPS analysis";
  if (normalized.includes("sparrow")) return "Reading sentiment with Sparrow";
  if (activeRowStage === "local rules" || normalized.includes("local rules")) return "Applying local NPS rules";
  if (normalized.includes("vulture")) return "Reading themes with Owl";
  if (normalized.includes("browser handoff")) return "Preparing the results screen";
  if (normalized.includes("browser preparation")) return "Preparing the results screen";
  if ((normalized.includes("dashboard") || normalized.includes("summary") || normalized.includes("assembly")) && Number(pct || 0) >= 99) return "Finalizing your results";
  if (normalized.includes("dashboard") || normalized.includes("summary") || normalized.includes("assembly")) return "Preparing your results";
  if (normalized.includes("analysis complete")) return "Analysis complete";
  return text;
}

function setOptions(select, columns, selected = "") {
  select.innerHTML = "";
  const blank = document.createElement("option");
  blank.value = "";
  blank.textContent = "-- None --";
  select.appendChild(blank);
  columns.forEach((column) => {
    const option = document.createElement("option");
    option.value = column;
    option.textContent = column;
    if (column === selected) option.selected = true;
    select.appendChild(option);
  });
}

function normalizeColumnName(value) {
  return String(value || "").toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function pickFeedbackColumn(columns, guessed = "") {
  const available = Array.isArray(columns) ? columns : [];
  if (guessed && available.includes(guessed)) return guessed;
  const exactLabels = new Set([
    "verbatim feedback",
    "verbatim",
    "customer verbatim",
    "customer comment",
    "customer comments",
    "comment",
    "comments",
    "feedback",
    "feedback comment",
    "survey comment",
    "survey comments",
    "response text",
    "open text",
    "remarks",
  ]);
  const exact = available.find((column) => exactLabels.has(normalizeColumnName(column)));
  if (exact) return exact;
  const rankedNeedles = [
    "verbatim",
    "comment",
    "feedback",
    "review",
    "response text",
    "open text",
    "free text",
    "remarks",
    "description",
  ];
  return available.find((column) => {
    const normalized = normalizeColumnName(column);
    return rankedNeedles.some((needle) => normalized.includes(needle));
  }) || "";
}

function dynamicDimensionUniqueCount(column, source) {
  const profiles = source === "lookup" ? state.lookupColumnStats : state.baseColumnStats;
  const profile = profiles?.[column] || {};
  const unique = Number(profile.unique ?? profile.uniqueCount ?? profile["Unique Count"]);
  if (Number.isFinite(unique)) return unique;
  if (Array.isArray(profile.uniqueValues)) return profile.uniqueValues.length;
  return NaN;
}

function isEligibleDynamicDimension(column) {
  const inBase = normalizeColumnList(state.baseColumns).includes(column);
  const inLookup = normalizeColumnList(state.lookupColumns).includes(column);
  const counts = [];
  if (inBase) counts.push(dynamicDimensionUniqueCount(column, "base"));
  if (inLookup) counts.push(dynamicDimensionUniqueCount(column, "lookup"));
  return counts.some((count) => Number.isFinite(count) && count > 0 && count <= 10);
}

function refreshDynamicDimensionPicker() {
  const select = $("dynamicDimensionSelect");
  if (!select) return;
  const baseColumns = normalizeColumnList(state.baseColumns);
  const lookupColumns = normalizeColumnList(state.lookupColumns);
  const columns = [...new Set([...baseColumns, ...lookupColumns])]
    .filter((column) => column && !state.dynamicDimensions.includes(column) && isEligibleDynamicDimension(column));
  setOptions(select, columns, "");
  renderDynamicDimensionChips();
}

function renderDynamicDimensionChips() {
  const target = $("dynamicDimensionChips");
  if (!target) return;
  target.innerHTML = state.dynamicDimensions.length
    ? state.dynamicDimensions.map((column) => `<span class="dimension-chip">${escapeHtml(column)}<button type="button" data-remove-dimension="${escapeHtml(column)}">x</button></span>`).join("")
    : `<small>No extra dimensions selected.</small>`;
  target.querySelectorAll("[data-remove-dimension]").forEach((button) => {
    button.addEventListener("click", () => {
      state.dynamicDimensions = state.dynamicDimensions.filter((column) => column !== button.dataset.removeDimension);
      refreshDynamicDimensionPicker();
    });
  });
}

function refreshMapping() {
  const baseColumns = normalizeColumnList(state.baseColumns);
  const lookupColumns = normalizeColumnList(state.lookupColumns);
  state.baseColumns = baseColumns;
  state.lookupColumns = lookupColumns;
  const dimensionColumns = [...new Set([...baseColumns, ...lookupColumns])];
  const pickDimension = (...needles) => dimensionColumns.find((column) => needles.some((needle) => String(column).toLowerCase().includes(needle))) || "";
  setOptions($("feedbackCol"), baseColumns, pickFeedbackColumn(baseColumns, state.guesses.feedback || ""));
  setOptions($("scoreCol"), baseColumns, state.guesses.score || "");
  setOptions($("npsTypeCol"), baseColumns, pickLoyaltyColumn(baseColumns));
  setOptions($("agentCol"), baseColumns, state.guesses.agent || "");
  setOptions($("managerCol"), dimensionColumns, state.guesses.manager || pickDimension("manager", "tl name", "team manager", "supervisor"));
  setOptions($("dateCol"), baseColumns, state.guesses.date || "");
  setOptions($("waveCol"), dimensionColumns, state.guesses.wave || pickDimension("wave", "batch", "cohort"));
  setOptions($("tenureCol"), dimensionColumns, state.guesses.tenure || pickDimension("tenure", "tenurity"));
  setOptions($("baseKey"), baseColumns, state.guesses.agent || "");
  setOptions($("lookupKey"), lookupColumns, state.guesses.agent || "");
  refreshDynamicDimensionPicker();
  updateNpsBandHelp();
  refreshSummaryBuilder();
  renderSummaryBuilderPreview();
  $("analyzeBtn").disabled = !baseColumns.length;
}

function formatFileSize(bytes) {
  const value = Number(bytes || 0);
  if (value >= 1024 * 1024 * 1024) return `${(value / (1024 * 1024 * 1024)).toFixed(2)} GB`;
  if (value >= 1024 * 1024) return `${(value / (1024 * 1024)).toFixed(1)} MB`;
  if (value >= 1024) return `${(value / 1024).toFixed(1)} KB`;
  return `${value.toLocaleString()} bytes`;
}

function safeNumber(value, fallback = 0) {
  const number = Number(value);
  return Number.isFinite(number) ? number : fallback;
}

function formatCount(value, fallback = 0) {
  return Math.round(safeNumber(value, fallback)).toLocaleString();
}

function normalizeColumnList(value) {
  if (Array.isArray(value)) return value.filter((column) => column !== null && column !== undefined).map(String);
  if (value && typeof value === "object") return Object.values(value).filter((column) => column !== null && column !== undefined).map(String);
  return [];
}

function payloadColumns(payload, kind) {
  if (!payload || typeof payload !== "object") return [];
  return normalizeColumnList(
    payload.columns ||
    payload[`${kind}_columns`] ||
    payload.columnNames ||
    payload.headers ||
    payload.preview?.columns
  );
}

function chooseWorkbookSheet(fileName, sheetNames = []) {
  const names = normalizeColumnList(sheetNames);
  if (!names.length) return "";
  if (names.length === 1) return names[0];
  const options = names.map((name, index) => `${index + 1}. ${name}`).join("\n");
  const answer = window.prompt(`The workbook "${fileName}" has multiple sheets.\n\nChoose the sheet number or name to upload:\n\n${options}`, "1");
  if (answer === null) return "";
  const trimmed = String(answer || "").trim();
  const index = Number(trimmed);
  if (Number.isInteger(index) && index >= 1 && index <= names.length) return names[index - 1];
  return names.find((name) => name.toLowerCase() === trimmed.toLowerCase()) || names[0];
}

function setupCacheKey() {
  return "npsDashboardSetupCache";
}

function readSetupCache() {
  try {
    return JSON.parse(window.sessionStorage.getItem(setupCacheKey()) || "{}") || {};
  } catch (_) {
    return {};
  }
}

function writeSetupCache(updates = {}) {
  try {
    const next = { ...readSetupCache(), ...updates };
    window.sessionStorage.setItem(setupCacheKey(), JSON.stringify(next));
    return next;
  } catch (_) {
    return {};
  }
}

function clearSetupCache() {
  try {
    window.sessionStorage.removeItem(setupCacheKey());
  } catch (_) {
    /* Ignore storage failures. */
  }
}

async function verifyServerUpload(kind) {
  const response = await fetch("/api/status", { cache: "no-store" });
  const payload = await response.json();
  const columns = normalizeColumnList(kind === "base" ? payload.base_columns : payload.lookup_columns);
  const rows = Number(kind === "base" ? (payload.row_counts?.base || payload.base_rows || 0) : (payload.row_counts?.lookup || payload.lookup_rows || 0));
  if (!columns.length) {
    throw new Error(`${kind === "base" ? "Base" : "Lookup"} file was read in the browser, but the local server did not retain its columns. Please upload it again.`);
  }
  return { rows: Number.isFinite(rows) ? rows : 0, columns, payload };
}

function runProgressCallback(callback, ...args) {
  if (!callback) return;
  try {
    callback(...args);
  } catch (error) {
    console.warn("Upload progress callback failed", error);
  }
}

function fileToDataUrl(file, onProgress = null) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onprogress = (event) => {
      if (event.lengthComputable) runProgressCallback(onProgress, event.loaded, event.total);
    };
    reader.onload = () => {
      runProgressCallback(onProgress, file.size || 1, file.size || 1);
      resolve(reader.result);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function postJsonWithUploadProgress(url, body, onProgress = null, onServerProcessing = null) {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open("POST", url);
    xhr.setRequestHeader("Content-Type", "application/json");
    xhr.upload.onprogress = (event) => {
      if (event.lengthComputable) runProgressCallback(onProgress, event.loaded, event.total);
    };
    xhr.upload.onload = () => {
      runProgressCallback(onServerProcessing);
    };
    xhr.onload = () => {
      try {
        const payload = JSON.parse(xhr.responseText || "{}");
        if (xhr.status < 200 || xhr.status >= 300) reject(new Error(payload.error || `Upload failed (${xhr.status})`));
        else resolve(payload);
      } catch (err) {
        reject(err);
      }
    };
    xhr.onerror = () => reject(new Error("Upload failed while sending data to the local server."));
    xhr.send(body);
  });
}

async function refreshUploadProgress(uploadId) {
  try {
    const response = await fetch(`/api/upload/progress?id=${encodeURIComponent(uploadId)}`, { cache: "no-store" });
    const progress = await response.json();
    if (progress.ok && progress.message) updateProgress(`${progress.stage}: ${progress.message}`, Number(progress.percent || 60));
  } catch (error) {
    console.warn("Upload progress checkpoint unavailable", error);
  }
}

function setUploadComplete(kind, filename) {
  const button = kind === "base" ? $("baseUploadButton") : $("lookupUploadButton");
  const label = kind === "base" ? $("baseUploadLabel") : $("lookupUploadLabel");
  if (!button || !label) return;
  button.classList.add("uploaded");
  label.textContent = kind === "base" ? "Base File Uploaded" : "Lookup File Uploaded";
  button.title = filename;
  const previewButton = kind === "base" ? $("previewBaseFile") : $("previewLookupFile");
  if (previewButton) {
    previewButton.hidden = false;
    previewButton.textContent = `Preview ${kind === "base" ? "Base" : "Lookup"} File`;
  }
}

async function loadUploadedFilePreview(options = {}) {
  const current = state.filePreview || {};
  const next = {
    kind: options.kind || current.kind || "base",
    page: Math.max(1, Number(options.page || current.page || 1)),
    pageSize: Math.max(25, Number(options.pageSize || current.pageSize || 100)),
    search: options.search ?? current.search ?? "",
    pageCount: current.pageCount || 1,
  };
  state.filePreview = next;
  const response = await fetch("/api/uploaded-file-preview", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(next),
  });
  const payload = await response.json();
  if (!response.ok || !payload.ok) throw new Error(payload.error || "Could not preview the uploaded file.");
  state.filePreview.page = Number(payload.page || next.page);
  state.filePreview.pageCount = Number(payload.pageCount || 1);
  const title = $("filePreviewTitle");
  const subtitle = $("filePreviewSubtitle");
  const count = $("filePreviewCount");
  const pageStatus = $("filePreviewPageStatus");
  if (title) title.textContent = `${next.kind === "lookup" ? "Lookup" : "Base"} File Preview`;
  const sheet = payload.sheetName ? ` | Sheet: ${payload.sheetName}` : "";
  if (subtitle) subtitle.textContent = `${payload.fileName || "Uploaded workbook"}${sheet} | ${formatCount(payload.rows)} rows | ${formatCount(payload.columnCount)} columns`;
  if (count) count.textContent = `${formatCount(payload.filteredRows)} matching rows`;
  if (pageStatus) pageStatus.textContent = `Page ${formatCount(payload.page)} of ${formatCount(payload.pageCount)}`;
  const table = $("filePreviewTable");
  if (table) table.dataset.displayLimit = String(payload.pageSize || 100);
  renderAnyTable("filePreviewTable", payload.previewRows || [], Math.max(1, (payload.columns || []).length));
  const prev = $("filePreviewPrev");
  const nextButton = $("filePreviewNext");
  if (prev) prev.disabled = Number(payload.page || 1) <= 1;
  if (nextButton) nextButton.disabled = Number(payload.page || 1) >= Number(payload.pageCount || 1);
}

async function openUploadedFilePreview(kind = "base") {
  state.filePreview = { kind, page: 1, pageSize: Number($("filePreviewPageSize")?.value || 100), search: $("filePreviewSearch")?.value || "", pageCount: 1 };
  $("filePreviewModal")?.classList.remove("hidden");
  await loadUploadedFilePreview(state.filePreview);
}

function wireUploadedFilePreview() {
  $("previewBaseFile")?.addEventListener("click", () => openUploadedFilePreview("base").catch((err) => alert(err.message)));
  $("previewLookupFile")?.addEventListener("click", () => openUploadedFilePreview("lookup").catch((err) => alert(err.message)));
  $("closeFilePreviewModal")?.addEventListener("click", () => $("filePreviewModal")?.classList.add("hidden"));
  $("filePreviewPrev")?.addEventListener("click", () => loadUploadedFilePreview({ page: Math.max(1, (state.filePreview?.page || 1) - 1) }).catch((err) => alert(err.message)));
  $("filePreviewNext")?.addEventListener("click", () => loadUploadedFilePreview({ page: (state.filePreview?.page || 1) + 1 }).catch((err) => alert(err.message)));
  $("filePreviewPageSize")?.addEventListener("change", (event) => loadUploadedFilePreview({ page: 1, pageSize: Number(event.target.value || 100) }).catch((err) => alert(err.message)));
  let previewSearchTimer = null;
  $("filePreviewSearch")?.addEventListener("input", (event) => {
    if (previewSearchTimer) clearTimeout(previewSearchTimer);
    previewSearchTimer = window.setTimeout(() => {
      loadUploadedFilePreview({ page: 1, search: event.target.value || "" }).catch((err) => alert(err.message));
    }, 350);
  });
}

function baseFileSizeComment(rowCount) {
  const rows = Number(rowCount || 0);
  if (rows >= 50000) {
    return {
      title: "Great!",
      text: `I found ${rows.toLocaleString()} rows. This is a large file, so heavier analysis steps may take a little longer. I will keep showing progress while I prepare the next steps.`,
    };
  }
  if (rows >= 10000) {
    return {
      title: "Great!",
      text: `I found ${rows.toLocaleString()} rows. There is enough volume for meaningful NPS patterns, and I will keep the workflow staged so the setup stays manageable.`,
    };
  }
  if (rows > 0) {
    return {
      title: "Great!",
      text: `I found ${rows.toLocaleString()} rows. Setup should be quick. Smaller files are useful for pilots, but treat very low-volume cuts as directional.`,
    };
  }
  return {
    title: "Great!",
    text: "I have read the file structure. Next I will ask whether all required fields are already present or whether a lookup file is needed.",
  };
}

function showBaseFileInsight(rowCount) {
  const panel = $("guidedFileInsight");
  const title = $("guidedFileInsightTitle");
  const text = $("guidedFileInsightText");
  if (!panel) return;
  const comment = baseFileSizeComment(rowCount);
  if (title) title.textContent = comment.title;
  if (text) text.textContent = comment.text;
  panel.hidden = false;
}

function guidedAnalysisDurationEstimate() {
  const rows = Number(state.setupBaseRowCount || state.statsRowCounts?.base || 0);
  const sentiment = $("guidedSentimentEngine")?.value || $("sentimentEngine")?.value || "local";
  const theme = $("guidedThemeEngine")?.value || $("themeEngine")?.value || "local";
  let estimate = rows >= 50000 ? "around 8 to 15 minutes" : rows >= 10000 ? "around 3 to 8 minutes" : rows >= 1000 ? "around 1 to 3 minutes" : "usually under 1 minute";
  if (sentiment !== "local" || theme !== "local") {
    estimate = rows >= 50000 ? "around 12 to 25 minutes" : rows >= 10000 ? "around 5 to 12 minutes" : rows >= 1000 ? "around 2 to 5 minutes" : "around 1 to 2 minutes";
  }
  const rowText = rows ? `${rows.toLocaleString()} rows` : "the uploaded rows";
  return `I have your file, lookup decision, and confirmed column mapping. Please choose the analysis options below. Based on ${rowText}, this may take ${estimate}.`;
}

function updateGuidedAnalysisEstimate() {
  const target = $("guidedAnalysisEstimate");
  if (target) target.textContent = guidedAnalysisDurationEstimate();
}

function syncGuidedNpsRulesFromPreset(forceValues = false) {
  const scale = $("guidedNpsScoreScale")?.value || "10";
  const preset = NPS_BAND_PRESETS[scale] || NPS_BAND_PRESETS["5"];
  if (forceValues || scale !== "custom") {
    if ($("guidedNpsPromoterMin")) $("guidedNpsPromoterMin").value = preset.promoterMin;
    if ($("guidedNpsPassiveMin")) $("guidedNpsPassiveMin").value = preset.passiveMin;
  }
  if ($("npsScoreScale")) $("npsScoreScale").value = scale;
  if ($("npsPromoterMin")) $("npsPromoterMin").value = $("guidedNpsPromoterMin")?.value || preset.promoterMin;
  if ($("npsPassiveMin")) $("npsPassiveMin").value = $("guidedNpsPassiveMin")?.value || preset.passiveMin;
  if ($("guidedNpsRuleNote")) $("guidedNpsRuleNote").textContent = (NPS_BAND_PRESETS[scale] || NPS_BAND_PRESETS["5"]).help;
  updateNpsBandHelp();
}

function guidedNpsTargetValue() {
  const target = parseMetricNumber($("guidedNpsTarget")?.value);
  return Number.isFinite(target) ? target : 85;
}

function markSetupStepComplete(step, nextSelector = "") {
  state.setupConfirmedSteps = { ...(state.setupConfirmedSteps || {}), [step]: true };
  state.setupReviewStep = 0;
  updateGuidedSetupState();
  if (nextSelector) {
    document.querySelector(nextSelector)?.scrollIntoView({ behavior: "smooth", block: "center" });
  }
}

function setupGuideTargetSelector(step) {
  return {
    1: "#guidedBaseStep",
    2: "#guidedCoverageStep",
    3: "#guidedLookupStep",
    4: "#guidedMappingPanel",
    5: ".guided-analysis-options:not(.guided-calendar-options):not(.guided-dimension-options):not(.guided-engine-options):not(.guided-run-options)",
    6: ".guided-calendar-options",
    7: ".guided-dimension-options",
    8: ".guided-engine-options",
    9: ".guided-run-options",
  }[step] || "";
}

function revisitSetupStep(step) {
  const hasBase = (state.baseColumns || []).length > 0 || state.baseUploadComplete === true;
  const hasLookup = (state.lookupColumns || []).length > 0;
  if (step > 1 && !hasBase) {
    alert("Please upload the Base File first.");
    return;
  }
  if (step === 3 && state.setupCoverageChoice !== "lookup") {
    alert("Lookup File is only needed when you choose lookup support in Field Check.");
    return;
  }
  if (step === 4 && !(state.setupCoverageChoice === "complete" || hasLookup)) {
    alert("Complete the Field Check first, then review column mapping.");
    return;
  }
  if (step >= 5 && state.guidedMappingConfirmed !== true) {
    alert("Please confirm column mapping first.");
    return;
  }
  state.setupReviewStep = step;
  updateGuidedSetupState();
  const selector = setupGuideTargetSelector(step);
  requestAnimationFrame(() => {
    document.querySelector(selector)?.scrollIntoView({ behavior: "smooth", block: "center" });
  });
}

function wireSetupProgressGuide() {
  document.querySelectorAll("[data-guide-step]").forEach((item) => {
    if (item.dataset.boundSetupGuide === "1") return;
    item.dataset.boundSetupGuide = "1";
    item.setAttribute("role", "button");
    item.setAttribute("tabindex", "0");
    const open = () => revisitSetupStep(Number(item.dataset.guideStep || 0));
    item.addEventListener("click", open);
    item.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        open();
      }
    });
  });
}

function updateSetupConfirmButtons() {
  const buttonMap = {
    5: "confirmTargetScaleBtn",
    6: "confirmCalendarBtn",
    7: "confirmDimensionsBtn",
    8: "confirmIntelligenceBtn",
  };
  Object.entries(buttonMap).forEach(([step, id]) => {
    const button = $(id);
    if (!button) return;
    if (!button.dataset.defaultLabel) button.dataset.defaultLabel = button.textContent;
    const complete = state.setupConfirmedSteps?.[step] === true;
    button.classList.toggle("is-confirmed", complete);
    button.textContent = complete ? "Confirmed" : (button.dataset.defaultLabel || button.textContent);
  });
  const runButton = $("guidedRunAnalysisBtn");
  if (runButton) {
    const ready = [5, 6, 7, 8].every((step) => state.setupConfirmedSteps?.[step] === true);
    runButton.disabled = !ready;
    runButton.title = ready ? "" : "Confirm Target & Scale, Calendar, Dimensions, and Intelligence before running analysis.";
  }
}

function updateSetupProgressRail({ hasBase, hasLookup, coverageChoice, mappingConfirmed, analysisComplete, confirmedSteps = {} }) {
  const lookupSkipped = coverageChoice === "complete";
  const confirmed = new Set(Object.entries(confirmedSteps || {}).filter(([, done]) => done).map(([step]) => Number(step)));
  const currentStep = !hasBase ? 1
    : !coverageChoice ? 2
    : coverageChoice === "lookup" && !hasLookup ? 3
    : !mappingConfirmed ? 4
    : !analysisComplete && !confirmed.has(5) ? 5
    : !analysisComplete && !confirmed.has(6) ? 6
    : !analysisComplete && !confirmed.has(7) ? 7
    : !analysisComplete && !confirmed.has(8) ? 8
    : !analysisComplete ? 9
    : 9;
  const completeSteps = new Set();
  if (hasBase) completeSteps.add(1);
  if (coverageChoice) completeSteps.add(2);
  if (hasLookup) completeSteps.add(3);
  if (mappingConfirmed || analysisComplete) completeSteps.add(4);
  confirmed.forEach((step) => completeSteps.add(step));
  if (analysisComplete) [5, 6, 7, 8].forEach((step) => completeSteps.add(step));
  if (analysisComplete) completeSteps.add(9);
  document.querySelectorAll("[data-guide-step]").forEach((item) => {
    const step = Number(item.dataset.guideStep || 0);
    item.classList.toggle("is-complete", completeSteps.has(step));
    item.classList.toggle("is-current", step === currentStep && !analysisComplete);
    item.classList.toggle("is-skipped", step === 3 && lookupSkipped);
  });
}

function updateGuidedSetupState() {
  const hasBase = (state.baseColumns || []).length > 0 || state.baseUploadComplete === true;
  const hasLookup = (state.lookupColumns || []).length > 0;
  const coverageChoice = state.setupCoverageChoice || "";
  const mappingConfirmed = state.guidedMappingConfirmed === true;
  const analysisComplete = state.guidedAnalysisComplete === true;
  const baseStep = $("guidedBaseStep");
  const coverageStep = $("guidedCoverageStep");
  const lookupStep = $("guidedLookupStep");
  const mappingPanel = $("guidedMappingPanel");
  const analysisStep = $("guidedAnalysisStep");
  const analysisCompleteStep = $("guidedAnalysisComplete");
  if (baseStep) {
    baseStep.classList.toggle("active", !hasBase);
    baseStep.classList.toggle("guided-step-complete", hasBase);
  }
  if (coverageStep) {
    coverageStep.classList.toggle("is-locked", !hasBase);
    coverageStep.classList.toggle("active", hasBase && !coverageChoice);
  }
  if (lookupStep) {
    const showLookup = coverageChoice === "lookup";
    lookupStep.hidden = !showLookup;
    lookupStep.classList.toggle("is-locked", !showLookup);
    lookupStep.classList.toggle("active", showLookup && !hasLookup);
  }
  if (mappingPanel) {
    mappingPanel.classList.toggle("guided-mapping-ready", hasBase && (coverageChoice === "complete" || hasLookup));
  }
  if (analysisStep) analysisStep.hidden = !(mappingConfirmed && !analysisComplete);
  if (analysisCompleteStep) analysisCompleteStep.hidden = !analysisComplete;
  updateSetupConfirmButtons();
  updateGuidedAnalysisEstimate();
  const onboardingActive = state.guidedReleaseToApp !== true;
  document.body.classList.toggle("nps-onboarding-active", onboardingActive);
  document.body.classList.remove("nps-stage-upload", "nps-stage-success", "nps-stage-coverage", "nps-stage-lookup", "nps-stage-mapping", "nps-stage-analysis", "nps-stage-complete", "nps-stage-story");
  document.body.classList.remove("nps-review-step-1", "nps-review-step-2", "nps-review-step-3", "nps-review-step-4", "nps-review-step-5", "nps-review-step-6", "nps-review-step-7", "nps-review-step-8", "nps-review-step-9");
  if (onboardingActive) {
    const reviewStep = Number(state.setupReviewStep || 0);
    const reviewStage = reviewStep === 1 ? "upload"
      : reviewStep === 2 ? "coverage"
      : reviewStep === 3 ? "lookup"
      : reviewStep === 4 ? "mapping"
      : reviewStep >= 5 ? "analysis"
      : "";
    const stage = reviewStage || (!hasBase
      ? "upload"
      : analysisComplete
        ? "complete"
      : mappingConfirmed
        ? "analysis"
      : (coverageChoice === "complete" || hasLookup)
        ? "mapping"
        : coverageChoice === "lookup"
          ? "lookup"
        : "coverage");
    document.body.classList.add(`nps-stage-${stage}`);
    if (reviewStep) document.body.classList.add(`nps-review-step-${reviewStep}`);
  }
  document.querySelectorAll("[data-coverage-choice]").forEach((button) => {
    button.classList.toggle("active", button.dataset.coverageChoice === coverageChoice);
    button.disabled = !hasBase;
  });
  updateSetupProgressRail({ hasBase, hasLookup, coverageChoice, mappingConfirmed, analysisComplete, confirmedSteps: state.setupConfirmedSteps });
  wireSetupProgressGuide();
  scheduleGuidedStageCoachTip();
}

function setGuidedCoverageChoice(choice) {
  const hasBase = normalizeColumnList(state.baseColumns).length > 0 || state.baseUploadComplete === true;
  if (!hasBase) {
    alert("Please upload the Base File first. I will read the columns, then help you decide whether a lookup file is needed.");
    return;
  }
  state.setupCoverageChoice = choice;
  state.guidedMappingConfirmed = false;
  state.setupReviewStep = 0;
  state.guidedSetupStage = choice === "lookup" ? "lookup" : "mapping";
  updateGuidedSetupState();
  if (choice === "lookup") {
    $("guidedLookupStep")?.scrollIntoView({ behavior: "smooth", block: "start" });
    showCoachTipSoon("lookupUploadButton", "Upload the lookup file, then select the unique key in both files.", { key: "lookup-upload", position: "top" });
  } else {
    $("guidedMappingPanel")?.scrollIntoView({ behavior: "smooth", block: "start" });
    showCoachTipSoon("confirmMappingBtn", "I mapped what I could. Check the dropdowns once, then confirm.", { key: "confirm-mapping", position: "top" });
  }
}

function wireBaseInfoPanel() {
  const button = $("baseInfoButton");
  const panel = $("baseInfoPanel");
  const close = $("baseInfoClose");
  if (!button || !panel || button.dataset.boundBaseInfo === "1") return;
  button.dataset.boundBaseInfo = "1";
  button.addEventListener("click", () => {
    panel.hidden = !panel.hidden;
    if (!panel.hidden) panel.scrollIntoView({ behavior: "smooth", block: "nearest" });
  });
  close?.addEventListener("click", () => {
    panel.hidden = true;
    button.focus();
  });
}

function wireGuidedSuccessContinue() {
  const button = $("guidedSuccessContinue");
  if (!button || button.dataset.boundGuidedSuccess === "1") return;
  button.dataset.boundGuidedSuccess = "1";
  button.addEventListener("click", () => {
    state.guidedSetupStage = "coverage";
    updateGuidedSetupState();
    $("guidedCoverageStep")?.scrollIntoView({ behavior: "smooth", block: "center" });
    showCoachTipSoon("guidedCoverageStep", "Choose whether the Base File is complete or needs a lookup file.", { key: "coverage-choice", position: "top" });
  });
}

function wireConfirmMapping() {
  const button = $("confirmMappingBtn");
  if (!button || button.dataset.boundConfirmMapping === "1") return;
  button.dataset.boundConfirmMapping = "1";
  button.addEventListener("click", () => {
    state.setupConfirmedSteps = {};
    state.setupReviewStep = 0;
    state.guidedMappingConfirmed = true;
    state.guidedSetupStage = "analysis";
    if ($("guidedAnalysisStep")) $("guidedAnalysisStep").hidden = false;
    updateGuidedSetupState();
    $("guidedAnalysisStep")?.scrollIntoView({ behavior: "smooth", block: "center" });
    showCoachTipSoon("confirmTargetScaleBtn", "Confirm the target and scale first. I will move you through the remaining setup checks.", { key: "target-scale-confirm", position: "top" });
  });
}

function wireGuidedRunAnalysis() {
  const button = $("guidedRunAnalysisBtn");
  if (!button || button.dataset.boundGuidedRun === "1") return;
  button.dataset.boundGuidedRun = "1";
  $("guidedNpsScoreScale")?.addEventListener("change", () => {
    syncGuidedNpsRulesFromPreset(true);
  });
  ["guidedNpsTarget", "guidedNpsPromoterMin", "guidedNpsPassiveMin"].forEach((id) => {
    $(id)?.addEventListener("input", () => {
      if (id !== "guidedNpsTarget" && $("guidedNpsScoreScale")) $("guidedNpsScoreScale").value = "custom";
      syncGuidedNpsRulesFromPreset(false);
    });
  });
  $("confirmTargetScaleBtn")?.addEventListener("click", () => {
    syncGuidedNpsRulesFromPreset(false);
    markSetupStepComplete(5, ".guided-calendar-options");
  });
  $("confirmCalendarBtn")?.addEventListener("click", () => {
    markSetupStepComplete(6, ".guided-dimension-options");
  });
  $("confirmDimensionsBtn")?.addEventListener("click", () => {
    markSetupStepComplete(7, ".guided-engine-options");
  });
  $("confirmIntelligenceBtn")?.addEventListener("click", () => {
    if ($("sentimentEngine") && $("guidedSentimentEngine")) $("sentimentEngine").value = $("guidedSentimentEngine").value || "local";
    if ($("themeEngine") && $("guidedThemeEngine")) $("themeEngine").value = $("guidedThemeEngine").value || "local";
    markSetupStepComplete(8, ".guided-run-options");
  });
  $("guidedSentimentEngine")?.addEventListener("change", () => {
    if ($("sentimentEngine")) $("sentimentEngine").value = $("guidedSentimentEngine").value || "local";
    updateGuidedAnalysisEstimate();
  });
  $("guidedThemeEngine")?.addEventListener("change", () => {
    if ($("themeEngine")) $("themeEngine").value = $("guidedThemeEngine").value || "local";
    updateGuidedAnalysisEstimate();
  });
  syncGuidedNpsRulesFromPreset(false);
  button.addEventListener("click", () => analyze({ guided: true }).catch((err) => {
    hideLoading();
    alert(err.message || "Analysis failed. Please retry.");
  }));
}

