function guidedStructuredStoryConfig(key) {
  const context = guidedPerformanceContext();
  const gapText = `${context.targetGap >= 0 ? "+" : ""}${formatMetric(context.targetGap)} pts`;
  const movementText = Number.isFinite(context.movement) ? `${context.movement >= 0 ? "+" : ""}${formatMetric(context.movement)} pts` : "not available";
  const volumeText = context.total ? `${context.total.toLocaleString()} responses` : "response volume not available";
  const configs = {
    health: {
      view: "executive",
      title: "Let's start with the overall NPS health.",
      intro: `Current NPS is ${formatMetric(context.nps)} against a target of ${formatMetric(context.target)}. The target gap is ${gapText}.`,
      points: [
        ["Target gap", `Compare actual NPS with the target. Current status: ${gapText}.`],
        ["Customer mix", `${formatMetric(context.promoterPct)}% promoter, ${formatMetric(context.neutralPct)}% passive, and ${formatMetric(context.detractorPct)}% detractor.`],
        ["COPC-style confidence", `Use ${volumeText} to decide whether the signal is strong, directional, or limited.`],
      ],
    },
    recovery: {
      view: "executive",
      title: "Let's inspect the recovery gap.",
      intro: context.targetGap < 0
        ? `NPS is ${formatMetric(Math.abs(context.targetGap))} points below target, so the first job is to size the recovery opportunity.`
        : `NPS is meeting target, so this recovery view is useful for finding hidden detractor or passive pockets.`,
      points: [
        ["Detractor share", `${formatMetric(context.detractorPct)}% of responses are detractor based on the scale you selected.`],
        ["Passive opportunity", `${formatMetric(context.neutralPct)}% are passive, which may be the fastest conversion pool if operational fixes are clear.`],
        ["Corrective-action trigger", "COPC-style read: below-target performance should move into owner, action, due date, and effectiveness review."],
      ],
    },
    watch: {
      view: "executive",
      title: "Let's run a target watch.",
      intro: `NPS is close to target at ${formatMetric(context.nps)} versus ${formatMetric(context.target)}. This route looks for small moves that can protect or lift the score.`,
      points: [
        ["Near-target risk", `The target gap is ${gapText}, so small group-level gaps can decide the result.`],
        ["Passive conversion", `${formatMetric(context.neutralPct)}% passive responses can be checked for quick-win movement.`],
        ["Consistency check", "COPC-style read: confirm the result is consistent across groups before calling it stable."],
      ],
    },
    sustain: {
      view: "executive",
      title: "Let's understand what is working.",
      intro: `NPS is meeting target. Now the story should explain whether performance is sustainable and where the best practices sit.`,
      points: [
        ["Sustained achievement", `Current target gap is ${gapText}. Check whether this is repeated across periods, not just one view.`],
        ["Benchmark groups", "Find the strongest groups and use them as internal benchmarks for process, coaching, or operating rhythm."],
        ["Variation control", "COPC-style read: good overall performance still needs variance checks so weak pockets are not hidden."],
      ],
    },
    movement: {
      view: "executive",
      title: "Let's look at trend and movement.",
      intro: `Latest movement is ${movementText}. This route checks whether direction is improving, declining, or volatile.`,
      points: [
        ["Latest movement", `Compare the latest period with the previous period. Current movement: ${movementText}.`],
        ["Volume by period", "Check whether each period has enough responses before trusting the movement."],
        ["Stability", "COPC-style read: stable performance matters as much as one good latest score."],
      ],
    },
    volume: {
      view: "executive",
      title: "Let's check whether the evidence is strong enough.",
      intro: `This route looks at response volume before we decide how strongly to act on any signal. Current volume is ${volumeText}.`,
      points: [
        ["Evidence strength", "Separate actionable findings from directional or monitor-only signals."],
        ["Period volume", "Check whether weekly or monthly changes are supported by enough responses."],
        ["Group volume", "Avoid over-reading small agent, channel, or site groups."],
      ],
    },
    people: {
      view: "agent",
      title: "Let's review people performance.",
      intro: "This story uses mapped agent, manager, wave, and tenure fields where available.",
      points: [
        ["Agent variance", "Find whether NPS differs meaningfully across agents, but only act where response volume is credible."],
        ["Manager variance", "Check whether team or TL-level gaps are creating consistent performance variation."],
        ["Coaching priority", "COPC-style read: prioritize material variance with clear evidence, not only the lowest score."],
      ],
    },
    data: {
      view: "executive",
      title: "Let's validate the data quality signal.",
      intro: `This route checks blanks, missing fields, and grouping reliability before we trust the investigation output.`,
      points: [
        ["Completeness", `Largest sampled blank concentration is ${formatMetric(context.maxBlankShare)}%.`],
        ["Mapping confidence", "Check whether the fields needed for people, trend, and operations analysis are present."],
        ["Use caution", "COPC-style read: unreliable data should be flagged before action is assigned."],
      ],
    },
    operations: {
      view: "executive",
      title: "Let's inspect operational variance.",
      intro: "This route is for channels, queues, sites, regions, LOBs, and other operational paths.",
      points: [
        ["Channel or queue", "Check whether a specific operational path is pulling NPS down."],
        ["Location or LOB", "Compare site, region, location, or business-line consistency."],
        ["Process signal", "COPC-style read: operational concentration often points to process or access-channel action."],
      ],
    },
  };
  return configs[key] || configs.health;
}

function openGuidedStory(key, signalIndex = -1) {
  const config = guidedStructuredStoryConfig(key);
  state.guidedStoryActive = true;
  state.guidedStoryKey = key;
  state.guidedStoryView = config.view;
  state.guidedAttackChooserVisible = true;
  if (Number.isFinite(signalIndex) && signalIndex >= 0) {
    state.guidedSelectedSignalIndex = signalIndex;
  } else {
    const cards = currentGuidedSignalCards();
    const fallbackIndex = cards.findIndex((card) => card.story === key);
    state.guidedSelectedSignalIndex = fallbackIndex >= 0 ? fallbackIndex : 0;
  }
  if ($("guidedStoryChooser")) $("guidedStoryChooser").hidden = true;
  if ($("guidedInsightDeck")) {
    $("guidedInsightDeck").hidden = false;
    $("guidedInsightDeck").classList.add("attack-mode", "story-selected");
  }
  if ($("guidedStoryTitle")) $("guidedStoryTitle").textContent = config.title;
  if ($("guidedStoryIntro")) $("guidedStoryIntro").textContent = config.intro;
  if ($("guidedStoryPoints")) {
    $("guidedStoryPoints").innerHTML = config.points.map((point, index) => `
      <div class="guided-story-point">
        <span>${index + 1}</span>
        <strong>${escapeHtml(point[0])}</strong>
        <small>${escapeHtml(point[1])}</small>
      </div>
    `).join("");
  }
  if ($("guidedStoryPanel")) $("guidedStoryPanel").hidden = false;
  if ($("guidedStoryContinue")) $("guidedStoryContinue").textContent = `Start ${guidedStoryName(key)} investigation`;
  updateGuidedSetupState();
  window.setTimeout(() => scrollGuidedElementIntoView("guidedStoryPanel", { block: "start", offset: 18 }), 120);
  showCoachTipSoon("guidedStoryContinue", "Review this route. Start it if it looks right, or choose a different signal if this is not what you wanted.", {
    key: `story-choice-${key}`,
    position: "top",
    force: true,
    delay: 900,
    duration: 4200,
  });
  scheduleGuidedStageCoachTip();
}

function returnToGuidedAttackDeck() {
  state.guidedStoryActive = false;
  state.guidedAttackChooserVisible = true;
  if ($("guidedStoryPanel")) $("guidedStoryPanel").hidden = true;
  if ($("guidedInsightDeck")) $("guidedInsightDeck").hidden = false;
  $("guidedInsightDeck")?.classList.remove("story-selected");
  renderGuidedAttackDeck();
  window.setTimeout(() => scrollGuidedElementIntoView("guidedInsightDeck", { block: "start", offset: 18 }), 90);
  showCoachTipSoon("guidedAttackDeck", "Pick another signal, or use Back to return to the 10th briefing insight.", { key: "return-to-attack-cards", position: "bottom", force: true, delay: 650, duration: 4600 });
  scheduleGuidedStageCoachTip();
}

async function uploadFile(kind, file) {
  if (!file) return;
  if (kind === "base") {
    state.baseUploadComplete = false;
    window.sessionStorage.removeItem("npsGuidedAnalysisId");
    window.sessionStorage.setItem("npsGuidedBaseFile", file.name);
    updateGuidedSetupState();
  }
  const fileSize = formatFileSize(file.size || 0);
  const statusEl = kind === "base" ? $("baseStatus") : $("lookupStatus");
  if (statusEl) statusEl.textContent = `Preparing ${file.name} (${fileSize})...`;
  showLoading(`Preparing ${kind} file upload: ${file.name} (${fileSize})...`, 2);
  const data = await fileToDataUrl(file, (loaded, total) => {
    const safeLoaded = safeNumber(loaded);
    const safeTotal = safeNumber(total, safeLoaded || 1);
    const pct = safeTotal ? safeLoaded / safeTotal : 0;
    if (statusEl) statusEl.textContent = `Reading workbook in browser... ${Math.round(pct * 100)}%`;
    updateProgress(`File Read: ${formatCount(safeLoaded)}/${formatCount(safeTotal || safeLoaded)} bytes. Reading ${kind} workbook in the browser before local upload...`, 2 + pct * 28);
  });
  const uploadId = `upload-${Date.now()}-${Math.random().toString(16).slice(2)}`;
  const body = JSON.stringify({ kind, name: file.name, data, uploadId });
  let parserTimer = null;
  let payload = await postJsonWithUploadProgress(
    "/api/upload",
    body,
    (loaded, total) => {
      const safeLoaded = safeNumber(loaded);
      const safeTotal = safeNumber(total, safeLoaded || 1);
      const pct = safeTotal ? safeLoaded / safeTotal : 0;
      if (statusEl) statusEl.textContent = `Uploading to local analyzer... ${Math.round(pct * 100)}%`;
      updateProgress(`Upload: ${formatCount(safeLoaded)}/${formatCount(safeTotal || safeLoaded)} bytes. Sending ${kind} workbook to the local server...`, 32 + pct * 28);
    },
    () => {
      if (statusEl) statusEl.textContent = "Local Python engine is opening the workbook...";
      updateProgress("Received: File transfer complete. Waiting for Python to open the workbook...", 62);
      refreshUploadProgress(uploadId);
      parserTimer = setInterval(() => refreshUploadProgress(uploadId), 750);
    }
  ).finally(() => {
    if (parserTimer) clearInterval(parserTimer);
  });
  if (payload.needsSheetSelection) {
    const sheetName = chooseWorkbookSheet(file.name, payload.sheetNames || []);
    if (!sheetName) throw new Error("Upload cancelled because no workbook sheet was selected.");
    const sheetUploadId = `upload-${Date.now()}-${Math.random().toString(16).slice(2)}`;
    const sheetBody = JSON.stringify({ kind, name: file.name, data, uploadId: sheetUploadId, sheetName });
    parserTimer = null;
    if (statusEl) statusEl.textContent = `Opening sheet: ${sheetName}...`;
    updateProgress(`Sheet selected: Opening "${sheetName}" and building the column profile...`, 64);
    payload = await postJsonWithUploadProgress(
      "/api/upload",
      sheetBody,
      null,
      () => {
        if (statusEl) statusEl.textContent = `Local Python engine is opening ${sheetName}...`;
        updateProgress(`Received: Sheet "${sheetName}" selected. Waiting for Python to open the workbook...`, 66);
        refreshUploadProgress(sheetUploadId);
        parserTimer = setInterval(() => refreshUploadProgress(sheetUploadId), 750);
      }
    ).finally(() => {
      if (parserTimer) clearInterval(parserTimer);
    });
  }
  if (!payload.ok) throw new Error(payload.error || "Upload failed");
  const loadedRows = safeNumber(payload.rows);
  const columns = payloadColumns(payload, kind);
  const verified = await verifyServerUpload(kind);
  const verifiedColumns = verified.columns.length ? verified.columns : columns;
  updateProgress(`Complete: Workbook parsed successfully. ${formatCount(loadedRows)} rows loaded from ${file.name}. Preparing the Explorer preview...`, 98);
  if (kind === "base") {
    state.baseColumns = verifiedColumns;
    state.baseColumnStats = payload.columnStats || {};
    state.guesses = payload.guesses || {};
    state.setupBaseRowCount = loadedRows;
    state.baseUploadComplete = true;
    $("baseStatus").textContent = `Uploaded: ${file.name}`;
    setUploadComplete("base", file.name);
    if (!state.setupCoverageChoice) state.setupCoverageChoice = "";
    state.guidedSetupStage = "coverage";
    state.setupConfirmedSteps = {};
    writeSetupCache({
      baseFile: file.name,
      baseRows: loadedRows,
      baseColumns: verifiedColumns,
      baseColumnStats: state.baseColumnStats,
      guesses: state.guesses,
    });
  } else {
    if (verifiedColumns.length) state.lookupColumns = verifiedColumns;
    state.lookupColumnStats = columns.length ? (payload.columnStats || {}) : state.lookupColumnStats;
    state.guidedSetupStage = "mapping";
    state.guidedMappingConfirmed = false;
    state.setupConfirmedSteps = {};
    $("lookupStatus").textContent = `Uploaded: ${file.name}`;
    setUploadComplete("lookup", file.name);
    writeSetupCache({
      lookupFile: file.name,
      lookupRows: loadedRows,
      lookupColumns: normalizeColumnList(state.lookupColumns),
      lookupColumnStats: state.lookupColumnStats,
    });
  }
  $("rowStatus").textContent = `${formatCount(loadedRows)} rows loaded from ${file.name}`;
  refreshMapping();
  updateGuidedSetupState();
  await loadStatisticsData();
  hideLoading();
  if (kind === "base") {
    $("guidedCoverageStep")?.scrollIntoView({ behavior: "smooth", block: "center" });
    showCoachTipSoon("guidedCoverageStep", "Choose whether the Base File is complete or needs a lookup file.", { key: "coverage-choice", position: "top" });
  } else {
    showCoachTipSoon("confirmMappingBtn", "Lookup is ready. Confirm the mapping once before analysis.", { key: "lookup-mapping-ready", position: "top" });
  }
}



async function loadStatisticsData() {
  try {
    const response = await fetch("/api/statistics-data");
    const payload = await response.json();
    if (!payload.ok) return;
    state.statsData = {
      baseRows: payload.baseRows || [],
      lookupRows: payload.lookupRows || [],
      analyzedRows: payload.analyzedRows || [],
    };
    state.statsRowCounts = payload.rowCounts || {};
    state.statsSampleLimit = Number(payload.sampleLimit || 200);
    state.baseColumnStats = payload.columnProfiles?.base || state.baseColumnStats || {};
    state.lookupColumnStats = payload.columnProfiles?.lookup || state.lookupColumnStats || {};
    state.analyzedColumnStats = payload.columnProfiles?.analyzed || {};
    renderCustomStatsShell();
    renderColumnExplorer();
  } catch (err) {
    console.warn("Statistics data could not be loaded", err);
  }
}

function parseMetricNumber(value) {
  if (typeof value === "number") return Number.isFinite(value) ? value : NaN;
  if (typeof value === "boolean") return value ? 1 : 0;
  const text = String(value ?? "").trim();
  if (!text) return NaN;
  const normalized = text.replace(/,/g, "").replace(/%$/g, "").trim();
  if (!normalized || /^nan|null|none|unknown|n\/a|-$/i.test(normalized)) return NaN;
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : NaN;
}
function metric(label, value, note = "", tone = "", artifact = "", logic = "") {
  const toneClass = tone ? ` metric-${tone}` : "";
  const noteHtml = note ? `<small>${escapeHtml(note)}</small>` : "";
  const artifactAttrs = artifact
    ? ` metric-clickable" role="button" tabindex="0" data-artifact="${escapeHtml(artifact)}" title="Click for supporting rows. Double-click for calculation logic."`
    : `"`;
  const logicAttr = logic ? ` data-logic="${escapeHtml(logic)}"` : "";
  return `<div class="metric-card${toneClass}${artifactAttrs}${logicAttr}><span>${escapeHtml(label)}</span><strong>${escapeHtml(String(value))}</strong>${noteHtml}</div>`;
}

function segmentNote(segmentSentiments, segment) {
  const counts = segmentSentiments?.[segment] || {};
  return `Positive ${counts.Positive || 0} | Passive ${counts.Passive || 0} | Negative ${counts.Negative || 0}`;
}

function artifactKeyForMetric(label) {
  const normalized = String(label || "").toLowerCase();
  if (normalized.includes("total response")) return "total";
  if (normalized.includes("Promoter")) return "Promoter";
  if (normalized.includes("Passive")) return "Passive";
  if (normalized.includes("Detractor") || normalized.includes("at-risk")) return "Detractor";
  if (normalized.includes("silent")) return "silent-Detractor";
  if (normalized.includes("positive sentiment")) return "positive-sentiment";
  if (normalized.includes("negative sentiment")) return "negative-sentiment";
  if (normalized.includes("top driver")) return "top-driver";
  if (normalized.includes("best week")) return "best-week";
  if (normalized.includes("lowest week")) return "lowest-week";
  if (normalized.includes("week") || normalized.includes("wow") || normalized.includes("volatility") || normalized.includes("4-week")) return "weekly";
  if (normalized.includes("NPS")) return "total";
  return "total";
}

function allFeedbackRows(context = {}) {
  const detailed = state.analysis.feedbackRows || [];
  const compact = state.analysis.feedbackTableRows || [];
  let rows;
  if (!compact.length) rows = detailed;
  else {
    const byId = new Map(detailed.map((row) => [String(row.__row_id), row]));
    rows = compact.map((row) => ({ ...(byId.get(String(row.__row_id)) || {}), ...row }));
  }
  if (!rows.length) rows = state.analysis.preview || state.statsData?.analyzedRows || state.statsData?.baseRows || [];
  if (context.type === "agent" && context.value && context.value !== "All Agents") {
    return rows.filter((row) => String(row["Agent Name"] || "") === context.value);
  }
  if (context.type === "manager" && context.value && context.value !== "All Managers") {
    return rows.filter((row) => String(row["Manager/TL"] || "") === context.value);
  }
  return rows;
}

function rowBool(value) {
  const text = String(value ?? "").trim().toLowerCase();
  return ["1", "true", "yes", "y"].includes(text);
}

function metricArtifactRows(key, context = {}) {
  const rows = allFeedbackRows(context);
  const summaryRows = state.analysis.weekly || [];
  const statsRows = selectedStatsRows();
  const statsMetricA = $("statsMetricA")?.value || "NPS";
  const statsMetricB = $("statsMetricB")?.value || "Responses";
  const lower = (value) => String(value ?? "").toLowerCase();
  if (key === "weekly") return { title: "Weekly Supporting Artifact", rows: summaryRows, kind: "summary" };
  if (key === "best-week") return { title: "Best Week Artifact", rows: summaryRows.slice().sort((a, b) => Number(b.NPS || 0) - Number(a.NPS || 0)).slice(0, 1), kind: "summary" };
  if (key === "lowest-week") return { title: "Lowest Week Artifact", rows: summaryRows.slice().sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0)).slice(0, 1), kind: "summary" };
  if (key === "Promoter") return { title: "Promoter Artifact", rows: rows.filter((row) => lower(row["NPS Type"]) === "Promoter") };
  if (key === "Passive") return { title: "Passive Artifact", rows: rows.filter((row) => lower(row["NPS Type"]) === "Passive") };
  if (key === "Detractor") return { title: "Detractor Artifact", rows: rows.filter((row) => lower(row["NPS Type"]) === "Detractor") };
  if (key === "silent-Detractor") return { title: "Passive Risk Artifact", rows: rows.filter((row) => rowBool(row["Passive Risk Alert"])) };
  if (key === "positive-sentiment") return { title: "Positive Sentiment Artifact", rows: rows.filter((row) => lower(row.Sentiment) === "positive") };
  if (key === "negative-sentiment") return { title: "Negative Sentiment Artifact", rows: rows.filter((row) => lower(row.Sentiment) === "negative") };
  if (key === "top-driver") {
    const reasons = state.analysis.reasons || [];
    const top = reasons[0] || {};
    const label = top["Primary Reason"] || top.Reason || top.Driver || top["Bucket Category"] || "";
    const filtered = label
      ? rows.filter((row) => [row["Primary Reason"], row["Bucket Category"], row["Owl Primary Driver"]].some((value) => lower(value) === lower(label)))
      : rows;
    return { title: label ? `Top Driver Artifact: ${label}` : "Top Driver Artifact", rows: filtered };
  }
  if (key === "stats-correlation" || key === "stats-sample" || key === "stats-direction") {
    const pairs = statsRows
      .map((row, index) => ({
        index: index + 1,
        label: row.Week || row["Agent Name"] || row["Manager/TL"] || `Row ${index + 1}`,
        a: Number(row[statsMetricA]),
        b: Number(row[statsMetricB]),
      }))
      .filter((row) => !Number.isNaN(row.a) && !Number.isNaN(row.b));
    const avgA = average(pairs.map((row) => row.a));
    const avgB = average(pairs.map((row) => row.b));
    const corr = correlation(pairs.map((row) => row.a), pairs.map((row) => row.b));
    const calcRows = [
      {
        Step: "Formula",
        Detail: "Pearson correlation = sum((A - average A) x (B - average B)) / sqrt(sum((A - average A)^2) x sum((B - average B)^2))",
        [statsMetricA]: "",
        [statsMetricB]: "",
      },
      {
        Step: "Result",
        Detail: corr ? `${corr.value.toFixed(4)} using ${corr.sample} ${$("statsLevel")?.value || "selected"} rows` : "Not enough variation to calculate correlation",
        [statsMetricA]: `Average ${formatMetric(avgA)}`,
        [statsMetricB]: `Average ${formatMetric(avgB)}`,
      },
      ...pairs.map((row) => {
        const deltaA = row.a - avgA;
        const deltaB = row.b - avgB;
        return {
          Step: row.index,
          Detail: row.label,
          [statsMetricA]: formatMetric(row.a),
          [statsMetricB]: formatMetric(row.b),
          "A - Avg A": formatMetric(deltaA),
          "B - Avg B": formatMetric(deltaB),
          "Cross Product": formatMetric(deltaA * deltaB),
        };
      }),
    ];
    return { title: `${statsMetricA} vs ${statsMetricB} Correlation Artifact`, rows: calcRows, kind: "summary" };
  }
  if (key === "stats-volatility") {
    const npsRows = summaryRows.map((row) => ({
      Week: row.Week,
      NPS: formatMetric(row.NPS),
      Responses: row.Responses,
      Promoter: row.Promoter,
      Passive: row.Passive,
      Detractor: row.Detractor,
    }));
    return { title: "NPS Volatility Artifact", rows: npsRows, kind: "summary" };
  }
  if (key === "stats-volume-variability") {
    const values = summaryRows.map((row) => Number(row.Responses || 0));
    const avg = average(values);
    const sd = stdDev(values);
    return {
      title: "Volume Variability Artifact",
      rows: [
        { Step: "Average weekly responses", Value: formatMetric(avg) },
        { Step: "Standard deviation", Value: formatMetric(sd) },
        { Step: "Coefficient of variation", Value: avg ? `${formatMetric((sd / avg) * 100)}%` : "0%" },
        ...summaryRows.map((row) => ({ Week: row.Week, Responses: row.Responses, "Response - Average": formatMetric(Number(row.Responses || 0) - avg) })),
      ],
      kind: "summary",
    };
  }
  if (key === "stats-sentiment-skew") {
    return {
      title: "Sentiment Skew Artifact",
      rows: [
        { Sentiment: "Positive", Share: `${formatMetric(state.analysis.sentiment?.Positive || 0)}%`, Records: rows.filter((row) => lower(row.Sentiment) === "positive").length },
        { Sentiment: "Negative", Share: `${formatMetric(state.analysis.sentiment?.Negative || 0)}%`, Records: rows.filter((row) => lower(row.Sentiment) === "negative").length },
        { Sentiment: "Skew", Share: `${formatMetric(Number(state.analysis.sentiment?.Positive || 0) - Number(state.analysis.sentiment?.Negative || 0))} pts`, Records: "" },
      ],
      kind: "summary",
    };
  }
  if (key === "stats-Detractor-rate") {
    return { title: "Detractor Rate Artifact", rows: rows.filter((row) => lower(row["NPS Type"]) === "Detractor") };
  }
  return { title: "Total Responses Artifact", rows };
}

function attachMetricArtifacts(targetId, context = {}) {
  const container = $(targetId);
  if (!container) return;
  container.querySelectorAll("[data-artifact]").forEach((card) => {
    let clickTimer = null;
    const open = () => openArtifact(card.dataset.artifact, card.querySelector("span")?.textContent || "Artifact", context);
    const openLogic = () => {
      const title = card.querySelector("span")?.textContent || "Metric logic";
      showPerformanceLogicDialog(title, card.dataset.logic || "No calculation logic is available for this metric.");
    };
    card.addEventListener("click", () => {
      if (clickTimer) clearTimeout(clickTimer);
      clickTimer = setTimeout(() => {
        clickTimer = null;
        open();
      }, card.dataset.logic ? 220 : 0);
    });
    card.addEventListener("dblclick", (event) => {
      event.preventDefault();
      event.stopPropagation();
      if (clickTimer) clearTimeout(clickTimer);
      clickTimer = null;
      openLogic();
    });
    card.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        open();
      }
    });
  });
}

function firstDefined(...values) {
  return values.find((value) => value !== undefined && value !== null && value !== "");
}

function roundedCountsFromShares(total, shares) {
  const raw = shares.map((share) => Math.max(0, Number(share || 0)) * total / 100);
  const counts = raw.map(Math.floor);
  let remaining = Math.max(0, total - counts.reduce((sum, value) => sum + value, 0));
  raw
    .map((value, index) => ({ index, remainder: value - Math.floor(value) }))
    .sort((a, b) => b.remainder - a.remainder)
    .forEach((item) => {
      if (remaining > 0) {
        counts[item.index] += 1;
        remaining -= 1;
      }
    });
  return counts;
}

function npsDisplayCounts(summary = {}, counts = {}) {
  const total = Number(summary.total || counts.Total || counts.Responses || 0) || 0;
  const supplied = [
    Number(counts.Promoter ?? 0),
    Number(counts.Passive ?? 0),
    Number(counts.Detractor ?? 0),
  ];
  const suppliedTotal = supplied.reduce((sum, value) => sum + value, 0);
  const percentShaped = total > 100 && suppliedTotal > 0 && Math.abs(suppliedTotal - 100) <= 1.5;
  const values = percentShaped ? roundedCountsFromShares(total, supplied) : supplied.map((value) => Math.round(value));
  return {
    Total: total || values.reduce((sum, value) => sum + value, 0),
    Promoter: values[0] || 0,
    Passive: values[1] || 0,
    Detractor: values[2] || 0,
  };
}

function interactiveAnalysisTotal(analysis = state.analysis || {}, summary = {}, counts = {}) {
  const rows = analysis.feedbackTableRows || analysis.feedbackRows || analysis.preview || [];
  return Number(
    analysis.population?.rows
    || analysis.population?.classifiedRows
    || analysis.population?.totalRows
    || analysis.outputCount
    || analysis.totalRows
    || summary.total
    || summary.Total
    || counts.Total
    || counts.total
    || counts.Responses
    || rows.length
    || 0
  ) || 0;
}

function interactiveNpsCounts(summary = {}, counts = {}, total = 0) {
  const visible = npsDisplayCounts(summary, counts);
  const visibleTotal = visible.Promoter + visible.Passive + visible.Detractor;
  if (!total || !visibleTotal || Math.abs(visibleTotal - total) <= 1) return visible;
  const shareValues = [
    summary.Promoter ?? summary.promoters ?? summary["Promoter %"],
    summary.passives ?? summary.Passive ?? summary["Passive %"],
    summary.detractors ?? summary.Detractor ?? summary["Detractor %"],
  ].map((value) => Number(value));
  const shareTotal = shareValues.reduce((sum, value) => sum + (Number.isFinite(value) ? value : 0), 0);
  if (shareValues.every(Number.isFinite) && shareTotal > 0) {
    const values = roundedCountsFromShares(total, shareValues);
    return { Total: total, Promoter: values[0] || 0, Passive: values[1] || 0, Detractor: values[2] || 0 };
  }
  const scaled = roundedCountsFromShares(total, [
    (visible.Promoter / visibleTotal) * 100,
    (visible.Passive / visibleTotal) * 100,
    (visible.Detractor / visibleTotal) * 100,
  ]);
  return { Total: total, Promoter: scaled[0] || 0, Passive: scaled[1] || 0, Detractor: scaled[2] || 0 };
}

function metricLogicText(label, value, note, summary = {}, counts = {}, segmentSentiments = {}, intelligence = [], context = {}) {
  const analysis = state.analysis || {};
  const weekly = analysis.weekly || [];
  const rows = allFeedbackRows(context);
  const normalized = String(label || "").toLowerCase();
  const fixedCounts = npsDisplayCounts(summary, counts);
  const total = Number(firstDefined(fixedCounts.Total, summary.total, counts.Total, rows.length, 0)) || 0;
  const promoter = Number(fixedCounts.Promoter || 0);
  const passive = Number(fixedCounts.Passive || 0);
  const detractor = Number(fixedCounts.Detractor || 0);
  const pct = (num, den = total) => den ? (Number(num || 0) / den) * 100 : 0;
  const sentimentCounts = rows.reduce((acc, row) => {
    const sentiment = String(row.Sentiment || "").trim().toLowerCase();
    if (sentiment === "positive") acc.Positive += 1;
    else if (sentiment === "neutral" || sentiment === "passive") acc.Neutral += 1;
    else if (sentiment === "negative") acc.Negative += 1;
    else acc.Blank += 1;
    return acc;
  }, { Positive: 0, Neutral: 0, Negative: 0, Blank: 0 });
  const sentimentTotal = sentimentCounts.Positive + sentimentCounts.Neutral + sentimentCounts.Negative;
  const latest = weekly[weekly.length - 1] || {};
  const previous = weekly[weekly.length - 2] || {};
  const latestScore = Number(firstDefined(latest.NPS, latest.NPS, latest.Score, NaN));
  const previousScore = Number(firstDefined(previous.NPS, previous.NPS, previous.Score, NaN));
  const latestResponses = Number(latest.Responses || 0);
  const previousResponses = Number(previous.Responses || 0);
  const weeklyScores = weekly.map((row) => Number(firstDefined(row.NPS, row.NPS, row.Score, NaN))).filter(Number.isFinite);
  const best = weekly.slice().sort((a, b) => Number(firstDefined(b.NPS, b.NPS, b.Score, -Infinity)) - Number(firstDefined(a.NPS, a.NPS, a.Score, -Infinity)))[0] || {};
  const lowest = weekly.slice().sort((a, b) => Number(firstDefined(a.NPS, a.NPS, a.Score, Infinity)) - Number(firstDefined(b.NPS, b.NPS, b.Score, Infinity)))[0] || {};
  const bestScore = Number(firstDefined(best.NPS, best.NPS, best.Score, 0));
  const lowestScore = Number(firstDefined(lowest.NPS, lowest.NPS, lowest.Score, 0));
  const fourWeek = weeklyScores.slice(-4);
  const fourWeekAvg = fourWeek.length ? fourWeek.reduce((sum, score) => sum + score, 0) / fourWeek.length : 0;
  const volatility = weeklyScores.length ? Math.max(...weeklyScores) - Math.min(...weeklyScores) : 0;
  const sentimentShare = (name) => sentimentTotal ? (sentimentCounts[name] / sentimentTotal) * 100 : 0;
  const baseLines = [`Total: ${label} calculation | Displayed value: ${value}${note ? ` | Card note: ${note}` : ""}`];
  const npsTypeColumn = $("npsTypeCol")?.value || "";
  const scoreColumn = $("scoreCol")?.value || "mapped NPS score";
  const bandConfig = selectedNpsBandConfig();
  const classificationSource = npsTypeColumn
    ? `Classification source - NPS Type is created from the mapped NPS Category column "${npsTypeColumn}".`
    : `Classification source - no NPS Category column is mapped, so NPS Type is created from "${scoreColumn}" using score bands: Promoter >= ${bandConfig.promoterMin}, Passive >= ${bandConfig.passiveMin}, Detractor < ${bandConfig.passiveMin}.`;
  if (normalized.includes("total response")) {
    return [
      ...baseLines,
      `Formula - total responses = count of selected analyzed feedback rows.`,
      `NPS type rollup - Promoter ${promoter.toLocaleString()} + Passive ${passive.toLocaleString()} + Detractor ${detractor.toLocaleString()} = ${(promoter + passive + detractor).toLocaleString()}.`,
      `Source - ${rows.length ? rows.length.toLocaleString() : total.toLocaleString()} rows are available in the current dashboard context.`,
    ].join("\n");
  }
  if (normalized === "promoter" || normalized === "passive" || normalized === "detractor") {
    const key = label;
    const segment = segmentSentiments?.[key] || {};
    const count = Number(counts[key] || 0);
    return [
      ...baseLines,
      classificationSource,
      `Formula - ${key} count = rows where the app-created NPS Type equals "${key}".`,
      `Count - ${count.toLocaleString()} ${key} rows out of ${Math.max(total, 1).toLocaleString()} total rows.`,
      `Share - ${count.toLocaleString()} / ${Math.max(total, 1).toLocaleString()} x 100 = ${formatMetric(pct(count))}%.`,
      `Sentiment inside this NPS segment - Positive ${segment.Positive || 0}, Neutral ${segment.Neutral || 0}, Negative ${segment.Negative || 0}.`,
    ].join("\n");
  }
  if (normalized.includes("% promoter")) {
    return [
      ...baseLines,
      classificationSource,
      `Formula - % Promoter = Promoter rows / Total responses x 100.`,
      `Substitution - ${promoter.toLocaleString()} / ${Math.max(total, 1).toLocaleString()} x 100 = ${formatMetric(pct(promoter))}%.`,
      `Included records - all selected rows with an app-created NPS Type in the current range are counted in the denominator.`,
    ].join("\n");
  }
  if (normalized === "nps") {
    return [
      ...baseLines,
      classificationSource,
      `Formula - NPS = Promoter rows / Total responses x 100.`,
      `Substitution - ${promoter.toLocaleString()} / ${Math.max(total, 1).toLocaleString()} x 100 = ${formatMetric(pct(promoter))}.`,
      `Passive and detractor records stay in the denominator - Passive ${passive.toLocaleString()}, Detractor ${detractor.toLocaleString()}.`,
    ].join("\n");
  }
  if (normalized.includes("wow") && normalized.includes("volume")) {
    return [
      ...baseLines,
      `Formula - WoW Volume = Latest week responses minus previous week responses.`,
      `Latest week - ${latest.Week || "latest"} has ${latestResponses.toLocaleString()} responses.`,
      `Previous week - ${previous.Week || "previous"} has ${previousResponses.toLocaleString()} responses.`,
      `Substitution - ${latestResponses.toLocaleString()} - ${previousResponses.toLocaleString()} = ${(latestResponses - previousResponses).toLocaleString()}.`,
    ].join("\n");
  }
  if (normalized.includes("wow")) {
    return [
      ...baseLines,
      `Formula - WoW NPS movement = Latest week NPS minus previous week NPS.`,
      `Latest week - ${latest.Week || "latest"} NPS ${formatMetric(latestScore)} across ${latestResponses.toLocaleString()} responses.`,
      `Previous week - ${previous.Week || "previous"} NPS ${formatMetric(previousScore)} across ${previousResponses.toLocaleString()} responses.`,
      `Substitution - ${formatMetric(latestScore)} - ${formatMetric(previousScore)} = ${formatMetric(latestScore - previousScore)} pts.`,
    ].join("\n");
  }
  if (normalized.includes("4-week")) {
    return [
      ...baseLines,
      `Formula - 4-week average NPS = average of the latest four weekly NPS values.`,
      `Values used - ${fourWeek.map((score) => formatMetric(score)).join(", ") || "No weekly values available"}.`,
      `Substitution - sum ${formatMetric(fourWeek.reduce((sum, score) => sum + score, 0))} / ${Math.max(fourWeek.length, 1)} = ${formatMetric(fourWeekAvg)}.`,
    ].join("\n");
  }
  if (normalized.includes("best week")) {
    return [
      ...baseLines,
      `Formula - Best week = weekly row with the highest NPS.`,
      `Selected week - ${best.Week || "not available"} with NPS ${formatMetric(bestScore)}.`,
      `Comparison set - ${weekly.length.toLocaleString()} weekly rows were sorted from highest NPS to lowest NPS.`,
    ].join("\n");
  }
  if (normalized.includes("lowest week")) {
    return [
      ...baseLines,
      `Formula - Lowest week = weekly row with the lowest NPS.`,
      `Selected week - ${lowest.Week || "not available"} with NPS ${formatMetric(lowestScore)}.`,
      `Comparison set - ${weekly.length.toLocaleString()} weekly rows were sorted from lowest NPS to highest NPS.`,
    ].join("\n");
  }
  if (normalized.includes("volatility")) {
    return [
      ...baseLines,
      `Formula - NPS volatility = highest weekly NPS minus lowest weekly NPS.`,
      `Highest weekly NPS - ${formatMetric(Math.max(...weeklyScores, 0))}.`,
      `Lowest weekly NPS - ${formatMetric(weeklyScores.length ? Math.min(...weeklyScores) : 0)}.`,
      `Substitution - ${formatMetric(Math.max(...weeklyScores, 0))} - ${formatMetric(weeklyScores.length ? Math.min(...weeklyScores) : 0)} = ${formatMetric(volatility)}.`,
    ].join("\n");
  }
  if (normalized.includes("positive sentiment")) {
    return [
      ...baseLines,
      `Formula - Positive Sentiment % = Positive sentiment rows / classified sentiment rows x 100.`,
      `Classified rows - Positive ${sentimentCounts.Positive.toLocaleString()} + Neutral ${sentimentCounts.Neutral.toLocaleString()} + Negative ${sentimentCounts.Negative.toLocaleString()} = ${sentimentTotal.toLocaleString()}.`,
      `Substitution - ${sentimentCounts.Positive.toLocaleString()} / ${Math.max(sentimentTotal, 1).toLocaleString()} x 100 = ${formatMetric(sentimentShare("Positive"))}%.`,
    ].join("\n");
  }
  if (normalized.includes("negative sentiment")) {
    return [
      ...baseLines,
      `Formula - Negative Sentiment % = Negative sentiment rows / classified sentiment rows x 100.`,
      `Classified rows - Positive ${sentimentCounts.Positive.toLocaleString()} + Neutral ${sentimentCounts.Neutral.toLocaleString()} + Negative ${sentimentCounts.Negative.toLocaleString()} = ${sentimentTotal.toLocaleString()}.`,
      `Substitution - ${sentimentCounts.Negative.toLocaleString()} / ${Math.max(sentimentTotal, 1).toLocaleString()} x 100 = ${formatMetric(sentimentShare("Negative"))}%.`,
    ].join("\n");
  }
  return [
    ...baseLines,
    `Source - this card comes from the executive dashboard intelligence payload generated after NPS analysis.`,
    `Supporting rows - single click the card to open the row/table artifact used by this metric.`,
  ].join("\n");
}

function renderMetricGrid(targetId, summary, counts, segmentSentiments = {}, intelligence = [], context = {}) {
  const target = $(targetId);
  if (!target) return;
  const displayCounts = npsDisplayCounts(summary, counts);
  const scoredTotal = displayCounts.Total || summary.total || 0;
  const populationTotal = Number(context.population?.rows || context.totalRows || context.outputCount || 0);
  const total = populationTotal || scoredTotal;
  const scoredNote = scoredTotal && total !== scoredTotal ? `${Number(scoredTotal).toLocaleString()} scored rows used for NPS mix.` : "";
  const displaySummary = {
    ...summary,
    total: scoredTotal,
    Promoter: scoredTotal ? (displayCounts.Promoter / scoredTotal) * 100 : Number(summary.Promoter || summary.promoters || 0),
    promoters: scoredTotal ? (displayCounts.Promoter / scoredTotal) * 100 : Number(summary.promoters || summary.Promoter || 0),
    passives: scoredTotal ? (displayCounts.Passive / scoredTotal) * 100 : Number(summary.passives || 0),
    detractors: scoredTotal ? (displayCounts.Detractor / scoredTotal) * 100 : Number(summary.detractors || 0),
  };
  const cards = [
    metric("Total Responses", total.toLocaleString(), scoredNote, "", "total", metricLogicText("Total Responses", total.toLocaleString(), scoredNote, displaySummary, displayCounts, segmentSentiments, intelligence, context)),
    metric("Promoter", displayCounts.Promoter || 0, segmentNote(segmentSentiments, "Promoter"), "", "Promoter", metricLogicText("Promoter", displayCounts.Promoter || 0, segmentNote(segmentSentiments, "Promoter"), displaySummary, displayCounts, segmentSentiments, intelligence, context)),
    metric("Passive", displayCounts.Passive || 0, segmentNote(segmentSentiments, "Passive"), "", "Passive", metricLogicText("Passive", displayCounts.Passive || 0, segmentNote(segmentSentiments, "Passive"), displaySummary, displayCounts, segmentSentiments, intelligence, context)),
    metric("Detractor", displayCounts.Detractor || 0, segmentNote(segmentSentiments, "Detractor"), "", "Detractor", metricLogicText("Detractor", displayCounts.Detractor || 0, segmentNote(segmentSentiments, "Detractor"), displaySummary, displayCounts, segmentSentiments, intelligence, context)),
    metric("% Promoter", `${(displaySummary.Promoter || 0).toFixed(1)}%`, "Promoter records in the selected range.", "", "Promoter", metricLogicText("% Promoter", `${(displaySummary.Promoter || 0).toFixed(1)}%`, "Promoter records in the selected range.", displaySummary, displayCounts, segmentSentiments, intelligence, context)),
    metric("NPS", (displaySummary.NPS || 0).toFixed(1), "All records used in this NPS calculation.", "", "total", metricLogicText("NPS", (displaySummary.NPS || 0).toFixed(1), "All records used in this NPS calculation.", displaySummary, displayCounts, segmentSentiments, intelligence, context)),
  ];
  intelligence.forEach((item) => {
    const label = item.label || "Metric";
    const value = item.value || "-";
    const note = item.note || "";
    cards.push(metric(label, value, note, item.tone || "", artifactKeyForMetric(label), metricLogicText(label, value, note, summary, counts, segmentSentiments, intelligence, context)));
  });
  target.innerHTML = cards.slice(0, 14).join("");
  attachMetricArtifacts(targetId, context);
}

function renderMetrics(summary, counts, segmentSentiments = {}, intelligence = [], context = {}) {
  renderMetricGrid("metricGrid", summary, counts, segmentSentiments, intelligence, context);
}

function svgPoint(x, y, label) {
  return `<circle cx="${x}" cy="${y}" r="4" fill="#f4a261" stroke="#fff" stroke-width="1"></circle><text x="${x}" y="${y - 10}" text-anchor="middle" fill="#06384e" font-size="11" font-weight="700">${label}</text>`;
}

function renderLineChart(svgId, rows, valueKey, emptyMessage, color = "#009b9b", labelFormatter = (value) => Number(value || 0).toFixed(1)) {
  const svg = $(svgId);
  if (!svg) return;
  if (!rows || !rows.length) {
    svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">${emptyMessage}</text>`;
    return;
  }
  const data = browserSafeSampleRows(rows, 400);
  const w = 760, h = 260, left = 54, right = 24, top = 28, bottom = 42;
  const plotW = w - left - right;
  const plotH = h - top - bottom;
  const values = data.map((row) => Number(row[valueKey] ?? row[valueKey.toUpperCase()] ?? 0));
  const minRaw = Math.min(...values, 0);
  const maxRaw = Math.max(...values, valueKey === "NPS" ? 100 : 1);
  const pad = Math.max((maxRaw - minRaw) * 0.12, 1);
  const min = valueKey === "NPS" ? Math.max(-100, minRaw - pad) : Math.max(0, minRaw - pad);
  const max = valueKey === "NPS" ? 100 : maxRaw + pad;
  const yFor = (value) => top + (max - Math.max(min, Math.min(max, value))) / Math.max(max - min, 1) * plotH;
  const xFor = (i) => left + (plotW * i) / Math.max(data.length - 1, 1);
  const points = data.map((row, i) => [xFor(i), yFor(values[i]), values[i]]);
  const line = points.map((p) => `${p[0]},${p[1]}`).join(" ");
  const area = `${left},${yFor(min)} ${line} ${w - right},${yFor(min)}`;
  const labels = points
    .filter((_, i) => i === 0 || i === points.length - 1 || i % Math.max(Math.floor(points.length / 5), 1) === 0)
    .map((p, i) => {
      const row = data[points.indexOf(p)];
      const rawLabel = row.Week || row["Agent Name"] || row["Manager/TL"] || row.Range || "";
      const label = String(rawLabel).includes("-") ? String(rawLabel).slice(5, 10) : String(rawLabel).slice(0, 12);
      return `<text x="${p[0]}" y="${h - 15}" text-anchor="middle" fill="#607888" font-size="11">${label}</text>`;
    })
    .join("");
  svg.innerHTML = `
    <defs>
      <linearGradient id="${svgId}Grad" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="${color}" stop-opacity="0.22"></stop>
        <stop offset="100%" stop-color="${color}" stop-opacity="0.02"></stop>
      </linearGradient>
    </defs>
    ${[min, (min + max) / 2, max].map((s) => `<line x1="${left}" x2="${w - right}" y1="${yFor(s)}" y2="${yFor(s)}" stroke="#e4ebf1"></line><text x="${left - 12}" y="${yFor(s) + 4}" text-anchor="end" fill="#728399" font-size="11">${labelFormatter(s)}</text>`).join("")}
    <polyline points="${area}" fill="url(#${svgId}Grad)" stroke="none"></polyline>
    <polyline points="${line}" fill="none" stroke="${color}" stroke-width="3.4" stroke-linecap="round" stroke-linejoin="round"></polyline>
    ${points.map((p) => `<circle cx="${p[0]}" cy="${p[1]}" r="4" fill="#fff" stroke="${color}" stroke-width="2"></circle><text x="${p[0]}" y="${p[1] - 10}" text-anchor="middle" fill="#0c2340" font-size="11" font-weight="800">${labelFormatter(p[2])}</text>`).join("")}
    ${labels}
  `;
}

function renderScoreVolumeLineChart(svgId, rows, scoreKey, emptyMessage, scoreColor = "#006d86", volumeColor = "#14b8a6", options = {}) {
  const svg = $(svgId);
  if (!svg) return;
  if (!rows || !rows.length) {
    svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">${emptyMessage}</text>`;
    return;
  }
  const data = browserSafeSampleRows(rows, 400);
  const w = 760, h = 260, left = 54, right = 58, top = 38, bottom = 42;
  const isMaximized = Boolean(options.maximized);
  const targetValue = Number.isFinite(Number(options.target)) ? Number(options.target) : (scoreKey === "NPS" ? 0 : 85);
  let readoutPanel = svg.parentElement?.querySelector(`[data-chart-readout="${svgId}"]`);
  if (!readoutPanel && svg.parentElement) {
    readoutPanel = document.createElement("div");
    readoutPanel.className = "score-volume-readout-panel";
    readoutPanel.dataset.chartReadout = svgId;
    readoutPanel.textContent = "Move over the graph to inspect each period.";
    svg.insertAdjacentElement("afterend", readoutPanel);
  }
  const plotW = w - left - right;
  const plotH = h - top - bottom;
  const scoreValues = data.map((row) => Number(row[scoreKey] ?? row[scoreKey.toUpperCase()] ?? 0));
  const volumeValues = data.map((row) => Number(row.Volume ?? row.volume ?? row.Responses ?? 0));
  const finiteScores = scoreValues.filter(Number.isFinite);
  const meanScore = finiteScores.length ? average(finiteScores) : NaN;
  const totalVolume = volumeValues.reduce((sum, value) => sum + (Number.isFinite(value) ? value : 0), 0);
  const rankedScores = data.map((row, i) => ({ i, score: scoreValues[i] })).filter((item) => Number.isFinite(item.score)).sort((a, b) => b.score - a.score);
  const scoreStdDev = finiteScores.length > 1 ? stdDev(finiteScores) : NaN;
  const rollingWindow = data.length >= 8 ? 4 : 3;
  const scoreMin = scoreKey === "NPS" ? -100 : 0;
  const scoreMax = 100;
  const volumeMaxRaw = Math.max(...volumeValues, 1);
  const volumeMax = volumeMaxRaw + Math.max(volumeMaxRaw * 0.12, 1);
  const yScore = (value) => top + (scoreMax - Math.max(scoreMin, Math.min(scoreMax, value))) / Math.max(scoreMax - scoreMin, 1) * plotH;
  const yVolume = (value) => top + (volumeMax - Math.max(0, Math.min(volumeMax, value))) / Math.max(volumeMax, 1) * plotH;
  const xFor = (i) => left + (plotW * i) / Math.max(data.length - 1, 1);
  const scorePoints = data.map((row, i) => [xFor(i), yScore(scoreValues[i]), scoreValues[i]]);
  const volumePoints = data.map((row, i) => [xFor(i), yVolume(volumeValues[i]), volumeValues[i]]);
  const rollingPoints = isMaximized ? data.map((row, i) => {
    const values = scoreValues.slice(Math.max(0, i - rollingWindow + 1), i + 1).filter(Number.isFinite);
    const value = values.length ? average(values) : NaN;
    return Number.isFinite(value) ? [xFor(i), yScore(value), value] : null;
  }).filter(Boolean) : [];
  const scoreLine = scorePoints.map((p) => `${p[0]},${p[1]}`).join(" ");
  const volumeLine = volumePoints.map((p) => `${p[0]},${p[1]}`).join(" ");
  const rollingLine = rollingPoints.map((p) => `${p[0]},${p[1]}`).join(" ");
  const scoreArea = `${left},${yScore(scoreMin)} ${scoreLine} ${w - right},${yScore(scoreMin)}`;
  const legendW = isMaximized ? 336 : 196;
  const legendX = (w / 2) - (legendW / 2);
  const labelEvery = Math.max(Math.floor(scorePoints.length / 5), 1);
  const valueLabelSize = Number.isFinite(Number(options.valueLabelSize)) ? Number(options.valueLabelSize) : (isMaximized ? 9 : 11);
  const labels = scorePoints
    .filter((_, i) => i === 0 || i === scorePoints.length - 1 || i % labelEvery === 0)
    .map((p) => {
      const row = data[scorePoints.indexOf(p)];
      const rawLabel = row.Week || row.period || row.Range || "";
      const label = String(rawLabel).includes("-") ? String(rawLabel).slice(5, 10) : String(rawLabel).slice(0, 12);
      return `<text x="${p[0]}" y="${h - 15}" text-anchor="middle" fill="#607888" font-size="11">${label}</text>`;
    })
    .join("");
  const scoreTicks = scoreKey === "NPS" ? [-100, 0, 100] : [0, 50, 100];
  const volumeTicks = [0, volumeMax / 2, volumeMax];
  const targetLine = isMaximized && Number.isFinite(targetValue) && targetValue >= scoreMin && targetValue <= scoreMax
    ? `<line x1="${left}" x2="${w - right}" y1="${yScore(targetValue)}" y2="${yScore(targetValue)}" stroke="#d97706" stroke-width="1.4" stroke-dasharray="7 5" opacity="0.78"></line><text x="${w - right - 4}" y="${yScore(targetValue) - 6}" text-anchor="end" fill="#a65f00" font-size="10">Target ${formatDataPoint(targetValue)}</text>`
    : "";
  const outlierMarkers = isMaximized && Number.isFinite(meanScore) && Number.isFinite(scoreStdDev) && scoreStdDev > 0
    ? scorePoints.filter((p) => Math.abs(p[2] - meanScore) >= scoreStdDev * 1.5).map((p) => {
      const markerTone = p[2] >= meanScore ? "high" : "low";
      const markerColor = markerTone === "high" ? "#16a34a" : "#dc2626";
      return `<circle class="trend-special-marker trend-special-marker-${markerTone}" cx="${p[0]}" cy="${p[1]}" r="8" fill="none" stroke="${markerColor}" stroke-width="1.8" opacity="0.78"></circle>`;
    }).join("")
    : "";
  svg.innerHTML = `
    <defs>
      <linearGradient id="${svgId}ScoreGrad" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="${scoreColor}" stop-opacity="0.20"></stop>
        <stop offset="100%" stop-color="${scoreColor}" stop-opacity="0.02"></stop>
      </linearGradient>
    </defs>
    <g>
      <rect x="${legendX - 12}" y="3" width="${legendW}" height="26" rx="13" fill="#ffffff" opacity="0.92" stroke="#d7e8ee"></rect>
      <circle cx="${legendX + 8}" cy="16" r="5" fill="${scoreColor}"></circle>
      <text x="${legendX + 20}" y="20" fill="#0c2340" font-size="11">${scoreKey}</text>
      <circle cx="${legendX + 100}" cy="16" r="5" fill="${volumeColor}"></circle>
      <text x="${legendX + 112}" y="20" fill="#0c2340" font-size="11">Volume</text>
      ${isMaximized ? `<line x1="${legendX + 185}" x2="${legendX + 207}" y1="16" y2="16" stroke="#7c3aed" stroke-width="2.2"></line><text x="${legendX + 216}" y="20" fill="#0c2340" font-size="11">Rolling avg</text>` : ""}
    </g>
    ${scoreTicks.map((s) => `<line x1="${left}" x2="${w - right}" y1="${yScore(s)}" y2="${yScore(s)}" stroke="#e4ebf1"></line><text x="${left - 12}" y="${yScore(s) + 4}" text-anchor="end" fill="#728399" font-size="11">${formatDataPoint(s)}</text>`).join("")}
    ${volumeTicks.map((s) => `<text x="${w - right + 10}" y="${yVolume(s) + 4}" text-anchor="start" fill="#0f8d83" font-size="11">${Math.round(s).toLocaleString()}</text>`).join("")}
    ${targetLine}
    <polyline points="${scoreArea}" fill="url(#${svgId}ScoreGrad)" stroke="none"></polyline>
    <polyline points="${volumeLine}" fill="none" stroke="${volumeColor}" stroke-width="2.8" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="6 5"></polyline>
    ${isMaximized && rollingLine ? `<polyline points="${rollingLine}" fill="none" stroke="#7c3aed" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" opacity="0.82"></polyline>` : ""}
    <polyline points="${scoreLine}" fill="none" stroke="${scoreColor}" stroke-width="3.4" stroke-linecap="round" stroke-linejoin="round"></polyline>
    ${volumePoints.map((p) => `<circle cx="${p[0]}" cy="${p[1]}" r="3" fill="${volumeColor}" opacity="0.9"></circle>`).join("")}
    ${outlierMarkers}
    ${scorePoints.map((p) => `<circle cx="${p[0]}" cy="${p[1]}" r="4" fill="#fff" stroke="${scoreColor}" stroke-width="2"></circle><text x="${p[0]}" y="${p[1] - 9}" text-anchor="middle" fill="#0c2340" font-size="${valueLabelSize}">${formatDataPoint(p[2])}</text>`).join("")}
    ${labels}
    <g class="score-volume-hover" opacity="0" pointer-events="none">
      <line class="hover-ruler" x1="${left}" x2="${left}" y1="${top}" y2="${h - bottom}" stroke="#0c2340" stroke-width="1.2" stroke-dasharray="4 4" opacity="0.55"></line>
      <circle class="hover-score-point" cx="${left}" cy="${top}" r="6" fill="#ffffff" stroke="${scoreColor}" stroke-width="3"></circle>
      <circle class="hover-volume-point" cx="${left}" cy="${top}" r="5" fill="${volumeColor}" stroke="#ffffff" stroke-width="2"></circle>
    </g>
    <rect class="score-volume-hit-area" x="0" y="0" width="${w}" height="${h}" fill="#ffffff" opacity="0" pointer-events="all" style="cursor: crosshair"></rect>
  `;
  const hoverGroup = svg.querySelector(".score-volume-hover");
  const hitArea = svg.querySelector(".score-volume-hit-area");
  const ruler = svg.querySelector(".hover-ruler");
  const scoreDot = svg.querySelector(".hover-score-point");
  const volumeDot = svg.querySelector(".hover-volume-point");
  const setHover = (event) => {
    if (!hoverGroup || !hitArea || !ruler || !scoreDot || !volumeDot) return;
    const rect = svg.getBoundingClientRect();
    const svgX = ((event.clientX - rect.left) / Math.max(rect.width, 1)) * w;
    const boundedX = Math.max(left, Math.min(w - right, svgX));
    const index = Math.max(0, Math.min(data.length - 1, Math.round(((boundedX - left) / Math.max(plotW, 1)) * (data.length - 1))));
    const scorePoint = scorePoints[index];
    const volumePoint = volumePoints[index];
    const row = data[index] || {};
    const rawLabel = row.Week || row.period || row.Range || `Point ${index + 1}`;
    const label = String(rawLabel).slice(0, 18);
    const volume = Math.round(Number(volumePoint[2] || 0)).toLocaleString();
    const previousScore = index > 0 ? scoreValues[index - 1] : NaN;
    const previousVolume = index > 0 ? volumeValues[index - 1] : NaN;
    const movement = Number.isFinite(previousScore) ? scorePoint[2] - previousScore : NaN;
    const volumeMovement = Number.isFinite(previousVolume) ? volumePoint[2] - previousVolume : NaN;
    const rollingValues = scoreValues.slice(Math.max(0, index - rollingWindow + 1), index + 1).filter(Number.isFinite);
    const rollingAverage = rollingValues.length ? average(rollingValues) : NaN;
    const rank = rankedScores.findIndex((item) => item.i === index) + 1;
    const vsAverage = Number.isFinite(meanScore) ? scorePoint[2] - meanScore : NaN;
    const vsTarget = Number.isFinite(targetValue) ? scorePoint[2] - targetValue : NaN;
    const volumeShare = totalVolume ? (Number(volumePoint[2] || 0) / totalVolume) * 100 : NaN;
    const shortReadout = `${label} | ${scoreKey} ${formatDataPoint(scorePoint[2])} | Volume ${volume}`;
    const richReadout = [
      shortReadout,
      `Move ${Number.isFinite(movement) ? `${movement >= 0 ? "+" : ""}${formatDataPoint(movement)}` : "N/A"}`,
      `Vol Move ${Number.isFinite(volumeMovement) ? `${volumeMovement >= 0 ? "+" : ""}${Math.round(volumeMovement).toLocaleString()}` : "N/A"}`,
      `Rolling Avg ${Number.isFinite(rollingAverage) ? formatDataPoint(rollingAverage) : "N/A"}`,
      `Rank ${rank || "N/A"}/${rankedScores.length || data.length}`,
      `vs Avg ${Number.isFinite(vsAverage) ? `${vsAverage >= 0 ? "+" : ""}${formatDataPoint(vsAverage)}` : "N/A"}`,
      `vs Target ${Number.isFinite(vsTarget) ? `${vsTarget >= 0 ? "+" : ""}${formatDataPoint(vsTarget)}` : "N/A"}`,
      `Vol Share ${Number.isFinite(volumeShare) ? `${formatDataPoint(volumeShare)}%` : "N/A"}`,
    ].join(" | ");
    const readout = isMaximized ? richReadout : shortReadout;
    hoverGroup.setAttribute("opacity", "1");
    ruler.setAttribute("x1", scorePoint[0]);
    ruler.setAttribute("x2", scorePoint[0]);
    scoreDot.setAttribute("cx", scorePoint[0]);
    scoreDot.setAttribute("cy", scorePoint[1]);
    volumeDot.setAttribute("cx", volumePoint[0]);
    volumeDot.setAttribute("cy", volumePoint[1]);
    if (readoutPanel) readoutPanel.textContent = readout;
  };
  hitArea.addEventListener("mousemove", setHover);
  hitArea.addEventListener("mouseenter", setHover);
  hitArea.addEventListener("mouseleave", () => {
    hoverGroup?.setAttribute("opacity", "0");
    if (readoutPanel) readoutPanel.textContent = "Move over the graph to inspect each period.";
  });
}

function renderTrend(rows, targetId = "npsTrend") {
  renderLineChart(targetId, rows, "NPS", "Run analysis with a valid date column to view trend.", "#006d86");
}

function renderVolumeTrend(rows) {
  renderLineChart("volumeTrend", rows, "Responses", "Run analysis to view response volume.", "#009b9b", (value) => Number(value || 0).toFixed(0));
}

function polar(cx, cy, r, angle) {
  const rad = (angle - 90) * Math.PI / 180;
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
}

function arcPath(cx, cy, r, start, end) {
  const a = polar(cx, cy, r, start);
  const b = polar(cx, cy, r, end);
  const large = Math.abs(end - start) <= 180 ? 0 : 1;
  return `M ${a.x} ${a.y} A ${r} ${r} 0 ${large} 1 ${b.x} ${b.y}`;
}

function renderGauge(summary, targetId = "npsGauge") {
  const svg = $(targetId);
  if (!svg) return;
  const NPS = Number(summary.NPS ?? summary.nps ?? 0);
  const bounded = Math.max(-100, Math.min(100, Number.isFinite(NPS) ? NPS : 0));
  const angle = -90 + ((bounded + 100) / 200) * 180;
  const needle = polar(180, 184, 88, angle);
  svg.innerHTML = `
    <path d="${arcPath(180, 184, 112, -90, 0)}" stroke="#d94045" stroke-width="26" fill="none"></path>
    <path d="${arcPath(180, 184, 112, 0, 45)}" stroke="#e3b34e" stroke-width="26" fill="none"></path>
    <path d="${arcPath(180, 184, 112, 45, 90)}" stroke="#19a55b" stroke-width="26" fill="none"></path>
    ${[-100, -50, 0, 50, 100].map((tick) => {
      const a = -90 + ((tick + 100) / 200) * 180;
      const outer = polar(180, 184, 118, a);
      const inner = polar(180, 184, 98, a);
      const text = polar(180, 184, 78, a);
      return `<line x1="${outer.x}" y1="${outer.y}" x2="${inner.x}" y2="${inner.y}" stroke="${tick === 0 ? "#0c2340" : "#dce5ee"}" stroke-width="${tick === 0 ? 4 : 3}"></line><text x="${text.x}" y="${text.y + 4}" text-anchor="middle" fill="#728399" font-size="11">${tick > 0 ? `+${tick}` : tick}</text>`;
    }).join("")}
    <line x1="180" y1="184" x2="${needle.x}" y2="${needle.y}" stroke="#0c2340" stroke-width="4" stroke-linecap="round"></line>
    <circle cx="180" cy="184" r="10" fill="#fff" stroke="#0c2340" stroke-width="3"></circle>
    <text x="180" y="226" text-anchor="middle" fill="#0c2340" font-size="34" font-weight="900">${bounded.toFixed(1)}</text>
    <text x="180" y="248" text-anchor="middle" fill="#728399" font-size="12">Net Promoter Score</text>
  `;
}

function renderComposition(counts, summary, targetId = "npsComposition") {
  const svg = $(targetId);
  if (!svg) return;
  const total = Math.max(Number(summary.total || 0), 1);
  const rows = [
    ["Promoter", Number(counts.Promoter || 0), "#19a55b"],
    ["Passive", Number(counts.Passive || 0), "#e3b34e"],
    ["Detractor", Number(counts.Detractor || 0), "#d94045"],
  ];
  let x = 36;
  const segments = rows.map(([label, count, color]) => {
    const width = Math.max(0, (count / total) * 288);
    const node = `<rect x="${x}" y="54" width="${width}" height="42" fill="${color}"></rect>`;
    x += width;
    return node;
  }).join("");
  svg.innerHTML = `
    <rect x="36" y="54" width="288" height="42" rx="8" fill="#edf2f6"></rect>
    <clipPath id="compositionClip"><rect x="36" y="54" width="288" height="42" rx="8"></rect></clipPath>
    <g clip-path="url(#compositionClip)">${segments}</g>
    ${rows.map(([label, count, color], i) => {
      const pct = (count / total) * 100;
      return `<rect x="46" y="${126 + i * 34}" width="13" height="13" rx="3" fill="${color}"></rect><text x="68" y="${137 + i * 34}" fill="#0c2340" font-size="13" font-weight="800">${label}: ${pct.toFixed(1)}% (${count})</text>`;
    }).join("")}
  `;
}

function renderSentimentTrend(rows) {
  const svg = $("sentimentTrend");
  if (!svg) return;
  if (!rows || !rows.length) {
    svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">Run analysis to view sentiment trend.</text>`;
    return;
  }
  const w = 760, h = 260, left = 138, right = 72;
  const laneH = 58;
  const laneGap = 16;
  const top = 28;
  const plotW = w - left - right;
  const xFor = (i) => left + (plotW * i) / Math.max(rows.length - 1, 1);
  const fmt = (value) => `${formatMetric(Number(value || 0))}%`;
  const periodLabel = (row) => String(row.Week || row.Period || row.Date || "").slice(0, 10);
  const series = [
    { key: "Positive", label: "Positive Sentiment", color: "#009b9b", betterUp: true },
    { key: "Neutral", label: "Neutral Sentiment", color: "#8492a6", betterUp: false },
    { key: "Negative", label: "Negative Sentiment", color: "#e76f51", betterUp: false },
  ];
  const lanes = series.map((item, sIndex) => {
    const values = rows.map((row) => Math.max(0, Math.min(100, Number(row[item.key] || 0))));
    const min = Math.min(...values);
    const max = Math.max(...values);
    const pad = Math.max(4, (max - min) * 0.18);
    const floor = Math.max(0, min - pad);
    const ceiling = Math.min(100, max + pad);
    const span = Math.max(1, ceiling - floor);
    const yTop = top + sIndex * (laneH + laneGap);
    const yFor = (value) => yTop + laneH - ((value - floor) / span) * laneH;
    const points = values.map((value, i) => `${xFor(i)},${yFor(value)}`).join(" ");
    const first = values[0] || 0;
    const latest = values[values.length - 1] || 0;
    const delta = latest - first;
    const direction = delta > 0.05 ? "up" : delta < -0.05 ? "down" : "flat";
    const good = direction === "flat" ? "passive" : ((delta > 0) === item.betterUp ? "good" : "watch");
    const arrow = direction === "up" ? "â†—" : direction === "down" ? "â†˜" : "â†’";
    return `
      <g>
        <text x="24" y="${yTop + 16}" fill="#0c2340" font-size="12" font-weight="900">${item.label}</text>
        <text x="24" y="${yTop + 34}" fill="#607888" font-size="11">${fmt(first)} to ${fmt(latest)}</text>
        <rect x="${left}" y="${yTop}" width="${plotW}" height="${laneH}" rx="12" fill="#f7fbfc" stroke="#dbe9ef"></rect>
        <line x1="${left}" x2="${left + plotW}" y1="${yFor(first)}" y2="${yFor(first)}" stroke="#d8e6ec" stroke-dasharray="4 5"></line>
        <polyline points="${points}" fill="none" stroke="${item.color}" stroke-width="3.5" stroke-linecap="round" stroke-linejoin="round"></polyline>
        ${values.map((value, i) => `<circle cx="${xFor(i)}" cy="${yFor(value)}" r="${i === values.length - 1 ? 4.8 : 3}" fill="#fff" stroke="${item.color}" stroke-width="2"></circle>`).join("")}
        <text x="${left + plotW + 16}" y="${yTop + 23}" fill="${good === "watch" ? "#d94045" : good === "good" ? "#007f6e" : "#607888"}" font-size="18" font-weight="900">${arrow}</text>
        <text x="${left + plotW + 16}" y="${yTop + 43}" fill="#0c2340" font-size="12" font-weight="900">${delta >= 0 ? "+" : ""}${formatMetric(delta)} pts</text>
      </g>`;
  }).join("");
  const tickIndexes = rows
    .map((_, i) => i)
    .filter((i) => i === 0 || i === rows.length - 1 || i % Math.max(Math.floor(rows.length / 4), 1) === 0);
  svg.innerHTML = `
    ${lanes}
    ${tickIndexes.map((index) => `<line x1="${xFor(index)}" x2="${xFor(index)}" y1="${h - 28}" y2="${h - 22}" stroke="#bdd2dd"></line><text x="${xFor(index)}" y="${h - 8}" text-anchor="middle" fill="#607888" font-size="10">${escapeHtml(periodLabel(rows[index]))}</text>`).join("")}
  `;
}

function renderSentiment(sentiment, targetId = "sentimentMix") {
  const target = $(targetId);
  if (!target) return;
  const items = [
    ["Negative", sentiment.Negative || 0, "Recovery signal"],
    ["Neutral", sentiment.Neutral || 0, "Mixed signal"],
    ["Positive", sentiment.Positive || 0, "Advocacy signal"],
  ];
  target.innerHTML = items
    .map(([label, pct, detail]) => `<div class="sentiment-card ${label.toLowerCase()}"><span>${label}</span><strong>${pct.toFixed(1)}%</strong><small>${detail}</small></div>`)
    .join("");
}

function sentimentComparisonSourceRows() {
  const rows = (state.analysis.sentimentMovement && state.analysis.sentimentMovement.length)
    ? state.analysis.sentimentMovement
    : (state.analysis.weekly || []);
  return [...rows].sort((a, b) => String(a.Week || a.Period || "").localeCompare(String(b.Week || b.Period || "")));
}

function normalizeSentimentWeek(row) {
  const responses = Number(row.Responses || row.Response || row.Total || 0);
  const positiveCount = Number(row.Positive || 0);
  const neutralCount = Number(row.Neutral || 0);
  const negativeCount = Number(row.Negative || 0);
  const pct = (key, count) => {
    const explicit = row[`${key} %`] ?? row[`${key}%`];
    if (explicit !== undefined && explicit !== "") return Number(explicit) || 0;
    return responses ? (count / responses) * 100 : 0;
  };
  return {
    Week: row.Week || row.Period || "",
    Responses: responses,
    Positive: +pct("Positive", positiveCount).toFixed(1),
    Neutral: +pct("Neutral", neutralCount).toFixed(1),
    Negative: +pct("Negative", negativeCount).toFixed(1),
    NPS: Number(row.NPS || 0),
  };
}

function sentimentWowRows() {
  const rows = sentimentComparisonSourceRows().map(normalizeSentimentWeek).filter((row) => row.Week);
  return rows.map((row, index) => {
    const prev = rows[index - 1] || {};
    return {
      Week: row.Week,
      Responses: row.Responses,
      "Positive %": row.Positive,
      "Positive WoW": index ? +(row.Positive - Number(prev.Positive || 0)).toFixed(1) : 0,
      "Neutral %": row.Neutral,
      "Neutral WoW": index ? +(row.Neutral - Number(prev.Neutral || 0)).toFixed(1) : 0,
      "Negative %": row.Negative,
      "Negative WoW": index ? +(row.Negative - Number(prev.Negative || 0)).toFixed(1) : 0,
      NPS: +row.NPS.toFixed(1),
    };
  });
}

function renderSentimentComparison() {
  const rows = sentimentWowRows();
  renderAnyTable("sentimentCompareTable", rows, 12);
  const grid = $("sentimentCompareMetricGrid");
  const meta = $("sentimentCompareMeta");
  if (!rows.length) {
    if (grid) grid.innerHTML = "";
    if (meta) meta.textContent = "Run analysis to view weekly sentiment movement.";
    ["sentimentComparePositiveChart", "sentimentCompareNegativeChart", "sentimentCompareNetChart", "sentimentCompareVolumeChart"].forEach((id) => {
      if ($(id)) $(id).innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">Run analysis to view sentiment comparison.</text>`;
    });
    return;
  }
  const latest = rows[rows.length - 1] || {};
  const previous = rows[rows.length - 2] || {};
  if (grid) {
    grid.innerHTML = [
      metric("Weeks Compared", rows.length.toLocaleString(), "Weekly sentiment rows"),
      metric("Latest Positive", `${formatMetric(latest["Positive %"] || 0)}%`, `${formatMetric(latest["Positive WoW"] || 0)} pts WoW`),
      metric("Latest Negative", `${formatMetric(latest["Negative %"] || 0)}%`, `${formatMetric(latest["Negative WoW"] || 0)} pts WoW`),
      metric("Latest Responses", Number(latest.Responses || 0).toLocaleString(), previous.Responses !== undefined ? `${Number(latest.Responses || 0) - Number(previous.Responses || 0)} vs previous week` : "Latest week volume"),
    ].join("");
  }
  renderLineChart("sentimentComparePositiveChart", rows.map((row) => ({ Week: row.Week, Positive: row["Positive %"] })), "Positive", "Run analysis to view positive sentiment.", "#19a55b");
  renderLineChart("sentimentCompareNegativeChart", rows.map((row) => ({ Week: row.Week, Negative: row["Negative %"] })), "Negative", "Run analysis to view negative sentiment.", "#d94045");
  const netRows = rows.map((row) => ({ Week: row.Week, "Net Sentiment": Number(row["Positive %"] || 0) - Number(row["Negative %"] || 0) }));
  renderLineChart("sentimentCompareNetChart", netRows, "Net Sentiment", "Run analysis to view net sentiment.", "#006d86");
  renderLineChart("sentimentCompareVolumeChart", rows.map((row) => ({ Week: row.Week, Responses: row.Responses })), "Responses", "Run analysis to view sentiment volume.", "#14b8a6", (value) => Number(value || 0).toLocaleString());
  if ($("sentimentComparePositiveInsight")) $("sentimentComparePositiveInsight").textContent = `Latest positive sentiment is ${formatMetric(latest["Positive %"] || 0)}%, moving ${formatMetric(latest["Positive WoW"] || 0)} pts week over week.`;
  if ($("sentimentCompareNegativeInsight")) $("sentimentCompareNegativeInsight").textContent = `Latest negative sentiment is ${formatMetric(latest["Negative %"] || 0)}%, moving ${formatMetric(latest["Negative WoW"] || 0)} pts week over week.`;
  if ($("sentimentCompareNetInsight")) {
    const latestNet = netRows[netRows.length - 1]?.["Net Sentiment"] || 0;
    const prevNet = netRows[netRows.length - 2]?.["Net Sentiment"] || 0;
    $("sentimentCompareNetInsight").textContent = `Latest net sentiment is ${formatMetric(latestNet)} pts, moving ${formatMetric(latestNet - prevNet)} pts week over week.`;
  }
  if ($("sentimentCompareVolumeInsight")) $("sentimentCompareVolumeInsight").textContent = `Latest sentiment volume is ${Number(latest.Responses || 0).toLocaleString()} rows, ${previous.Responses !== undefined ? `${Number(latest.Responses || 0) - Number(previous.Responses || 0)} vs previous week` : "latest available period"}.`;
  if (meta) meta.textContent = `${rows.length.toLocaleString()} weekly sentiment periods compared.`;
  renderSentimentThemeSelection();
}

function sentimentThemeColumns() {
  return themeBuilderThemeColumns(themeBuilderJoinedRows()[0] || {});
}

function ensureSentimentThemeSelection() {
  const columns = sentimentThemeColumns();
  const current = state.sentimentThemeSelection;
  [...current].forEach((column) => {
    if (!columns.includes(column)) current.delete(column);
  });
  if (!current.size && columns.length) current.add(columns[0]);
}

function selectedSentimentThemeRows() {
  ensureSentimentThemeSelection();
  const selected = [...state.sentimentThemeSelection][0];
  if (!selected) return [];
  return themeBuilderJoinedRows().filter((row) => row[selected] === "Yes");
}

function weekLabelFromRow(row) {
  const candidates = ["Week", "Feedback Date", "Date", "Survey Date", "Response Date", "Created Date"];
  const raw = candidates.map((key) => row?.[key]).find((value) => value !== undefined && value !== null && String(value).trim());
  if (!raw) return "Unknown";
  if (/^\d{4}-\d{2}-\d{2}/.test(String(raw))) return String(raw).slice(0, 10);
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return String(raw).slice(0, 16);
  const day = date.getDay();
  const monday = new Date(date);
  monday.setDate(date.getDate() - ((day + 6) % 7));
  return monday.toISOString().slice(0, 10);
}

function sentimentThemeWowRows() {
  const grouped = new Map();
  selectedSentimentThemeRows().forEach((row) => {
    const week = weekLabelFromRow(row);
    if (!grouped.has(week)) grouped.set(week, { Week: week, Responses: 0, PositiveCount: 0, NeutralCount: 0, NegativeCount: 0 });
    const bucket = grouped.get(week);
    bucket.Responses += 1;
    const sentiment = String(row.Sentiment || "").toLowerCase();
    if (sentiment === "positive") bucket.PositiveCount += 1;
    else if (sentiment === "negative") bucket.NegativeCount += 1;
    else bucket.NeutralCount += 1;
  });
  const rows = [...grouped.values()].sort((a, b) => String(a.Week).localeCompare(String(b.Week))).map((row) => ({
    Week: row.Week,
    Responses: row.Responses,
    "Positive %": row.Responses ? +((row.PositiveCount / row.Responses) * 100).toFixed(1) : 0,
    "Neutral %": row.Responses ? +((row.NeutralCount / row.Responses) * 100).toFixed(1) : 0,
    "Negative %": row.Responses ? +((row.NegativeCount / row.Responses) * 100).toFixed(1) : 0,
  }));
  return rows.map((row, index) => {
    const prev = rows[index - 1] || {};
    return {
      ...row,
      "Positive WoW": index ? +(row["Positive %"] - Number(prev["Positive %"] || 0)).toFixed(1) : 0,
      "Negative WoW": index ? +(row["Negative %"] - Number(prev["Negative %"] || 0)).toFixed(1) : 0,
    };
  });
}

function renderSentimentThemeSelection() {
  const selector = $("sentimentThemeSelector");
  if (!selector) return;
  const columns = sentimentThemeColumns();
  ensureSentimentThemeSelection();
  if (!columns.length) {
    selector.innerHTML = '<span class="empty-note">Build Theme Classification first to enable custom theme sentiment views.</span>';
    ["sentimentThemePositiveChart", "sentimentThemeNegativeChart"].forEach((id) => {
      if ($(id)) $(id).innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">Build Theme Classification first.</text>`;
    });
    renderAnyTable("sentimentThemeTable", [], 10);
    return;
  }
  const active = [...state.sentimentThemeSelection][0] || columns[0];
  selector.innerHTML = `
    <label class="inline-select sentiment-theme-control">Theme
      <select id="sentimentThemeSelect">
        ${columns.map((column) => `<option value="${escapeHtml(column)}"${column === active ? " selected" : ""}>${escapeHtml(column.replace(/^Theme:\s*/i, ""))}</option>`).join("")}
      </select>
    </label>`;
  selector.querySelector("#sentimentThemeSelect")?.addEventListener("change", (event) => {
      state.sentimentThemeSelection.clear();
      if (event.target.value) state.sentimentThemeSelection.add(event.target.value);
      renderSentimentThemeSelection();
  });
  const rows = sentimentThemeWowRows();
  renderAnyTable("sentimentThemeTable", rows, 10);
  const percentLabel = (value) => `${Math.round(Number(value || 0))}%`;
  renderLineChart("sentimentThemePositiveChart", rows.map((row) => ({ Week: row.Week, Positive: row["Positive %"], Sample: row.Responses })), "Positive", "Select one or more themes.", "#19a55b", percentLabel);
  renderLineChart("sentimentThemeNegativeChart", rows.map((row) => ({ Week: row.Week, Negative: row["Negative %"], Sample: row.Responses })), "Negative", "Select one or more themes.", "#d94045", percentLabel);
  const labels = [...state.sentimentThemeSelection].map((column) => column.replace(/^Theme:\s*/i, ""));
  const latest = rows[rows.length - 1] || {};
  $("sentimentThemeMeta").textContent = labels.length ? `Selected theme: ${labels.join(", ")}. ${rows.length.toLocaleString()} weekly points found.` : "Select a custom theme.";
  if ($("sentimentThemePositiveInsight")) $("sentimentThemePositiveInsight").textContent = latest.Week ? `Latest selected-theme positive sentiment is ${percentLabel(latest["Positive %"])}.` : "No selected-theme rows found for weekly trend.";
  if ($("sentimentThemeNegativeInsight")) $("sentimentThemeNegativeInsight").textContent = latest.Week ? `Latest selected-theme negative sentiment is ${percentLabel(latest["Negative %"])}.` : "No selected-theme rows found for weekly trend.";
  const themeText = labels.length ? labels.join(", ") : "the selected theme";
  if ($("sentimentThemePositiveGuide")) {
    $("sentimentThemePositiveGuide").innerHTML = latest.Week
      ? `<strong>How to read this:</strong> Each point is the percentage of rows tagged <b>${escapeHtml(themeText)}</b> that were Positive in that week. The latest week, ${escapeHtml(String(latest.Week).slice(0, 10))}, is <b>${percentLabel(latest["Positive %"])}</b> positive across ${Number(latest.Responses || 0).toLocaleString()} matching row${Number(latest.Responses || 0) === 1 ? "" : "s"}.`
      : `<strong>How to read this:</strong> Select a theme to see what share of matching rows were Positive each week.`;
  }
  if ($("sentimentThemeNegativeGuide")) {
    $("sentimentThemeNegativeGuide").innerHTML = latest.Week
      ? `<strong>How to read this:</strong> Each point is the percentage of rows tagged <b>${escapeHtml(themeText)}</b> that were Negative in that week. The latest week, ${escapeHtml(String(latest.Week).slice(0, 10))}, is <b>${percentLabel(latest["Negative %"])}</b> negative across ${Number(latest.Responses || 0).toLocaleString()} matching row${Number(latest.Responses || 0) === 1 ? "" : "s"}.`
      : `<strong>How to read this:</strong> Select a theme to see what share of matching rows were Negative each week.`;
  }
}

function renderDrivers(reasons) {
  if (!reasons || !reasons.length) {
    $("driversList").innerHTML = `<p class="insight-text">No driver data yet.</p>`;
    return;
  }
  $("driversList").innerHTML = reasons
    .slice(0, 8)
    .map((row) => `<div class="driver"><strong>${row["Primary Reason"] || row.Reason || "General"}</strong><span>${row.Count || ""}</span></div>`)
    .join("");
}

function renderHorizontalBars(svgId, rows, labelKey, valueKey, color = "#009b9b", limit = 8) {
  const svg = $(svgId);
  const data = (rows || [])
    .filter((row) => row && row[labelKey] !== undefined)
    .slice()
    .sort((a, b) => Number(b[valueKey] || 0) - Number(a[valueKey] || 0))
    .slice(0, limit);
  if (!data.length) {
    svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">Run analysis to view segment ranking.</text>`;
    return;
  }
  const w = 760, h = 260, left = 180, right = 34, top = 24;
  const rowH = Math.min(27, (h - top - 18) / data.length);
  const max = Math.max(...data.map((row) => Math.abs(Number(row[valueKey] || 0))), 1);
  svg.innerHTML = data.map((row, i) => {
    const y = top + i * rowH;
    const label = String(row[labelKey] || "").slice(0, 24);
    const value = Number(row[valueKey] || 0);
    const barW = (Math.abs(value) / max) * (w - left - right);
    const barColor = value < 0 ? "#d94045" : color;
    return `
      <text x="${left - 10}" y="${y + 15}" text-anchor="end" fill="#50647a" font-size="11" font-weight="700">${label}</text>
      <rect x="${left}" y="${y + 3}" width="${w - left - right}" height="16" rx="8" fill="#edf2f6"></rect>
      <rect x="${left}" y="${y + 3}" width="${barW}" height="16" rx="8" fill="${barColor}" opacity="0.9"></rect>
      <text x="${left + barW + 8}" y="${y + 15}" fill="#0c2340" font-size="11" font-weight="800">${value.toFixed(1)}</text>
    `;
  }).join("");
}

function movementLabel(row, labelKey) {
  if (!row) return "Unknown";
  const candidates = [
    row[labelKey],
    row["Manager/TL"],
    row["TL Name"],
    row["Team Manager"],
    row["Manager Name"],
    row.Manager,
    row.Supervisor,
    row["Agent Name"],
    row.Agent,
    row.Name,
  ];
  const value = candidates.find((item) => item !== undefined && item !== null && String(item).trim());
  return value ? String(value).trim() : "Unknown";
}

function renderSimpleBar(svgId, rows, labelKey, valueKey, color = "#009b9b") {
  const svg = $(svgId);
  const data = browserSafeSampleRows(rows || [], 60);
  if (!data.length) {
    svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">Run analysis to view chart.</text>`;
    return;
  }
  const w = 760, h = 260, left = 54, right = 22, bottom = 38, top = 24;
  const plotW = w - left - right;
  const plotH = h - top - bottom;
  const values = data.map((row) => Number(row[valueKey] || 0));
  const rawMin = Math.min(0, ...values);
  const rawMax = Math.max(1, ...values);
  const pad = Math.max((rawMax - rawMin) * 0.14, 4);
  const min = Math.floor((rawMin - pad) / 10) * 10;
  const max = Math.ceil((rawMax + pad) / 10) * 10;
  const yZero = top + (max - 0) / Math.max(max - min, 1) * plotH;
  const barW = Math.min(92, plotW / Math.max(data.length, 1) * 0.52);
  const ticks = [min, Math.round((min + max) / 2), 0, max].filter((value, index, array) => array.indexOf(value) === index).sort((a, b) => a - b);
  svg.innerHTML = `
    <rect x="${left}" y="${top}" width="${plotW}" height="${plotH}" fill="#ffffff"></rect>
    <rect x="${left}" y="${top}" width="${plotW}" height="${plotH}" fill="url(#softGrid${svgId})" opacity="0.45"></rect>
    <defs>
      <linearGradient id="barGrad${svgId}" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="${color}" stop-opacity="0.92"></stop>
        <stop offset="100%" stop-color="${color}" stop-opacity="0.78"></stop>
      </linearGradient>
      <pattern id="softGrid${svgId}" width="90" height="28" patternUnits="userSpaceOnUse">
        <path d="M 90 0 L 0 0 0 28" fill="none" stroke="#e7eef4" stroke-width="1"></path>
      </pattern>
    </defs>
    ${ticks.map((tick) => {
      const y = top + (max - tick) / Math.max(max - min, 1) * plotH;
      return `<line x1="${left}" x2="${w - right}" y1="${y}" y2="${y}" stroke="${tick === 0 ? "#b8c6d1" : "#e8eef4"}" stroke-width="${tick === 0 ? 1.3 : 1}"></line>
        <text x="${left - 12}" y="${y + 4}" text-anchor="end" fill="#6b8194" font-size="13" font-weight="800">${tick}</text>`;
    }).join("")}
    <rect x="${left + plotW / 2 - 48}" y="4" width="11" height="11" rx="2" fill="${color}"></rect>
    <text x="${left + plotW / 2 - 31}" y="15" fill="#52677b" font-size="14" font-weight="850">${escapeHtml(valueKey.replaceAll("_", " "))}</text>
    ${data.map((row, i) => {
      const value = Number(row[valueKey] || 0);
      const x = left + (plotW * (i + 0.5)) / data.length - barW / 2;
      const y = top + (max - value) / Math.max(max - min, 1) * plotH;
      const height = Math.max(4, Math.abs(yZero - y));
      const fill = value < 0 ? "#d94045" : `url(#barGrad${svgId})`;
      const label = formatMetric(value);
      const labelY = value < 0 ? Math.min(yZero + height + 16, h - 28) : Math.max(y - 8, 20);
      const tooltip = `${row[labelKey]}|${valueKey.replaceAll("_", " ")}: ${label}`;
      return `<rect class="quartile-mark quartile-bar" data-tooltip="${escapeHtml(tooltip)}" data-quartile="${escapeHtml(row[labelKey])}" x="${x}" y="${Math.min(y, yZero)}" width="${barW}" height="${height}" rx="8" fill="${fill}" opacity="0.96"></rect>
        <text x="${x + barW / 2}" y="${labelY}" text-anchor="middle" fill="#0c2340" font-size="15" font-weight="950">${label}</text>
        <text x="${x + barW / 2}" y="${h - 12}" text-anchor="middle" fill="#647b8f" font-size="14" font-weight="850">${escapeHtml(row[labelKey])}</text>`;
    }).join("")}
  `;
}

function renderQuartileSpread(svgId, rows) {
  const spreadRows = (rows || []).map((row) => ({
    Quartile: row.Quartile,
    Spread: Math.abs(Number(row.Average || 0)),
  }));
  renderSimpleBar(svgId, spreadRows, "Quartile", "Spread", "#6c5ce7");
}

function renderDimensionCards(targetId, cards, emptyLabel, mappedColumn = "") {
  const container = $(targetId);
  if (!container) return;
  if (!cards || !cards.length) {
    container.innerHTML = mappedColumn
      ? metric(emptyLabel, `Mapped: ${mappedColumn}`, "Click Analyze Feedback to refresh this intelligence.")
      : metric(emptyLabel, "Not mapped", "Select the field in setup and run analysis.");
    return;
  }
  container.innerHTML = cards.map((card) => metric(card.Metric || "Metric", card.Value ?? "-", card.Comment || "")).join("");
}

function findDimensionColumn(rows, aliases, selectedColumn = "") {
  const sample = rows.find((row) => row && Object.keys(row).length) || {};
  const columns = Object.keys(sample).filter((column) => !column.startsWith("__"));
  if (selectedColumn) {
    const selectedLower = selectedColumn.toLowerCase();
    const selectedMatch = columns.find((column) => column.toLowerCase() === selectedLower || column.toLowerCase().includes(selectedLower) || selectedLower.includes(column.toLowerCase()));
    if (selectedMatch) return selectedMatch;
  }
  const normalized = columns.map((column) => [column, column.toLowerCase()]);
  for (const alias of aliases) {
    const exact = normalized.find(([, lower]) => lower === alias);
    if (exact) return exact[0];
  }
  for (const alias of aliases) {
    const partial = normalized.find(([, lower]) => lower.includes(alias));
    if (partial) return partial[0];
  }
  return "";
}

function tenureBucket(value) {
  const text = String(value ?? "").trim();
  if (!text || text === "-" || ["nan", "none", "unknown"].includes(text.toLowerCase())) return "Unknown";
  const normalized = text.toLowerCase().replace(/\s+/g, "");
  const known = {
    "0-30": "0-30",
    "31-60": "31-60",
    "61-90": "61-90",
    "90-180": "91-180",
    "91-180": "91-180",
    "180-365": "181-365",
    "181-365": "181-365",
    ">1year": ">1 year",
    "1+year": ">1 year",
    ">2years": ">2 years",
    "2+years": ">2 years",
    ">3years": ">3 years",
    "3+years": ">3 years",
  };
  if (known[normalized]) return known[normalized];
  const match = text.match(/-?\d+(\.\d+)?/);
  if (!match) return text;
  const days = Number(match[0]);
  if (Number.isNaN(days)) return text;
  if (days <= 30) return "0-30";
  if (days <= 60) return "31-60";
  if (days <= 90) return "61-90";
  if (days <= 180) return "91-180";
  if (days <= 365) return "181-365";
  if (days <= 730) return ">1 year";
  if (days <= 1095) return ">2 years";
  return ">3 years";
}

function dimensionRowsFromFeedback(label, aliases, selectedColumn = "") {
  const candidateSets = [
    state.analysis.feedbackRows || [],
    state.analysis.themeRows || [],
    state.analysis.feedbackTableRows || [],
    state.analysis.preview || [],
    allFeedbackRows(),
  ].filter((rows) => rows && rows.length);
  let sourceRows = [];
  let column = "";
  for (const rows of candidateSets) {
    const match = findDimensionColumn(rows, aliases, selectedColumn);
    if (!match) continue;
    const hasUsableValues = rows.some((row) => {
      const value = String(row[match] ?? "").trim();
      return value && value !== "-";
    });
    if (hasUsableValues) {
      sourceRows = rows;
      column = match;
      break;
    }
  }
  if (!column || !sourceRows.length) return [];
  const groups = new Map();
  sourceRows.forEach((row) => {
    const rawSegment = String(row[column] ?? "").trim();
    const segment = label === "Tenure" ? tenureBucket(rawSegment) : rawSegment || "Unknown";
    if (!groups.has(segment)) {
      groups.set(segment, { [label]: segment, Responses: 0, Promoters: 0, Passives: 0, Detractors: 0, Positive: 0, Neutral: 0, Negative: 0, Silent_Detractors: 0, Score_Total: 0, Score_Count: 0, Driver_Counts: {} });
    }
    const item = groups.get(segment);
    item.Responses += 1;
    const npsType = String(row["NPS Type"] || "").toLowerCase();
    if (npsType === "promoter") item.Promoters += 1;
    if (npsType === "passive") item.Passives += 1;
    if (npsType === "detractor") item.Detractors += 1;
    const sentiment = String(row.Sentiment || "").toLowerCase();
    if (sentiment === "positive") item.Positive += 1;
    if (sentiment === "neutral" || sentiment === "passive") item.Neutral += 1;
    if (sentiment === "negative") item.Negative += 1;
    if (String(row["Silent Detractor Alert"] || "").toLowerCase() === "true" || String(row["Silent Detractor Alert"] || "") === "1") item.Silent_Detractors += 1;
    const score = Number(row["NPS Score"]);
    if (!Number.isNaN(score)) {
      item.Score_Total += score;
      item.Score_Count += 1;
    }
    const driver = String(row["Primary Reason"] || row["Owl Primary Driver"] || "").trim();
    if (driver) item.Driver_Counts[driver] = (item.Driver_Counts[driver] || 0) + 1;
  });
  return [...groups.values()].map((item) => {
    const topDriver = Object.entries(item.Driver_Counts).sort((a, b) => b[1] - a[1])[0]?.[0] || "";
    const row = {
      [label]: item[label],
      Responses: item.Responses,
      Promoters: item.Promoters,
      Passives: item.Passives,
      Detractors: item.Detractors,
      Avg_Rating: item.Score_Count ? Number((item.Score_Total / item.Score_Count).toFixed(2)) : 0,
      Positive: item.Positive,
      Neutral: item.Neutral,
      Negative: item.Negative,
      Silent_Detractors: item.Silent_Detractors,
      NPS: Number((((item.Promoters / Math.max(item.Responses, 1)) * 100) - ((item.Detractors / Math.max(item.Responses, 1)) * 100)).toFixed(1)),
      "Promoter %": Number(((item.Promoters / Math.max(item.Responses, 1)) * 100).toFixed(1)),
      "Negative %": Number(((item.Negative / Math.max(item.Responses, 1)) * 100).toFixed(1)),
      "Top Driver": topDriver,
    };
    return row;
  }).sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0));
}

function dimensionCardsFromRows(rows, label) {
  if (!rows.length) return [];
  const best = [...rows].sort((a, b) => Number(b.NPS || 0) - Number(a.NPS || 0))[0];
  const risk = [...rows].sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0))[0];
  const negative = [...rows].sort((a, b) => Number(b["Negative %"] || 0) - Number(a["Negative %"] || 0))[0];
  return [
    { Metric: label === "Wave" ? "Waves Covered" : "Tenure Bands Covered", Value: rows.length, Comment: "Unique segments found in the selected data." },
    { Metric: "Highest NPS", Value: formatMetric(best?.NPS || 0), Comment: best?.[label] || "" },
    { Metric: "Lowest NPS", Value: formatMetric(risk?.NPS || 0), Comment: risk?.[label] || "" },
    { Metric: "Highest Negative Share", Value: `${formatMetric(negative?.["Negative %"] || 0)}%`, Comment: negative?.[label] || "" },
  ];
}

function dimensionLensRows(dimensions) {
  return (dimensions || []).map((item) => {
    const label = item.name || "Dimension";
    const rows = item.rows || [];
    const total = rows.reduce((sum, row) => sum + Number(row.Responses || 0), 0);
    const totalDetractors = rows.reduce((sum, row) => sum + Number(row.Detractors || 0), 0);
    const weightedScore = total
      ? rows.reduce((sum, row) => sum + (Number(row.NPS || 0) * Number(row.Responses || 0)), 0) / total
      : 0;
    const best = [...rows].sort((a, b) => Number(b.NPS || 0) - Number(a.NPS || 0))[0] || {};
    const worst = [...rows].sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0))[0] || {};
    const bestScore = Number(best.NPS || 0);
    const worstScore = Number(worst.NPS || 0);
    const gap = bestScore - worstScore;
    const drag = Math.max(0, weightedScore - worstScore);
    const worstDetractors = Number(worst.Detractors || 0);
    const detractorConcentration = totalDetractors ? (worstDetractors / totalDetractors) * 100 : 0;
    const matters = rows.length > 1 && total >= 30 && (gap >= 8 || detractorConcentration >= 25);
    return {
      Dimension: label,
      Values: rows.length,
      Best: best[label] ? `${best[label]} (${formatMetric(bestScore, 2)})` : "-",
      Worst: worst[label] ? `${worst[label]} (${formatMetric(worstScore, 2)})` : "-",
      Gap: formatMetric(gap, 2),
      "Gap trend": gap >= 15 ? "Widening risk" : gap >= 5 ? "Watch" : "Tight",
      Drag: `+${formatMetric(drag, 2)}`,
      "Detr. conc.": totalDetractors ? `${formatMetric(detractorConcentration, 2)}%` : "0.00%",
      "Matters?": matters ? "Yes" : "No",
    };
  }).sort((a, b) => Number.parseFloat(b.Gap || 0) - Number.parseFloat(a.Gap || 0));
}

function dimensionPivotSourceRows(rowDimension = "", columnDimension = "") {
  const analysis = state.analysis || {};
  const candidates = [
    analysis.feedbackRows,
    analysis.feedbackTableRows,
    analysis.preview,
    state.statsData?.analyzedRows,
    state.statsData?.baseRows,
  ].filter((rows) => Array.isArray(rows) && rows.length);
  if (!rowDimension || !columnDimension) return candidates[0] || [];
  const scored = candidates.map((rows) => {
    const validBoth = rows.reduce((count, row) => {
      const rowValue = dimensionPivotCellValue(row, rowDimension);
      const columnValue = dimensionPivotCellValue(row, columnDimension);
      return count + (rowValue !== "Unknown" && columnValue !== "Unknown" ? 1 : 0);
    }, 0);
    return { rows, validBoth };
  }).sort((a, b) => b.validBoth - a.validBoth || b.rows.length - a.rows.length);
  return (scored.find((item) => item.validBoth > 0) || scored[0])?.rows || [];
}

function dimensionPivotCellValue(row, column) {
  const direct = row?.[column];
  if (direct !== undefined && direct !== null && String(direct).trim() !== "") return String(direct).trim();
  const wanted = String(column || "").toLowerCase();
  const foundKey = Object.keys(row || {}).find((key) => String(key).toLowerCase() === wanted);
  const value = foundKey ? row[foundKey] : "";
  return value === undefined || value === null || String(value).trim() === "" ? "Unknown" : String(value).trim();
}

function dimensionPivotScore(rows) {
  const total = rows.length;
  if (!total) return { score: null, volume: 0 };

  const npsCounts = rows.reduce((acc, row) => {
    const type = String(row["NPS Type"] || row.NPS_Type || row.NPSType || "").toLowerCase();
    if (type.includes("promoter")) acc.promoters += 1;
    else if (type.includes("detractor")) acc.detractors += 1;
    else if (type.includes("passive")) acc.passives += 1;
    return acc;
  }, { promoters: 0, passives: 0, detractors: 0 });
  const npsTotal = npsCounts.promoters + npsCounts.passives + npsCounts.detractors;
  if (npsTotal) {
    return { score: ((npsCounts.promoters - npsCounts.detractors) / npsTotal) * 100, volume: npsTotal };
  }

  const csatCounts = rows.reduce((acc, row) => {
    const type = String(row["Satisfaction Level"] || row["Satisfaction Status"] || row["CSAT Category"] || "").toLowerCase();
    if (type.includes("satisfied") || type.includes("positive")) acc.satisfied += 1;
    else if (type.includes("neutral")) acc.neutral += 1;
    else if (type.includes("dissatisfied") || type.includes("negative")) acc.dissatisfied += 1;
    return acc;
  }, { satisfied: 0, neutral: 0, dissatisfied: 0 });
  const csatTotal = csatCounts.satisfied + csatCounts.neutral + csatCounts.dissatisfied;
  if (csatTotal) {
    return { score: (csatCounts.satisfied / csatTotal) * 100, volume: csatTotal };
  }

  const scoreKeys = ["NPS", "NPS Score", "CSAT", "CSAT Score", "Score", "Rating"];
  const values = rows.map((row) => {
    const key = scoreKeys.find((item) => row?.[item] !== undefined && row?.[item] !== null && row?.[item] !== "");
    return key ? Number(row[key]) : NaN;
  }).filter(Number.isFinite);
  if (values.length) {
    return { score: values.reduce((sum, value) => sum + value, 0) / values.length, volume: values.length };
  }

  return { score: null, volume: total };
}

function dimensionPivotCell(metric) {
  if (!metric || !metric.volume) return "-";
  const score = Number.isFinite(Number(metric.score)) ? formatMetric(metric.score, 1) : "-";
  return `${score} (${Number(metric.volume || 0).toLocaleString()})`;
}

function buildDimensionPivotRows(rowDimension, columnDimension) {
  const rows = dimensionPivotSourceRows(rowDimension, columnDimension);
  if (!rowDimension || !columnDimension || rowDimension === columnDimension || !rows.length) return [];
  const rowValues = [...new Set(rows.map((row) => dimensionPivotCellValue(row, rowDimension)))].filter(Boolean);
  const columnValues = [...new Set(rows.map((row) => dimensionPivotCellValue(row, columnDimension)))].filter(Boolean);
  const rankedRows = rowValues
    .map((value) => ({ value, volume: rows.filter((row) => dimensionPivotCellValue(row, rowDimension) === value).length }))
    .sort((a, b) => b.volume - a.volume || String(a.value).localeCompare(String(b.value)))
    .map((item) => item.value);
  const rankedColumns = columnValues
    .map((value) => ({ value, volume: rows.filter((row) => dimensionPivotCellValue(row, columnDimension) === value).length }))
    .sort((a, b) => b.volume - a.volume || String(a.value).localeCompare(String(b.value)))
    .map((item) => item.value);
  const rowHeader = `${rowDimension} \\ ${columnDimension}`;
  const body = rankedRows.map((rowValue) => {
    const item = { [rowHeader]: rowValue };
    rankedColumns.forEach((columnValue) => {
      const subset = rows.filter((row) => dimensionPivotCellValue(row, rowDimension) === rowValue && dimensionPivotCellValue(row, columnDimension) === columnValue);
      item[columnValue] = dimensionPivotCell(dimensionPivotScore(subset));
    });
    item["Row Total"] = dimensionPivotCell(dimensionPivotScore(rows.filter((row) => dimensionPivotCellValue(row, rowDimension) === rowValue)));
    return item;
  });
  if (body.length) {
    const totalRow = { [rowHeader]: "Col Total" };
    rankedColumns.forEach((columnValue) => {
      totalRow[columnValue] = dimensionPivotCell(dimensionPivotScore(rows.filter((row) => dimensionPivotCellValue(row, columnDimension) === columnValue)));
    });
    totalRow["Row Total"] = dimensionPivotCell(dimensionPivotScore(rows));
    body.push(totalRow);
  }
  return body;
}

function populateDimensionPivotControls(dimensions) {
  const rowSelect = $("dimensionLensRowSelect");
  const columnSelect = $("dimensionLensColumnSelect");
  if (!rowSelect || !columnSelect) return;
  const names = (dimensions || []).map((item) => item.name).filter(Boolean);
  const currentRow = rowSelect.value;
  const currentColumn = columnSelect.value;
  const options = names.map((name) => `<option value="${escapeHtml(name)}">${escapeHtml(name)}</option>`).join("");
  rowSelect.innerHTML = options;
  columnSelect.innerHTML = options;
  rowSelect.value = names.includes(currentRow) ? currentRow : (names[0] || "");
  columnSelect.value = names.includes(currentColumn) ? currentColumn : (names.find((name) => name !== rowSelect.value) || names[1] || "");
  rowSelect.onchange = renderDimensionPivotTable;
  columnSelect.onchange = renderDimensionPivotTable;
}

function renderDimensionPivotTable() {
  const rowDimension = $("dimensionLensRowSelect")?.value || "";
  const columnDimension = $("dimensionLensColumnSelect")?.value || "";
  const meta = $("dimensionPivotMeta");
  const rows = buildDimensionPivotRows(rowDimension, columnDimension);
  if (meta) {
    meta.textContent = rows.length
      ? `${rowDimension} by ${columnDimension}. Each cell shows score and volume.`
      : rowDimension === columnDimension
        ? "Choose two different dimensions to generate the table."
        : "Run analysis with at least two dimensions to generate the table.";
  }
  renderAnyTable("dimensionPivotTable", rows, 100);
}

function renderDimensionLens(dimensions) {
  const rows = dimensionLensRows(dimensions || []);
  if ($("dimensionLensCount")) $("dimensionLensCount").textContent = `(${rows.length})`;
  const meta = $("dimensionLensMeta");
  if (meta) {
    meta.textContent = rows.length
      ? `${rows.length.toLocaleString()} dimensions compared by gap, drag, detractor concentration, and action value.`
      : "Run analysis with selected dimensions to generate the cross-dimension lens.";
  }
  renderAnyTable("dimensionLensTable", rows, 100);
  populateDimensionPivotControls(dimensions || []);
  renderDimensionPivotTable();
}

function renderDimensionDashboard(config) {
  const rows = config.rows || [];
  if (config.cardId) renderDimensionCards(config.cardId, config.cards || [], `${config.label} Field`, config.mappedColumn || "");
  renderAnyTable(config.tableId, rows, 10);
  if (!rows.length) {
    [config.npsChart, config.mixChart, config.negativeChart, config.silentChart].forEach((id) => {
      if ($(id)) $(id).innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">Map ${config.label.toLowerCase()} and run analysis.</text>`;
    });
    [config.npsInsight, config.mixInsight, config.negativeInsight, config.silentInsight].forEach((id) => {
      if ($(id)) $(id).textContent = config.mappedColumn
        ? `${config.label} field is mapped to ${config.mappedColumn}. Click Analyze Feedback to refresh this view.`
        : `${config.label} intelligence will appear after analysis.`;
    });
    return;
  }
  const ranked = [...rows].sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0)).slice(0, 8);
  renderHorizontalBars(config.npsChart, ranked, config.label, "NPS", "#006d86", 8);
  renderComparisonBars(
    config.mixChart,
    rows.slice(0, 6).map((row) => ({ ...row, Range: row[config.label] })),
    ["Promoters", "Passives", "Detractors"],
    ["#19a55b", "#e3b34e", "#d94045"],
    `${config.label} response mix appears after analysis.`
  );
  renderHorizontalBars(config.negativeChart, [...rows].sort((a, b) => Number(b["Negative %"] || 0) - Number(a["Negative %"] || 0)), config.label, "Negative %", "#d94045", 8);
  renderHorizontalBars(config.silentChart, [...rows].sort((a, b) => Number(b.Silent_Detractors || 0) - Number(a.Silent_Detractors || 0)), config.label, "Silent_Detractors", "#8492a6", 8);
  const best = [...rows].sort((a, b) => Number(b.NPS || 0) - Number(a.NPS || 0))[0];
  const risk = [...rows].sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0))[0];
  const negative = [...rows].sort((a, b) => Number(b["Negative %"] || 0) - Number(a["Negative %"] || 0))[0];
  const silent = [...rows].sort((a, b) => Number(b.Silent_Detractors || 0) - Number(a.Silent_Detractors || 0))[0];
  if ($(config.npsInsight)) $(config.npsInsight).textContent = risk ? `${risk[config.label]} is the lowest ${config.label.toLowerCase()} NPS segment at ${formatMetric(risk.NPS)}.` : "";
  if ($(config.mixInsight)) $(config.mixInsight).textContent = best ? `${best[config.label]} leads the ${config.label.toLowerCase()} view with NPS ${formatMetric(best.NPS)}.` : "";
  if ($(config.negativeInsight)) $(config.negativeInsight).textContent = negative ? `${negative[config.label]} has the highest negative sentiment share at ${formatMetric(negative["Negative %"])}%.` : "";
  if ($(config.silentInsight)) $(config.silentInsight).textContent = silent ? `${silent[config.label]} has ${Number(silent.Silent_Detractors || 0).toLocaleString()} silent detractor signals.` : "";
}

