function feedbackRowsForDimension(item, selectedValue = "__all") {
  const label = item.name || "";
  const rows = state.analysis.feedbackRows || state.analysis.preview || [];
  if (!label || !rows.length) return [];
  return rows.filter((row) => {
    const value = String(row[label] ?? "").trim() || "Unknown";
    return selectedValue === "__all" || value === String(selectedValue);
  });
}

function weekStartLabel(value) {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "";
  const start = new Date(date);
  start.setHours(0, 0, 0, 0);
  start.setDate(start.getDate() - start.getDay());
  return start.toISOString().slice(0, 10);
}

function customDimensionWeeklyRows(item, selectedValue = "__all") {
  const rows = feedbackRowsForDimension(item, selectedValue);
  const groups = new Map();
  rows.forEach((row) => {
    const week = weekStartLabel(row["Feedback Date"] || row["Response Date"] || row.Date || row.Week);
    if (!week) return;
    if (!groups.has(week)) {
      groups.set(week, { Week: week, Responses: 0, Promoter: 0, Passive: 0, Detractor: 0, Positive_Count: 0, Neutral_Count: 0, Negative_Count: 0 });
    }
    const itemRow = groups.get(week);
    itemRow.Responses += 1;
    const npsType = String(row["NPS Type"] || "").toLowerCase();
    if (npsType === "promoter") itemRow.Promoter += 1;
    if (npsType === "passive") itemRow.Passive += 1;
    if (npsType === "detractor") itemRow.Detractor += 1;
    const sentiment = String(row.Sentiment || "").toLowerCase();
    if (sentiment === "positive") itemRow.Positive_Count += 1;
    if (sentiment === "neutral" || sentiment === "passive") itemRow.Neutral_Count += 1;
    if (sentiment === "negative") itemRow.Negative_Count += 1;
  });
  return [...groups.values()].sort((a, b) => String(a.Week).localeCompare(String(b.Week))).map((row) => {
    const sentimentTotal = Math.max(row.Positive_Count + row.Neutral_Count + row.Negative_Count, 1);
    return {
      Week: row.Week,
      Responses: row.Responses,
      NPS: Number((((row.Promoter / Math.max(row.Responses, 1)) * 100) - ((row.Detractor / Math.max(row.Responses, 1)) * 100)).toFixed(1)),
      Positive: Number(((row.Positive_Count / sentimentTotal) * 100).toFixed(1)),
      Neutral: Number(((row.Neutral_Count / sentimentTotal) * 100).toFixed(1)),
      Negative: Number(((row.Negative_Count / sentimentTotal) * 100).toFixed(1)),
    };
  });
}

function renderCustomDimensionWeeklyCharts(item, index, selectedValue = "__all") {
  const prefix = `dynamicDimension${index}`;
  const weekly = customDimensionWeeklyRows(item, selectedValue);
  renderTrend(weekly, `${prefix}WeeklyNpsTrend`);
  renderVolumeTrend(weekly, `${prefix}WeeklyVolumeTrend`);
  renderSentimentTrend(weekly, `${prefix}WeeklySentimentTrend`);
  const insight = $(`${prefix}WeeklyInsight`);
  if (insight) {
    if (!weekly.length) {
      insight.textContent = "Weekly movement needs a valid feedback date in the analyzed data.";
    } else {
      const latest = weekly[weekly.length - 1];
      const best = [...weekly].sort((a, b) => Number(b.NPS || 0) - Number(a.NPS || 0))[0];
      insight.textContent = `${selectedValue === "__all" ? item.name : selectedValue}: latest week ${latest.Week} has ${latest.Responses} responses and NPS ${formatMetric(latest.NPS)}. Best week is ${best.Week} at NPS ${formatMetric(best.NPS)}.`;
    }
  }
}

function customDimensionSnapshot(item, selectedValue = "__all") {
  const label = item.name || "Dimension";
  const rows = item.rows || [];
  const selectedRows = selectedValue === "__all"
    ? rows
    : rows.filter((row) => String(row[label] || "") === String(selectedValue));
  const total = selectedRows.reduce((sum, row) => sum + Number(row.Responses || 0), 0);
  const promoters = selectedRows.reduce((sum, row) => sum + Number(row.Promoters || 0), 0);
  const passives = selectedRows.reduce((sum, row) => sum + Number(row.Passives || 0), 0);
  const detractors = selectedRows.reduce((sum, row) => sum + Number(row.Detractors || 0), 0);
  const positive = selectedRows.reduce((sum, row) => sum + Number(row.Positive || 0), 0);
  const neutral = selectedRows.reduce((sum, row) => sum + Number(row.Neutral || row.Passive || 0), 0);
  const negative = selectedRows.reduce((sum, row) => sum + Number(row.Negative || 0), 0);
  const weightedNps = total
    ? selectedRows.reduce((sum, row) => sum + (Number(row.NPS || 0) * Number(row.Responses || 0)), 0) / total
    : 0;
  const sentimentTotal = Math.max(positive + neutral + negative, 1);
  const rankedRows = [...(selectedValue === "__all" ? rows : selectedRows)].sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0));
  const best = [...selectedRows].sort((a, b) => Number(b.NPS || 0) - Number(a.NPS || 0))[0];
  const risk = [...selectedRows].sort((a, b) => Number(a.NPS || 0) - Number(b.NPS || 0))[0];
  const negativeRisk = [...selectedRows].sort((a, b) => Number(b["Negative %"] || 0) - Number(a["Negative %"] || 0))[0];
  return {
    summary: {
      total,
      nps: weightedNps,
      promoters: total ? (promoters / total) * 100 : 0,
      passives: total ? (passives / total) * 100 : 0,
      detractors: total ? (detractors / total) * 100 : 0,
    },
    counts: { Promoter: promoters, Passive: passives, Detractor: detractors },
    sentiment: {
      Positive: (positive / sentimentTotal) * 100,
      Neutral: (neutral / sentimentTotal) * 100,
      Negative: (negative / sentimentTotal) * 100,
    },
    segmentSentiments: {},
    weekly: rankedRows.slice(0, 12).map((row) => ({ Week: row[label], NPS: Number(row.NPS || 0), Responses: Number(row.Responses || 0) })),
    intelligence: [
      { label: "Segments", value: selectedRows.length || rows.length || 0, note: "Visible custom dimension segments.", tone: "", },
      { label: "Lowest NPS", value: risk ? formatMetric(risk.NPS) : "-", note: risk ? String(risk[label] || "") : "No segment available.", tone: "risk" },
      { label: "Highest NPS", value: best ? formatMetric(best.NPS) : "-", note: best ? String(best[label] || "") : "No segment available.", tone: "positive" },
      { label: "Highest Negative Share", value: negativeRisk ? `${formatMetric(negativeRisk["Negative %"])}%` : "-", note: negativeRisk ? String(negativeRisk[label] || "") : "No segment available.", tone: "risk" },
    ],
  };
}

function renderDashboardSnapshot(prefix, snapshot = {}, context = {}) {
  const summary = snapshot.summary || {};
  const counts = snapshot.counts || {};
  const sentiment = snapshot.sentiment || {};
  const intelligence = Array.isArray(snapshot.intelligence) ? snapshot.intelligence : [];
  const score = Number(summary.NPS ?? summary.nps ?? summary.CSAT ?? summary.csat ?? 0);
  const metricName = summary.CSAT !== undefined || summary.csat !== undefined ? "CSAT" : "NPS";
  const total = Number(summary.total || 0);
  const cards = [
    { label: "Scope", value: context.value || "Selected view", note: context.type === "dynamic" ? "Custom dimension read" : "Dashboard snapshot" },
    { label: "Responses", value: total.toLocaleString(), note: "Rows in this view" },
    { label: metricName, value: formatMetric(score), note: "Weighted segment score", tone: score >= 0 ? "positive" : "risk" },
    ...intelligence.slice(0, 4),
  ];
  const grid = $(`${prefix}MetricGrid`);
  if (grid) {
    grid.innerHTML = cards.map((card) => metric(card.label, card.value, card.note || "", card.tone || "")).join("");
  }
  const weekly = Array.isArray(snapshot.weekly) ? snapshot.weekly : [];
  const trendRows = weekly.map((row) => ({ ...row, NPS: Number(row.NPS ?? row.CSAT ?? row.nps ?? row.csat ?? 0), CSAT: Number(row.CSAT ?? row.NPS ?? row.csat ?? row.nps ?? 0) }));
  renderLineChart(`${prefix}NpsTrend`, trendRows, metricName === "CSAT" ? "CSAT" : "NPS", `Run analysis to view ${metricName} trend.`, "#006d86");
  renderGauge({ ...summary, NPS: score, CSAT: score }, `${prefix}NpsGauge`);
  renderComposition(counts, { ...summary, total }, `${prefix}NpsComposition`);
  renderSentiment(sentiment, `${prefix}SentimentMix`);
}

function customDimensionTableRows(rows, label) {
  return (rows || []).map((row) => ({
    [label]: row[label] ?? row.Dimension ?? "",
    "NPS Score": Number(Number(row.NPS ?? row["NPS Score"] ?? 0).toFixed(2)),
    Responses: Number(row.Responses || 0),
    Promoters: Number(row.Promoters || 0),
    Passives: Number(row.Passives || 0),
    Detractors: Number(row.Detractors || 0),
    Avg_Rating: Number(Number(row.Avg_Rating || 0).toFixed(2)),
    Positive: Number(row.Positive || 0),
    Neutral: Number(row.Neutral || 0),
    Negative: Number(row.Negative || 0),
    "Promoter %": Number(Number(row["Promoter %"] || 0).toFixed(2)),
    "Negative %": Number(Number(row["Negative %"] || 0).toFixed(2)),
    "Top Driver": row["Top Driver"] || "",
  }));
}

function renderCustomDimensionDashboard(item, index) {
  const select = $(`dynamicDimensionSelect${index}`);
  const selectedValue = select?.value || "__all";
  const prefix = `dynamicDimension${index}`;
  const title = item.name || "Dimension";
  const segmentRows = selectedValue === "__all"
    ? item.rows || []
    : (item.rows || []).filter((row) => String(row[title] || "") === String(selectedValue));
  if ($("dynamicDimensionActiveTitle")) $("dynamicDimensionActiveTitle").textContent = title;
  if ($("dynamicDimensionActiveMeta")) $("dynamicDimensionActiveMeta").textContent = `${Number((item.rows || []).length).toLocaleString()} segment${(item.rows || []).length === 1 ? "" : "s"} available`;
  [
    ["TrendTitle", `${title} NPS Trend`],
    ["GaugeTitle", `${title} NPS Gauge`],
    ["SentimentTitle", `${title} Sentiment Mix`],
    ["CompositionTitle", `${title} NPS Composition`],
    ["RankingTitle", `${title} NPS Ranking`],
    ["MixTitle", `${title} Response Mix`],
    ["NegativeTitle", `${title} Negative Share`],
    ["SilentTitle", `${title} Silent Detractors`],
    ["WeeklyTitle", `${title} weekly trend`],
  ].forEach(([suffix, text]) => {
    const el = $(`${prefix}${suffix}`);
    if (el) el.textContent = text;
  });
  const snapshot = customDimensionSnapshot(item, selectedValue);
  renderDashboardSnapshot(prefix, snapshot, { type: "dynamic", value: selectedValue === "__all" ? item.name : selectedValue });
  renderDimensionDashboard({
    label: title,
    rows: segmentRows,
    cards: item.cards || [],
    mappedColumn: title,
    tableId: `dynamicDimensionTable${index}`,
    npsChart: `${prefix}NpsRanking`,
    mixChart: `${prefix}MixChart`,
    negativeChart: `${prefix}NegativeChart`,
    silentChart: `${prefix}SilentChart`,
    npsInsight: `${prefix}NpsInsight`,
    mixInsight: `${prefix}MixInsight`,
    negativeInsight: `${prefix}NegativeInsight`,
    silentInsight: `${prefix}SilentInsight`,
  });
  renderAnyTable(`dynamicDimensionTable${index}`, customDimensionTableRows(segmentRows, title), 10);
  renderCustomDimensionWeeklyCharts(item, index, selectedValue);
}

function renderQuartileWeekly(svgId, rows) {
  const svg = $(svgId);
  const data = rows || [];
  if (!data.length) {
    svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">Run analysis with valid dates to view quartile movement.</text>`;
    return;
  }
  const w = 760, h = 260, left = 54, right = 38, top = 30, bottom = 34;
  const plotW = w - left - right;
  const plotH = h - top - bottom;
  const keys = ["Q1", "Q2", "Q3", "Q4"];
  const colors = { Q1: "#19a55b", Q2: "#009b9b", Q3: "#e3b34e", Q4: "#d94045" };
  const values = data.flatMap((row) => keys.map((key) => Number(row[key] || 0)));
  const min = Math.min(-100, ...values);
  const max = Math.max(100, ...values);
  const xFor = (i) => left + (plotW * i) / Math.max(data.length - 1, 1);
  const yFor = (value) => top + (max - Math.max(min, Math.min(max, value))) / Math.max(max - min, 1) * plotH;
  const labelBox = (x, y, value, color, index, valueIndex) => {
    const yShift = value >= 0 ? -14 - index * 3 : 12 + index * 3;
    const label = value.toFixed(value % 1 ? 1 : 0);
    const width = Math.max(28, label.length * 7 + 12);
    const labelY = Math.max(top + 10, Math.min(h - bottom - 6, y + yShift));
    return `<rect x="${x - width / 2}" y="${labelY - 14}" width="${width}" height="20" rx="10" fill="#fff" stroke="${color}" stroke-opacity="0.42"></rect>
      <text x="${x}" y="${labelY}" text-anchor="middle" fill="${color}" font-size="13" font-weight="950">${label}</text>`;
  };
  svg.innerHTML = `
    <rect x="${left}" y="${top}" width="${plotW}" height="${plotH}" fill="#ffffff"></rect>
    ${[-100, -50, 0, 50, 100].map((tick) => `<line x1="${left}" x2="${w - right}" y1="${yFor(tick)}" y2="${yFor(tick)}" stroke="${tick === 0 ? "#b8c6d1" : "#e8eef4"}" stroke-width="${tick === 0 ? 1.4 : 1}"></line><text x="${left - 10}" y="${yFor(tick) + 4}" text-anchor="end" fill="#6b8194" font-size="13" font-weight="850">${tick}</text>`).join("")}
    ${keys.map((key, index) => {
      const pts = data.map((row, i) => `${xFor(i)},${yFor(Number(row[key] || 0))}`).join(" ");
      const labels = data.map((row, i) => {
        const value = Number(row[key] || 0);
        const y = yFor(value);
        const tooltip = `${key} on ${String(row.Week || "").slice(0, 10)}|Average NPS: ${formatMetric(value)}`;
        return `<circle class="quartile-mark quartile-point-hit" data-tooltip="${escapeHtml(tooltip)}" cx="${xFor(i)}" cy="${y}" r="11" fill="${colors[key]}" opacity="0"></circle>
          <circle class="quartile-mark quartile-point" data-tooltip="${escapeHtml(tooltip)}" cx="${xFor(i)}" cy="${y}" r="4" fill="#fff" stroke="${colors[key]}" stroke-width="2.2"></circle>
          ${labelBox(xFor(i), y, value, colors[key], index, i)}`;
      }).join("");
      return `<polyline points="${pts}" fill="none" stroke="${colors[key]}" stroke-width="3.2" stroke-linecap="round" stroke-linejoin="round"></polyline>
        ${labels}
        <rect x="${left + plotW / 2 - 116 + index * 62}" y="5" width="11" height="11" rx="3" fill="${colors[key]}"></rect>
        <text x="${left + plotW / 2 - 100 + index * 62}" y="16" fill="#0c2340" font-size="14" font-weight="950">${key}</text>`;
    }).join("")}
    ${data.filter((_, i) => i === 0 || i === data.length - 1 || i % Math.max(Math.floor(data.length / 5), 1) === 0).map((row) => {
      const index = data.indexOf(row);
      return `<text x="${xFor(index)}" y="${h - 12}" text-anchor="middle" fill="#3f566a" font-size="15" font-weight="900">${String(row.Week || "").slice(5, 10)}</text>`;
    }).join("")}
  `;
}

function renderDonut(svgId, rows, labelKey, valueKey) {
  const svg = $(svgId);
  const data = (rows || []).slice(0, 6);
  const total = data.reduce((sum, row) => sum + Number(row[valueKey] || 0), 0);
  if (!data.length || total <= 0) {
    svg.innerHTML = `<text x="180" y="130" text-anchor="middle" fill="#728399">No segment volume yet.</text>`;
    return;
  }
  const colors = ["#009b9b", "#0c2340", "#40c8c8", "#8492a6", "#e3b34e", "#d94045"];
  let angle = -90;
  const arcs = data.map((row, i) => {
    const pct = Number(row[valueKey] || 0) / total;
    const next = angle + pct * 360;
    const path = arcPath(180, 124, 74, angle, next);
    angle = next;
    return `<path d="${path}" stroke="${colors[i % colors.length]}" stroke-width="24" fill="none"></path>`;
  }).join("");
  svg.innerHTML = `
    ${arcs}
    <text x="180" y="120" text-anchor="middle" fill="#0c2340" font-size="28" font-weight="900">${total.toFixed(0)}</text>
    <text x="180" y="140" text-anchor="middle" fill="#728399" font-size="11">responses</text>
    ${data.slice(0, 4).map((row, i) => `<rect x="42" y="${202 + i * 14}" width="8" height="8" rx="2" fill="${colors[i]}"></rect><text x="58" y="${210 + i * 14}" fill="#0c2340" font-size="10" font-weight="700">${String(row[labelKey] || "").slice(0, 22)} (${row[valueKey]})</text>`).join("")}
  `;
}

function renderAlerts(alerts) {
  const active = alerts.filter((a) => a.tone !== "clear").length;
  $("alertScore").textContent = `${active}/${alerts.length} Alerts`;
  $("alertCards").innerHTML = alerts
    .map((alert) => `<button class="alert-card ${alert.tone}" onclick="alert('${String(alert.detail).replaceAll("'", "\\'")}')"><small>${alert.title}</small><h3>${alert.title}</h3><div class="status">${alert.status}</div><p>${alert.detail}</p></button>`)
    .join("");
}

function cellClass(value) {
  const normalized = String(value || "").toLowerCase();
  if (normalized === "positive") return "sentiment-positive";
  if (normalized === "negative") return "sentiment-negative";
  if (normalized === "passive") return "sentiment-passive";
  return "";
}

function renderTable(rows) {
  renderAnyTable("previewTable", rows);
}

function columnClass(column) {
  return `col-${String(column || "").toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "")}`;
}

function tableHeaderLabel(tableId, column) {
  const text = String(column || "");
  if (tableId === "themeBuilderTable" && text.startsWith("Theme: ")) {
    return text.replace(/^Theme:\s*/i, "");
  }
  if (tableId === "themeBuilderTable" && text === "Classification Source") return "Source";
  return text;
}

function tableHeaderClass(tableId, column) {
  const classes = [columnClass(column)];
  if (tableId === "themeBuilderTable" && String(column || "").startsWith("Theme: ")) classes.push("theme-builder-theme-col");
  return classes.join(" ");
}

function renderAnyTable(tableId, rows, maxColumns = 18) {
  const table = $(tableId);
  if (!table) return;
  if (!rows || !rows.length) {
    table.innerHTML = "<tbody><tr><td>No data available yet.</td></tr></tbody>";
    return;
  }
  const displayRows = rows.slice(0, tableDisplayLimit(tableId));
  const columns = Object.keys(displayRows[0]).filter((column) => !column.startsWith("__")).slice(0, maxColumns);
  const notice = rows.length > displayRows.length
    ? `<caption class="table-preview-caption">Showing ${displayRows.length.toLocaleString()} of ${rows.length.toLocaleString()} rows to keep the browser smooth. Downloads and backend calculations use the full available source where supported.</caption>`
    : "";
  table.innerHTML = `${notice}<thead><tr>${columns.map((c) => `<th class="${tableHeaderClass(tableId, c)}" title="${escapeHtml(c)}">${escapeHtml(tableHeaderLabel(tableId, c))}</th>`).join("")}</tr></thead><tbody>${displayRows
    .map((row) => `<tr data-row-id="${escapeHtml(row.__row_id)}">${columns.map((c) => `<td class="${cellClass(row[c])} ${tableHeaderClass(tableId, c)}" title="${escapeHtml(c)}: ${escapeHtml(displayCellValue(row[c]))}"><span class="cell-value">${escapeHtml(displayCellValue(row[c]))}</span></td>`).join("")}</tr>`)
    .join("")}</tbody>`;
}

function tableDisplayLimit(tableId) {
  const explicit = Number($(tableId)?.dataset?.displayLimit || 0);
  if (Number.isFinite(explicit) && explicit > 0) return explicit;
  const limits = {
    artifactTable: 1000,
    themeBuilderTable: 500,
    customStatsTable: 1000,
    summaryBuilderPreviewTable: 250,
    performanceLensTable: 500,
    analysisTable: 500,
    previewTable: 500,
  };
  return limits[tableId] || 1000;
}

function browserSafeSampleRows(rows, limit = 500) {
  const source = Array.isArray(rows) ? rows : [];
  const safeLimit = Math.max(1, Number(limit) || 500);
  if (source.length <= safeLimit) return source;
  if (safeLimit === 1) return [source[source.length - 1]];
  const step = (source.length - 1) / (safeLimit - 1);
  return Array.from({ length: safeLimit }, (_, index) => source[Math.round(index * step)]).filter(Boolean);
}

function renderFeedbackSummary(sentiment) {
  const positive = Number(sentiment.Positive || 0);
  const neutral = Number(sentiment.Neutral || 0);
  const negative = Number(sentiment.Negative || 0);
  $("feedbackSentimentSummary").innerHTML = `
    <button class="pill positive" data-sentiment-filter="Positive">Positive ${positive.toFixed(1)}%</button>
    <button class="pill neutral" data-sentiment-filter="Neutral">Neutral ${neutral.toFixed(1)}%</button>
    <button class="pill negative" data-sentiment-filter="Negative">Negative ${negative.toFixed(1)}%</button>
  `;
  document.querySelectorAll("[data-sentiment-filter]").forEach((button) => {
    button.classList.toggle("active", state.feedbackFilter === button.dataset.sentimentFilter);
    button.addEventListener("click", (event) => {
      event.stopPropagation();
      state.feedbackFilter = button.dataset.sentimentFilter;
      if (typeof renderFeedbackTable === "function") renderFeedbackTable();
      document.querySelectorAll("[data-sentiment-filter]").forEach((pill) => pill.classList.toggle("active", state.feedbackFilter === pill.dataset.sentimentFilter));
    });
  });
  renderFeedbackSentimentChart({ Positive: positive, Neutral: neutral, Negative: negative });
}

function renderFeedbackSentimentChart(sentiment) {
  const svg = $("feedbackSentimentChart");
  if (!svg) return;
  const rows = [
    { Label: "Positive", Value: Number(sentiment.Positive || 0), Color: "#19a55b" },
    { Label: "Neutral", Value: Number(sentiment.Neutral || 0), Color: "#8492a6" },
    { Label: "Negative", Value: Number(sentiment.Negative || 0), Color: "#d94045" },
  ];
  const max = Math.max(...rows.map((row) => row.Value), 1);
  const w = 760, h = 240, left = 68, right = 32, top = 38, bottom = 38;
  const plotW = w - left - right;
  const plotH = h - top - bottom;
  const groupW = plotW / rows.length;
  const barW = Math.min(118, groupW * 0.42);
  svg.innerHTML = `
    <line x1="${left}" x2="${w - right}" y1="${top + plotH}" y2="${top + plotH}" stroke="#c7d5df" stroke-width="1.4"></line>
    ${[0, 50, 100].map((tick) => {
      const y = top + plotH - (tick / 100) * plotH;
      return `<line x1="${left}" x2="${w - right}" y1="${y}" y2="${y}" stroke="#edf2f6"></line>
        <text x="${left - 12}" y="${y + 4}" text-anchor="end" fill="#728399" font-size="11" font-weight="700">${tick}%</text>`;
    }).join("")}
    ${rows.map((row, i) => {
      const height = Math.max((row.Value / Math.max(max, 100)) * plotH, 3);
      const x = left + i * groupW + (groupW - barW) / 2;
      const y = top + plotH - height;
      return `<rect x="${x}" y="${y}" width="${barW}" height="${height}" rx="10" fill="${row.Color}" opacity="0.92"></rect>
        <text x="${x + barW / 2}" y="${y - 10}" text-anchor="middle" fill="#0c2340" font-size="15" font-weight="900">${row.Value.toFixed(1)}%</text>
        <text x="${x + barW / 2}" y="${h - 12}" text-anchor="middle" fill="#3f566a" font-size="13" font-weight="850">${row.Label}</text>`;
    }).join("")}
  `;
  const lead = rows.slice().sort((a, b) => b.Value - a.Value)[0];
  if ($("feedbackSentimentInsight")) $("feedbackSentimentInsight").textContent = `${lead.Label} is the largest sentiment segment at ${lead.Value.toFixed(1)}%. Click a sentiment pill above to filter the table.`;
}

function numericColumns(rows) {
  if (!rows || !rows.length) return [];
  return Object.keys(rows[0]).filter((column) => {
    if (column.startsWith("__")) return false;
    const populated = rows.map((row) => row[column]).filter((value) => value !== "" && value != null);
    if (!populated.length) return false;
    const numeric = populated.filter((value) => !Number.isNaN(parseMetricNumber(value))).length;
    return numeric / populated.length >= 0.85;
  });
}

function setupMetricOptions(select, metrics, preferred) {
  const current = select.value || preferred || metrics[0] || "";
  select.innerHTML = metrics.map((metricName) => `<option value="${escapeHtml(metricName)}">${escapeHtml(metricName)}</option>`).join("");
  select.value = metrics.includes(current) ? current : (preferred && metrics.includes(preferred) ? preferred : metrics[0] || "");
}

function selectedStatsRows() {
  const level = $("statsLevel").value;
  return level === "Agent" ? (state.analysis.agents || []) : (state.analysis.weekly || []);
}

function setupStatsControls(analysis) {
  const rows = selectedStatsRows();
  const metrics = numericColumns(rows);
  setupMetricOptions($("statsMetricA"), metrics, metrics.includes("NPS") ? "NPS" : metrics[0]);
  setupMetricOptions($("statsMetricB"), metrics, metrics.find((item) => item !== $("statsMetricA").value));
  renderStatsCorrelation();
}

function correlation(xs, ys) {
  const pairs = xs.map((x, i) => [parseMetricNumber(x), parseMetricNumber(ys[i])]).filter(([x, y]) => !Number.isNaN(x) && !Number.isNaN(y));
  if (pairs.length < 2) return null;
  const meanX = pairs.reduce((sum, [x]) => sum + x, 0) / pairs.length;
  const meanY = pairs.reduce((sum, [, y]) => sum + y, 0) / pairs.length;
  const numerator = pairs.reduce((sum, [x, y]) => sum + (x - meanX) * (y - meanY), 0);
  const denomX = Math.sqrt(pairs.reduce((sum, [x]) => sum + (x - meanX) ** 2, 0));
  const denomY = Math.sqrt(pairs.reduce((sum, [, y]) => sum + (y - meanY) ** 2, 0));
  if (!denomX || !denomY) return null;
  return { value: numerator / (denomX * denomY), sample: pairs.length };
}

function renderStatsCorrelation() {
  const rows = selectedStatsRows();
  const metricA = $("statsMetricA").value;
  const metricB = $("statsMetricB").value;
  if (!rows.length || !metricA || !metricB) {
    $("statsCorrelationText").textContent = "Choose two metrics to view correlation.";
    renderCorrelationScatter("statsCorrelationChart", [], metricA, metricB);
    return;
  }
  const result = correlation(rows.map((row) => row[metricA]), rows.map((row) => row[metricB]));
  if (!result) {
    $("statsCorrelationText").textContent = `Not enough usable variation to correlate ${metricA} and ${metricB}.`;
    renderCorrelationScatter("statsCorrelationChart", rows, metricA, metricB);
    return;
  }
  const direction = result.value > 0 ? "move together" : "move in opposite directions";
  const strength = Math.abs(result.value) >= 0.7 ? "strong" : Math.abs(result.value) >= 0.4 ? "moderate" : "weak";
  $("statsCorrelationText").textContent = `${metricA} vs ${metricB}: correlation ${result.value.toFixed(2)} across ${result.sample} ${$("statsLevel").value.toLowerCase()} rows. This is a ${strength} relationship where the metrics generally ${direction}.`;
  renderCorrelationScatter("statsCorrelationChart", rows, metricA, metricB, result);
}

function renderCorrelationScatter(svgId, rows, metricA, metricB, corr = null) {
  const svg = $(svgId);
  if (!svg) return;
  const viewBox = svg.viewBox?.baseVal;
  const w = viewBox?.width || 760;
  const h = viewBox?.height || 260;
  if ($("statsCorrelationSubtitle")) $("statsCorrelationSubtitle").textContent = `${metricA || "Metric A"} x ${metricB || "Metric B"}`;
  const points = (rows || [])
    .map((row) => ({
      label: row.Week || row["Agent Name"] || row["Manager/TL"] || row.Range || "",
      x: parseMetricNumber(row[metricA]),
      y: parseMetricNumber(row[metricB]),
    }))
    .filter((point) => !Number.isNaN(point.x) && !Number.isNaN(point.y));
  if (points.length < 2) {
    svg.innerHTML = `<text x="${w / 2}" y="${h / 2}" text-anchor="middle" fill="#728399">Run correlation with two numeric metrics.</text>`;
    return;
  }
  const isLarge = w >= 900 || h >= 340;
  const left = isLarge ? 92 : 74;
  const right = isLarge ? 54 : 38;
  const top = isLarge ? 54 : 30;
  const bottom = isLarge ? 94 : 58;
  const plotW = w - left - right;
  const plotH = h - top - bottom;
  const xs = points.map((point) => point.x);
  const ys = points.map((point) => point.y);
  const minX = Math.min(...xs), maxX = Math.max(...xs);
  const minY = Math.min(...ys), maxY = Math.max(...ys);
  const padX = Math.max((maxX - minX) * 0.08, 1);
  const padY = Math.max((maxY - minY) * 0.08, 1);
  const x0 = minX - padX, x1 = maxX + padX;
  const y0 = minY - padY, y1 = maxY + padY;
  const xFor = (value) => left + ((value - x0) / Math.max(x1 - x0, 1)) * plotW;
  const yFor = (value) => top + ((y1 - value) / Math.max(y1 - y0, 1)) * plotH;
  const meanX = average(xs);
  const meanY = average(ys);
  const denom = xs.reduce((sum, x) => sum + (x - meanX) ** 2, 0);
  const slope = denom ? points.reduce((sum, point) => sum + (point.x - meanX) * (point.y - meanY), 0) / denom : 0;
  const intercept = meanY - slope * meanX;
  const lineY0 = intercept + slope * x0;
  const lineY1 = intercept + slope * x1;
  svg.innerHTML = `
    <defs>
      <filter id="${svgId}PointShadow" x="-30%" y="-30%" width="160%" height="160%">
        <feDropShadow dx="0" dy="2" stdDeviation="2.5" flood-color="#006d86" flood-opacity="0.16"></feDropShadow>
      </filter>
    </defs>
    <rect x="${left}" y="${top}" width="${plotW}" height="${plotH}" rx="10" fill="#fbfdff" stroke="#dfe9f1"></rect>
    ${[0, 0.5, 1].map((ratio) => {
      const x = left + ratio * plotW;
      const y = top + ratio * plotH;
      const xValue = x0 + ratio * (x1 - x0);
      const yValue = y1 - ratio * (y1 - y0);
      return `<line x1="${x}" x2="${x}" y1="${top}" y2="${top + plotH}" stroke="#e7eef4"></line>
        <line x1="${left}" x2="${left + plotW}" y1="${y}" y2="${y}" stroke="#e7eef4"></line>
        <text x="${x}" y="${h - 40}" text-anchor="middle" fill="#38526a" font-size="${isLarge ? 16 : 12}" font-weight="800">${formatMetric(xValue)}</text>
        <text x="${left - 16}" y="${y + 5}" text-anchor="end" fill="#38526a" font-size="${isLarge ? 16 : 12}" font-weight="800">${formatMetric(yValue)}</text>`;
    }).join("")}
    <line x1="${left}" y1="${yFor(lineY0)}" x2="${left + plotW}" y2="${yFor(lineY1)}" stroke="#006d86" stroke-width="${isLarge ? 6 : 4}" stroke-linecap="round" opacity="0.86"></line>
    ${points.map((point) => `<circle cx="${xFor(point.x)}" cy="${yFor(point.y)}" r="${isLarge ? 8 : 6}" fill="#009b9b" stroke="#ffffff" stroke-width="${isLarge ? 2.8 : 2}" opacity="0.86" filter="url(#${svgId}PointShadow)"><title>${escapeHtml(point.label)}: ${metricA} ${formatMetric(point.x)}, ${metricB} ${formatMetric(point.y)}</title></circle>`).join("")}
    <rect x="${left}" y="14" width="${isLarge ? 112 : 82}" height="${isLarge ? 34 : 24}" rx="${isLarge ? 17 : 12}" fill="#e8fbfb" stroke="#9ddede"></rect>
    <text x="${left + (isLarge ? 56 : 41)}" y="${isLarge ? 36 : 24}" text-anchor="middle" fill="#006d86" font-size="${isLarge ? 16 : 12}" font-weight="900">r = ${corr ? corr.value.toFixed(2) : "n/a"}</text>
    <text x="${left + plotW}" y="${h - 10}" text-anchor="end" fill="#38526a" font-size="${isLarge ? 15 : 12}" font-weight="900">${escapeHtml(metricA || "")}</text>
    <text x="24" y="${top + 20}" fill="#38526a" font-size="${isLarge ? 15 : 12}" font-weight="900" transform="rotate(-90 24 ${top + 20})">${escapeHtml(metricB || "")}</text>
  `;
}

function average(values) {
  const nums = values.map((value) => parseMetricNumber(value)).filter((value) => !Number.isNaN(value));
  return nums.length ? nums.reduce((sum, value) => sum + value, 0) / nums.length : 0;
}

function stdDev(values) {
  const nums = values.map((value) => parseMetricNumber(value)).filter((value) => !Number.isNaN(value));
  if (nums.length < 2) return 0;
  const mean = average(nums);
  return Math.sqrt(nums.reduce((sum, value) => sum + (value - mean) ** 2, 0) / nums.length);
}

function correlationLabel(value) {
  const absolute = Math.abs(Number(value || 0));
  if (absolute >= 0.7) return "Strong";
  if (absolute >= 0.4) return "Moderate";
  if (absolute >= 0.2) return "Weak";
  return "Very weak";
}

function renderStatsDashboard(analysis) {
  const summary = analysis.summary || {};
  const counts = analysis.counts || {};
  const weekly = analysis.weekly || [];
  const reasons = analysis.reasons || [];
  const sentiment = analysis.sentiment || {};
  const npsValues = weekly.map((row) => Number(row.NPS ?? row.NPS ?? 0));
  const volumeValues = weekly.map((row) => Number(row.Responses || 0));
  const metricA = $("statsMetricA")?.value || "NPS";
  const metricB = $("statsMetricB")?.value || "Responses";
  const correlationRows = selectedStatsRows();
  const activeMetricA = $("statsMetricA")?.value || metricA;
  const activeMetricB = $("statsMetricB")?.value || metricB;
  const corr = correlation(correlationRows.map((row) => row[activeMetricA]), correlationRows.map((row) => row[activeMetricB])) || { value: 0, sample: 0 };
  const volatility = npsValues.length > 1 ? Math.max(...npsValues) - Math.min(...npsValues) : 0;
  const volumeCv = average(volumeValues) ? (stdDev(volumeValues) / average(volumeValues)) * 100 : 0;
  const topDriver = reasons[0] || {};
  const sentimentSkew = Number(sentiment.Positive || 0) - Number(sentiment.Negative || 0);
  const detractorRate = Number(summary.total || 0) ? (Number(counts.Detractor || 0) / Number(summary.total || 1)) * 100 : 0;
  const activeCorr = corr;
  const cards = [
    metric("Selected Correlation", activeCorr.value.toFixed(2), `${activeMetricA} vs ${activeMetricB}. Click to see the formula rows.`, Math.abs(activeCorr.value) >= 0.7 ? "positive" : "", "stats-correlation"),
    metric("Correlation Sample", activeCorr.sample.toLocaleString(), `${$("statsLevel")?.value || "Selected"} rows used in this relationship.`, "", "stats-sample"),
    metric("Relationship Direction", activeCorr.value >= 0 ? "Positive" : "Negative", activeCorr.value >= 0 ? "Metrics generally move together." : "Metrics generally move in opposite directions.", activeCorr.value < 0 ? "negative" : "positive", "stats-direction"),
    metric("NPS Volatility", formatMetric(volatility), "Highest weekly NPS minus lowest weekly NPS.", volatility > 40 ? "negative" : "", "stats-volatility"),
    metric("Volume Variability", `${formatMetric(volumeCv)}%`, "Standard deviation divided by average weekly responses.", volumeCv > 60 ? "negative" : "", "stats-volume-variability"),
    metric("Sentiment Skew", `${formatMetric(sentimentSkew)} pts`, "Positive sentiment share minus negative sentiment share.", sentimentSkew < 0 ? "negative" : "positive", "stats-sentiment-skew"),
    metric("Detractor Rate", `${formatMetric(detractorRate)}%`, "Detractors as a share of total responses.", detractorRate > 30 ? "negative" : "", "stats-detractor-rate"),
    metric("Top Driver Mentions", topDriver.Count || 0, topDriver["Primary Reason"] || topDriver.Reason || "Uncategorized", "", "top-driver"),
  ];
  $("statsMetricGrid").innerHTML = cards.join("");
  attachMetricArtifacts("statsMetricGrid");
  if ($("statsMetricATitle")) $("statsMetricATitle").textContent = `${activeMetricA} Movement`;
  if ($("statsMetricASubtitle")) $("statsMetricASubtitle").textContent = `${$("statsLevel")?.value || "Selected"} level x ${activeMetricA}`;
  if ($("statsMetricBTitle")) $("statsMetricBTitle").textContent = `${activeMetricB} Movement`;
  if ($("statsMetricBSubtitle")) $("statsMetricBSubtitle").textContent = `${$("statsLevel")?.value || "Selected"} level x ${activeMetricB}`;
  renderLineChart("statsNpsTrend", correlationRows, activeMetricA, `Run analysis to view ${activeMetricA}.`, "#006d86");
  renderLineChart("statsVolumeTrend", correlationRows, activeMetricB, `Run analysis to view ${activeMetricB}.`, "#009b9b");
  renderCorrelationScatter("statsCorrelationChart", correlationRows, activeMetricA, activeMetricB, activeCorr);
  renderHorizontalBars("statsDriverBars", reasons, "Primary Reason", "Count", "#006d86", 6);
  const sentimentLead = Object.entries(sentiment).sort((a, b) => Number(b[1] || 0) - Number(a[1] || 0))[0] || ["No sentiment", 0];
  $("statsIntelligenceText").textContent =
    `${activeMetricA} and ${activeMetricB} show a ${correlationLabel(activeCorr.value).toLowerCase()} ${activeCorr.value >= 0 ? "positive" : "negative"} relationship across ${activeCorr.sample} ${($("statsLevel")?.value || "selected").toLowerCase()} rows. ` +
    `Weekly NPS volatility is ${formatMetric(volatility)} points and response-volume variability is ${formatMetric(volumeCv)}%. ` +
    `The strongest sentiment signal is ${sentimentLead[0]} at ${Number(sentimentLead[1] || 0).toFixed(1)}%. ` +
    `Top driver is ${topDriver["Primary Reason"] || topDriver.Reason || "Uncategorized"}.`;
}

function customStatsSources() {
  const analysis = state.analysis || {};
  const analyzedRows = enrichSentimentScoreRows(
    state.statsData.analyzedRows?.length ? state.statsData.analyzedRows : (analysis.feedbackRows || analysis.feedbackTableRows || analysis.preview || [])
  );
  const themeAnalysisRows = themeBuilderAnalysisRows();
  return {
    "Base Sheet": state.statsData.baseRows || [],
    "Lookup Sheet": state.statsData.lookupRows || [],
    "Analyzed Feedback Rows": analyzedRows,
    "Theme Builder Rows": themeAnalysisRows,
    "Theme Comparison Rows": state.themeBuilder.comparisonRows || [],
    "Weekly Summary": analysis.weekly || [],
    "Agent Summary": analysis.agents || [],
    "Manager Summary": analysis.managers || [],
    "Theme Rows": analysis.themeRows || [],
    "Wave Summary": analysis.wave || [],
    "Tenure Summary": analysis.tenure || [],
  };
}

function customStatsTotalForSource(name, rows) {
  const counts = state.statsRowCounts || {};
  if (name === "Base Sheet") return Number(counts.baseRows || rows?.length || 0);
  if (name === "Lookup Sheet") return Number(counts.lookupRows || rows?.length || 0);
  if (name === "Analyzed Feedback Rows") return Number(counts.analyzedRows || rows?.length || 0);
  if (name === "Theme Rows") return Number(counts.analyzedRows || rows?.length || 0);
  return Number(rows?.length || 0);
}

function customStatsSourceLabel(name, rows) {
  const sample = Number(rows?.length || 0);
  const total = customStatsTotalForSource(name, rows);
  if (total > sample) return `${name} (${total.toLocaleString()} rows)`;
  return `${name} (${sample.toLocaleString()} rows)`;
}

function customStatsCoverageText(name, rows) {
  const sample = Number(rows?.length || 0);
  const total = customStatsTotalForSource(name, rows);
  const filter = state.analysis?.dateFilter || { mode: "All Time" };
  const range = filter.mode === "Custom Range" && (filter.start || filter.end)
    ? `Custom Range ${filter.start || "..."} to ${filter.end || "..."}`
    : (filter.mode || "All Time");
  return total > sample
    ? `Full source available: ${total.toLocaleString()} rows. Browser preview: ${sample.toLocaleString()} rows. Date range: ${range}. Python calculations use the full source.`
    : `Rows available: ${sample.toLocaleString()}. Date range: ${range}.`;
}

const SUMMARY_BUILDER_MEASURES = [
  { value: "nps", label: "NPS Performance" },
  { value: "count", label: "Count Rows" },
  { value: "avg", label: "Average Value Field" },
  { value: "sum", label: "Sum Value Field" },
  { value: "min", label: "Minimum Value Field" },
  { value: "max", label: "Maximum Value Field" },
];

function summaryBuilderSources() {
  const sources = customStatsSources();
  const filtered = {};
  Object.entries(sources).forEach(([name, rows]) => {
    if (Array.isArray(rows) && rows.length) filtered[name] = rows;
  });
  if (!Object.keys(filtered).length) {
    filtered["Base Sheet"] = state.statsData.baseRows || [];
    filtered["Lookup Sheet"] = state.statsData.lookupRows || [];
  }
  return filtered;
}

function summaryBuilderColumns(rows) {
  const seen = new Set();
  (rows || []).slice(0, 1000).forEach((row) => {
    Object.keys(row || {}).forEach((column) => {
      if (!String(column || "").startsWith("__")) seen.add(column);
    });
  });
  return [...seen].sort((a, b) => a.localeCompare(b));
}

function summaryBuilderNumericColumns(rows) {
  const columns = summaryBuilderColumns(rows);
  return columns.filter((column) => {
    const populated = (rows || []).map((row) => row?.[column]).filter((value) => value !== "" && value != null);
    if (!populated.length) return false;
    const sample = populated.slice(0, 500);
    const numeric = sample.filter((value) => Number.isFinite(parseMetricNumber(value))).length;
    return numeric / sample.length >= 0.75;
  });
}

function setSelectOptions(select, options, preferred = "") {
  if (!select) return "";
  const current = select.value || preferred;
  select.innerHTML = "";
  options.forEach((option) => {
    const node = document.createElement("option");
    node.value = option.value;
    node.textContent = option.label;
    select.appendChild(node);
  });
  const values = options.map((option) => option.value);
  select.value = values.includes(current) ? current : (values.includes(preferred) ? preferred : (values[0] || ""));
  return select.value;
}

function summaryBuilderMetricFieldOptions(columns) {
  return [{ value: "__none__", label: "Not needed" }].concat((columns || []).map((column) => ({ value: column, label: column })));
}

function pickSummaryMetricField(columns, pattern) {
  return (columns || []).find((column) => pattern.test(column)) || "__none__";
}

function summaryBuilderMetricDefaults(index, columns = []) {
  const layout = $("summaryBuilderLayout")?.value || "multi";
  if (layout === "best" || layout === "worst") {
    const isBest = layout === "best";
    const rankedDefaults = [
      { name: isBest ? "Best FCR" : "Lowest FCR", calc: isBest ? "bestRate" : "worstRate", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: pickSummaryMetricField(columns, /fcr|first.*resolution|resolution.*first/i), successValue: "Yes" },
      { name: isBest ? "Best Avg Score" : "Lowest Avg Score", calc: isBest ? "bestAvg" : "worstAvg", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: pickSummaryMetricField(columns, /score|rating|nps/i), successValue: "" },
      { name: isBest ? "Lowest Wait Time" : "Highest Wait Time", calc: isBest ? "worstAvg" : "bestAvg", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: pickSummaryMetricField(columns, /wait|hold|queue/i), successValue: "" },
    ];
    return rankedDefaults[index] || { name: `${isBest ? "Best" : "Focus"} Metric ${index + 1}`, calc: isBest ? "bestRate" : "worstRate", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: "__none__", successValue: "" };
  }
  if (layout === "kpi") {
    const kpiDefaults = [
      { name: "Total Tickets", calc: "count", groupBy: "__global__", field: "__none__", successValue: "" },
      { name: "First Call Resolution Rate", calc: "rate", groupBy: "__global__", field: pickSummaryMetricField(columns, /fcr|first.*resolution|resolution.*first/i), successValue: "Yes" },
      { name: "Overall Loyalty Rate", calc: "nps", groupBy: "__global__", field: "__none__", successValue: "" },
      { name: "Resolution Rate", calc: "rate", groupBy: "__global__", field: pickSummaryMetricField(columns, /resolution|resolved|status/i), successValue: "Resolved" },
      { name: "Avg Wait Time", calc: "avg", groupBy: "__global__", field: pickSummaryMetricField(columns, /wait|hold|queue/i), successValue: "" },
      { name: "Avg Loyalty Score", calc: "avg", groupBy: "__global__", field: pickSummaryMetricField(columns, /score|rating|nps/i), successValue: "" },
      { name: "FCR Leader", calc: "leaderRate", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: pickSummaryMetricField(columns, /fcr|first.*resolution|resolution.*first/i), successValue: "Yes" },
      { name: "FCR Focus Area", calc: "focusRate", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: pickSummaryMetricField(columns, /fcr|first.*resolution|resolution.*first/i), successValue: "Yes" },
      { name: "Best FCR", calc: "bestRate", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: pickSummaryMetricField(columns, /fcr|first.*resolution|resolution.*first/i), successValue: "Yes" },
      { name: "Lowest FCR", calc: "worstRate", groupBy: pickSummaryMetricField(columns, /channel|manager|center|region|issue|type/i), field: pickSummaryMetricField(columns, /fcr|first.*resolution|resolution.*first/i), successValue: "Yes" },
    ];
    return kpiDefaults[index] || { name: `KPI ${index + 1}`, calc: "avg", groupBy: "__global__", field: "__none__", successValue: "" };
  }
  const defaults = [
    { name: "Tickets", calc: "count", field: "__none__", successValue: "" },
    { name: "FCR Rate", calc: "rate", field: pickSummaryMetricField(columns, /fcr|first.*resolution|resolution.*first/i), successValue: "Yes" },
    { name: "Sat Rate", calc: "nps", field: "__none__", successValue: "" },
    { name: "Avg Wait", calc: "avg", field: pickSummaryMetricField(columns, /wait|hold|queue/i), successValue: "" },
    { name: "Avg Score", calc: "avg", field: pickSummaryMetricField(columns, /score|rating|nps/i), successValue: "" },
  ];
  return defaults[index] || { name: `Metric ${index + 1}`, calc: "avg", groupBy: "__global__", field: "__none__", successValue: "" };
}

function syncSummaryMetricDraftsFromDom() {
  state.summaryMetricDrafts = (state.summaryMetricDrafts || []).map((metric) => ({
    id: metric.id,
    name: document.querySelector(`[data-summary-metric-name="${metric.id}"]`)?.value?.trim() || "",
    calc: document.querySelector(`[data-summary-metric-calc="${metric.id}"]`)?.value || "count",
    groupBy: document.querySelector(`[data-summary-metric-group="${metric.id}"]`)?.value || metric.groupBy || "__global__",
    field: document.querySelector(`[data-summary-metric-field="${metric.id}"]`)?.value || "__none__",
    successValue: document.querySelector(`[data-summary-metric-success="${metric.id}"]`)?.value?.trim() || "",
  }));
}

function metricCalcOptions(selected) {
  const options = [
    ["count", "Count rows"],
    ["nps", "NPS / Sat Rate"],
    ["avg", "Average"],
    ["sum", "Sum"],
    ["rate", "Rate where field equals value"],
    ["leaderRate", "Leader by rate"],
    ["focusRate", "Focus area by rate"],
    ["leaderAvg", "Leader by average"],
    ["focusAvg", "Focus area by average"],
    ["bestRate", "Best by rate"],
    ["worstRate", "Worst by rate"],
    ["bestAvg", "Best by average"],
    ["worstAvg", "Worst by average"],
  ];
  return options.map(([value, label]) => `<option value="${value}"${selected === value ? " selected" : ""}>${escapeHtml(label)}</option>`).join("");
}

function renderSummaryMetricRows(columns = null) {
  const host = $("summaryBuilderMetricRows");
  if (!host) return;
  const sourceRows = summaryBuilderSources()[$("summaryBuilderSource")?.value || ""] || [];
  const availableColumns = columns || summaryBuilderColumns(sourceRows);
  const layout = $("summaryBuilderLayout")?.value || "nps";
  const supportsRowGroup = ["kpi", "best", "worst"].includes(layout);
  if (!state.summaryMetricDrafts?.length) {
    state.summaryMetricDrafts = [{ id: "metric-1", ...summaryBuilderMetricDefaults(0, availableColumns) }];
  }
  const fieldOptions = summaryBuilderMetricFieldOptions(availableColumns);
  const groupOptions = [{ value: "__global__", label: "Use main Group By" }].concat(
    availableColumns.map((column) => ({ value: column, label: column }))
  );
  host.innerHTML = state.summaryMetricDrafts.map((metric, index) => `
    <div class="summary-metric-row${supportsRowGroup ? " summary-metric-row-with-group" : ""}" data-summary-metric-row="${escapeHtml(metric.id)}">
      <label>Name<input data-summary-metric-name="${escapeHtml(metric.id)}" value="${escapeHtml(metric.name)}" /></label>
      <label>Calculation<select data-summary-metric-calc="${escapeHtml(metric.id)}">${metricCalcOptions(metric.calc)}</select></label>
      ${supportsRowGroup ? `<label>Group By<select data-summary-metric-group="${escapeHtml(metric.id)}"></select></label>` : ""}
      <label>Field<select data-summary-metric-field="${escapeHtml(metric.id)}"></select></label>
      <label>Value<input data-summary-metric-success="${escapeHtml(metric.id)}" value="${escapeHtml(metric.successValue)}" placeholder="Yes" /></label>
      <div class="summary-column-actions">
        <button type="button" data-summary-metric-move="${escapeHtml(metric.id)}" data-direction="up" ${index === 0 ? "disabled" : ""} title="Move column up">â†‘</button>
        <button type="button" data-summary-metric-move="${escapeHtml(metric.id)}" data-direction="down" ${index === state.summaryMetricDrafts.length - 1 ? "disabled" : ""} title="Move column down">â†“</button>
        <button type="button" data-summary-metric-remove="${escapeHtml(metric.id)}" ${state.summaryMetricDrafts.length <= 1 ? "disabled" : ""} title="Remove column">-</button>
      </div>
    </div>
  `).join("");
  state.summaryMetricDrafts.forEach((metric) => {
    if (supportsRowGroup) setSelectOptions(document.querySelector(`[data-summary-metric-group="${metric.id}"]`), groupOptions, metric.groupBy || "__global__");
    setSelectOptions(document.querySelector(`[data-summary-metric-field="${metric.id}"]`), fieldOptions, metric.field || "__none__");
  });
  wireSummaryMetricRowControls();
}

function refreshSummaryBuilderMetricFields(columns) {
  renderSummaryMetricRows(columns);
}

function toggleSummaryMetricConfig() {
  const layout = $("summaryBuilderLayout")?.value || "nps";
  const isMetricLayout = ["multi", "kpi", "best", "worst"].includes(layout);
  $("summaryBuilderMetricConfig")?.classList.toggle("hidden", !isMetricLayout);
  const titleMap = {
    kpi: "KPI Rows",
    best: "Best Performer Rows",
    worst: "Focus Area Rows",
  };
  if ($("summaryMetricConfigTitle")) $("summaryMetricConfigTitle").textContent = titleMap[layout] || "Table Columns";
  if ($("summaryMetricConfigHelp")) {
    const helpMap = {
      kpi: "Each row becomes one KPI in this custom dashboard list.",
      best: "Each row finds the top group for the selected metric.",
      worst: "Each row finds the lowest-performing group for the selected metric.",
    };
    $("summaryMetricConfigHelp").textContent = helpMap[layout] || "Each row becomes one column in this custom dashboard table.";
  }
}

function updateSummaryBuilderFromMetricEdit() {
  syncSummaryMetricDraftsFromDom();
  refreshSummaryBuilderSortOptions();
  renderSummaryBuilderPreview();
}

function wireSummaryMetricRowControls() {
  document.querySelectorAll("[data-summary-metric-name], [data-summary-metric-success]").forEach((input) => {
    input.addEventListener("input", updateSummaryBuilderFromMetricEdit);
  });
  document.querySelectorAll("[data-summary-metric-calc], [data-summary-metric-group], [data-summary-metric-field]").forEach((select) => {
    select.addEventListener("change", updateSummaryBuilderFromMetricEdit);
  });
}

function addSummaryMetricDraft() {
  syncSummaryMetricDraftsFromDom();
  const rows = summaryBuilderSources()[$("summaryBuilderSource")?.value || ""] || [];
  const columns = summaryBuilderColumns(rows);
  const metric = summaryBuilderMetricDefaults(state.summaryMetricDrafts.length, columns);
  state.summaryMetricDrafts.push({ id: `metric-${Date.now()}`, ...metric });
  renderSummaryMetricRows(columns);
  refreshSummaryBuilderSortOptions();
  renderSummaryBuilderPreview();
}

function removeSummaryMetricDraft(id) {
  if ((state.summaryMetricDrafts || []).length <= 1) return;
  syncSummaryMetricDraftsFromDom();
  state.summaryMetricDrafts = state.summaryMetricDrafts.filter((metric) => metric.id !== id);
  renderSummaryMetricRows();
  refreshSummaryBuilderSortOptions();
  renderSummaryBuilderPreview();
}

function moveSummaryMetricDraft(id, direction) {
  syncSummaryMetricDraftsFromDom();
  const index = state.summaryMetricDrafts.findIndex((metric) => metric.id === id);
  if (index < 0) return;
  const target = direction === "up" ? index - 1 : index + 1;
  if (target < 0 || target >= state.summaryMetricDrafts.length) return;
  const drafts = [...state.summaryMetricDrafts];
  [drafts[index], drafts[target]] = [drafts[target], drafts[index]];
  state.summaryMetricDrafts = drafts;
  renderSummaryMetricRows();
  refreshSummaryBuilderSortOptions();
  renderSummaryBuilderPreview();
}

function refreshSummaryBuilder() {
  const sourceSelect = $("summaryBuilderSource");
  if (!sourceSelect) return;
  const sources = summaryBuilderSources();
  const sourceOptions = Object.entries(sources).map(([name, rows]) => ({
    value: name,
    label: customStatsSourceLabel(name, rows),
  }));
  const sourceName = setSelectOptions(sourceSelect, sourceOptions, "Analyzed Feedback Rows");
  const rows = sources[sourceName] || [];
  const columns = summaryBuilderColumns(rows);
  const groupOptions = [{ value: "__all__", label: "Overall Total" }].concat(columns.map((column) => ({ value: column, label: column })));
  const noColumnOption = { value: "__none__", label: "No column cut" };
  setSelectOptions($("summaryBuilderGroup"), groupOptions, columns.find((column) => /manager|agent|channel|region|issue|type|center/i.test(column)) || "__all__");
  setSelectOptions($("summaryBuilderColumn"), [noColumnOption].concat(columns.map((column) => ({ value: column, label: column }))), "__none__");
  setSelectOptions($("summaryBuilderMeasure"), SUMMARY_BUILDER_MEASURES, "nps");
  refreshSummaryBuilderMetricFields(columns);
  const numeric = summaryBuilderNumericColumns(rows);
  const numericOptions = [{ value: "__none__", label: "Not needed" }].concat(numeric.map((column) => ({ value: column, label: column })));
  const preferredNumeric = numeric.find((column) => /wait|duration|score|rate|nps|resolution|fcr|ticket|count/i.test(column)) || "__none__";
  setSelectOptions($("summaryBuilderValueField"), numericOptions, preferredNumeric);
  toggleSummaryMetricConfig();
  refreshSummaryBuilderSortOptions();
  if ($("summaryBuilderStatus")) $("summaryBuilderStatus").textContent = rows.length ? `${rows.length.toLocaleString()} rows available from ${sourceName}.` : "Upload and analyze data to unlock rows.";
}

function summaryBuilderMetricColumns(config) {
  if (["kpi", "best", "worst"].includes(config.layout)) return ["Metric", "Value"];
  if (config.layout === "multi") return ["Group"].concat((config.metrics || []).map((metric) => metric.name));
  const valueLabel = config.valueField && config.valueField !== "__none__" ? `${SUMMARY_BUILDER_MEASURES.find((item) => item.value === config.measure)?.label.replace(" Value Field", "") || "Value"} ${config.valueField}` : "";
  const columns = ["Group", "Total", "Promoter", "Passive", "Detractor", "NPS"];
  if (valueLabel && !["nps", "count"].includes(config.measure)) columns.push(valueLabel);
  return columns;
}

function refreshSummaryBuilderSortOptions() {
  const config = summaryBuilderCurrentConfig();
  const columns = summaryBuilderMetricColumns(config);
  const preferred = ["kpi", "best", "worst"].includes(config.layout) ? "Metric" : (config.layout === "multi" ? (columns[1] || "Group") : (config.measure === "count" ? "Total" : "NPS"));
  setSelectOptions($("summaryBuilderSort"), columns.map((column) => ({ value: column, label: column })), preferred);
}

function summaryBuilderMetricConfig() {
  syncSummaryMetricDraftsFromDom();
  return (state.summaryMetricDrafts || []).filter((metric) => metric.name);
}

function summaryBuilderCurrentConfig() {
  const rawLimit = String($("summaryBuilderLimit")?.value ?? "").trim();
  const parsedLimit = Number(rawLimit);
  return {
    id: "",
    title: $("summaryBuilderTitle")?.value?.trim() || "Custom Performance Summary",
    layout: $("summaryBuilderLayout")?.value || "nps",
    source: $("summaryBuilderSource")?.value || "Analyzed Feedback Rows",
    groupBy: $("summaryBuilderGroup")?.value || "__all__",
    columnBy: $("summaryBuilderColumn")?.value || "__none__",
    measure: $("summaryBuilderMeasure")?.value || "nps",
    valueField: $("summaryBuilderValueField")?.value || "__none__",
    metrics: summaryBuilderMetricConfig(),
    sortBy: $("summaryBuilderSort")?.value || "NPS",
    sortDirection: $("summaryBuilderSortDirection")?.value || "desc",
    limit: rawLimit === "" || parsedLimit <= 0 ? Number.MAX_SAFE_INTEGER : Math.max(1, Math.min(100000, parsedLimit)),
  };
}

function summaryBuilderGroupValue(row, field, fallback) {
  if (!field || field === "__all__" || field === "__none__") return fallback;
  const value = displayCellValue(row?.[field]);
  return value || "(Blank)";
}

function summaryBuilderFilterOptions(config) {
  if (["kpi", "best", "worst"].includes(config?.layout)) return [];
  if (!config?.groupBy || config.groupBy === "__all__") return [];
  const rows = summaryBuilderSources()[config.source] || [];
  const values = new Set();
  rows.forEach((row) => {
    values.add(summaryBuilderGroupValue(row, config.groupBy, "Overall"));
  });
  return [...values].sort((a, b) => a.localeCompare(b));
}

function summaryBuilderExistingCount(rows, names) {
  const keys = summaryBuilderColumns(rows).filter((column) => names.some((name) => column.toLowerCase() === name.toLowerCase()));
  if (!keys.length) return null;
  return rows.reduce((sum, row) => sum + keys.reduce((inner, key) => inner + (Number.isFinite(parseMetricNumber(row?.[key])) ? parseMetricNumber(row?.[key]) : 0), 0), 0);
}

function summaryBuilderExistingTotal(rows) {
  return summaryBuilderExistingCount(rows, ["Total", "Tickets", "Count", "Responses", "Total Responses", "Rows", "Volume"]);
}

function summaryBuilderExistingNps(rows) {
  const keys = summaryBuilderColumns(rows).filter((column) => /^(nps|% promoter|loyalty rate|sat rate|overall loyalty rate)$/i.test(column));
  if (!keys.length) return null;
  const values = [];
  rows.forEach((row) => {
    keys.forEach((key) => {
      const value = parseMetricNumber(row?.[key]);
      if (Number.isFinite(value)) values.push(value);
    });
  });
  return values.length ? values.reduce((sum, value) => sum + value, 0) / values.length : null;
}

function summaryBuilderCanClassifyRows(sourceName) {
  return ["Base Sheet", "Analyzed Feedback Rows", "Theme Builder Rows"].includes(sourceName);
}

function summaryBuilderNpsCounts(rows, sourceName) {
  const existingPromoter = summaryBuilderExistingCount(rows, ["Promoter"]);
  const existingPassive = summaryBuilderExistingCount(rows, ["Passive"]);
  const existingDetractor = summaryBuilderExistingCount(rows, ["Detractor", "Unpromoter"]);
  if ([existingPromoter, existingPassive, existingDetractor].some((value) => value !== null)) {
    return {
      Promoter: Number(existingPromoter || 0),
      Passive: Number(existingPassive || 0),
      Detractor: Number(existingDetractor || 0),
      valid: Number(existingPromoter || 0) + Number(existingPassive || 0) + Number(existingDetractor || 0),
    };
  }
  if (!summaryBuilderCanClassifyRows(sourceName)) return { Promoter: 0, Passive: 0, Detractor: 0, valid: 0 };
  const counts = { Promoter: 0, Passive: 0, Detractor: 0, valid: 0 };
  (rows || []).forEach((row) => {
    const type = npsDashboardType(row);
    if (type === "promoter") counts.Promoter += 1;
    if (type === "passive") counts.Passive += 1;
    if (type === "detractor") counts.Detractor += 1;
    if (["promoter", "passive", "detractor"].includes(type)) counts.valid += 1;
  });
  return counts;
}

function summaryBuilderAggregate(rows, measure, valueField) {
  if (!valueField || valueField === "__none__" || ["nps", "count"].includes(measure)) return null;
  const values = (rows || []).map((row) => parseMetricNumber(row?.[valueField])).filter(Number.isFinite);
  if (!values.length) return null;
  if (measure === "sum") return values.reduce((sum, value) => sum + value, 0);
  if (measure === "min") return Math.min(...values);
  if (measure === "max") return Math.max(...values);
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function summaryBuilderCountWithShare(count, total) {
  const number = Number(count || 0);
  const denominator = Number(total || 0);
  const share = denominator ? (number / denominator) * 100 : 0;
  return `${formatMetric(number, 0)} (${formatMetric(share)}%)`;
}

function summaryBuilderSortNumber(value) {
  if (typeof value === "string") {
    const leading = value.trim().match(/^-?\d+(?:,\d{3})*(?:\.\d+)?/);
    if (leading) return parseMetricNumber(leading[0]);
  }
  return parseMetricNumber(value);
}

function summaryBuilderRateMatches(value, expected) {
  const actual = displayCellValue(value).trim().toLowerCase();
  const target = String(expected || "").trim().toLowerCase();
  return Boolean(target) && actual === target;
}

function summaryBuilderMetricValue(groupRows, metric, sourceName) {
  if (metric.calc === "count") return { display: groupRows.length, sort: groupRows.length };
  if (metric.calc === "nps") {
    const counts = summaryBuilderNpsCounts(groupRows, sourceName);
    const existingNps = summaryBuilderExistingNps(groupRows);
    const nps = counts.valid ? ((counts.Promoter / counts.valid) * 100) - ((counts.Detractor / counts.valid) * 100) : (existingNps ?? 0);
    return { display: `${formatMetric(nps)}%`, sort: nps };
  }
  if (metric.calc === "rate") {
    const total = summaryBuilderExistingTotal(groupRows) ?? groupRows.length;
    const count = metric.field && metric.field !== "__none__"
      ? groupRows.filter((row) => summaryBuilderRateMatches(row?.[metric.field], metric.successValue)).length
      : 0;
    const rate = total ? (count / total) * 100 : 0;
    return { display: `${formatMetric(rate)}%`, sort: rate };
  }
  const values = metric.field && metric.field !== "__none__"
    ? groupRows.map((row) => parseMetricNumber(row?.[metric.field])).filter(Number.isFinite)
    : [];
  if (!values.length) return { display: "", sort: -Infinity };
  const value = metric.calc === "sum"
    ? values.reduce((sum, item) => sum + item, 0)
    : values.reduce((sum, item) => sum + item, 0) / values.length;
  return { display: formatMetric(value), sort: value };
}

function summaryBuilderRankedGroupValue(rows, metric, config, mode) {
  const groupField = metric.groupBy && metric.groupBy !== "__global__" ? metric.groupBy : config.groupBy;
  if (!groupField || groupField === "__all__") return { display: "", sort: -Infinity };
  const groups = new Map();
  (rows || []).forEach((row) => {
    const group = summaryBuilderGroupValue(row, groupField, "Overall");
    if (!groups.has(group)) groups.set(group, []);
    groups.get(group).push(row);
  });
  const ranked = [...groups.entries()].map(([group, groupRows]) => {
    let score = 0;
    if (mode.endsWith("Rate")) {
      const total = summaryBuilderExistingTotal(groupRows) ?? groupRows.length;
      const count = metric.field && metric.field !== "__none__"
        ? groupRows.filter((row) => summaryBuilderRateMatches(row?.[metric.field], metric.successValue)).length
        : 0;
      score = total ? (count / total) * 100 : 0;
    } else {
      const values = metric.field && metric.field !== "__none__"
        ? groupRows.map((row) => parseMetricNumber(row?.[metric.field])).filter(Number.isFinite)
        : [];
      score = values.length ? values.reduce((sum, value) => sum + value, 0) / values.length : -Infinity;
    }
    return { group, score };
  }).filter((item) => item.group && Number.isFinite(item.score));
  if (!ranked.length) return { display: "", sort: -Infinity };
  ranked.sort((a, b) => (mode.startsWith("leader") || mode.startsWith("best")) ? b.score - a.score : a.score - b.score);
  const selected = ranked[0];
  const suffix = mode.endsWith("Rate") ? `${formatMetric(selected.score)}%` : formatMetric(selected.score);
  return { display: `${selected.group} (${suffix})`, sort: selected.score };
}

function buildSummaryBuilderMultiRows(config, groups) {
  const metrics = (config.metrics || []).length ? config.metrics : [{ name: "Total", calc: "count", field: "__none__", successValue: "" }];
  return [...groups.entries()].map(([label, groupRows]) => {
    const row = { Group: label };
    metrics.forEach((metric) => {
      const value = summaryBuilderMetricValue(groupRows, metric, config.source);
      row[metric.name] = value.display;
      row[`__sort_${metric.name}`] = value.sort;
    });
    return row;
  });
}

function buildSummaryBuilderKpiRows(config, rows) {
  const metrics = (config.metrics || []).length ? config.metrics : [{ name: "Total", calc: "count", field: "__none__", successValue: "" }];
  return metrics.map((metric) => {
    const value = ["leaderRate", "focusRate", "leaderAvg", "focusAvg", "bestRate", "worstRate", "bestAvg", "worstAvg"].includes(metric.calc)
      ? summaryBuilderRankedGroupValue(rows, metric, config, metric.calc)
      : summaryBuilderMetricValue(rows, metric, config.source);
    return {
      Metric: metric.name,
      Value: value.display,
      __sort_Metric: metric.name,
      __sort_Value: value.sort,
    };
  });
}

function buildSummaryBuilderRows(config) {
  const rows = summaryBuilderSources()[config.source] || [];
  if (["kpi", "best", "worst"].includes(config.layout)) {
    return sortSummaryBuilderRows(buildSummaryBuilderKpiRows(config, rows), config).slice(0, config.limit);
  }
  const groups = new Map();
  const activeFilter = config.filterValue || "__all__";
  rows.forEach((row) => {
    const primary = summaryBuilderGroupValue(row, config.groupBy, "Overall");
    if (activeFilter !== "__all__" && primary !== activeFilter) return;
    const secondary = summaryBuilderGroupValue(row, config.columnBy, "");
    const label = activeFilter !== "__all__" && secondary ? secondary : (secondary ? `${primary} | ${secondary}` : primary);
    if (!groups.has(label)) groups.set(label, []);
    groups.get(label).push(row);
  });
  if (config.layout === "multi") {
    return sortSummaryBuilderRows(buildSummaryBuilderMultiRows(config, groups), config).slice(0, config.limit);
  }
  const valueLabel = config.valueField && config.valueField !== "__none__" ? `${SUMMARY_BUILDER_MEASURES.find((item) => item.value === config.measure)?.label.replace(" Value Field", "") || "Value"} ${config.valueField}` : "";
  const output = [...groups.entries()].map(([label, groupRows]) => {
    const counts = summaryBuilderNpsCounts(groupRows, config.source);
    const existingNps = summaryBuilderExistingNps(groupRows);
    const existingTotal = summaryBuilderExistingTotal(groupRows);
    const total = existingTotal ?? groupRows.length;
    const nps = counts.valid ? ((counts.Promoter / counts.valid) * 100) - ((counts.Detractor / counts.valid) * 100) : (existingNps ?? 0);
    const row = {
      Group: label,
      Total: total,
      Promoter: summaryBuilderCountWithShare(counts.Promoter, total),
      Passive: summaryBuilderCountWithShare(counts.Passive, total),
      Detractor: summaryBuilderCountWithShare(counts.Detractor, total),
      NPS: `${formatMetric(nps)}%`,
      __sort_CSTAT: nps,
      __sort_NPS: nps,
      __sort_Promoter: counts.Promoter,
      __sort_Neutral: counts.Neutral,
      __sort_Detractor: counts.Detractor,
    };
    const aggregate = summaryBuilderAggregate(groupRows, config.measure, config.valueField);
    if (valueLabel) row[valueLabel] = aggregate === null ? "" : formatMetric(aggregate);
    return row;
  });
  return sortSummaryBuilderRows(output, config).slice(0, config.limit);
}

function sortSummaryBuilderRows(output, config) {
  const sortKey = config.sortBy || "NPS";
  output.sort((a, b) => {
    const av = sortKey === "Group" ? String(a.Group || "") : (Number.isFinite(a[`__sort_${sortKey}`]) ? a[`__sort_${sortKey}`] : summaryBuilderSortNumber(a[sortKey]));
    const bv = sortKey === "Group" ? String(b.Group || "") : (Number.isFinite(b[`__sort_${sortKey}`]) ? b[`__sort_${sortKey}`] : summaryBuilderSortNumber(b[sortKey]));
    if (sortKey === "Group") return config.sortDirection === "asc" ? av.localeCompare(bv) : bv.localeCompare(av);
    const left = Number.isFinite(av) ? av : -Infinity;
    const right = Number.isFinite(bv) ? bv : -Infinity;
    return config.sortDirection === "asc" ? left - right : right - left;
  });
  return output;
}

function renderSummaryBuilderPreview() {
  const config = summaryBuilderCurrentConfig();
  refreshSummaryBuilderSortOptions();
  const rows = buildSummaryBuilderRows(config);
  renderAnyTable("summaryBuilderPreviewTable", rows, 12);
  if ($("summaryBuilderMessage")) {
    const limitText = config.limit >= Number.MAX_SAFE_INTEGER
      ? "all matching rows"
      : `${rows.length.toLocaleString()} row${rows.length === 1 ? "" : "s"}`;
    $("summaryBuilderMessage").textContent = rows.length
      ? `Previewing ${Math.min(rows.length, 12).toLocaleString()} rows here; the Custom Dashboard will include ${limitText} from ${config.source}.`
      : "No rows available for this summary yet.";
  }
}

function addSummaryBuilderDefinition() {
  const config = { ...summaryBuilderCurrentConfig(), id: `summary-${Date.now()}` };
  state.summaryBuilder.definitions.push(config);
  renderSummaryBuilderDashboard();
  activateView("customdashboards");
  if ($("summaryBuilderMessage")) $("summaryBuilderMessage").textContent = `"${config.title}" was added to Custom Dashboards.`;
}

function renderSummaryBuilderDashboard() {
  const host = $("summaryBuilderDashboard");
  if (!host) return;
  const definitions = state.summaryBuilder.definitions || [];
  if ($("summaryBuilderDashboardMeta")) {
    $("summaryBuilderDashboardMeta").textContent = definitions.length
      ? `${definitions.length} custom summary ${definitions.length === 1 ? "table" : "tables"} built from current analysis data.`
      : "Use Summary Builder to add custom summary tables here.";
  }
  if (!definitions.length) {
    host.innerHTML = `<div class="summary-empty">No custom summaries added yet.</div>`;
    return;
  }
  host.innerHTML = definitions.map((definition) => {
    const filterOptions = summaryBuilderFilterOptions(definition);
    if (definition.filterValue && definition.filterValue !== "__all__" && !filterOptions.includes(definition.filterValue)) definition.filterValue = "__all__";
    const rows = buildSummaryBuilderRows(definition);
    const columns = rows.length ? Object.keys(rows[0]).filter((column) => !column.startsWith("__")) : [];
    const displayRows = rows.slice(0, 1000);
    const previewNote = rows.length > displayRows.length
      ? `<caption class="table-preview-caption">Showing ${displayRows.length.toLocaleString()} of ${rows.length.toLocaleString()} custom summary rows. Export CSV includes the full summary output.</caption>`
      : "";
    const filterLabel = definition.groupBy === "__all__" ? "Filter" : definition.groupBy;
    const filterControl = filterOptions.length
      ? `<label class="summary-output-filter">Filter by ${escapeHtml(filterLabel)}
          <select data-summary-filter="${escapeHtml(definition.id)}">
            <option value="__all__">All</option>
            ${filterOptions.map((value) => `<option value="${escapeHtml(value)}"${(definition.filterValue || "__all__") === value ? " selected" : ""}>${escapeHtml(value)}</option>`).join("")}
          </select>
        </label>`
      : "";
    const table = rows.length
      ? `<div class="table-wrap compact-table fit-table summary-resizable-table"><table>${previewNote}<thead><tr>${columns.map((column) => `<th>${escapeHtml(column)}</th>`).join("")}</tr></thead><tbody>${displayRows.map((row) => `<tr>${columns.map((column) => `<td>${escapeHtml(displayCellValue(row[column]))}</td>`).join("")}</tr>`).join("")}</tbody></table></div>`
      : `<div class="summary-empty">No rows available for this summary.</div>`;
    return `<div class="summary-output-card">
      <div class="summary-output-head">
        <div>
          <h3>${escapeHtml(definition.title)}</h3>
          <span>${escapeHtml(definition.source)} by ${escapeHtml(definition.groupBy === "__all__" ? "Overall Total" : definition.groupBy)}</span>
        </div>
        <div class="summary-output-actions">
          ${filterControl}
          <button class="button button-secondary" type="button" data-summary-export="${escapeHtml(definition.id)}">Export CSV</button>
          <button class="button button-secondary" type="button" data-summary-remove="${escapeHtml(definition.id)}">Remove</button>
        </div>
      </div>
      ${table}
    </div>`;
  }).join("");
}

function removeSummaryBuilderDefinition(id) {
  state.summaryBuilder.definitions = (state.summaryBuilder.definitions || []).filter((definition) => definition.id !== id);
  renderSummaryBuilderDashboard();
}

function downloadSummaryDefinitionCsv(id) {
  const definition = (state.summaryBuilder.definitions || []).find((item) => item.id === id);
  if (!definition) return;
  const rows = buildSummaryBuilderRows(definition);
  if (!rows.length) {
    alert("No rows available to export for this summary.");
    return;
  }
  const columns = Object.keys(rows[0]).filter((column) => !column.startsWith("__"));
  const escapeCsv = (value) => `"${String(displayCellValue(value)).replace(/"/g, '""')}"`;
  const csv = [columns.map(escapeCsv).join(","), ...rows.map((row) => columns.map((column) => escapeCsv(row[column])).join(","))].join("\n");
  triggerBlobDownload(
    new Blob([csv], { type: "text/csv;charset=utf-8" }),
    `${String(definition.title || "custom-summary").replace(/[^a-z0-9]+/gi, "_").replace(/^_|_$/g, "").toLowerCase() || "custom-summary"}.csv`
  );
}

function analysisCompleteSummary(analysis = state.analysis || {}) {
  const summary = analysis.summary || {};
  const counts = analysis.counts || {};
  const sentiment = analysis.sentiment || {};
  const weekly = analysis.weekly || [];
  const reasons = analysis.reasons || analysis.themeRows || [];
  const fixedCounts = npsDisplayCounts(summary, counts);
  const total = Number(fixedCounts.Total || summary.total || counts.Total || counts.Responses || 0);
  const nps = Number(summary.nps ?? summary.NPS ?? 0);
  const promoter = Number(fixedCounts.Promoter || 0);
  const passive = Number(fixedCounts.Passive || 0);
  const detractor = Number(fixedCounts.Detractor || 0);
  const latest = weekly[weekly.length - 1] || {};
  const previous = weekly.length > 1 ? weekly[weekly.length - 2] : {};
  const latestScore = Number(latest.NPS ?? latest.NPS ?? latest.Score ?? nps);
  const previousScore = Number(previous.NPS ?? previous.NPS ?? previous.Score ?? latestScore);
  const movement = Number.isFinite(latestScore - previousScore) ? latestScore - previousScore : 0;
  const topDriver = reasons[0]?.["Primary Reason"] || reasons[0]?.Reason || reasons[0]?.Driver || reasons[0]?.Theme || "No driver identified yet";
  return {
    total,
    nps,
    promoter,
    passive,
    detractor,
    positive: Number(sentiment.Positive || 0),
    negative: Number(sentiment.Negative || 0),
    movement,
    topDriver,
  };
}

function analysisCompleteSummaryHtml(snapshot) {
  const satShare = snapshot.total ? (snapshot.promoter / snapshot.total) * 100 : 0;
  const passiveShare = snapshot.total ? (snapshot.passive / snapshot.total) * 100 : 0;
  const disShare = snapshot.total ? (snapshot.detractor / snapshot.total) * 100 : 0;
  const score = Math.max(0, Math.min(100, Number(snapshot.nps || 0)));
  const positive = Math.max(0, Math.min(100, Number(snapshot.positive || 0)));
  const negative = Math.max(0, Math.min(100, Number(snapshot.negative || 0)));
  const passiveSentiment = Math.max(0, 100 - positive - negative);
  const volumeMax = Math.max(snapshot.promoter || 0, snapshot.passive || 0, snapshot.detractor || 0, 1);
  return `<div class="analysis-complete-hero">
    <div class="analysis-complete-dial" style="--score:${score}%">
      <div class="analysis-complete-dial-ring">
        <span>NPS</span>
        <strong>${formatMetric(snapshot.nps)}</strong>
        <small>${formatMetric(satShare)}% promoter</small>
      </div>
    </div>
    <div class="analysis-complete-visuals">
      <div class="analysis-complete-strip">
        <div class="strip-head"><span>NPS mix</span><strong>${Number(snapshot.total || 0).toLocaleString()} rows</strong></div>
        <div class="distribution-bar" aria-label="NPS distribution">
          <i class="dist-Promoter" style="--w:${Math.max(0, satShare)}%"></i>
          <i class="dist-Passive" style="--w:${Math.max(0, passiveShare)}%"></i>
          <i class="dist-Detractor" style="--w:${Math.max(0, disShare)}%"></i>
        </div>
        <div class="distribution-legend">
          <span><i class="dot Promoter"></i>Promoter ${Number(snapshot.promoter || 0).toLocaleString()} (${formatMetric(satShare)}%)</span>
          <span><i class="dot Passive"></i>Passive ${Number(snapshot.passive || 0).toLocaleString()} (${formatMetric(passiveShare)}%)</span>
          <span><i class="dot Detractor"></i>Detractor ${Number(snapshot.detractor || 0).toLocaleString()} (${formatMetric(disShare)}%)</span>
        </div>
      </div>
      <div class="analysis-complete-strip">
        <div class="strip-head"><span>Sentiment mix</span><strong>${formatMetric(positive)}% positive</strong></div>
        <div class="sentiment-meter positive"><b>Positive Sentiment</b><span style="--w:${positive}%"></span><em>${formatMetric(positive)}%</em></div>
        <div class="sentiment-meter passive"><b>Neutral</b><span style="--w:${passiveSentiment}%"></span><em>${formatMetric(passiveSentiment)}%</em></div>
        <div class="sentiment-meter negative"><b>Negative Sentiment</b><span style="--w:${negative}%"></span><em>${formatMetric(negative)}%</em></div>
      </div>
      <div class="analysis-complete-strip">
        <div class="strip-head"><span>Volume shape</span><strong>${snapshot.movement >= 0 ? "+" : ""}${formatMetric(snapshot.movement)} pts</strong></div>
        <div class="quartile-mini-chart">
          <div class="quartile-mini-bar q1"><span>SAT</span><i style="--h:${Math.max(12, (snapshot.promoter || 0) / volumeMax * 100)}%"></i><em>${Number(snapshot.promoter || 0).toLocaleString()}</em><small>${formatMetric(satShare)}%</small></div>
          <div class="quartile-mini-bar q2"><span>NEU</span><i style="--h:${Math.max(12, (snapshot.passive || 0) / volumeMax * 100)}%"></i><em>${Number(snapshot.passive || 0).toLocaleString()}</em><small>${formatMetric(passiveShare)}%</small></div>
          <div class="quartile-mini-bar q3"><span>DIS</span><i style="--h:${Math.max(12, (snapshot.detractor || 0) / volumeMax * 100)}%"></i><em>${Number(snapshot.detractor || 0).toLocaleString()}</em><small>${formatMetric(disShare)}%</small></div>
          <div class="quartile-mini-bar q4"><span>WOW</span><i style="--h:${Math.max(12, Math.min(100, Math.abs(snapshot.movement || 0) * 12 + 20))}%"></i><em>${snapshot.movement >= 0 ? "+" : ""}${formatMetric(snapshot.movement)}</em><small>pts</small></div>
        </div>
      </div>
      <div class="analysis-complete-strip">
        <div class="strip-head"><span>Driver signal</span><strong>Top theme</strong></div>
        <div class="word-signal-cloud">
          ${String(snapshot.topDriver || "No driver identified yet").split(/\s+/).slice(0, 6).map((word, index) => `<span style="--i:${index}">${escapeHtml(word)}</span>`).join("")}
        </div>
      </div>
    </div>
  </div>
  <div class="analysis-complete-summary-grid">
    <div class="analysis-complete-card"><span>Total Responses</span><strong>${Number(snapshot.total || 0).toLocaleString()}</strong><small>Rows included in this analysis.</small></div>
    <div class="analysis-complete-card"><span>NPS</span><strong>${formatMetric(snapshot.nps)}</strong><small>Promoter rate / score from current setup.</small></div>
    <div class="analysis-complete-card"><span>Promoter</span><strong>${Number(snapshot.promoter || 0).toLocaleString()} (${formatMetric(satShare)}%)</strong><small>Rows classified as promoter.</small></div>
    <div class="analysis-complete-card"><span>Detractor</span><strong>${Number(snapshot.detractor || 0).toLocaleString()} (${formatMetric(disShare)}%)</strong><small>Rows classified as detractor.</small></div>
    <div class="analysis-complete-card"><span>WoW Movement</span><strong>${snapshot.movement >= 0 ? "+" : ""}${formatMetric(snapshot.movement)} pts</strong><small>Latest period versus prior period.</small></div>
    <div class="analysis-complete-card"><span>Top Driver</span><strong>${escapeHtml(snapshot.topDriver)}</strong><small>Largest available driver/theme signal.</small></div>
  </div>
  <div class="analysis-complete-insights">
    <ul>
      <li>Sentiment mix: ${formatMetric(snapshot.positive)}% positive and ${formatMetric(snapshot.negative)}% negative.</li>
      <li>NPS distribution: ${formatMetric(satShare)}% promoter, ${formatMetric(passiveShare)}% passive, ${formatMetric(disShare)}% detractor.</li>
    </ul>
  </div>`;
}

function renderAnalysisSnapshot(analysis = state.analysis || {}) {
  const body = $("analysisSnapshotBody");
  if (!body) return;
  body.innerHTML = analysisCompleteSummaryHtml(analysisCompleteSummary(analysis));
}

function showAnalysisCompleteSummary(analysis = state.analysis || {}, reason = "Analysis complete") {
  const modal = $("summaryModal");
  if (!modal) return;
  if ($("summaryTitle")) $("summaryTitle").textContent = "Analysis Snapshot";
  if ($("summarySubtitle")) $("summarySubtitle").textContent = reason;
  if ($("summaryBody")) $("summaryBody").innerHTML = analysisCompleteSummaryHtml(analysisCompleteSummary(analysis));
  modal.classList.remove("hidden");
}

function sentimentScoreValue(sentiment) {
  const text = String(sentiment || "").toLowerCase();
  if (text === "positive") return 1;
  if (text === "negative") return -1;
  if (text === "passive") return 0;
  return "";
}

function enrichSentimentScoreRows(rows) {
  return (rows || []).map((row) => {
    if (row["Sentiment Score"] !== undefined && row["Sentiment Score"] !== "") return row;
    const score = sentimentScoreValue(row.Sentiment);
    return score === "" ? row : { ...row, "Sentiment Score": score };
  });
}

function rowValue(row, column) {
  if (row && row[column] != null && row[column] !== "") return row[column];
  const rowId = String(row?.__row_id ?? row?.Row ?? "");
  const feedbackRow = (state.analysis.feedbackRows || []).find((item) => String(item.__row_id ?? item.Row ?? "") === rowId);
  if (feedbackRow && feedbackRow[column] != null && feedbackRow[column] !== "") return feedbackRow[column];
  const themeRow = (state.analysis.themeRows || []).find((item) => String(item.__row_id ?? item.Row ?? "") === rowId);
  return themeRow ? themeRow[column] || "" : "";
}

const THEME_STOP_WORDS = new Set("about above after again against all also are because been before being below between both but cannot could did does doing down during each few for from further had has have having here how into itself just more most nor not now off once only other our out over own same she should some such than that the their them then there these they this those through too under until very was were what when where which while who why will with would your customer customers agent issue problem service call get got use used using".split(" "));

const THEME_SEEDS = {
  "Long Wait": ["wait", "waiting", "hold", "queue", "delay", "delayed", "slow", "time"],
  "Resolution": ["resolve", "resolved", "resolution", "fix", "fixed", "solution", "closed", "pending"],
  "Agent Behavior": ["agent", "rude", "polite", "helpful", "professional", "empathy", "attitude"],
  "Communication": ["communicate", "communication", "update", "callback", "explain", "informed", "response"],
  "Billing": ["bill", "billing", "charge", "charged", "payment", "refund", "invoice", "fee"],
  "Product Quality": ["quality", "defect", "broken", "working", "fault", "damage", "damaged"],
  "Technical Issue": ["technical", "system", "app", "website", "login", "network", "error", "bug"],
  "Process": ["process", "procedure", "policy", "approval", "document", "verification"],
  "Knowledge": ["knowledge", "training", "information", "answer", "understand", "expert"],
  "Follow Up": ["follow", "followup", "callback", "contact", "promised", "email"],
  "Positive Experience": ["good", "great", "excellent", "happy", "promoter", "helpful", "quick"],
  "Escalation": ["escalate", "escalated", "supervisor", "manager", "complaint", "urgent"],
};

function themeBuilderCandidateRows() {
  const detailed = state.analysis.feedbackRows || [];
  const compact = state.analysis.feedbackTableRows || [];
  const preview = state.analysis.preview || [];
  return detailed.length ? detailed : (compact.length ? compact : preview);
}

function themeBuilderSourceRows() {
  return themeBuilderCandidateRows().filter((row) => String(themeBuilderText(row) || "").trim());
}

function themeBuilderBlankSkippedCount() {
  return Math.max(0, themeBuilderCandidateRows().length - themeBuilderSourceRows().length);
}

function themeBuilderAvailableFields() {
  const rows = [
    ...(state.analysis.feedbackRows || []),
    ...(state.analysis.feedbackTableRows || []),
    ...(state.analysis.themeRows || []),
    ...(state.analysis.preview || []),
  ];
  const seen = new Set();
  rows.slice(0, 25).forEach((row) => {
    Object.keys(row || {}).forEach((key) => {
      if (!key.startsWith("__")) seen.add(key);
    });
  });
  return [...seen].sort((a, b) => {
    const rank = (name) => /verbatim|feedback|comment|text/i.test(name) ? 0 : 1;
    return rank(a) - rank(b) || a.localeCompare(b);
  });
}

function refreshThemeBuilderFieldSelect() {
  const select = $("themeBuilderTextField");
  if (!select) return;
  const current = select.value;
  const fields = themeBuilderAvailableFields();
  const preferred = fields.find((field) => /verbatim feedback/i.test(field))
    || fields.find((field) => /feedback|comment|verbatim|text/i.test(field))
    || fields[0]
    || "";
  select.innerHTML = fields.length
    ? fields.map((field) => `<option value="${escapeHtml(field)}">${escapeHtml(field)}</option>`).join("")
    : '<option value="">Run analysis first</option>';
  select.value = fields.includes(current) ? current : preferred;
}

function themeBuilderText(row) {
  const selected = $("themeBuilderTextField")?.value || "";
  if (selected && row?.[selected] != null && String(row[selected]).trim()) return String(row[selected]);
  return feedbackText(row);
}

function themeWords(text) {
  return String(text || "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .map((word) => word.trim())
    .filter((word) => word.length >= 3 && !THEME_STOP_WORDS.has(word));
}

function expandThemeKeywords(name, extra = []) {
  const direct = THEME_SEEDS[name] || [];
  const words = themeWords(name);
  const variants = words.flatMap((word) => [word, `${word}s`, word.endsWith("e") ? `${word}d` : `${word}ed`, word.endsWith("y") ? `${word.slice(0, -1)}ies` : ""]);
  return [...new Set([...direct, ...words, ...variants, ...extra].map((word) => String(word || "").toLowerCase()).filter(Boolean))];
}

function themeBuilderSelectedThemes() {
  return state.themeBuilder.themes.filter((theme) => state.themeBuilder.active.has(theme.name));
}

function themeBuilderProvider(selectId) {
  const raw = $(selectId)?.value || "local";
  if (raw === "openai" || raw === "claude" || raw === "local") return raw;
  if (raw.startsWith("ollama:")) return "ollama";
  return raw;
}

function themeBuilderOllamaModel(selectId) {
  const raw = $(selectId)?.value || "";
  return raw.startsWith("ollama:") ? raw.slice("ollama:".length) : "qwen2.5:7b-instruct";
}

function themeBuilderApiKey(provider) {
  if (provider === "openai") return $("themeBuilderOpenAiKey")?.value.trim() || "";
  if (provider === "claude") return $("themeBuilderClaudeKey")?.value.trim() || "";
  return "";
}

function updateThemeBuilderApiFields() {
  const providers = [themeBuilderProvider("themeBuilderDiscoveryMode"), themeBuilderProvider("themeBuilderClassifyMode")];
  const needOpenAi = providers.includes("openai");
  const needClaude = providers.includes("claude");
  $("themeBuilderApiKeys")?.classList.toggle("hidden", !needOpenAi && !needClaude);
  $("themeBuilderOpenAiKeyWrap")?.classList.toggle("hidden", !needOpenAi);
  $("themeBuilderClaudeKeyWrap")?.classList.toggle("hidden", !needClaude);
}

function requireThemeBuilderKey(provider) {
  const key = themeBuilderApiKey(provider);
  if ((provider === "openai" || provider === "claude") && !key) {
    throw new Error(`${provider === "openai" ? "OpenAI" : "Claude"} API key is required for this mode.`);
  }
  return key;
}

function themeBuilderSampleComments(limit) {
  return themeBuilderSourceRows().slice(0, limit).map((row, index) => ({ row: Number(row.__row_id || index + 1), text: themeBuilderText(row) }));
}

async function discoverThemeCandidates() {
  const rows = themeBuilderSourceRows();
  const sampleLimit = Math.max(10, Math.min(Number($("themeBuilderSample")?.value || 120), rows.length || 120));
  const maxThemes = Math.max(3, Math.min(Number($("themeBuilderMax")?.value || 12), 30));
  const provider = themeBuilderProvider("themeBuilderDiscoveryMode");
  if (!rows.length) {
    alert("Run NPS analysis first so the builder has verbatims to scan.");
    return;
  }
  if (provider !== "local") {
    const source = $("themeBuilderSource");
    if (source) source.textContent = `Sending ${sampleLimit.toLocaleString()} sampled verbatims for AI theme discovery...`;
    try {
      const response = await fetch("/api/theme-builder/discover", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          provider,
          apiKey: requireThemeBuilderKey(provider),
          ollamaModel: themeBuilderOllamaModel("themeBuilderDiscoveryMode"),
          comments: themeBuilderSampleComments(sampleLimit),
          maxThemes,
        }),
      });
      const payload = await response.json();
      if (!payload.ok) throw new Error(payload.error || "AI theme discovery failed.");
      state.themeBuilder.themes = (payload.themes || []).map((theme) => ({
        name: theme.name,
        keywords: theme.keywords?.length ? theme.keywords : expandThemeKeywords(theme.name),
        count: 0,
        source: payload.model || provider,
      }));
      state.themeBuilder.active = new Set(state.themeBuilder.themes.map((theme) => theme.name));
      renderThemeBuilder();
      return;
    } catch (err) {
      alert(err.message || "AI theme discovery failed.");
      renderThemeBuilder();
      return;
    }
  }
  const counts = {};
  rows.slice(0, sampleLimit).forEach((row) => {
      const text = themeBuilderText(row);
    const uniqueWords = new Set(themeWords(text));
    uniqueWords.forEach((word) => {
      counts[word] = (counts[word] || 0) + 1;
    });
  });
  const seeded = Object.entries(THEME_SEEDS).map(([name, keywords]) => {
    const count = rows.slice(0, sampleLimit).reduce((total, row) => {
      const text = String(themeBuilderText(row) || "").toLowerCase();
      return total + (keywords.some((word) => text.includes(word)) ? 1 : 0);
    }, 0);
    return { name, keywords: expandThemeKeywords(name), count, source: "suggested" };
  }).filter((theme) => theme.count > 0);
  const keywordThemes = Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .filter(([word]) => !seeded.some((theme) => theme.keywords.includes(word)))
    .slice(0, maxThemes)
    .map(([word, count]) => ({ name: word.replace(/\b\w/g, (char) => char.toUpperCase()), keywords: expandThemeKeywords(word), count, source: "keyword" }));
  const merged = [...seeded, ...keywordThemes]
    .sort((a, b) => b.count - a.count)
    .slice(0, maxThemes);
  state.themeBuilder.themes = merged;
  state.themeBuilder.active = new Set(merged.map((theme) => theme.name));
  renderThemeBuilder();
}

function classifyThemeText(text, themes = themeBuilderSelectedThemes()) {
  const lower = String(text || "").toLowerCase();
  const words = new Set(themeWords(lower));
  return themes.map((theme) => {
    const keywords = theme.keywords?.length ? theme.keywords : expandThemeKeywords(theme.name);
    let score = 0;
    keywords.forEach((keyword) => {
      if (!keyword) return;
      if (words.has(keyword) || lower.includes(keyword)) score += 1;
    });
    const value = !String(text || "").trim() ? "NA" : (score > 0 ? "Yes" : "No");
    return { name: theme.name, value, score };
  });
}

async function classifyThemeBuilderBatch(comments, themes, provider) {
  if (provider === "local") {
    return comments.map((comment) => ({
      row: comment.row,
      categories: Object.fromEntries(classifyThemeText(comment.text, themes).map((label) => [label.name, label.value])),
    }));
  }
  const response = await fetch("/api/theme-builder/classify", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      provider,
      apiKey: requireThemeBuilderKey(provider),
      ollamaModel: themeBuilderOllamaModel("themeBuilderClassifyMode"),
      comments,
      themes,
    }),
  });
  const payload = await response.json();
  if (!payload.ok) throw new Error(payload.error || "AI theme classification failed.");
  return payload.assignments || [];
}

async function buildThemeClassificationRows() {
  const rows = themeBuilderSourceRows();
  const themes = themeBuilderSelectedThemes();
  const provider = themeBuilderProvider("themeBuilderClassifyMode");
  if (!rows.length) {
    alert("Run NPS analysis first so the builder has verbatims to classify.");
    return;
  }
  if (!themes.length) {
    alert("Discover or add at least one active theme category first.");
    return;
  }
  const outputRows = rows.map((row, index) => {
    const text = themeBuilderText(row);
    const out = {
      Row: row.__row_id || index + 1,
      "Verbatim Feedback": text,
      "NPS score": rowValue(row, "NPS score"),
      "NPS Type": rowValue(row, "NPS Type"),
      Sentiment: rowValue(row, "Sentiment"),
    };
    themes.forEach((theme) => { out[`Theme: ${theme.name}`] = ""; });
    out["Classification Source"] = provider === "local" ? "NPS Theme Builder - Local Rules" : `NPS Theme Builder - ${themeBuilderOllamaModel("themeBuilderClassifyMode")}`;
    return out;
  });
  const byRow = new Map(outputRows.map((row) => [Number(row.Row), row]));
  const providerLabel = provider === "local" ? "Local Rules" : themeBuilderOllamaModel("themeBuilderClassifyMode");
  $("themeBuilderOutputMeta").textContent = `Classifying ${rows.length.toLocaleString()} rows with ${providerLabel}...`;
  showLoading(`Theme Builder 0/${rows.length.toLocaleString()} rows with ${providerLabel}`, 8);
  try {
    for (let i = 0; i < rows.length; i += provider === "local" ? 200 : 20) {
      const sourceBatch = rows.slice(i, i + (provider === "local" ? 200 : 20)).map((row, offset) => ({
        row: Number(row.__row_id || i + offset + 1),
        text: themeBuilderText(row),
      }));
      const assignments = await classifyThemeBuilderBatch(sourceBatch, themes, provider);
      assignments.forEach((assignment) => {
        const out = byRow.get(Number(assignment.row));
        if (!out) return;
        themes.forEach((theme) => {
          out[`Theme: ${theme.name}`] = assignment.categories?.[theme.name] || "No";
        });
      });
      const done = Math.min(i + sourceBatch.length, rows.length);
      $("themeBuilderOutputMeta").textContent = `Classified ${done.toLocaleString()} of ${rows.length.toLocaleString()} rows...`;
      updateProgress(`Theme Builder ${done.toLocaleString()}/${rows.length.toLocaleString()} rows with ${providerLabel}`, Math.min(98, 8 + (done / Math.max(rows.length, 1)) * 88));
      await new Promise((resolve) => setTimeout(resolve, 0));
    }
  } catch (err) {
    hideLoading();
    alert(err.message || "Theme classification failed.");
    return;
  }
  state.themeBuilder.rows = outputRows;
  mergeThemeBuilderIntoAnalysis();
  renderThemeBuilderTable();
  renderCustomStatsShell();
  renderColumnExplorer();
  renderPerformanceLens(state.analysis || {});
  renderMovingAveragesView(state.analysis || {});
  hideLoading();
  const scoreCount = Object.keys(themeBuilderAnalysisRows()[0] || {}).filter((key) => key.startsWith("Theme Score: ")).length;
  const skipped = themeBuilderBlankSkippedCount();
  state.themeBuilder.completeMessage = `Theme classification complete. ${rows.length.toLocaleString()} nonblank verbatim rows and ${themes.length.toLocaleString()} themes are now included in Analysis Output and available in Custom Statistics as Theme Builder Rows${scoreCount ? ` with ${scoreCount} numeric Theme Score fields` : ""}.${skipped ? ` ${skipped.toLocaleString()} rows were skipped because the selected theme-analysis field is blank.` : ""}`;
  $("themeBuilderOutputMeta").textContent = state.themeBuilder.completeMessage;
  alert(`${state.themeBuilder.completeMessage}

Use Custom Statistics > Theme Builder Rows for theme correlation and statistical analysis.`);
}

function addThemeBuilderCategory() {
  const input = $("themeBuilderNewName");
  const name = input?.value.trim();
  if (!name) return;
  const exists = state.themeBuilder.themes.some((theme) => theme.name.toLowerCase() === name.toLowerCase());
  if (exists) {
    alert("That category already exists.");
    return;
  }
  state.themeBuilder.themes.push({ name, keywords: expandThemeKeywords(name), count: 0, source: "custom" });
  state.themeBuilder.active.add(name);
  input.value = "";
  renderThemeBuilder();
}

function toggleThemeBuilderCategory(name) {
  if (state.themeBuilder.active.has(name)) state.themeBuilder.active.delete(name);
  else state.themeBuilder.active.add(name);
  renderThemeBuilder();
}

function removeThemeBuilderCategory(name) {
  state.themeBuilder.themes = state.themeBuilder.themes.filter((theme) => theme.name !== name);
  state.themeBuilder.active.delete(name);
  renderThemeBuilder();
}

function loadThemeBuilderSample() {
  const rows = themeBuilderSourceRows();
  if (!rows.length) return;
  state.themeBuilder.testIndex = (state.themeBuilder.testIndex || 0) % rows.length;
  $("themeBuilderTestText").value = themeBuilderText(rows[state.themeBuilder.testIndex]) || "";
  state.themeBuilder.testIndex += 1;
}

async function testThemeBuilderText() {
  const text = $("themeBuilderTestText")?.value || "";
  const themes = themeBuilderSelectedThemes();
  const provider = themeBuilderProvider("themeBuilderClassifyMode");
  const target = $("themeBuilderTestResult");
  if (!target) return;
  if (!themes.length) {
    target.textContent = "Discover or add categories first.";
    return;
  }
  target.textContent = "Classifying test verbatim...";
  let labels = [];
  try {
    if (provider === "local") {
      labels = classifyThemeText(text, themes);
    } else {
      const assignments = await classifyThemeBuilderBatch([{ row: 1, text }], themes, provider);
      const cats = assignments[0]?.categories || {};
      labels = themes.map((theme) => ({ name: theme.name, value: cats[theme.name] || "No" }));
    }
  } catch (err) {
    target.textContent = err.message || "Test classification failed.";
    return;
  }
  target.innerHTML = labels.map((label) => `<span class="theme-result-pill ${label.value.toLowerCase()}"><b>${escapeHtml(label.name)}</b>${label.value}</span>`).join("");
}

function renderThemeBuilderTable() {
  const rows = state.themeBuilder.rows || [];
  renderAnyTable("themeBuilderTable", rows, 80);
  attachThemeBuilderRows();
  const meta = $("themeBuilderOutputMeta");
  if (meta) meta.textContent = rows.length ? `${rows.length.toLocaleString()} rows classified across ${themeBuilderSelectedThemes().length.toLocaleString()} active categories.` : "No custom classification has been built yet.";
}

function attachThemeBuilderRows() {
  const table = $("themeBuilderTable");
  if (!table) return;
  table.querySelectorAll("tbody tr").forEach((tr, index) => {
    tr.classList.add("clickable-row");
    tr.title = "Double-click to review and override theme classifications.";
    tr.addEventListener("dblclick", () => openThemeBuilderOverride(index));
  });
}

function openThemeBuilderOverride(index) {
  const rows = state.themeBuilder.rows || [];
  if (index < 0 || index >= rows.length) return;
  state.themeBuilder.activeIndex = index;
  const row = rows[index];
  const columns = themeBuilderThemeColumns(row);
  $("themeBuilderModalMeta").textContent = `Row ${index + 1} of ${rows.length.toLocaleString()} - ${columns.length} theme categories`;
  $("themeBuilderModalText").textContent = row["Verbatim Feedback"] || "";
  $("themeBuilderOverrideGrid").innerHTML = columns.map((column) => {
    const label = column.replace(/^Theme:\s*/i, "");
    const value = row[column] || "No";
    return `<label>${escapeHtml(label)}<select data-theme-builder-override="${escapeHtml(column)}">
      <option value="Yes" ${value === "Yes" ? "selected" : ""}>Yes</option>
      <option value="No" ${value === "No" ? "selected" : ""}>No</option>
      <option value="NA" ${value === "NA" ? "selected" : ""}>NA</option>
    </select></label>`;
  }).join("");
  $("prevThemeBuilderRow").disabled = index <= 0;
  $("nextThemeBuilderRow").disabled = index >= rows.length - 1;
  $("themeBuilderOverrideStatus").textContent = "";
  $("themeBuilderModal").classList.remove("hidden");
}

function closeThemeBuilderOverride() {
  $("themeBuilderModal")?.classList.add("hidden");
  state.themeBuilder.activeIndex = -1;
}

function saveThemeBuilderOverride({ stayOpen = false } = {}) {
  const index = state.themeBuilder.activeIndex;
  const row = state.themeBuilder.rows?.[index];
  if (!row) return;
  document.querySelectorAll("[data-theme-builder-override]").forEach((select) => {
    row[select.dataset.themeBuilderOverride] = select.value;
  });
  row["Classification Source"] = `${row["Classification Source"] || "NPS Theme Builder"} + Manual Override`;
  $("themeBuilderOverrideStatus").textContent = "Saved.";
  renderThemeBuilderTable();
  if (stayOpen) openThemeBuilderOverride(index);
  else closeThemeBuilderOverride();
}

function moveThemeBuilderOverride(delta) {
  const current = state.themeBuilder.activeIndex;
  if (current < 0) return;
  saveThemeBuilderOverride({ stayOpen: true });
  const next = current + delta;
  if (next < 0 || next >= (state.themeBuilder.rows || []).length) return;
  openThemeBuilderOverride(next);
}

function themeBuilderExportRows() {
  const builtRows = state.themeBuilder.rows || [];
  if (!builtRows.length) return [];
  const sourceByRow = new Map(themeBuilderSourceRows().map((row, index) => [String(row.__row_id || index + 1), row]));
  return builtRows.map((built) => {
    const source = sourceByRow.get(String(built.Row)) || {};
    const cleanSource = Object.fromEntries(Object.entries(source).filter(([key]) => !key.startsWith("__")));
    const themeValues = Object.fromEntries(Object.entries(built).filter(([key]) => key.startsWith("Theme: ") || key === "Classification Source"));
    return {
      ...cleanSource,
      "Theme Builder Analysis Field": $("themeBuilderTextField")?.value || "",
      ...themeValues,
    };
  });
}

function refreshThemeCompareDateField() {
  const select = $("themeCompareDateField");
  if (!select) return;
  const current = select.value;
  const rows = themeBuilderJoinedRows();
  const fields = [...new Set(rows.flatMap((row) => Object.keys(row || {}).filter((key) => !key.startsWith("__"))))].sort((a, b) => {
    const rank = (name) => /date|week|month|created|survey/i.test(name) ? 0 : 1;
    return rank(a) - rank(b) || a.localeCompare(b);
  });
  const preferred = fields.find((field) => /date/i.test(field)) || fields[0] || "";
  select.innerHTML = fields.length ? fields.map((field) => `<option value="${escapeHtml(field)}">${escapeHtml(field)}</option>`).join("") : '<option value="">Build themes first</option>';
  select.value = fields.includes(current) ? current : preferred;
}

function parseThemeCompareDate(value) {
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function inThemeCompareRange(row, field, start, end) {
  const date = parseThemeCompareDate(row?.[field]);
  if (!date) return false;
  if (start && date < start) return false;
  if (end) {
    const inclusiveEnd = new Date(end);
    inclusiveEnd.setHours(23, 59, 59, 999);
    if (date > inclusiveEnd) return false;
  }
  return true;
}

function themeComparePeriodStats(rows, themeColumns) {
  const total = rows.length;
  const scoreKeys = ["NPS score", "NPS", "Score"];
  return Object.fromEntries(themeColumns.map((column) => {
    const yesRows = rows.filter((row) => row[column] === "Yes");
    const scores = yesRows.map((row) => Number(scoreKeys.map((key) => row[key]).find((value) => value !== undefined && value !== ""))).filter((value) => Number.isFinite(value));
    const Detractor = yesRows.filter((row) => /Detractor/i.test(String(row["NPS Type"] || row.NPS_Type || ""))).length;
    const negative = yesRows.filter((row) => /negative/i.test(String(row.Sentiment || ""))).length;
    return [column, {
      yes: yesRows.length,
      share: total ? (yesRows.length / total) * 100 : 0,
      avgNps: scores.length ? scores.reduce((sum, value) => sum + value, 0) / scores.length : 0,
      Detractor,
      negative,
    }];
  }));
}

function runThemeComparison() {
  refreshThemeCompareDateField();
  const rows = themeBuilderJoinedRows();
  const themeColumns = themeBuilderThemeColumns(state.themeBuilder.rows?.[0] || {});
  if (!rows.length || !themeColumns.length) {
    alert("Build Theme Classification first, then run Theme Comparison.");
    return;
  }
  const field = $("themeCompareDateField")?.value || "";
  if (!field) {
    alert("Select a date field for comparison.");
    return;
  }
  const currentStart = parseThemeCompareDate($("themeCompareCurrentStart")?.value);
  const currentEnd = parseThemeCompareDate($("themeCompareCurrentEnd")?.value);
  const previousStart = parseThemeCompareDate($("themeComparePreviousStart")?.value);
  const previousEnd = parseThemeCompareDate($("themeComparePreviousEnd")?.value);
  const currentRows = rows.filter((row) => inThemeCompareRange(row, field, currentStart, currentEnd));
  const previousRows = rows.filter((row) => inThemeCompareRange(row, field, previousStart, previousEnd));
  const current = themeComparePeriodStats(currentRows, themeColumns);
  const previous = themeComparePeriodStats(previousRows, themeColumns);
  const movementRows = themeColumns.map((column) => {
    const theme = column.replace(/^Theme:\s*/i, "");
    const c = current[column] || {};
    const p = previous[column] || {};
    return {
      Theme: theme,
      "Previous Yes": p.yes || 0,
      "Current Yes": c.yes || 0,
      "Yes Change": (c.yes || 0) - (p.yes || 0),
      "Previous Share %": +(p.share || 0).toFixed(1),
      "Current Share %": +(c.share || 0).toFixed(1),
      "Share Change": +((c.share || 0) - (p.share || 0)).toFixed(1),
      "Current Avg NPS": +(c.avgNps || 0).toFixed(1),
      "Current Detractor": c.Detractor || 0,
      "Current Negative": c.negative || 0,
    };
  }).sort((a, b) => Math.abs(b["Yes Change"]) - Math.abs(a["Yes Change"]));
  const rising = movementRows.filter((row) => row["Yes Change"] > 0).sort((a, b) => b["Yes Change"] - a["Yes Change"]);
  renderAnyTable("themeCompareTable", movementRows, 12);
  renderHorizontalBars("themeCompareRisingChart", rising, "Theme", "Yes Change", "#009b9b", 8);
  renderHorizontalBars("themeCompareReducedChart", movementRows.filter((row) => row["Yes Change"] < 0).map((row) => ({ ...row, Reduction: Math.abs(row["Yes Change"]) })), "Theme", "Reduction", "#d94045", 8);
  $("themeCompareMetricGrid").innerHTML = [
    metric("Previous Rows", previousRows.length.toLocaleString(), "Rows in previous period"),
    metric("Current Rows", currentRows.length.toLocaleString(), "Rows in current period"),
    metric("Themes Compared", themeColumns.length.toLocaleString(), "Active theme categories"),
    metric("Biggest Increase", rising[0]?.Theme || "-", rising[0] ? `+${rising[0]["Yes Change"]} Yes rows` : "No increase found"),
  ].join("");
  $("themeCompareMeta").textContent = `${movementRows.length.toLocaleString()} themes compared using ${field}.`;
}

function renderThemeBuilder() {
  refreshThemeBuilderFieldSelect();
  const rows = themeBuilderSourceRows();
  const totalCandidates = themeBuilderCandidateRows().length;
  const skipped = Math.max(0, totalCandidates - rows.length);
  const source = $("themeBuilderSource");
  const discoverMode = $("themeBuilderDiscoveryMode")?.selectedOptions?.[0]?.textContent || "Local Rules";
  const classifyMode = $("themeBuilderClassifyMode")?.selectedOptions?.[0]?.textContent || "Local Rules";
  if (source) source.textContent = rows.length
    ? `${rows.length.toLocaleString()} nonblank verbatim rows available from ${totalCandidates.toLocaleString()} analyzed rows. ${skipped.toLocaleString()} blank rows will be skipped. Discovery: ${discoverMode}. Classification: ${classifyMode}.`
    : "Run analysis first to load nonblank verbatims.";
  const stats = $("themeBuilderStats");
  if (stats) {
    stats.innerHTML = [
      metric("Verbatims", rows.length.toLocaleString(), "nonblank source rows"),
      metric("Skipped Blanks", skipped.toLocaleString(), "selected field blank"),
      metric("Categories", state.themeBuilder.themes.length.toLocaleString(), "available"),
      metric("Active", state.themeBuilder.active.size.toLocaleString(), "selected"),
    ].join("");
  }
  const chips = $("themeBuilderChips");
  if (chips) {
    chips.innerHTML = state.themeBuilder.themes.length
      ? state.themeBuilder.themes.map((theme) => {
        const active = state.themeBuilder.active.has(theme.name);
        return `<span class="theme-builder-chip ${active ? "active" : ""}">
          <button type="button" data-theme-toggle="${escapeHtml(theme.name)}">${active ? "Yes" : "No"}</button>
          <strong>${escapeHtml(theme.name)}</strong>
          <small>${escapeHtml(theme.source || "custom")}${theme.count ? ` - ${theme.count}` : ""}</small>
          <button type="button" class="chip-remove" data-theme-remove="${escapeHtml(theme.name)}">X</button>
        </span>`;
      }).join("")
      : '<span class="empty-note">Click Discover Themes or add a custom category.</span>';
    chips.querySelectorAll("[data-theme-toggle]").forEach((button) => button.addEventListener("click", () => toggleThemeBuilderCategory(button.dataset.themeToggle)));
    chips.querySelectorAll("[data-theme-remove]").forEach((button) => button.addEventListener("click", () => removeThemeBuilderCategory(button.dataset.themeRemove)));
  }
  renderThemeBuilderTable();
  updateThemeBuilderApiFields();
  refreshThemeCompareDateField();
}


function themeBuilderThemeColumns(row) {
  return Object.keys(row || {}).filter((key) => key.startsWith("Theme: "));
}
function themeFlagScore(value) {
  const text = String(value ?? "").trim().toLowerCase();
  if (text === "yes" || text === "y" || text === "true" || text === "1") return 1;
  if (text === "no" || text === "n" || text === "false" || text === "0") return 0;
  return "";
}

function themeBuilderJoinedRows() {
  const analysis = state.analysis || {};
  const currentBuilt = Array.isArray(state.themeBuilder?.rows) ? state.themeBuilder.rows : [];
  if (currentBuilt.length) return currentBuilt;
  const direct = Array.isArray(analysis.themeBuilderRows) ? analysis.themeBuilderRows : [];
  if (direct.length) return direct;
  const built = Array.isArray(analysis.themeBuilderAnalysisRows) ? analysis.themeBuilderAnalysisRows : [];
  if (built.length) return built;
  const themed = Array.isArray(analysis.themeRows) ? analysis.themeRows : [];
  if (themed.some((row) => Object.keys(row || {}).some((key) => key.startsWith("Theme: ") || key.startsWith("Theme Score: ")))) return themed;
  const feedback = Array.isArray(analysis.feedbackRows) ? analysis.feedbackRows : (Array.isArray(analysis.feedbackTableRows) ? analysis.feedbackTableRows : []);
  return feedback.filter((row) => Object.keys(row || {}).some((key) => key.startsWith("Theme: ") || key.startsWith("Theme Score: ")));
}
function themeBuilderAnalysisRows() {
  return themeBuilderJoinedRows().map((row) => {
    const output = { ...row };
    Object.keys(row || {}).filter((key) => key.startsWith("Theme: ")).forEach((column) => {
      const label = column.replace(/^Theme:\s*/i, "");
      output[`Theme Score: ${label}`] = themeFlagScore(row[column]);
    });
    return output;
  });
}

function mergeThemeBuilderIntoAnalysis() {
  const themeRows = themeBuilderAnalysisRows();
  if (!themeRows.length) return;
  const byRow = new Map(themeRows.map((row) => [String(row.Row || row.__row_id || ""), row]));
  const themeColumns = Object.keys(themeRows[0] || {}).filter((key) => key.startsWith("Theme: ") || key.startsWith("Theme Score: ") || key === "Theme Builder Analysis Field" || key === "Classification Source");
  const enrich = (rows = []) => (rows || []).map((row, index) => {
    const key = String(row.__row_id || row.Row || index + 1);
    const theme = byRow.get(key);
    if (!theme) return row;
    const additions = Object.fromEntries(themeColumns.map((column) => [column, theme[column] ?? ""]));
    return { ...row, ...additions };
  });
  state.analysis.feedbackRows = enrich(state.analysis.feedbackRows || []);
  state.analysis.feedbackTableRows = enrich(state.analysis.feedbackTableRows || []);
  state.analysis.themeRows = enrich(state.analysis.themeRows || []);
  state.analysis.preview = enrich(state.analysis.preview || []);
  state.analysis.themeBuilderRows = themeBuilderExportRows();
  state.analysis.themeBuilderAnalysisRows = themeRows;
  state.statsData.analyzedRows = enrich(state.statsData.analyzedRows || []);
}

function activeCustomStatsRows() {
  return customStatsSources()[$("customStatsSource")?.value || "Analyzed Feedback Rows"] || [];
}

function visibleColumns(rows) {
  return Object.keys(rows?.[0] || {}).filter((column) => !column.startsWith("__"));
}

function textColumns(rows) {
  return visibleColumns(rows).filter((column) => rows.some((row) => String(row[column] ?? "").trim() && Number.isNaN(parseMetricNumber(row[column]))));
}

function dateColumns(rows) {
  return visibleColumns(rows).filter((column) => {
    const nameLooksDate = /date|week|month|period/i.test(column);
    const populated = (rows || []).map((row) => row[column]).filter((value) => value !== "" && value != null);
    if (!populated.length) return false;
    const parsed = populated.filter((value) => !Number.isNaN(Date.parse(value))).length / populated.length;
    const numeric = populated.filter((value) => !Number.isNaN(parseMetricNumber(value))).length / populated.length;
    return nameLooksDate ? parsed >= 0.25 : (parsed >= 0.85 && numeric < 0.85);
  });
}

function statsNums(rows, column) {
  return (rows || []).map((row) => parseMetricNumber(row[column])).filter((value) => !Number.isNaN(value));
}

function median(values) {
  const nums = values.slice().sort((a, b) => a - b);
  if (!nums.length) return 0;
  const mid = Math.floor(nums.length / 2);
  return nums.length % 2 ? nums[mid] : (nums[mid - 1] + nums[mid]) / 2;
}

function percentile(values, pct) {
  const nums = values.slice().sort((a, b) => a - b);
  if (!nums.length) return 0;
  const index = (nums.length - 1) * pct;
  const low = Math.floor(index), high = Math.ceil(index);
  if (low === high) return nums[low];
  return nums[low] + (nums[high] - nums[low]) * (index - low);
}

function rankValues(values) {
  const sorted = values.map((value, index) => ({ value, index })).sort((a, b) => a.value - b.value);
  const ranks = Array(values.length).fill(0);
  sorted.forEach((item, index) => { ranks[item.index] = index + 1; });
  return ranks;
}

function spearmanCorrelation(xs, ys) {
  const pairs = xs.map((x, i) => [parseMetricNumber(x), parseMetricNumber(ys[i])]).filter(([x, y]) => !Number.isNaN(x) && !Number.isNaN(y));
  if (pairs.length < 2) return null;
  return correlation(rankValues(pairs.map(([x]) => x)), rankValues(pairs.map(([, y]) => y)));
}

function weekStartFromValue(value) {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "";
  const normalized = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  normalized.setDate(normalized.getDate() - normalized.getDay());
  return normalized.toISOString().slice(0, 10);
}

function weeklyCorrelationRows(rows, metricA, metricB, dateColumn, method = "pearson") {
  if (!dateColumn) return [];
  const groups = new Map();
  (rows || []).forEach((row) => {
    const week = weekStartFromValue(row[dateColumn]);
    const a = parseMetricNumber(row[metricA]);
    const b = parseMetricNumber(row[metricB]);
    if (!week || Number.isNaN(a) || Number.isNaN(b)) return;
    if (!groups.has(week)) groups.set(week, { xs: [], ys: [] });
    groups.get(week).xs.push(a);
    groups.get(week).ys.push(b);
  });
  return [...groups.entries()]
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([week, values]) => {
      const result = method === "spearman" ? spearmanCorrelation(values.xs, values.ys) : correlation(values.xs, values.ys);
      return result && result.sample >= 3
        ? { Week: week, Correlation: Number(result.value.toFixed(4)), Sample: result.sample, Direction: result.value >= 0 ? "Positive" : "Negative" }
        : { Week: week, Correlation: "", Sample: values.xs.length, Direction: "Not enough data" };
    })
    .filter((row) => row.Correlation !== "");
}

function statsSelect(id, label, columns, preferred = "", multiple = false) {
  const options = (columns || []).map((column) => `<option value="${escapeHtml(column)}"${column === preferred ? " selected" : ""}>${escapeHtml(column)}</option>`).join("");
  return `<label>${escapeHtml(label)}<select id="${id}"${multiple ? " multiple size=\"7\"" : ""}>${multiple ? options : `<option value="">-- Choose --</option>${options}`}</select></label>`;
}

function setCustomStatsSvg(svgId, message = "Select an analysis type and click Run Analysis") {
  const svg = $(svgId);
  if (svg) svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399">${escapeHtml(message)}</text>`;
}

function customStatsOptions(tab) {
  const options = {
    single: [
      ["desc", "Full Descriptive Stats"],
      ["mode", "Mode Analysis"],
      ["outlier", "Outlier Detection"],
      ["volatility", "Volatility Analysis"],
      ["pareto", "Pareto Analysis"],
    ],
    dual: [
      ["pearson", "Pearson Correlation"],
      ["spearman", "Spearman Correlation"],
      ["scatter", "Scatter Plot"],
      ["gap", "Gap Analysis"],
      ["benchmark", "Benchmark Comparison"],
    ],
    multi: [
      ["corrmatrix", "Correlation Matrix"],
      ["driver", "Driver Analysis"],
      ["multilevel", "Multi Level Correlation"],
      ["segment", "Segment Comparison"],
    ],
  };
  return options[tab] || options.single;
}

function isBackendStatsSource(name) {
  return ["Base Sheet", "Lookup Sheet", "Analyzed Feedback Rows", "Theme Rows"].includes(name);
}

function backendStatsProfile(name) {
  if (name === "Base Sheet") return state.baseColumnStats || {};
  if (name === "Lookup Sheet") return state.lookupColumnStats || {};
  return state.analyzedColumnStats || {};
}

function renderCustomStatsControls() {
  const rows = activeCustomStatsRows();
  const type = $("customStatsType")?.value || "";
  const sourceName = $("customStatsSource")?.value || "Analyzed Feedback Rows";
  const multilevelRows = [
    ...(state.analysis.weekly || []),
    ...(state.analysis.agents || []),
    ...(state.analysis.managers || []),
    ...(state.analysis.wave || []),
    ...(state.analysis.tenure || []),
  ];
  const profile = backendStatsProfile(sourceName);
  const profileColumns = Object.keys(profile);
  const profileNums = profileColumns.filter((column) => profile[column]?.dataType === "Number");
  const profileDates = profileColumns.filter((column) => profile[column]?.dataType === "Date/Time");
  const profileTexts = profileColumns.filter((column) => !["Number", "Date/Time", "Blank"].includes(profile[column]?.dataType));
  const nums = type === "multilevel" ? numericColumns(multilevelRows) : (isBackendStatsSource(sourceName) ? profileNums : numericColumns(rows));
  const texts = isBackendStatsSource(sourceName) ? profileTexts : textColumns(rows);
  const dates = isBackendStatsSource(sourceName) ? profileDates : dateColumns(rows);
  const firstNum = nums.includes("NPS Score") ? "NPS Score" : nums.includes("NPS") ? "NPS" : nums.includes("Rating") ? "Rating" : nums[0] || "";
  const secondNum = nums.includes("Sentiment Score") && firstNum !== "Sentiment Score"
    ? "Sentiment Score"
    : nums.find((column) => column !== firstNum) || "";
  const firstText = texts.includes("Agent Name") ? "Agent Name" : texts[0] || "";
  let html = "";
  if (["desc", "outlier", "volatility", "corrmatrix"].includes(type)) {
    html = statsSelect("customStatsColumns", "Metric Columns", nums, firstNum, true);
  } else if (type === "mode" || type === "pareto" || type === "segment") {
    html = statsSelect("customStatsCategory", "Category Column", texts.length ? texts : visibleColumns(rows), firstText);
    html += statsSelect("customStatsPrimary", "Value / Metric Column", nums, firstNum);
  } else if (["pearson", "spearman", "scatter", "gap"].includes(type)) {
    html = statsSelect("customStatsPrimary", "Metric A", nums, firstNum);
    html += statsSelect("customStatsSecondary", "Metric B", nums, secondNum);
  } else if (type === "benchmark") {
    html = statsSelect("customStatsCategory", "Benchmark Group", texts, firstText);
    html += statsSelect("customStatsPrimary", "Metric Column", nums, firstNum);
  } else if (type === "driver") {
    html = statsSelect("customStatsPrimary", "Target Metric", nums, firstNum);
    html += statsSelect("customStatsColumns", "Predictor Columns", nums.filter((column) => column !== firstNum), secondNum, true);
  } else if (type === "multilevel") {
    html = statsSelect("customStatsPrimary", "Metric A", nums, firstNum);
    html += statsSelect("customStatsSecondary", "Metric B", nums, nums.includes("Positive %") ? "Positive %" : secondNum);
  }
  if (dates.length && ["scatter", "pearson", "spearman"].includes(type)) {
    html += statsSelect("customStatsDate", "Optional Date Column", dates, dates[0]);
  }
  const controls = $("customStatsControls");
  if (controls) controls.innerHTML = html || `<small>Select an analysis type to configure the fields.</small>`;
}

function renderCustomStatsShell() {
  const sourceSelect = $("customStatsSource");
  const typeSelect = $("customStatsType");
  if (!sourceSelect || !typeSelect) return;
  const sources = customStatsSources();
  const currentSource = sourceSelect.value || Object.keys(sources)[0];
  sourceSelect.innerHTML = Object.entries(sources).map(([name, rows]) => `<option value="${escapeHtml(name)}">${escapeHtml(customStatsSourceLabel(name, rows))}</option>`).join("");
  sourceSelect.value = sources[currentSource] ? currentSource : Object.keys(sources)[0];
  const options = customStatsOptions(state.customStatsTab);
  const currentType = typeSelect.value;
  typeSelect.innerHTML = options.map(([value, label]) => `<option value="${value}">${escapeHtml(label)}</option>`).join("");
  typeSelect.value = options.some(([value]) => value === currentType) ? currentType : options[0]?.[0] || "";
  const rows = activeCustomStatsRows();
  const activeSourceName = sourceSelect.value || "Selected data";
  const num = numericColumns(rows).length;
  const text = textColumns(rows).length;
  const date = dateColumns(rows).length;
  if ($("customStatsMeta")) $("customStatsMeta").textContent = `${customStatsCoverageText(activeSourceName, rows)} ${num} numeric - ${text} text - ${date} date.`;
  document.querySelectorAll("[data-custom-stats-tab]").forEach((button) => button.classList.toggle("active", button.dataset.customStatsTab === state.customStatsTab));
  renderCustomStatsControls();
  if (!$("customStatsTable")?.querySelector("tbody")) {
    renderAnyTable("customStatsTable", []);
    setCustomStatsSvg("customStatsChart");
    setCustomStatsSvg("customStatsSecondChart");
  }
}

function selectedCustomStatsColumns() {
  return [...($("customStatsColumns")?.selectedOptions || [])].map((option) => option.value).filter(Boolean);
}

function descriptiveRows(rows, columns) {
  return columns.map((column) => {
    const values = statsNums(rows, column);
    const q1 = percentile(values, 0.25);
    const q3 = percentile(values, 0.75);
    return {
      Column: column,
      Count: values.length,
      Mean: formatMetric(average(values)),
      Median: formatMetric(median(values)),
      "Std Dev": formatMetric(stdDev(values)),
      Min: formatMetric(Math.min(...values)),
      Max: formatMetric(Math.max(...values)),
      Q1: formatMetric(q1),
      Q3: formatMetric(q3),
      IQR: formatMetric(q3 - q1),
    };
  });
}

function modeRows(rows, column) {
  const counts = new Map();
  rows.forEach((row) => {
    const value = String(row[column] ?? "").trim() || "Blank";
    counts.set(value, (counts.get(value) || 0) + 1);
  });
  return [...counts.entries()].sort((a, b) => b[1] - a[1]).slice(0, 30).map(([value, count]) => ({ Value: value, Count: count, Share: `${((count / Math.max(rows.length, 1)) * 100).toFixed(1)}%` }));
}

function groupedMetricRows(rows, category, metric) {
  const groups = new Map();
  rows.forEach((row) => {
    const key = String(row[category] ?? "").trim() || "Unknown";
    const value = parseMetricNumber(row[metric]);
    if (!Number.isNaN(value)) {
      if (!groups.has(key)) groups.set(key, []);
      groups.get(key).push(value);
    }
  });
  return [...groups.entries()].map(([key, values]) => ({ Group: key, Responses: values.length, Average: average(values), Median: median(values), "Std Dev": stdDev(values) }));
}

function groupedTwoMetricRows(rows, category, metricA, metricB) {
  const groups = new Map();
  (rows || []).forEach((row) => {
    const key = String(row[category] ?? "").trim() || "Unknown";
    const a = parseMetricNumber(row[metricA]);
    const b = parseMetricNumber(row[metricB]);
    if (!Number.isNaN(a) && !Number.isNaN(b)) {
      if (!groups.has(key)) groups.set(key, { a: [], b: [] });
      groups.get(key).a.push(a);
      groups.get(key).b.push(b);
    }
  });
  return [...groups.entries()].map(([key, values]) => ({
    Group: key,
    Responses: values.a.length,
    [metricA]: average(values.a),
    [metricB]: average(values.b),
  }));
}

function correlationMatrixRows(rows, columns) {
  return columns.map((a) => {
    const row = { Metric: a };
    columns.forEach((b) => {
      const result = correlation(statsNums(rows, a), statsNums(rows, b));
      row[b] = result ? result.value.toFixed(2) : "n/a";
    });
    return row;
  });
}

function multiLevelCorrelationRows(metricA, metricB) {
  const analysis = state.analysis || {};
  const levels = [
    ["Weekly", analysis.weekly || []],
    ["Agent", analysis.agents || []],
    ["Manager/TL", analysis.managers || []],
    ["LOB/Stream", groupedTwoMetricRows(analysis.feedbackRows || [], "LOB", metricA, metricB)],
    ["Wave", analysis.wave || []],
    ["Tenure", analysis.tenure || []],
  ];
  return levels.map(([level, rows]) => {
    const result = correlation((rows || []).map((row) => row[metricA]), (rows || []).map((row) => row[metricB]));
    return {
      Level: level,
      "Metric A": metricA,
      "Metric B": metricB,
      Correlation: result ? result.value.toFixed(3) : "n/a",
      Sample: result ? result.sample : 0,
      Strength: result ? correlationLabel(result.value) : "Not enough data",
      Direction: result ? (result.value >= 0 ? "Positive" : "Negative") : "n/a",
    };
  }).filter((row) => row.Sample > 1 || row.Level === "LOB/Stream");
}

function renderCustomStatsResultCards(rows, title, note = "") {
  const first = rows[0] || {};
  const cards = [
    metric("Analysis", title, note || "Custom statistics output", "", ""),
    metric("Rows", (rows || []).length.toLocaleString(), "Rows generated in the output table.", "", ""),
    metric("Source", $("customStatsSource")?.value || "Selected data", "Current statistics source.", "", ""),
  ];
  if (first.Correlation || first.Correlation === 0) cards.push(metric("Lead Correlation", first.Correlation, `${first.Level || first.Metric || "Top"} relationship`, Math.abs(Number(first.Correlation)) >= 0.6 ? "positive" : "", ""));
  const summary = $("customStatsSummary");
  if (summary) summary.innerHTML = cards.join("");
}

function customStatsSimpleRead(type, rows, context = {}) {
  const first = rows?.[0] || {};
  const title = context.title || "Statistics read";
  if (!rows?.length) {
    return {
      headline: "No result yet",
      body: "Choose an analysis type and click Run Analysis to generate a plain-English read.",
      chips: ["Waiting for input"],
    };
  }
  if (type === "desc") {
    const mean = Number(first.Mean);
    const medianValue = Number(first.Median);
    const min = first.Min;
    const max = first.Max;
    const q1 = first.Q1;
    const q3 = first.Q3;
    const iqr = Number(first.IQR);
    const center = !Number.isNaN(medianValue) ? medianValue : mean;
    const spread = iqr >= 7 ? "wide spread" : iqr >= 3 ? "moderate spread" : "tight spread";
    const meanMedianGap = Math.abs((Number.isNaN(mean) ? center : mean) - center);
    const shape = meanMedianGap <= 1 ? "fairly balanced" : mean > center ? "pulled upward by high values" : "pulled downward by low values";
    return {
      headline: `${first.Column || "Selected metric"} typically sits around ${formatMetric(center)}`,
      body: `In simple terms: the average is ${first.Mean}, the middle value is ${first.Median}, and most normal values sit between ${q1} and ${q3}. The full range is ${min} to ${max}, so this column has a ${spread} and looks ${shape}.`,
      chips: [`${first.Count || 0} records`, `Typical: ${formatMetric(center)}`, `Middle range: ${q1} to ${q3}`, `Spread: ${spread}`],
    };
  }
  if (type === "gap") {
    const gap = parseMetricNumber(first.Gap);
    const meanA = first["Mean A"];
    const meanB = first["Mean B"];
    const metricA = first["Metric A"] || context.primary || "Metric A";
    const metricB = first["Metric B"] || context.secondary || "Metric B";
    const gapSize = Number.isNaN(gap) ? "not clear" : Math.abs(gap) >= 10 ? "large" : Math.abs(gap) >= 3 ? "moderate" : "small";
    const lead = Number.isNaN(gap) ? "the difference could not be calculated" : gap >= 0 ? `${metricA} is higher than ${metricB}` : `${metricB} is higher than ${metricA}`;
    return {
      headline: `${metricA} and ${metricB} have a ${gapSize} average gap`,
      body: `In simple terms: the average ${metricA} is ${meanA}, while the average ${metricB} is ${meanB}. The gap is ${first.Gap}. This means ${lead}. Use this to understand distance between the two metrics, not whether one is causing the other.`,
      chips: [`${metricA}: ${meanA}`, `${metricB}: ${meanB}`, `Gap: ${first.Gap}`, `Records: ${first.Sample}`],
    };
  }
  if (["pearson", "spearman", "scatter"].includes(type)) {
    const corr = Number(first.Correlation);
    const strength = Number.isNaN(corr) ? "not enough signal" : correlationLabel(corr).toLowerCase();
    const direction = corr >= 0 ? "move in the same direction" : "move in opposite directions";
    const method = type === "spearman" ? "rank-based relationship" : type === "scatter" ? "visual relationship" : "linear relationship";
    return {
      headline: `${first["Metric A"] || context.primary} and ${first["Metric B"] || context.secondary} show a ${strength} relationship`,
      body: `This is a ${method}. The correlation is ${first.Correlation}, so the two metrics generally ${direction}. A positive value means they rise together; a negative value means one tends to rise when the other falls. Treat this as a signal to investigate, not proof of cause and effect.`,
      chips: [`Correlation: ${first.Correlation}`, `Records: ${first.Sample}`, `Direction: ${corr >= 0 ? "Positive" : "Negative"}`],
    };
  }
  if (type === "volatility") {
    return {
      headline: `${first.Column || "Selected metric"} has ${first["CV %"] || "measured"} variability`,
      body: `This checks how much the selected metric moves around compared with its average. Higher variability means performance is less stable and needs closer monitoring. For ${first.Column}, the average is ${first.Mean}, the standard deviation is ${first["Std Dev"]}, and the variability score is ${first["CV %"]}.`,
      chips: [`Average: ${first.Mean}`, `Std dev: ${first["Std Dev"]}`, `CV: ${first["CV %"]}`],
    };
  }
  if (type === "multilevel") {
    return {
      headline: `${first.Level || "Top level"} has the strongest relationship`,
      body: `${first["Metric A"]} vs ${first["Metric B"]} is strongest at ${first.Level} level with correlation ${first.Correlation}. This helps leaders decide which level deserves deeper review first.`,
      chips: [`Top level: ${first.Level}`, `Strength: ${first.Strength}`, `Sample: ${first.Sample}`],
    };
  }
  if (type === "driver") {
    return {
      headline: `${first.Predictor || "Top predictor"} is the strongest driver signal`,
      body: `${first.Predictor} has the strongest relationship with ${first.Target}, with correlation ${first.Correlation}. In plain terms, this is the metric most worth checking first when trying to understand movement in ${first.Target}.`,
      chips: [`Driver: ${first.Predictor}`, `Strength: ${first.Strength}`, `Direction: ${first.Direction}`],
    };
  }
  if (type === "benchmark") {
    const vsBenchmark = first["Vs Benchmark"] || "n/a";
    return {
      headline: `${first.Group || "Top group"} is ahead of the benchmark`,
      body: `This compares each group against the overall average. ${first.Group} has an average of ${first.Average}, which is ${vsBenchmark} versus the benchmark of ${first.Benchmark}. Positive values are above benchmark; negative values need review.`,
      chips: [`Group: ${first.Group}`, `Average: ${first.Average}`, `Vs benchmark: ${vsBenchmark}`],
    };
  }
  if (type === "segment") {
    return {
      headline: `${first.Group || "Top segment"} performs highest on ${context.primary || "the selected metric"}`,
      body: `This compares the selected metric across groups. ${first.Group} is currently highest with an average of ${first.Average} across ${first.Responses} records. Use this to identify which segment is leading and which segments may need support.`,
      chips: [`Top segment: ${first.Group}`, `Average: ${first.Average}`, `Records: ${first.Responses}`],
    };
  }
  if (type === "pareto") {
    return {
      headline: `${first.Value || "Top value"} is the biggest concentration`,
      body: `Pareto analysis helps answer: â€œWhat shows up most often?â€ ${first.Value} is the largest item, appearing ${first.Count} times and making up ${first.Share}. Start here if you want to reduce the biggest volume first.`,
      chips: [`Top item: ${first.Value}`, `Count: ${first.Count}`, `Share: ${first.Share}`],
    };
  }
  if (type === "mode") {
    return {
      headline: `${first.Value || "Top value"} appears most often`,
      body: `Mode simply means the most common value. Here, ${first.Value} appears most often, with ${first.Count} records. This helps users quickly spot the dominant category or repeated pattern.`,
      chips: [`Top value: ${first.Value}`, `Count: ${first.Count}`, `Share: ${first.Share}`],
    };
  }
  if (type === "outlier") {
    return {
      headline: `${first.Column || "Selected metric"} has ${first.Outliers || 0} outliers`,
      body: `Values below ${first["Lower Fence"]} or above ${first["Upper Fence"]} are unusual for this column. Review high outlier rates before trusting averages.`,
      chips: [`Outliers: ${first.Outliers}`, `Outlier rate: ${first["Outlier %"]}`, `Column: ${first.Column}`],
    };
  }
  return {
    headline: title,
    body: "The table below contains the result. Start with the first row and use the chart only as a supporting visual.",
    chips: [`Rows: ${rows.length}`, context.primary || context.category || "Selected analysis"],
  };
}

function renderCustomStatsExplain(type, rows, context = {}) {
  const target = $("customStatsExplain");
  if (!target) return;
  const read = customStatsSimpleRead(type, rows, context);
  target.innerHTML = `
    <div>
      <p class="eyebrow">Plain English Read</p>
      <h2>${escapeHtml(read.headline)}</h2>
      <p>${escapeHtml(read.body)}</p>
    </div>
    <div class="custom-stats-explain-chips">
      ${(read.chips || []).filter(Boolean).map((chip) => `<span>${escapeHtml(chip)}</span>`).join("")}
    </div>`;
}

async function runBackendCustomStats(request) {
  const button = $("customStatsRun");
  if (button) button.disabled = true;
  try {
    const response = await fetch("/api/custom-statistics", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(request),
    });
    const payload = await response.json();
    if (!response.ok || !payload.ok) throw new Error(payload.error || "Statistics calculation failed.");
    const output = payload.output || [];
    const title = $("customStatsType")?.selectedOptions?.[0]?.textContent || "Custom Statistics";
    renderCustomStatsResultCards(output, title, request.primary && request.secondary ? `${request.primary} x ${request.secondary}` : (request.primary || request.category || ""));
    renderCustomStatsExplain(request.type, output, { title, primary: request.primary, secondary: request.secondary, category: request.category });
    renderAnyTable("customStatsTable", output, 18);
    if ($("customStatsMeta")) $("customStatsMeta").textContent = `Calculated in Python using all ${Number(payload.totalRows || 0).toLocaleString()} rows. Browser visuals remain bounded for smooth performance.`;
    if ($("customStatsChartTitle")) $("customStatsChartTitle").textContent = title;
    if (["pearson", "spearman", "scatter", "gap"].includes(request.type)) {
      const chartRows = payload.chartRows || [];
      const first = output[0] || {};
      const corr = Number(first.Correlation);
      renderCorrelationScatter("customStatsSecondChart", chartRows, request.primary, request.secondary, Number.isFinite(corr) ? { value: corr, sample: Number(first.Sample || 0) } : null);
      renderHorizontalBars("customStatsChart", output, "Metric A", "Sample", "#009b9b", 8);
      if ($("customStatsSecondSubtitle")) $("customStatsSecondSubtitle").textContent = `${chartRows.length.toLocaleString()} sampled points; calculation uses ${Number(payload.totalRows || 0).toLocaleString()} rows`;
    } else {
      const labelKey = output[0]?.Group != null ? "Group" : output[0]?.Value != null ? "Value" : output[0]?.Column != null ? "Column" : output[0]?.Predictor != null ? "Predictor" : "Metric";
      const valueKey = output[0]?.Responses != null ? "Responses" : output[0]?.Count != null ? "Count" : output[0]?.Outliers != null ? "Outliers" : "Sample";
      renderHorizontalBars("customStatsChart", output, labelKey, valueKey, "#009b9b", 8);
      setCustomStatsSvg("customStatsSecondChart", "Full-dataset calculations are shown in the table.");
    }
  } catch (error) {
    alert(error.message || String(error));
  } finally {
    if (button) button.disabled = false;
  }
}

function runCustomStats() {
  const rows = activeCustomStatsRows();
  const type = $("customStatsType")?.value || "";
  const primary = $("customStatsPrimary")?.value || "";
  const secondary = $("customStatsSecondary")?.value || "";
  const category = $("customStatsCategory")?.value || "";
  const dateColumn = $("customStatsDate")?.value || "";
  const selected = selectedCustomStatsColumns();
  const source = $("customStatsSource")?.value || "Analyzed Feedback Rows";
  if (isBackendStatsSource(source) && type !== "multilevel") {
    runBackendCustomStats({ source, type, primary, secondary, category, dateColumn, columns: selected });
    return;
  }
  let output = [];
  let title = $("customStatsType")?.selectedOptions?.[0]?.textContent || "Custom Statistics";
  if (!rows.length) {
    alert("Run analysis first, then open Custom Statistics.");
    return;
  }
  if (type === "desc") output = descriptiveRows(rows, selected.length ? selected : numericColumns(rows).slice(0, 8));
  if (type === "mode") output = modeRows(rows, category || visibleColumns(rows)[0]);
  if (type === "outlier") {
    output = (selected.length ? selected : numericColumns(rows).slice(0, 8)).map((column) => {
      const values = statsNums(rows, column);
      const q1 = percentile(values, 0.25), q3 = percentile(values, 0.75), iqr = q3 - q1;
      const low = q1 - 1.5 * iqr, high = q3 + 1.5 * iqr;
      const outliers = values.filter((value) => value < low || value > high).length;
      return { Column: column, Count: values.length, "Lower Fence": formatMetric(low), "Upper Fence": formatMetric(high), Outliers: outliers, "Outlier %": `${((outliers / Math.max(values.length, 1)) * 100).toFixed(1)}%` };
    });
  }
  if (type === "volatility") output = descriptiveRows(rows, selected.length ? selected : numericColumns(rows).slice(0, 8)).map((row) => ({ ...row, "CV %": row.Mean !== "0.0" ? `${((Number(row["Std Dev"]) / Math.max(Math.abs(Number(row.Mean)), 1)) * 100).toFixed(1)}%` : "n/a" }));
  if (type === "pareto") output = modeRows(rows, category || visibleColumns(rows)[0]);
  if (["pearson", "spearman", "scatter", "gap"].includes(type)) {
    const result = type === "spearman" ? spearmanCorrelation(rows.map((row) => row[primary]), rows.map((row) => row[secondary])) : correlation(rows.map((row) => row[primary]), rows.map((row) => row[secondary]));
    const numsA = statsNums(rows, primary), numsB = statsNums(rows, secondary);
    output = [{ "Metric A": primary, "Metric B": secondary, Correlation: result ? result.value.toFixed(4) : "n/a", Sample: result ? result.sample : 0, "Mean A": formatMetric(average(numsA)), "Mean B": formatMetric(average(numsB)), Gap: formatMetric(average(numsA) - average(numsB)) }];
  }
  if (type === "benchmark") {
    const grouped = groupedMetricRows(rows, category, primary);
    const overall = average(statsNums(rows, primary));
    output = grouped.sort((a, b) => b.Average - a.Average).map((row) => ({ Group: row.Group, Responses: row.Responses, Average: formatMetric(row.Average), "Vs Benchmark": formatMetric(row.Average - overall), "Benchmark": formatMetric(overall) }));
  }
  if (type === "corrmatrix") output = correlationMatrixRows(rows, (selected.length ? selected : numericColumns(rows)).slice(0, 10));
  if (type === "driver") {
    output = (selected.length ? selected : numericColumns(rows).filter((column) => column !== primary)).map((column) => {
      const result = correlation(rows.map((row) => row[primary]), rows.map((row) => row[column]));
      return { Predictor: column, Target: primary, Correlation: result ? result.value.toFixed(3) : "n/a", Sample: result ? result.sample : 0, Strength: result ? correlationLabel(result.value) : "Not enough data", Direction: result ? (result.value >= 0 ? "Positive" : "Negative") : "n/a" };
    }).sort((a, b) => Math.abs(Number(b.Correlation) || 0) - Math.abs(Number(a.Correlation) || 0));
  }
  if (type === "multilevel") output = multiLevelCorrelationRows(primary, secondary).sort((a, b) => Math.abs(Number(b.Correlation) || 0) - Math.abs(Number(a.Correlation) || 0));
  if (type === "segment") output = groupedMetricRows(rows, category, primary).sort((a, b) => b.Average - a.Average).map((row) => ({ Group: row.Group, Responses: row.Responses, Average: formatMetric(row.Average), Median: formatMetric(row.Median), "Std Dev": formatMetric(row["Std Dev"]) }));
  renderCustomStatsResultCards(output, title, primary && secondary ? `${primary} x ${secondary}` : (primary || category || ""));
  renderCustomStatsExplain(type, output, { title, primary, secondary, category });
  renderAnyTable("customStatsTable", output, 18);
  if ($("customStatsTableHelp")) $("customStatsTableHelp").textContent = "Read the plain-English summary first, then use this table for the exact numbers.";
  if ($("customStatsChartTitle")) $("customStatsChartTitle").textContent = title;
  if ($("customStatsChartSubtitle")) $("customStatsChartSubtitle").textContent = output.length ? "Top output rows" : "No output generated";
  if ($("customStatsSecondSubtitle")) $("customStatsSecondSubtitle").textContent = primary && secondary ? `${primary} x ${secondary}` : "Distribution";
  if (["pearson", "spearman", "scatter", "gap"].includes(type)) {
    renderCorrelationScatter("customStatsSecondChart", rows, primary, secondary, correlation(rows.map((row) => row[primary]), rows.map((row) => row[secondary])));
    const weeklyRows = weeklyCorrelationRows(rows, primary, secondary, dateColumn, type === "spearman" ? "spearman" : "pearson");
    if (weeklyRows.length) {
      if ($("customStatsChartSubtitle")) $("customStatsChartSubtitle").textContent = `Week-over-week correlation using ${dateColumn}`;
      renderLineChart("customStatsChart", weeklyRows, "Correlation", "Select a valid date column to view weekly correlation.", "#006d86", (value) => Number(value || 0).toFixed(2));
    } else {
      if ($("customStatsChartSubtitle")) $("customStatsChartSubtitle").textContent = dateColumn ? `Not enough weekly data using ${dateColumn}` : "Select a date column to view weekly correlation";
      renderHorizontalBars("customStatsChart", output, "Metric A", "Sample", "#009b9b", 8);
    }
  } else if (type === "multilevel") {
    renderHorizontalBars("customStatsChart", output.map((row) => ({ ...row, Abs: Math.abs(Number(row.Correlation) || 0) })), "Level", "Abs", "#006d86", 8);
    renderAnyTable("customStatsTable", output, 18);
    setCustomStatsSvg("customStatsSecondChart", "Multi-level readout shown in the table.");
  } else {
    const labelKey = output[0]?.Group != null ? "Group" : output[0]?.Value != null ? "Value" : output[0]?.Column != null ? "Column" : output[0]?.Predictor != null ? "Predictor" : "Metric";
    const valueKey = output[0]?.Responses != null ? "Responses" : output[0]?.Count != null ? "Count" : output[0]?.Outliers != null ? "Outliers" : "Sample";
    renderHorizontalBars("customStatsChart", output, labelKey, valueKey, "#009b9b", 8);
    setCustomStatsSvg("customStatsSecondChart", "Detailed values available in the output table.");
  }
}

function inferColumnType(column, rows) {
  const values = (rows || []).map((row) => row[column]).filter((value) => value !== "" && value != null).slice(0, 50);
  if (!values.length) return "Unknown";
  if (values.every((value) => !Number.isNaN(Number(value)))) return "Number";
  if (/date|week|month|period|range/i.test(column) || values.some((value) => !Number.isNaN(Date.parse(value)))) return "Date/Time";
  return "Text";
}

function columnProfile(source, column) {
  if (source === "Base Sheet") return state.baseColumnStats?.[column] || {};
  if (source === "Lookup Sheet") return state.lookupColumnStats?.[column] || {};
  if (source === "Analysis Output") return state.analyzedColumnStats?.[column] || {};
  return {};
}

function compactUniqueValues(profile) {
  const values = Array.isArray(profile?.uniqueValues) ? profile.uniqueValues : [];
  return values.length ? values.join(", ") : "";
}

function uniqueSummaryFromRows(rows, column) {
  const values = [...new Set((rows || []).map((row) => String(row[column] ?? "").trim()).filter(Boolean))];
  values.sort((a, b) => a.localeCompare(b));
  return {
    count: values.length,
    values: values.length && values.length < 8 ? values.join(", ") : "",
  };
}

function columnRole(column) {
  const mappings = [
    ["Verbatim Feedback", $("feedbackCol")?.value],
    ["NPS Score", $("scoreCol")?.value],
    ["Agent Name", $("agentCol")?.value],
    ["Manager / TL", $("managerCol")?.value],
    ["LOB / Stream", $("lobCol")?.value],
    ["Feedback Date", $("dateCol")?.value],
    ["Wave Field", $("waveCol")?.value],
    ["Tenure Field", $("tenureCol")?.value],
    ["Base Join Key", $("baseKey")?.value],
    ["Lookup Join Key", $("lookupKey")?.value],
  ];
  (state.dynamicDimensions || []).forEach((dimension) => {
    mappings.push(["Custom Dimension", dimension]);
  });
  return mappings.filter(([, selected]) => selected === column).map(([label]) => label).join(", ") || "Available";
}

function buildColumnExplorerRows(columns, source, sampleRows) {
  const analyzedColumns = new Set(Object.keys(state.analyzedColumnStats || {}));
  return (columns || []).map((column, index) => ({
    __column_explorer: true,
    "#": index + 1,
    Source: source,
    Column: column,
    Type: columnProfile(source, column).dataType || inferColumnType(column, sampleRows),
    Role: columnRole(column),
    "Unique Count": columnProfile(source, column).uniqueLabel || "",
    "Unique Values": compactUniqueValues(columnProfile(source, column)),
    "In Analysis Output": analyzedColumns.has(column) ? "Yes" : "No",
    "Sample Value": displayCellValue(columnProfile(source, column).sampleValue || sampleRows.find((row) => row[column] !== "" && row[column] != null)?.[column] || ""),
  }));
}

function allColumnExplorerRows() {
  const baseRows = buildColumnExplorerRows(state.baseColumns, "Base Sheet", state.statsData.baseRows || []);
  const lookupRows = buildColumnExplorerRows(state.lookupColumns, "Lookup Sheet", state.statsData.lookupRows || []);
  const analysisColumns = Object.keys(state.analyzedColumnStats || {});
  const analysisRows = analysisColumns.map((column, index) => {
    const profile = columnProfile("Analysis Output", column);
    return {
      __column_explorer: true,
      "#": index + 1,
      Source: "Analysis Output",
      Column: column,
      Type: profile.dataType || "Unknown",
      Role: columnRole(column),
      "Unique Count": profile.uniqueLabel || Number(profile.unique || 0).toLocaleString(),
      "Unique Values": compactUniqueValues(profile),
      "In Analysis Output": "Yes",
      "Sample Value": displayCellValue(profile.sampleValue || ""),
    };
  });
  return { baseRows, lookupRows, analysisRows, allRows: [...baseRows, ...lookupRows, ...analysisRows] };
}

function columnExplorerMatches(row) {
  const filters = state.columnExplorer || {};
  const query = String(filters.search || "").trim().toLowerCase();
  if (filters.source && filters.source !== "All" && row.Source !== filters.source) return false;
  if (filters.type && filters.type !== "All" && row.Type !== filters.type) return false;
  if (filters.role === "Mapped Only" && row.Role === "Available") return false;
  if (filters.role === "Available" && row.Role !== "Available") return false;
  if (filters.role === "In Analysis Output" && row["In Analysis Output"] !== "Yes") return false;
  if (!query) return true;
  return ["Source", "Column", "Type", "Role", "Unique Count", "Unique Values", "In Analysis Output", "Sample Value"]
    .some((key) => String(row[key] ?? "").toLowerCase().includes(query));
}

function renderColumnExplorerTable(tableId, rows) {
  const table = $(tableId);
  if (!table) return;
  if (!rows || !rows.length) {
    table.innerHTML = "<tbody><tr><td>No matching columns found.</td></tr></tbody>";
    return;
  }
  const columns = ["Source", "Column", "Type", "Role", "Unique Count", "Unique Values", "In Analysis Output"];
  table.innerHTML = `<thead><tr>${columns.map((c) => `<th class="${tableHeaderClass(tableId, c)}" title="${escapeHtml(c)}">${escapeHtml(tableHeaderLabel(tableId, c))}</th>`).join("")}</tr></thead><tbody>${rows
    .map((row) => `<tr>${columns.map((c) => `<td class="${cellClass(row[c])} ${tableHeaderClass(tableId, c)}" title="${escapeHtml(c)}: ${escapeHtml(displayCellValue(row[c]))}"><span class="cell-value">${escapeHtml(displayCellValue(row[c]))}</span></td>`).join("")}</tr>`)
    .join("")}</tbody>`;
}

function columnExplorerCard(label, value, note, tooltip) {
  return `<div class="metric-card column-explorer-card" title="${escapeHtml(tooltip || note || label)}">
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(String(value))}</strong>
    ${note ? `<small>${escapeHtml(note)}</small>` : ""}
  </div>`;
}

function applyColumnExplorerFilters(rows) {
  return (rows || []).filter(columnExplorerMatches);
}

function updateColumnExplorerFilterState() {
  state.columnExplorer = {
    search: $("columnExplorerSearch")?.value || "",
    source: $("columnExplorerSource")?.value || "All",
    type: $("columnExplorerType")?.value || "All",
    role: $("columnExplorerRole")?.value || "All",
  };
}

function renderColumnExplorer() {
  if (!$("columnExplorerCards") && !$("columnExplorerSearchTable")) return;
  const { baseRows, lookupRows, analysisRows, allRows } = allColumnExplorerRows();
  const filteredBase = applyColumnExplorerFilters(baseRows);
  const filteredLookup = applyColumnExplorerFilters(lookupRows);
  const filteredAnalysis = applyColumnExplorerFilters(analysisRows);
  const filteredAll = applyColumnExplorerFilters(allRows);
  renderColumnExplorerTable("columnExplorerSearchTable", filteredAll);
  renderColumnExplorerTable("baseColumnExplorerTable", filteredBase);
  renderColumnExplorerTable("lookupColumnExplorerTable", filteredLookup);
  renderColumnExplorerTable("analysisColumnExplorerTable", filteredAnalysis);
  const mapped = [...baseRows, ...lookupRows].filter((row) => row.Role !== "Available").length;
  const query = String(state.columnExplorer?.search || "").trim();
  const resultText = query || state.columnExplorer?.source !== "All" || state.columnExplorer?.type !== "All" || state.columnExplorer?.role !== "All"
    ? `${filteredAll.length.toLocaleString()} matching columns found across ${allRows.length.toLocaleString()} total columns.`
    : `${allRows.length.toLocaleString()} total columns available. Type in search to find any column quickly.`;
  if ($("columnExplorerResultText")) $("columnExplorerResultText").textContent = resultText;
  const cards = $("columnExplorerCards");
  const rowCounts = state.statsRowCounts || {};
  const baseRowCount = Number(rowCounts.baseRows || (state.analysis.feedbackRows || state.analysis.preview || []).length || 0);
  const lookupRowCount = Number(rowCounts.lookupRows || 0);
  const analyzedRowCount = Number(rowCounts.analyzedRows || (state.analysis.feedbackRows || state.analysis.preview || []).length || 0);
  const visibleRowCount = analyzedRowCount || baseRowCount || lookupRowCount;
  const fmtRows = (count) => `${Number(count || 0).toLocaleString()} rows`;
  if (cards) cards.innerHTML = [
    columnExplorerCard(
      "Data Rows",
      visibleRowCount.toLocaleString(),
      `Base ${baseRowCount.toLocaleString()} | Analyzed ${analyzedRowCount.toLocaleString()} | Lookup ${lookupRowCount.toLocaleString()}`,
      "Data Rows shows the currently available row count. Base is the uploaded file, Analyzed is available after analysis output is created, and Lookup is the optional lookup file."
    ),
    columnExplorerCard(
      "Base Columns",
      (state.baseColumns || []).length.toLocaleString(),
      `${fmtRows(baseRowCount)} in uploaded base file`,
      "Base Columns are the fields found in the main uploaded survey file. Row count shows how many base records are available."
    ),
    columnExplorerCard(
      "Lookup Columns",
      (state.lookupColumns || []).length.toLocaleString(),
      `${fmtRows(lookupRowCount)} in optional lookup file`,
      "Lookup Columns are the extra fields brought from the optional lookup file, such as LOB, tenure, manager, or certification details."
    ),
    columnExplorerCard(
      "Mapped Fields",
      mapped.toLocaleString(),
      "Selected setup + custom dimension fields",
      "Mapped Fields are columns currently assigned in setup mapping, including optional custom dimensions where selected."
    ),
    columnExplorerCard(
      "Output Columns",
      analysisRows.length.toLocaleString(),
      `${fmtRows(analyzedRowCount)} after analysis`,
      "Output Columns are fields available after analysis, including generated sentiment, alerts, themes, and analysis-ready metrics."
    ),
    columnExplorerCard(
      "Matches",
      filteredAll.length.toLocaleString(),
      query ? `Current search: ${query}` : `${allRows.length.toLocaleString()} searchable columns`,
      "Matches shows how many columns match the current search and filters across base, lookup, and analysis output."
    ),
  ].join("");
}

function toCsv(rows) {
  if (!rows || !rows.length) return "";
  const columns = Object.keys(rows[0]).filter((column) => !column.startsWith("__"));
  const escapeCell = (value) => `"${String(value ?? "").replaceAll('"', '""')}"`;
  return [columns.join(","), ...rows.map((row) => columns.map((column) => escapeCell(row[column])).join(","))].join("\n");
}

function triggerBlobDownload(blob, filename) {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  link.style.display = "none";
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1200);
}

function setExportBusy(enabled) {
  ["exportAnalysisProject", "exportAnalysisProjectSetup"].forEach((id) => {
    const button = $(id);
    if (!button) return;
    button.disabled = Boolean(enabled);
    button.classList.toggle("is-busy", Boolean(enabled));
  });
}

function showExportProgress(message = "Preparing export package...", pct = 8) {
  let overlay = document.querySelector(".export-progress-overlay");
  if (!overlay) {
    overlay = document.createElement("div");
    overlay.className = "export-progress-overlay";
    overlay.innerHTML = `<div class="export-progress-card" role="status" aria-live="polite">
      <span class="export-progress-kicker">Export Analysis</span>
      <strong id="exportProgressTitle">Preparing your saved analysis file</strong>
      <p id="exportProgressMessage">Packaging the current analysis, setup, result views, and dashboard data.</p>
      <div class="export-progress-track"><span id="exportProgressBar"></span></div>
      <small id="exportProgressNote">Please keep this browser window open until the download starts.</small>
    </div>`;
    document.body.appendChild(overlay);
  }
  const boundedPct = Math.max(0, Math.min(100, Number(pct) || 0));
  const messageEl = overlay.querySelector("#exportProgressMessage");
  const barEl = overlay.querySelector("#exportProgressBar");
  if (messageEl) messageEl.textContent = message;
  if (barEl) barEl.style.width = `${boundedPct}%`;
  overlay.classList.toggle("is-complete", boundedPct >= 100);
}

function hideExportProgress(delay = 0) {
  const close = () => document.querySelector(".export-progress-overlay")?.remove();
  if (delay > 0) setTimeout(close, delay);
  else close();
}

function warnBeforeExportClose(event) {
  event.preventDefault();
  event.returnValue = "Your analysis export is still being prepared.";
  return event.returnValue;
}

function downloadRows(rows, filename) {
  const csv = toCsv(rows || []);
  if (!csv) {
    alert("No rows available to download yet.");
    return;
  }
  triggerBlobDownload(new Blob([csv], { type: "text/csv;charset=utf-8" }), filename);
}

function cleanDownloadFilename(value, fallback, extension) {
  const withoutExtension = String(value || fallback || "analysis_raw_data")
    .replace(/\.[^.]+$/i, "")
    .replace(/[\\/:*?"<>|]+/g, "_")
    .replace(/\s+/g, " ")
    .trim();
  return `${withoutExtension || fallback}.${extension}`;
}

function rawDataRowCount() {
  const counts = state.statsRowCounts || {};
  const analysis = state.analysis || {};
  return Number(
    counts.analyzedRows
    || analysis.summary?.total
    || analysis.summary?.Total
    || analysis.counts?.Total
    || analysis.totalRows
    || 0
  );
}

function renderAnalysisRawDataPage() {
  const rowCount = rawDataRowCount();
  const columns = state.analysis?.columns || state.analysis?.analyzedColumns || Object.keys((state.analysis?.feedbackRows || state.analysis?.preview || [{}])[0] || {});
  if ($("rawDataRowCount")) $("rawDataRowCount").textContent = rowCount ? rowCount.toLocaleString() : "-";
  if ($("rawDataColumnCount")) $("rawDataColumnCount").textContent = Array.isArray(columns) && columns.length ? columns.length.toLocaleString() : "-";
}

async function downloadAnalysisRawData(format = "excel") {
  if (!analysisHasDashboardData()) {
    alert("Run or import an analysis before downloading raw analysis data.");
    return;
  }
  const isCsv = format === "csv";
  const defaultName = `NPS_Analysis_Raw_Data_${new Date().toISOString().slice(0, 10)}`;
  const requestedName = prompt(`Save ${isCsv ? "CSV" : "Excel"} raw analysis as:`, defaultName);
  if (requestedName === null) return;
  const filename = cleanDownloadFilename(requestedName, defaultName, isCsv ? "csv" : "xlsx");
  const endpoint = isCsv ? "/api/export/raw-csv" : "/api/export/excel";
  const beforeUnload = warnBeforeExportClose;
  try {
    window.addEventListener("beforeunload", beforeUnload);
    showExportProgress("Preparing the complete raw analysis output. Please keep this window open.", 18);
    const response = await fetch(endpoint);
    showExportProgress("Receiving the export file from the local analysis server...", 72);
    if (!response.ok) {
      const payload = await response.json().catch(() => ({ error: "Raw data export failed." }));
      throw new Error(payload.error || "Raw data export failed.");
    }
    const blob = await response.blob();
    triggerBlobDownload(blob, filename);
    showExportProgress(`Download started: ${filename}. Please check your browser Downloads folder.`, 100);
    hideExportProgress(1200);
  } catch (error) {
    hideExportProgress();
    alert(error.message || "Raw data export failed.");
  } finally {
    window.removeEventListener("beforeunload", beforeUnload);
  }
}

function selectedCalendarConfig() {
  return {
    weekStartDay: $("setupWeekStartDay")?.value || "Monday",
    fiscalStartMonth: $("setupFiscalStartMonth")?.value || "January",
  };
}

function analysisProjectSetupPayload() {
  const fieldIds = [
    "feedbackCol", "scoreCol", "satisfactionCol", "npsTypeCol", "agentCol", "managerCol", "dateCol",
    "waveCol", "tenureCol", "baseJoinKeyCol", "lookupJoinKeyCol", "analysisMethod", "sentimentMethod",
    "themeMethod", "csatScaleSelect", "csatTargetInput", "minimumSampleInput", "setupWeekStartDay", "setupFiscalStartMonth"
  ];
  return {
    fields: Object.fromEntries(fieldIds.map((id) => [id, $(id)?.value || ""])),
    dynamicDimensions: state.dynamicDimensions || [],
    setupCoverageChoice: state.setupCoverageChoice || "",
    calendar: selectedCalendarConfig(),
  };
}

function safeAnalysisProjectFilename(name) {
  return `${String(name || "CXSuite_Analysis").trim().replace(/[^a-z0-9._-]+/gi, "_").replace(/^_+|_+$/g, "") || "CXSuite_Analysis"}.json`;
}

async function exportAnalysisProject() {
  const hasAnalysis = state.analysis && Object.keys(state.analysis || {}).length;
  if (!hasAnalysis) {
    alert("Run or import an analysis before exporting.");
    return;
  }
  const preferredName = prompt("Save analysis as:", `NPS_Analysis_${new Date().toISOString().slice(0, 10)}`);
  if (preferredName === null) return;
  try {
    setExportBusy(true);
    window.addEventListener("beforeunload", warnBeforeExportClose);
    showExportProgress("Preparing the export request. Please keep this window open.", 12);
    await new Promise((resolve) => requestAnimationFrame(() => resolve()));
    showExportProgress("Packaging setup, dashboard data, result views, and analysis outputs...", 32);
    const response = await fetch("/api/export-analysis-project", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ appMode: "nps", preferredName, setup: analysisProjectSetupPayload() }),
    });
    showExportProgress("Validating the export package from the local server...", 72);
    const payload = await response.json();
    if (!response.ok || !payload.ok) throw new Error(payload.error || "Could not export analysis.");
    const filename = safeAnalysisProjectFilename(preferredName);
    showExportProgress("Starting the browser download...", 92);
    triggerBlobDownload(
      new Blob([JSON.stringify(payload.project, null, 2)], { type: "application/json;charset=utf-8" }),
      filename
    );
    showExportProgress(`Download started: ${filename}. Please check your browser Downloads folder.`, 100);
    showToastMessage(`Analysis export started: ${filename}`);
    hideExportProgress(2600);
  } catch (error) {
    hideExportProgress();
    alert(error.message || "Could not export analysis.");
  } finally {
    window.removeEventListener("beforeunload", warnBeforeExportClose);
    setExportBusy(false);
  }
}

function restoreAnalysisProjectSetup(project = {}) {
  state.baseColumns = normalizeColumnList(project.baseColumns || state.baseColumns || []);
  state.lookupColumns = normalizeColumnList(project.lookupColumns || state.lookupColumns || []);
  state.baseColumnStats = project.baseColumnStats || {};
  state.lookupColumnStats = project.lookupColumnStats || {};
  state.analyzedColumnStats = project.analyzedColumnStats || {};
  state.dynamicDimensions = Array.isArray(project.dynamicDimensions) ? project.dynamicDimensions : [];
  state.baseUploadComplete = state.baseColumns.length > 0 || Boolean(project.analysis);
  const setup = project.setup || {};
  const fields = setup.fields || {};
  Object.entries(fields).forEach(([id, value]) => {
    if ($(id)) $(id).value = value || "";
  });
  if (setup.calendar?.weekStartDay && $("setupWeekStartDay")) $("setupWeekStartDay").value = setup.calendar.weekStartDay;
  if (setup.calendar?.fiscalStartMonth && $("setupFiscalStartMonth")) $("setupFiscalStartMonth").value = setup.calendar.fiscalStartMonth;
  if ($("baseStatus")) $("baseStatus").textContent = project.files?.base ? `Imported: ${project.files.base}` : "Imported analysis";
  if ($("lookupStatus")) $("lookupStatus").textContent = project.files?.lookup ? `Imported: ${project.files.lookup}` : "Optional - not uploaded";
  refreshMapping();
  refreshDynamicDimensionPicker();
}

async function importAnalysisProject(file) {
  if (!file) return;
  try {
    showLoading("Import: Reading the saved analysis file...", 12);
    const project = JSON.parse(await file.text());
    updateProgress("Import: Validating the analysis package...", 28);
    if (project.schema && project.schema !== "cx-suite-analysis-project") {
      throw new Error("This is not a CX Suite analysis export file.");
    }
    updateProgress("Import: Restoring the saved analysis on the local server...", 48);
    const response = await fetch("/api/import-analysis-project", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ project }),
    });
    const payload = await response.json();
    if (!response.ok || !payload.ok) throw new Error(payload.error || "Could not import analysis.");
    updateProgress("Import: Rebuilding setup, dashboards, and date filters...", 78);
    restoreAnalysisProjectSetup(project);
    renderAnalysis(payload.analysis || project.analysis || {}, { showCompletionSummary: false });
    updateProgress("Import: Opening the restored analysis results...", 96);
    state.guidedReleaseToApp = true;
    activateView("executivesummary");
    showCoachTipSoon("exportExecutiveSummaryHtml", "Imported analysis is ready. Start with this Executive Summary, then export it or use Help Me to move through the detailed views.", { key: "imported-executive-summary", position: "top", force: true, duration: 5200 });
    hideLoading();
    alert(`Imported analysis successfully. ${Number(payload.rows || 0).toLocaleString()} rows are ready.`);
  } catch (error) {
    hideLoading();
    alert(error.message || "Could not import analysis.");
  } finally {
    if ($("importAnalysisProjectFile")) $("importAnalysisProjectFile").value = "";
  }
}

function startNewAnalysisWorkspace() {
  const proceed = !Object.keys(state.analysis || {}).length || confirm("Start a new analysis? Current in-memory results will remain only if you exported them.");
  if (!proceed) return;
  state.analysis = {};
  state.analysisComparison = {};
  updateAnalysisAccessUi();
  state.baseUploadComplete = false;
  state.guidedMappingConfirmed = false;
  state.guidedAnalysisComplete = false;
  state.setupCoverageChoice = "";
  ["baseStatus", "lookupStatus"].forEach((id) => { if ($(id)) $(id).textContent = id === "baseStatus" ? "Pending" : "Optional - not uploaded"; });
  ["previewBaseFile", "previewLookupFile"].forEach((id) => { if ($(id)) $(id).hidden = true; });
  if ($("baseUploadLabel")) $("baseUploadLabel").textContent = "Upload Base File";
  if ($("lookupUploadLabel")) $("lookupUploadLabel").textContent = "Upload Lookup File";
  $("baseUploadButton")?.classList.remove("uploaded");
  $("lookupUploadButton")?.classList.remove("uploaded");
  state.guidedReleaseToApp = true;
  activateView("setup");
  showCoachTipSoon("baseUploadButton", "Start here. Upload the Base File, then I will guide you through lookup, mapping, business rules, model selection, and Run Analysis.", { key: "new-analysis-base-upload", position: "top", force: true, duration: 5200 });
  document.querySelector(".workspace")?.scrollTo({ top: 0, left: 0, behavior: "auto" });
}

async function signOutAndStopServer() {
  if (!confirm("Sign out and stop the local analysis server?")) return;
  const stoppedServer = window.location.host || "this local CX Suite server";
  try {
    await fetch("/api/signout", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ closeBrowsers: true, url: window.location.href }) });
  } catch (_) {
    /* Server may stop before the browser receives the final response. */
  }
  document.body.innerHTML = `<main style="font-family:Segoe UI,Arial,sans-serif;display:grid;place-items:center;min-height:100vh;background:#f4f8fb;color:#0b2942;"><section style="max-width:620px;padding:32px;border:1px solid #cfe3ed;border-radius:12px;background:white;box-shadow:0 20px 60px rgba(0,0,0,.08);"><p style="text-transform:uppercase;letter-spacing:.14em;color:#008b8b;font-size:12px;">Signed out</p><h1 style="margin:0 0 10px;">Server stopped.</h1><p><strong>${stoppedServer}</strong> has been stopped.</p><p>Closing this CX Suite browser window now. If your browser blocks automatic close, you can safely close it manually.</p></section></main>`;
  setTimeout(() => {
    try {
      window.open("", "_self");
      window.close();
    } catch (_) {
      /* Some browsers block scripts from closing manually opened tabs. */
    }
  }, 900);
}

function rowsFromTable(tableId) {
  const table = $(tableId);
  if (!table) return [];
  const columns = Array.from(table.querySelectorAll("thead th")).map((th) => th.textContent.trim());
  return Array.from(table.querySelectorAll("tbody tr")).map((tr) => {
    const cells = Array.from(tr.querySelectorAll("td"));
    return Object.fromEntries(columns.map((column, index) => [column || `Column ${index + 1}`, cells[index]?.textContent.trim() || ""]));
  }).filter((row) => Object.values(row).some((value) => value && value !== "No data available yet."));
}

function downloadTableCsv(tableId) {
  const filename = `${tableId.replace(/([A-Z])/g, "-$1").toLowerCase()}-${new Date().toISOString().slice(0, 10)}.csv`;
  downloadRows(rowsFromTable(tableId), filename);
}

function readOnlySectionHtml(sectionId) {
  const source = $(sectionId);
  if (!source) return "";
  const clone = source.cloneNode(true);
  clone.classList.remove("hidden", "active");
  clone.querySelectorAll("button, input, select, textarea, .custom-stats-config, .download-action-row, .download-select-grid, .date-panel, .modal, .loading").forEach((node) => node.remove());
  clone.querySelectorAll(".hidden").forEach((node) => node.classList.remove("hidden"));
  return clone.innerHTML.trim() ? `<section class="readonly-section readonly-${sectionId}">${clone.innerHTML}</section>` : "";
}

