function downloadCustomStatsHtml() {
  const html = standaloneCustomStatsHtml();
  if (!html) {
    alert("Run analysis first, then export the full read-only HTML output.");
    return;
  }
  const type = "full-nps-analysis";
  const safeType = type.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "custom-statistics";
  triggerBlobDownload(
    new Blob([html], { type: "text/html;charset=utf-8" }),
    `nps-${safeType}-readonly-${new Date().toISOString().slice(0, 10)}.html`
  );
}

