function buildGenAiJsonExport() {
  const tableIds = [
    "previewTable", "sentimentCompareTable", "sentimentThemeTable", "themeTable", "themeBuilderTable", "themeCompareTable", "waveTable", "tenureTable", "agentTable", "managerTable",
    "quartileTable", "statsFormulaTable", "analysisCompareTable", "analysisSummaryTable",
    "analysisTable", "analysisManagerTable", "analysisAgentTable", "analysisSentimentTable",
    "analysisConsistencyTable",
  ];
  const renderedTables = Object.fromEntries(
    tableIds.map((id) => [id, rowsFromTable(id)]).filter(([, rows]) => rows.length)
  );
  return {
    schema: "NPS_ANALYZER_GENAI_EXPORT_V1",
    generatedAt: new Date().toISOString(),
    purpose: "Use this JSON as full context for natural-language questions about the NPS Analyzer output.",
    confidentiality: "Contains customer feedback analytics exported from the local standalone NPS Analyzer. Handle according to internal data policy.",
    suggestedQuestions: [
      "Summarize the most important NPS risks and opportunities.",
      "Which managers or agents need attention and why?",
      "What are the strongest positive and negative themes?",
      "Explain the NPS movement and sentiment movement in executive language.",
      "Create a prioritized action plan from these insights.",
      "Find contradictions between NPS, sentiment, themes, and alert badges.",
    ],
    currentSetup: selectedOptionsSnapshot(),
    executiveSummaryText: $("insightsText")?.textContent || "",
    analysisStatus: $("analysisStatus")?.textContent || "",
    dashboardData: enrichedAnalysisForExport(),
    renderedTables,
    renderedMetrics: {
      executiveCards: rowsFromMetricCards("metricGrid"),
      alertCards: rowsFromAlertCards(),
    },
    notesForGenAiTool: [
      "dashboardData is the primary source of truth from the analyzer backend.",
      "renderedTables are included to make tabular Q&A easier when the UI has transformed data for display.",
      "Use row-level feedback data carefully; do not invent values that are not present in the JSON.",
      "When answering, cite the relevant section keys such as dashboardData.summary, dashboardData.feedbackTableRows, or renderedTables.",
    ],
  };
}

function enrichedAnalysisForExport() {
  return {
    ...(state.analysis || {}),
    sentimentCompareRows: sentimentWowRows(),
    sentimentThemeRows: sentimentThemeWowRows(),
    themeBuilderRows: themeBuilderExportRows(),
    themeCompareRows: (state.themeBuilder.comparisonRows || []).length ? state.themeBuilder.comparisonRows : rowsFromTable("themeCompareTable"),
  };
}

function rowsFromMetricCards(containerId) {
  const container = $(containerId);
  if (!container) return [];
  return Array.from(container.querySelectorAll(".metric-card")).map((card) => ({
    label: card.querySelector("span")?.textContent.trim() || "",
    value: card.querySelector("strong")?.textContent.trim() || "",
    note: card.querySelector("small")?.textContent.trim() || "",
  })).filter((row) => row.label || row.value || row.note);
}

function rowsFromAlertCards() {
  return Array.from(document.querySelectorAll(".alert-card")).map((card) => ({
    title: card.querySelector("h3")?.textContent.trim() || "",
    status: card.querySelector(".status")?.textContent.trim() || "",
    detail: card.querySelector("p")?.textContent.trim() || "",
  })).filter((row) => row.title || row.status || row.detail);
}

function downloadGenAiJson() {
  const payload = buildGenAiJsonExport();
  const json = JSON.stringify(payload, null, 2);
  triggerBlobDownload(
    new Blob([json], { type: "application/json;charset=utf-8" }),
    `nps-analyzer-genai-export-${new Date().toISOString().slice(0, 10)}.json`
  );
}

function executivePdfRows(rows, limit = 12) {
  return Array.isArray(rows) ? rows.filter(Boolean).slice(0, limit) : [];
}

function executivePdfValue(value) {
  if (value === null || value === undefined || value === "") return "Not available";
  if (typeof value === "number") return Number.isInteger(value) ? value.toLocaleString() : value.toFixed(2);
  return displayCellValue(value);
}

function executivePdfColumns(rows, maxColumns = 7) {
  const keys = [];
  (Array.isArray(rows) ? rows : []).slice(0, 20).forEach((row) => {
    Object.keys(row || {}).forEach((key) => {
      if (!keys.includes(key)) keys.push(key);
    });
  });
  return keys.slice(0, maxColumns);
}

function executivePdfTable(title, rows, limit = 12, maxColumns = 7) {
  const selected = executivePdfRows(rows, limit);
  if (!selected.length) {
    return `<div class="empty-note"><strong>${escapeHtml(title)}</strong><span>No data available in the current analysis output.</span></div>`;
  }
  const columns = executivePdfColumns(selected, maxColumns);
  return `<div class="report-table-card">
    <h3>${escapeHtml(title)}</h3>
    <table>
      <thead><tr>${columns.map((column) => `<th>${escapeHtml(column)}</th>`).join("")}</tr></thead>
      <tbody>${selected.map((row) => `<tr>${columns.map((column) => `<td>${escapeHtml(executivePdfValue(row[column]))}</td>`).join("")}</tr>`).join("")}</tbody>
    </table>
  </div>`;
}

function executivePdfMetricHtml(metrics) {
  const selected = executivePdfRows(metrics, 12);
  if (!selected.length) return `<p class="muted-report">No KPI cards are available yet. Run analysis before exporting the report.</p>`;
  return selected.map((metric) => `<article class="kpi-card">
    <span>${escapeHtml(metric.label || "Metric")}</span>
    <strong>${escapeHtml(metric.value || "Not available")}</strong>
    <small>${escapeHtml(metric.note || "")}</small>
  </article>`).join("");
}

function executivePdfBullets(text) {
  const cleaned = String(text || "").replace(/\s+/g, " ").trim();
  if (!cleaned) return ["Run analysis to generate the executive narrative and recommended focus areas."];
  return cleaned.split(/(?<=[.!?])\s+/).filter(Boolean).slice(0, 12);
}

function executivePdfSortRows(rows, keys = []) {
  const list = Array.isArray(rows) ? rows.slice() : [];
  return list.sort((a, b) => {
    for (const key of keys) {
      const av = Number(String(a?.[key] ?? "").replace(/[^0-9.-]/g, ""));
      const bv = Number(String(b?.[key] ?? "").replace(/[^0-9.-]/g, ""));
      if (Number.isFinite(av) && Number.isFinite(bv) && av !== bv) return bv - av;
    }
    return 0;
  });
}

function executivePdfChunkRows(rows, size = 12, limit = 48) {
  const selected = (Array.isArray(rows) ? rows : []).slice(0, limit);
  const chunks = [];
  for (let index = 0; index < selected.length; index += size) {
    chunks.push(selected.slice(index, index + size));
  }
  return chunks;
}

function executivePdfObjectRows(objectValue) {
  if (!objectValue || typeof objectValue !== "object" || Array.isArray(objectValue)) return [];
  return Object.entries(objectValue).map(([key, value]) => ({ Metric: key, Value: executivePdfValue(value) }));
}

function executivePdfInsightCards(payload) {
  const data = payload.dashboardData || {};
  const summary = data.summary || {};
  const counts = data.counts || {};
  const sentiment = data.sentiment || {};
  const weekly = data.weekly || [];
  const reasons = data.reasons || [];
  const agents = data.agents || [];
  const managers = data.managers || [];
  const alerts = payload.renderedMetrics?.alertCards || [];
  const cards = [];
  const total = Number(summary.total || 0);
  const nps = Number(summary.nps || 0);
  if (total) cards.push({ title: "Survey coverage", detail: `${total.toLocaleString()} survey rows are included in the current analysis. This is the response universe used for the executive readout.` });
  if (Number.isFinite(nps)) cards.push({ title: "NPS position", detail: `Current NPS is ${nps.toFixed(1)}. Read this alongside promoter, passive, and detractor mix before drawing leader-level conclusions.` });
  if (Object.keys(counts).length) cards.push({ title: "Response mix", detail: `Promoter, passive, and detractor counts are included in the JSON. This mix explains whether NPS is being moved by advocacy growth, detractor control, or passive conversion.` });
  if (Object.keys(sentiment).length) cards.push({ title: "Sentiment layer", detail: `Sparrow sentiment distribution is available and should be compared with NPS to find mismatches between score and verbatim tone.` });
  if (weekly.length) cards.push({ title: "Trend context", detail: `${weekly.length} weekly or period rows are available. Review the trend pages to separate structural movement from one-off volume swings.` });
  if (reasons.length) cards.push({ title: "Driver intelligence", detail: `${reasons.length} reason or root-cause rows are available. The top drivers should be converted into owned actions.` });
  if (managers.length) cards.push({ title: "Manager lens", detail: `${managers.length} manager rows are available for leadership review. Use this to identify where support is needed at team level.` });
  if (agents.length) cards.push({ title: "Agent lens", detail: `${agents.length} agent rows are available. Use this carefully to separate coaching needs from process or policy issues.` });
  if (alerts.length) cards.push({ title: "Alert coverage", detail: `${alerts.length} alert badge rows are available. Active or risk-toned alerts should be reviewed before sending final action plans.` });
  return cards;
}

function executivePdfRecommendations(payload) {
  const data = payload.dashboardData || {};
  const alerts = payload.renderedMetrics?.alertCards || [];
  const managers = data.managers || payload.renderedTables?.managerTable || [];
  const agents = data.agents || payload.renderedTables?.agentTable || [];
  const themes = data.themeRows || payload.renderedTables?.themeTable || [];
  const weekly = data.weekly || [];
  const recommendations = [];
  if (alerts.length) recommendations.push("Assign owners to every active alert badge and review closure progress in the next operating rhythm.");
  if (weekly.length) recommendations.push("Use weekly movement to identify whether NPS changes are sustained, seasonal, or caused by short-term volume shifts.");
  if (managers.length) recommendations.push("Prioritize manager-level outliers for calibration, coaching design, and operational support.");
  if (agents.length) recommendations.push("Use agent-level findings to identify coaching themes, but validate with sample size and feedback context.");
  if (themes.length) recommendations.push("Convert the top Owl themes and drivers into a ranked action backlog with business owners and timelines.");
  recommendations.push("Compare NPS, Sparrow sentiment, Owl themes, and alert badges before finalizing the leadership narrative.");
  recommendations.push("After actions are agreed, re-run analysis and export the report again to track improvement and residual risk.");
  return recommendations.slice(0, 8);
}

function executivePdfSection(id, title, eyebrow, bodyHtml) {
  return `<section class="page" id="${escapeHtml(id)}">
    <a class="back" href="#index">Back to index</a>
    <div class="section-header"><p class="eyebrow">${escapeHtml(eyebrow)}</p><h2>${escapeHtml(title)}</h2></div>
    ${bodyHtml}
  </section>`;
}

function executivePdfInsightCardHtml(cards) {
  if (!cards.length) return `<p class="muted-report">No insight cards are available yet.</p>`;
  return `<div class="insight-grid">${cards.map((card) => `<article class="insight-card"><h3>${escapeHtml(card.title)}</h3><p>${escapeHtml(card.detail)}</p></article>`).join("")}</div>`;
}

function executivePdfDataPages(sectionDefinitions) {
  const pages = [];
  sectionDefinitions.forEach((definition) => {
    const chunks = executivePdfChunkRows(definition.rows, definition.chunkSize || 12, definition.limit || 48);
    if (!chunks.length) {
      pages.push({
        id: definition.id,
        title: definition.title,
        purpose: definition.purpose,
        html: executivePdfSection(definition.id, definition.title, definition.eyebrow || "Analysis Detail", `<p class="lead">${escapeHtml(definition.purpose)}</p>${executivePdfTable(definition.title, [], 0)}`),
      });
      return;
    }
    chunks.forEach((chunk, index) => {
      const id = `${definition.id}-${index + 1}`;
      const title = chunks.length > 1 ? `${definition.title} (${index + 1}/${chunks.length})` : definition.title;
      pages.push({
        id,
        title,
        purpose: definition.purpose,
        html: executivePdfSection(id, title, definition.eyebrow || "Analysis Detail", `<p class="lead">${escapeHtml(definition.purpose)}</p>${executivePdfTable(title, chunk, chunk.length, definition.maxColumns || 7)}`),
      });
    });
  });
  return pages;
}

