function boardPdfAvailableTabs() {
  const available = Object.keys(PDF_TAB_TITLES)
    .filter((tab, index, tabs) => tabs.indexOf(tab) === index)
    .filter((tab) => Boolean($(tab)));
  const ordered = BOARD_ROOM_TAB_ORDER.filter((tab) => available.includes(tab));
  const remaining = available.filter((tab) => !ordered.includes(tab));
  return [...ordered, ...remaining];
}

function boardPdfOptionCountLine(tab) {
  const row = reportReferenceRows([tab])[0] || { cardCount: 0, chartCount: 0, tableCount: 0 };
  return `${row.cardCount.toLocaleString()} cards | ${row.chartCount.toLocaleString()} visuals | ${row.tableCount.toLocaleString()} tables`;
}

function renderBoardPdfOptionCards() {
  const grid = document.querySelector("#boardpdf .pdf-builder-option-grid");
  if (!grid) return;
  const existingChecked = new Set([...grid.querySelectorAll("[data-board-pdf-tab]:checked")].map((input) => input.dataset.boardPdfTab));
  const tabs = boardPdfAvailableTabs();
  grid.innerHTML = tabs.map((tab, index) => {
    const checked = existingChecked.size ? existingChecked.has(tab) : BOARD_PDF_RECOMMENDED_TABS.includes(tab);
    const guide = BOARD_PDF_SECTION_GUIDES[tab] || "Selected dashboard view with cards, visuals, tables, and leadership context.";
    return `<label>
      <input type="checkbox" data-board-pdf-tab="${escapeHtml(tab)}" ${checked ? "checked" : ""} />
      <span>
        <em>${String(index + 1).padStart(2, "0")}</em>
        <strong>${escapeHtml(PDF_TAB_TITLES[tab] || tab)}</strong>
        <small>${escapeHtml(guide)}</small>
        <small class="pdf-builder-card-counts">${escapeHtml(boardPdfOptionCountLine(tab))}</small>
      </span>
    </label>`;
  }).join("");
}

function selectedPdfTabs() {
  return [...document.querySelectorAll("[data-pdf-tab]:checked")]
    .map((input) => input.dataset.pdfTab)
    .filter((id) => id && $(id));
}

function selectedBoardPdfTabs() {
  const selected = new Set([...document.querySelectorAll("[data-board-pdf-tab]:checked")]
    .map((input) => input.dataset.boardPdfTab)
    .filter((id) => id && $(id)));
  return boardPdfAvailableTabs().filter((tab) => selected.has(tab));
}

function setBoardPdfSelection(mode) {
  document.querySelectorAll("[data-board-pdf-tab]").forEach((input) => {
    if (mode === "all") input.checked = true;
    else if (mode === "clear") input.checked = false;
    else input.checked = BOARD_PDF_RECOMMENDED_TABS.includes(input.dataset.boardPdfTab);
  });
}

function handleBoardPdfSeparatorImages(files) {
  const selected = Array.from(files || []).slice(0, 5);
  if (!selected.length) {
    state.boardPdfSeparatorImages = [];
    return;
  }
  if (selected.some((file) => !file.type.startsWith("image/"))) {
    alert("Please select image files only for separator pages.");
    return;
  }
  Promise.all(selected.map((file) => new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = reject;
    reader.readAsDataURL(file);
  }))).then((images) => {
    state.boardPdfSeparatorImages = images.filter(Boolean);
  }).catch(() => {
    state.boardPdfSeparatorImages = [];
    alert("One or more separator images could not be loaded. Please try again.");
  });
}

function handleBoardPdfHomeImage(files) {
  const selected = Array.from(files || [])[0];
  if (!selected) {
    state.boardPdfHomeImage = "";
    return;
  }
  if (!selected.type.startsWith("image/")) {
    alert("Please select an image file for the home page.");
    return;
  }
  const reader = new FileReader();
  reader.onload = () => {
    state.boardPdfHomeImage = String(reader.result || "");
  };
  reader.onerror = () => {
    state.boardPdfHomeImage = "";
    alert("The home page image could not be loaded. Please try again.");
  };
  reader.readAsDataURL(selected);
}

