function boardPdfSectionDivider(tab, index, tabs) {
  const title = PDF_TAB_TITLES[tab] || tab;
  const ref = `R${String(index + 1).padStart(2, "0")}`;
  const previous = index > 0 ? tabs[index - 1] : "";
  const next = index < tabs.length - 1 ? tabs[index + 1] : "";
  const guide = BOARD_PDF_SECTION_GUIDES[tab] || "Selected dashboard view with cards, charts, tables, and analysis context.";
  const images = state.boardPdfSeparatorImages || [];
  const selectedImage = images.length ? images[(index * 3 + 1) % images.length] : "";
  const imageHtml = selectedImage
    ? `<div class="divider-image-panel"><img src="${selectedImage}" alt="" /></div>`
    : "";
  return `<section id="divider-${escapeHtml(tab)}" class="board-section-divider">
    <div class="divider-nav">
      <a href="#report-home">Home</a>
      <a href="#report-index">Index</a>
      ${previous ? `<a href="#divider-${escapeHtml(previous)}">Previous Section</a>` : `<span>Previous Section</span>`}
      ${next ? `<a href="#divider-${escapeHtml(next)}">Next Section</a>` : `<span>Next Section</span>`}
    </div>
    <div class="divider-content">
      <p class="report-eyebrow">Start of Section</p>
      <span class="divider-ref">${escapeHtml(ref)}</span>
      <h2>${escapeHtml(title)}</h2>
      <p>${escapeHtml(guide)}</p>
      <div class="divider-expect-grid">
        <div><strong>What to expect</strong><span>Leadership-ready cards, charts, and interpretation from this selected view.</span></div>
        <div><strong>How to use it</strong><span>Review the headline signal first, then scan movement, risk, and action cues.</span></div>
        <div><strong>Navigation</strong><span>Use the links above to jump home, return to index, or move between sections.</span></div>
      </div>
      ${tab === "performancequestions" ? masterLensSubsectionJumps() : ""}
      ${boardPdfSectionDirectory(tabs, index)}
    </div>
    ${imageHtml}
  </section>`;
}

function boardPdfSectionWithDivider(tab, index, tabs) {
  return `${boardPdfSectionDivider(tab, index, tabs)}${cloneTabForReport(tab, index)}`;
}

function reportReferenceRows(tabs) {
  return tabs
    .map((tab, index) => {
      const ref = `R${String(index + 1).padStart(2, "0")}`;
      const source = $(tab);
      const isMasterLens = tab === "performancequestions";
      const cardCount = isMasterLens ? MASTER_LENS_EXPORT_TABS.length * 6 : source?.querySelectorAll(".metric-card, .quartile-kpi, .stat-card").length || 0;
      const chartCount = isMasterLens ? MASTER_LENS_EXPORT_TABS.length * 2 : source?.querySelectorAll("svg, canvas, .chart-card").length || 0;
      const tableCount = isMasterLens ? MASTER_LENS_EXPORT_TABS.length : source?.querySelectorAll("table").length || 0;
      return { ref, tab, title: PDF_TAB_TITLES[tab] || tab, cardCount, chartCount, tableCount };
    });
}

function reportIndexHtml(rows) {
  const listRows = rows
    .map(
      (row) => `<tr>
        <td><a class="report-index-link" href="#divider-${escapeHtml(row.tab)}">${escapeHtml(row.ref)}</a></td>
        <td><a class="report-index-link" href="#divider-${escapeHtml(row.tab)}">${escapeHtml(row.title)}</a></td>
        <td>${row.cardCount}</td>
        <td>${row.chartCount}</td>
        <td>${row.tableCount}</td>
      </tr>`
    )
    .join("");
  return `<section id="report-index" class="report-index-card">
    <p class="report-eyebrow">Index</p>
    <h2>Report Contents & Reference Sheets</h2>
    <p>Each selected dashboard tab is included as an executive reference sheet. Use the reference code beside each section title to connect the PDF/PPT page back to the source tab.</p>
    <table class="report-index-table">
      <thead><tr><th>Ref</th><th>Dashboard Sheet</th><th>Cards</th><th>Visuals</th><th>Tables</th></tr></thead>
      <tbody>${listRows}</tbody>
    </table>
  </section>`;
}

