  if (!reportWindow) {
    alert("The PDF report window was blocked. Please allow pop-ups for this local app.");
    return;
  }
  const references = reportReferenceRows(tabs);
  const sections = tabs.map((tab, index) => cloneTabForReport(tab, index)).join("");
  const generatedAt = new Date().toLocaleString();
  const baseHref = `${window.location.origin}${window.location.pathname.replace(/[^/]*$/, "")}`;
  reportWindow.document.open();
