  const latestWeekLabel = lensText(latest, ["Week", "Date", "Period"], "latest week");
  const priorWeekLabel = lensText(previous, ["Week", "Date", "Period"], "prior week");
  const latestWeekResponses = lensNumber(latest, ["Responses", "Total", "Count", "Records"], "");
