function normalizedAnalysisRows(analysis = {}) {
  return analysis.feedbackRows || analysis.feedbackTableRows || analysis.preview || state.statsData?.analyzedRows || [];
}

function hasActualNpsValues(rows = []) {
  const npsTypeCol = $("npsTypeCol")?.value || "";
  const scoreCol = $("scoreCol")?.value || "";
  const useNpsTypeCol = npsTypeCol && !isSentimentMappedAsNpsType(npsTypeCol);
  return (rows || []).some((row) => {
    if (normalizeNpsCategory(useNpsTypeCol ? row?.[npsTypeCol] : "")) return true;
    return Number.isFinite(parseMetricNumber(firstValue(row || {}, [scoreCol, "NPS Score", "NPS", "Inline NPS", "Rating", "Score"])));
  });
}

function normalizeNpsCountPayload(analysis = {}) {
  const rows = normalizedAnalysisRows(analysis);
  const summary = analysis.summary || {};
  const rawCounts = analysis.counts || {};
  const total = Number(summary.total || rawCounts.Total || rawCounts.Responses || rows.length || 0);
  const supplied = {
    Promoter: Number(rawCounts.Promoter ?? 0),
    Passive: Number(rawCounts.Passive ?? 0),
    Detractor: Number(rawCounts.Detractor ?? 0),
  };
  const suppliedTotal = supplied.Promoter + supplied.Passive + supplied.Detractor;
  const looksPercentShaped = total > 100 && suppliedTotal > 0 && Math.abs(suppliedTotal - 100) <= 1.5;
  const mismatchedTotal = total > 0 && suppliedTotal > 0 && Math.abs(suppliedTotal - total) > Math.max(2, total * 0.02);
  const missingCounts = total > 0 && suppliedTotal <= 0;
  const hasNpsRows = hasActualNpsValues(rows);
  if (!rows.length || (!hasNpsRows && !looksPercentShaped && !mismatchedTotal && !missingCounts)) return analysis || {};
  const rebuilt = npsDashboardSummary(rows);
  if (!rebuilt.total) return analysis || {};
  return {
    ...analysis,
    counts: {
      ...rawCounts,
      Total: rebuilt.total,
      Responses: rebuilt.total,
      Promoter: rebuilt.counts.Promoter,
      Passive: rebuilt.counts.Passive,
      Detractor: rebuilt.counts.Detractor,
    },
    summary: {
      ...summary,
      total: rebuilt.total,
      NPS: rebuilt.summary.NPS,
      nps: rebuilt.summary.NPS,
      Promoter: rebuilt.summary.Promoter,
      promoters: rebuilt.summary.promoters,
      passives: rebuilt.summary.passives,
      detractors: rebuilt.summary.detractors,
    },
  };
}

function normalizeBlankCommentSentiment(analysis) {
  // Defensive frontend guard: backend/local rules own sentiment classification.
  // Blank/no-verbatim rows are handled as blind-spot coverage in Master Lens, not forced negative here.
  return normalizeNpsCountPayload(analysis || {});
}

function executiveLensRows(analysis = state.analysis || {}) {
  return analysis.feedbackRows || analysis.feedbackTableRows || analysis.preview || state.statsData?.analyzedRows || state.statsData?.baseRows || [];
}

function executiveLensTopLabel(rows, keys) {
  const counts = new Map();
  (rows || []).forEach((row) => {
    const value = displayCellValue(firstValue(row || {}, keys)).trim();
    if (!value) return;
    counts.set(value, (counts.get(value) || 0) + 1);
  });
  return [...counts.entries()].sort((a, b) => b[1] - a[1])[0]?.[0] || "Not available";
}

function executiveLensSnapshot(analysis = state.analysis || {}) {
  const rows = executiveLensRows(analysis);
  const summary = analysis.summary || {};
  const counts = analysis.counts || {};
  const sentiment = analysis.sentiment || {};
  const total = Number(summary.total || counts.Total || counts.Responses || rows.length || 0);
  const promoter = Number(counts.Promoter || counts.Promoter || 0);
  const passive = Number(counts.Passive || counts.Passive || 0);
  const detractor = Number(counts.Detractor || counts.Detractor || 0);
  const nps = Number(summary.NPS ?? summary.nps ?? summary.nps ?? (total ? (promoter / total) * 100 : 0));
  const reasons = analysis.reasons || analysis.themeRows || [];
  return {
    rows,
    total,
    promoter,
    passive,
    detractor,
    nps,
    satRate: total ? (promoter / total) * 100 : 0,
    disRate: total ? (detractor / total) * 100 : 0,
    positive: Number(sentiment.Positive || 0),
    negative: Number(sentiment.Negative || 0),
    topDriver: reasons[0]?.["Primary Reason"] || reasons[0]?.Reason || reasons[0]?.Driver || reasons[0]?.Theme || executiveLensTopLabel(rows, ["Primary Reason", "Reason", "Issue Type", "Theme", "Driver"]),
    topAgent: executiveLensTopLabel(rows, [$("agentCol")?.value, "Agent", "Agent Name", "Advisor", "Employee"]),
    topManager: executiveLensTopLabel(rows, [$("managerCol")?.value, "Manager", "Manager / TL", "Team Manager", "TL"]),
    topChannel: executiveLensTopLabel(rows, ["Channel", "Contact Channel", "Survey Channel"]),
  };
}

