function resultFirstValue(row = {}, names = [], fallback = "") {
  for (const name of names) {
    const value = row?.[name];
    if (value !== undefined && value !== null && String(value).trim() !== "") return value;
  }
  const lookup = Object.fromEntries(Object.keys(row || {}).map((key) => [key.toLowerCase(), key]));
  for (const name of names) {
    const key = lookup[String(name).toLowerCase()];
    const value = key ? row[key] : "";
    if (value !== undefined && value !== null && String(value).trim() !== "") return value;
  }
  return fallback;
}

function resultScoreName(analysis = state.analysis || {}) {
  const summary = analysis.summary || {};
  return summary.CSAT !== undefined || summary.csat !== undefined ? "CSAT" : "NPS";
}

function resultAllRows(analysis = state.analysis || {}) {
  return analysis.feedbackRows || analysis.feedbackTableRows || analysis.preview || state.statsData?.analyzedRows || [];
}

function resultDimensionNumber(value) {
  const parsed = parseMetricNumber(value);
  return Number.isFinite(parsed) ? parsed : NaN;
}

function resultDimensionMetricValue(row = {}, scoreName = "NPS") {
  return resultDimensionNumber(resultFirstValue(row, [scoreName, scoreName.toLowerCase(), `${scoreName} Score`, "Score", "Rating", "Survey Score"], ""));
}

function resultDimensionSentimentValue(row = {}) {
  return String(resultFirstValue(row, ["Sentiment", "Sparrow Sentiment", "Sentiment Label", "AI Sentiment"], "")).trim().toLowerCase();
}

function resultDimensionThemeValue(row = {}) {
  return String(resultFirstValue(row, ["Theme", "Theme Group", "Primary Theme", "ACPT", "Driver", "Root Cause", "Reason"], "")).trim();
}

function resultDimensionExcludeColumn(column = "", scoreName = "NPS") {
  const text = String(column || "").toLowerCase();
  if (!text || text.startsWith("__")) return true;
  if (new RegExp(`\\b${scoreName.toLowerCase()}\\b|score|rating|target|gap|sentiment|theme|acpt|driver|resolution|confidence|positive|negative|neutral|satisfied|dissatisfied|promoter|passive|detractor`).test(text)) return true;
  return /id$|^id$|case|ticket|interaction|conversation|contact|phone|email|date|time|timestamp|comment|feedback|verbatim|text|summary|notes|url|link|rank|percent|pct|share|volume|count|row|index/.test(text);
}

function resultDimensionDisplayName(column = "") {
  const text = String(column || "").toLowerCase();
  if (/agent|advisor|employee/.test(text)) return "Agent";
  if (/manager|supervisor|team lead|\btl\b/.test(text)) return "Manager";
  return column || "Dimension";
}

function resultAutoDimensionRows(analysis = state.analysis || {}, scoreName = "NPS") {
  const rows = resultAllRows(analysis);
  if (!rows.length) return [];
  const totalRows = rows.length;
  const columns = Array.from(new Set(rows.slice(0, 250).flatMap((row) => Object.keys(row || {}))))
    .filter((column) => !resultDimensionExcludeColumn(column, scoreName));
  const output = [];
  columns.forEach((column) => {
    const displayDimension = resultDimensionDisplayName(column);
    if (displayDimension === "Agent" || displayDimension === "Manager") return;
    const values = rows.map((row) => String(row?.[column] ?? "").trim()).filter(Boolean);
    const unique = Array.from(new Set(values));
    if (unique.length < 2 || unique.length >= 15) return;
    const groups = new Map();
    rows.forEach((row) => {
      const value = String(row?.[column] ?? "").trim();
      if (!value) return;
      if (!groups.has(value)) groups.set(value, []);
      groups.get(value).push(row);
    });
    groups.forEach((groupRows, value) => {
      const scores = groupRows.map((row) => resultDimensionMetricValue(row, scoreName)).filter(Number.isFinite);
      const sentiments = groupRows.map(resultDimensionSentimentValue);
      const positive = sentiments.filter((item) => /positive|promoter|satisfied/.test(item)).length;
      const negative = sentiments.filter((item) => /negative|detractor|dissatisfied/.test(item)).length;
      const themeCounts = new Map();
      groupRows.forEach((row) => {
        const theme = resultDimensionThemeValue(row);
        if (theme) themeCounts.set(theme, (themeCounts.get(theme) || 0) + 1);
      });
      const topTheme = Array.from(themeCounts.entries()).sort((a, b) => b[1] - a[1])[0]?.[0] || "";
      const volume = groupRows.length;
      output.push({
        Dimension: displayDimension,
        "Dimension Value": value,
        Volume: volume,
        "Volume Share %": totalRows ? (volume / totalRows) * 100 : NaN,
        [scoreName]: scores.length ? average(scores) : NaN,
        "Positive %": groupRows.length ? (positive / groupRows.length) * 100 : NaN,
        "Negative Sentiment %": groupRows.length ? (negative / groupRows.length) * 100 : NaN,
        "Top Theme": topTheme,
        Source: "Auto",
      });
    });
  });
  return output;
}

function resultNormalizeDimensionRows(rows = [], analysis = state.analysis || {}, scoreName = "NPS") {
  const totalRows = Math.max(resultAllRows(analysis).length, Number(analysis.summary?.total || analysis.summary?.Total || 0), 1);
  const target = scoreName === "NPS"
    ? (typeof guidedNpsTargetValue === "function" ? guidedNpsTargetValue() : 0)
    : (typeof guidedCsatTargetValue === "function" ? guidedCsatTargetValue() : 85);
  const overall = resultDimensionNumber(resultFirstValue(analysis.summary || {}, [scoreName, scoreName.toLowerCase(), "Score"], NaN));
  const normalized = rows.map((row) => {
    const volume = resultDimensionNumber(resultFirstValue(row, ["Volume", "Rows", "Responses", "Count", "Total", "N"], NaN));
    const score = resultDimensionNumber(resultFirstValue(row, [scoreName, "CSAT", "NPS", "Score", "Average CSAT", "Average NPS"], NaN));
    const volumeShare = resultDimensionNumber(row["Volume Share %"]);
    const share = Number.isFinite(volumeShare) ? volumeShare : (Number.isFinite(volume) ? (volume / totalRows) * 100 : NaN);
    const negative = resultDimensionNumber(resultFirstValue(row, ["Negative Sentiment %", "Negative %", "Negative", "Negative Sentiment"], NaN));
    const positive = resultDimensionNumber(resultFirstValue(row, ["Positive %", "Positive", "Positive Sentiment"], NaN));
    const gapOverall = Number.isFinite(score) && Number.isFinite(overall) ? score - overall : NaN;
    const gapTarget = Number.isFinite(score) && Number.isFinite(target) ? score - target : NaN;
    const opportunity = Number.isFinite(gapOverall) && Number.isFinite(share) ? Math.abs(gapOverall) * share / 100 : NaN;
    const confidence = Number.isFinite(volume) && volume >= 30 ? "High" : Number.isFinite(volume) && volume >= 10 ? "Medium" : "Low";
    const decision = Number.isFinite(volume) && volume < 10 ? "Monitor" : (Number.isFinite(gapTarget) && gapTarget < -10) || (Number.isFinite(negative) && negative >= 30) ? "Actionable" : Number.isFinite(gapTarget) && gapTarget >= 0 ? "No Action Required" : "Monitor";
    const value = resultFirstValue(row, ["Dimension Value", "Value", "Segment", "Group", "Name", "Label"], "-");
    const insight = Number.isFinite(score)
      ? `${confidence} confidence segment ${Number.isFinite(gapOverall) ? `${Math.abs(gapOverall).toFixed(2)} pts ${gapOverall >= 0 ? "above" : "below"} overall` : "with score available"}${Number.isFinite(negative) ? `; negative sentiment ${negative.toFixed(2)}%` : ""}.`
      : `${confidence} confidence segment; score not available.`;
    return {
      Dimension: row.Dimension || "Dimension",
      "Dimension Value": value,
      Volume: Number.isFinite(volume) ? Math.round(volume) : "",
      "Volume Share %": Number.isFinite(share) ? Number(share.toFixed(2)) : "",
      [scoreName]: Number.isFinite(score) ? Number(score.toFixed(2)) : "",
      "Gap to Overall": Number.isFinite(gapOverall) ? Number(gapOverall.toFixed(2)) : "",
      "Gap to Target": Number.isFinite(gapTarget) ? Number(gapTarget.toFixed(2)) : "",
      "Negative Sentiment %": Number.isFinite(negative) ? Number(negative.toFixed(2)) : "",
      "Top Theme": resultFirstValue(row, ["Top Theme", "Theme", "Driver", "Root Cause"], ""),
      "Opportunity Size": Number.isFinite(opportunity) ? Number(opportunity.toFixed(2)) : "",
      Confidence: confidence,
      Decision: decision,
      Insight: insight,
      "Positive %": Number.isFinite(positive) ? Number(positive.toFixed(2)) : "",
    };
  });
  const byDimension = new Map();
  normalized.forEach((row) => {
    const key = String(row.Dimension || "Dimension");
    if (!byDimension.has(key)) byDimension.set(key, []);
    byDimension.get(key).push(row);
  });
  byDimension.forEach((items) => {
    items.sort((a, b) => Number(b[scoreName] || -Infinity) - Number(a[scoreName] || -Infinity));
    items.forEach((row, index) => { row.Rank = index + 1; });
  });
  return normalized.map((row) => ({
    Dimension: row.Dimension,
    "Dimension Value": row["Dimension Value"],
    Volume: row.Volume,
    "Volume Share %": row["Volume Share %"],
    [scoreName]: row[scoreName],
    "Gap to Overall": row["Gap to Overall"],
    "Gap to Target": row["Gap to Target"],
    "Negative Sentiment %": row["Negative Sentiment %"],
    "Top Theme": row["Top Theme"],
    "Opportunity Size": row["Opportunity Size"],
    Confidence: row.Confidence,
    Decision: row.Decision,
    Insight: row.Insight,
  }));
}

function resultMetricCards(containerId, cards = []) {
  const container = $(containerId);
  if (!container) return;
  container.innerHTML = cards.map((card) => `<article class="metric-card ${card.tone || ""}"><span>${escapeHtml(card.label)}</span><strong>${escapeHtml(card.value)}</strong><small>${escapeHtml(card.note || "")}</small></article>`).join("");
}

function resultReadoutList(containerId, items = []) {
  const container = $(containerId);
  if (!container) return;
  const rows = items.filter(Boolean);
  container.innerHTML = rows.length
    ? rows.map((item) => `<div class="driver-row"><span>${escapeHtml(item.label || item.title || "")}</span><strong>${escapeHtml(item.value || "")}</strong><small>${escapeHtml(item.note || item.text || "")}</small></div>`).join("")
    : '<p class="insight-text">Run analysis to generate this result.</p>';
}

function resultDimensionRows(analysis = state.analysis || {}) {
  const scoreName = resultScoreName(analysis);
  const mapRows = (rows = [], type, labelNames = []) => rows.slice(0, 12).map((row) => ({
    Dimension: type,
    "Dimension Value": resultFirstValue(row, labelNames, row.Segment || row.Group || row.Name || "-"),
    Volume: resultFirstValue(row, ["Rows", "Responses", "Count", "Total", "N"], ""),
    [scoreName]: resultFirstValue(row, [scoreName, "CSAT", "NPS", "Score", "Average CSAT", "Average NPS"], ""),
    "Positive %": resultFirstValue(row, ["Positive %", "Positive", "Positive Sentiment"], ""),
    "Negative Sentiment %": resultFirstValue(row, ["Negative %", "Negative", "Negative Sentiment"], ""),
    "Top Theme": resultFirstValue(row, ["Top Theme", "Theme", "Driver", "Root Cause"], ""),
  }));
  const dynamicRows = (analysis.dynamicDimensions || []).flatMap((dimension) => {
    const name = dimension.name || dimension.title || "Custom Dimension";
    return mapRows(dimension.rows || dimension.table || dimension.cards || [], name, [name, "Value", "Segment", "Group", "Name", "Label"]);
  });
  const peopleSourceRows = typeof performanceAgentSourceRows === "function" ? performanceAgentSourceRows(analysis) : resultAllRows(analysis);
  const calculatedAgentRows = typeof performanceAgentStatsRows === "function" ? performanceAgentStatsRows(peopleSourceRows, peopleSourceRows) : [];
  const calculatedManagerRows = typeof performanceManagerStatsRows === "function" ? performanceManagerStatsRows(peopleSourceRows, peopleSourceRows) : [];
  const existingRows = [
    ...mapRows(analysis.quartiles || analysis.quartileRollup || [], "Quartile", ["Quartile", "Segment", "Group"]),
    ...mapRows(analysis.wave || [], "Wave", ["Wave", "Segment", "Group"]),
    ...mapRows(analysis.tenure || [], "Tenure", ["Tenure", "Segment", "Group"]),
    ...mapRows(calculatedAgentRows, "Agent", ["Agent", "Agent Name", "Name"]),
    ...mapRows(calculatedManagerRows, "Manager", ["Manager", "Manager/Team", "Manager / TL", "Name"]),
    ...dynamicRows,
  ];
  const autoRows = resultAutoDimensionRows(analysis, scoreName);
  return resultNormalizeDimensionRows([...existingRows, ...autoRows], analysis, scoreName);
}

function resultDimensionTargetValue(metric = "NPS") {
  return metric === "NPS"
    ? (typeof guidedNpsTargetValue === "function" ? guidedNpsTargetValue() : 0)
    : (typeof guidedCsatTargetValue === "function" ? guidedCsatTargetValue() : 85);
}

function resultDimensionChartSummary(rows = [], metric = "NPS", selectedValue = "") {
  const scored = rows.filter((row) => Number.isFinite(Number(row[metric])));
  const scores = scored.map((row) => Number(row[metric]));
  const meanScore = scores.length ? average(scores) : NaN;
  const volatility = scores.length > 1 ? stdDev(scores) : NaN;
  const consistency = !Number.isFinite(volatility) ? "Pending" : volatility <= 4 ? "High" : volatility <= 9 ? "Moderate" : "Low";
  const best = scored.slice().sort((a, b) => Number(b[metric]) - Number(a[metric]))[0];
  const lowest = scored.slice().sort((a, b) => Number(a[metric]) - Number(b[metric]))[0];
  const volumeLead = rows.slice().sort((a, b) => Number(b.Volume || 0) - Number(a.Volume || 0))[0];
  const selected = rows.find((row) => String(row["Dimension Value"]) === String(selectedValue));
  const totalVolume = rows.reduce((sum, row) => sum + (Number(row.Volume) || 0), 0);
  const target = resultDimensionTargetValue(metric);
  const opportunity = scored.slice().sort((a, b) => {
    const aGap = Number.isFinite(meanScore) ? Math.max(0, meanScore - Number(a[metric])) : 0;
    const bGap = Number.isFinite(meanScore) ? Math.max(0, meanScore - Number(b[metric])) : 0;
    return (bGap * (Number(b.Volume) || 0)) - (aGap * (Number(a.Volume) || 0));
  })[0];
  return { scored, scores, meanScore, volatility, consistency, best, lowest, volumeLead, selected, totalVolume, target, opportunity };
}

function resultDimensionInsightStrip(rows = [], metric = "NPS", selectedValue = "") {
  const summary = resultDimensionChartSummary(rows, metric, selectedValue);
  if (!summary.scored.length) return "Score comparison is not available for this dimension.";
  const weakestGap = summary.lowest && Number.isFinite(summary.meanScore) ? summary.meanScore - Number(summary.lowest[metric]) : NaN;
  const selectedGap = summary.selected && Number.isFinite(summary.meanScore) ? Number(summary.selected[metric]) - summary.meanScore : NaN;
  const parts = [
    summary.lowest ? `${summary.lowest["Dimension Value"]} needs focus${Number.isFinite(weakestGap) ? `, ${formatDataPoint(Math.abs(weakestGap))} pts below average` : ""}.` : "",
    summary.best ? `${summary.best["Dimension Value"]} leads at ${formatDataPoint(Number(summary.best[metric]))}.` : "",
    summary.volumeLead ? `${summary.volumeLead["Dimension Value"]} has highest volume (${Math.round(Number(summary.volumeLead.Volume) || 0).toLocaleString()}).` : "",
    summary.selected ? `Selected segment is ${Number.isFinite(selectedGap) ? `${selectedGap >= 0 ? "above" : "below"} average by ${formatDataPoint(Math.abs(selectedGap))} pts` : "shown for context"}.` : "",
    `Consistency is ${summary.consistency.toLowerCase()}${Number.isFinite(summary.volatility) ? ` (SD ${formatDataPoint(summary.volatility)})` : ""}.`,
  ].filter(Boolean);
  return parts.join(" ");
}

function resultDimensionChartExplanation(rows = [], metric = "NPS", selectedValue = "") {
  const summary = resultDimensionChartSummary(rows, metric, selectedValue);
  if (!summary.scored.length) return "This view needs segment scores before it can explain the dimension.";
  const hitTarget = summary.scored.filter((row) => Number(row[metric]) >= Number(summary.target)).length;
  const aboveAvg = summary.scored.filter((row) => Number(row[metric]) >= summary.meanScore).length;
  const belowAvg = summary.scored.length - aboveAvg;
  const concentration = summary.totalVolume && summary.volumeLead ? (Number(summary.volumeLead.Volume || 0) / summary.totalVolume) * 100 : NaN;
  const opportunity = summary.opportunity?.["Dimension Value"] || summary.lowest?.["Dimension Value"] || "the weakest segment";
  const selected = summary.selected ? `${summary.selected["Dimension Value"]} is highlighted for reference` : "This chart is showing the selected dimension";
  return `${selected}. It compares score strength against volume weight: green ring is the best segment, red ring is the lowest score, and amber highlights the highest recovery opportunity. ${aboveAvg}/${summary.scored.length} segments are at or above average, ${belowAvg} are below average, and ${hitTarget} meet target. ${opportunity} should be reviewed first when volume and weak score combine. ${Number.isFinite(concentration) ? `The largest segment holds ${formatDataPoint(concentration)}% of this dimension volume.` : ""}`;
}

function renderResultDimensionChartSvg(chartId, rows = [], metric = "NPS", selectedValue = "") {
  const svg = $(chartId);
  if (!svg) return;
  const data = rows
    .filter((row) => row && row["Dimension Value"])
    .slice()
    .sort((a, b) => Number(b[metric] || -Infinity) - Number(a[metric] || -Infinity))
    .slice(0, 12);
  if (!data.length) {
    svg.innerHTML = `<text x="30" y="60" fill="#536c80" font-size="13">No dimension chart data available.</text>`;
    return;
  }
  const rowHeight = 24;
  const top = 48;
  const left = 160;
  const chartWidth = 430;
  const summary = resultDimensionChartSummary(rows, metric, selectedValue);
  const scaleMin = metric === "NPS" ? -100 : 0;
  const scaleMax = 100;
  const xForScore = (value) => left + ((Math.max(scaleMin, Math.min(scaleMax, Number(value) || 0)) - scaleMin) / (scaleMax - scaleMin)) * chartWidth;
  const xZero = xForScore(0);
  const maxVolume = Math.max(1, ...data.map((row) => Number(row.Volume) || 0));
  const volumeX = (value) => left + Math.max(0, Math.min(chartWidth, (Number(value) || 0) / maxVolume * chartWidth));
  const meanX = Number.isFinite(summary.meanScore) ? xForScore(summary.meanScore) : null;
  const targetX = Number.isFinite(Number(summary.target)) ? xForScore(summary.target) : null;
  const focusValue = summary.lowest?.["Dimension Value"];
  const bestValue = summary.best?.["Dimension Value"];
  const opportunityValue = summary.opportunity?.["Dimension Value"];
  const axisY = top + data.length * rowHeight + 20;
  const ticks = metric === "NPS" ? [-100, -50, 0, 50, 100] : [0, 25, 50, 75, 100];
  const tickHtml = ticks.map((value) => `<g>
    <line x1="${xForScore(value)}" y1="${axisY - 8}" x2="${xForScore(value)}" y2="${axisY - 2}" stroke="#b8d3dc"></line>
    <text x="${xForScore(value)}" y="${axisY + 12}" text-anchor="middle" fill="#536c80" font-size="10">${value}</text>
  </g>`).join("");
  const rowsHtml = data.map((row, index) => {
    const y = top + index * rowHeight;
    const isSelected = String(row["Dimension Value"]) === String(selectedValue);
    const isBest = String(row["Dimension Value"]) === String(bestValue);
    const isFocus = String(row["Dimension Value"]) === String(focusValue);
    const isOpportunity = String(row["Dimension Value"]) === String(opportunityValue);
    const score = Number(row[metric]);
    const scoreText = Number.isFinite(score) ? formatDataPoint(score) : "N/A";
    const volume = Number(row.Volume);
    const scoreX = xForScore(score);
    const barX = Math.min(xZero, scoreX);
    const barWidth = Math.max(4, Math.abs(scoreX - xZero));
    const gap = Number.isFinite(score) && Number.isFinite(summary.meanScore) ? score - summary.meanScore : NaN;
    const ring = isFocus
      ? `<circle class="trend-special-marker trend-special-marker-low" cx="${scoreX}" cy="${y + 6}" r="9" fill="none" stroke="#dc2626" stroke-width="1.8"></circle>`
      : isBest
        ? `<circle class="trend-special-marker trend-special-marker-high" cx="${scoreX}" cy="${y + 6}" r="9" fill="none" stroke="#16a34a" stroke-width="1.8"></circle>`
        : isOpportunity
          ? `<circle class="dimension-opportunity-ring" cx="${scoreX}" cy="${y + 6}" r="9" fill="none" stroke="#f59e0b" stroke-width="1.8"></circle>`
          : "";
    return `<g class="${isSelected ? "dimension-chart-selected" : ""}">
      <text x="12" y="${y + 13}" fill="#0c2340" font-size="10">${escapeHtml(String(row["Dimension Value"]).slice(0, 24))}</text>
      <rect x="${barX}" y="${y}" width="${barWidth}" height="12" rx="6" fill="${isSelected ? "#006d86" : isFocus ? "#fecaca" : isBest ? "#bbf7d0" : "#8bd9d2"}" opacity="${isSelected ? "0.92" : "0.72"}"></rect>
      ${ring}
      <circle cx="${volumeX(volume)}" cy="${y + 6}" r="${isSelected ? "5" : "3.5"}" fill="#14b8a6" stroke="#fff" stroke-width="1.5"></circle>
      <text x="${left + chartWidth + 18}" y="${y + 10}" fill="#0c2340" font-size="10">${escapeHtml(scoreText)} | Vol ${Number.isFinite(volume) ? Math.round(volume).toLocaleString() : "N/A"}${Number.isFinite(gap) ? ` | ${gap >= 0 ? "+" : ""}${formatDataPoint(gap)} vs avg` : ""}</text>
    </g>`;
  }).join("");
  svg.innerHTML = `<line x1="${left}" y1="20" x2="${left}" y2="${top + data.length * rowHeight + 4}" stroke="#d9e7ed"></line>
    <line x1="${left}" y1="${top + data.length * rowHeight + 4}" x2="${left + chartWidth}" y2="${top + data.length * rowHeight + 4}" stroke="#d9e7ed"></line>
    <line x1="${left}" y1="${axisY - 5}" x2="${left + chartWidth}" y2="${axisY - 5}" stroke="#d9e7ed"></line>
    ${tickHtml}
    <text x="${left + chartWidth / 2}" y="${axisY + 30}" text-anchor="middle" fill="#536c80" font-size="10">${escapeHtml(metric)} score scale</text>
    ${meanX ? `<line x1="${meanX}" y1="${top - 10}" x2="${meanX}" y2="${top + data.length * rowHeight + 4}" stroke="#7c3aed" stroke-width="1.6" opacity="0.72"></line><text x="${meanX + 4}" y="${top - 15}" font-size="10" fill="#6d28d9">Avg ${formatDataPoint(summary.meanScore)}</text>` : ""}
    ${targetX ? `<line x1="${targetX}" y1="${top - 10}" x2="${targetX}" y2="${top + data.length * rowHeight + 4}" stroke="#f59e0b" stroke-width="1.4" stroke-dasharray="6 6" opacity="0.82"></line><text x="${targetX + 4}" y="${top - 2}" font-size="10" fill="#b45309">Target ${formatDataPoint(Number(summary.target))}</text>` : ""}
    <g class="dimension-chart-legend">
      <circle cx="${left}" cy="14" r="4" fill="#006d86"></circle><text x="${left + 10}" y="18" font-size="10" fill="#0c2340">${escapeHtml(metric)}</text>
      <circle cx="${left + 72}" cy="14" r="4" fill="#14b8a6"></circle><text x="${left + 82}" y="18" font-size="10" fill="#0c2340">Volume</text>
      <circle cx="${left + 150}" cy="14" r="4" fill="#7c3aed"></circle><text x="${left + 160}" y="18" font-size="10" fill="#0c2340">Avg</text>
      <circle cx="${left + 208}" cy="14" r="4" fill="#f59e0b"></circle><text x="${left + 218}" y="18" font-size="10" fill="#0c2340">Target / opportunity</text>
    </g>
    ${rowsHtml}`;
}

function resultDimensionChartStatsHtml(rows = [], metric = "NPS", selectedValue = "") {
  const summary = resultDimensionChartSummary(rows, metric, selectedValue);
  const { scored, best, lowest, volumeLead, selected, totalVolume, meanScore, volatility, consistency, opportunity } = summary;
  const actionable = rows.filter((row) => /actionable/i.test(String(row.Decision || ""))).length;
  const topTheme = rows.map((row) => String(row["Top Theme"] || "").trim()).filter(Boolean)[0] || "Not available";
  const gap = best && lowest ? Number(best[metric]) - Number(lowest[metric]) : NaN;
  const targetHits = scored.filter((row) => Number(row[metric]) >= Number(summary.target)).length;
  const aboveAvg = scored.filter((row) => Number(row[metric]) >= meanScore).length;
  const belowAvg = scored.length - aboveAvg;
  const concentration = totalVolume && volumeLead ? (Number(volumeLead.Volume || 0) / totalVolume) * 100 : NaN;
  const reliability = totalVolume >= 100 ? "Strong" : totalVolume >= 30 ? "Directional" : "Low volume";
  const stat = (label, value, note = "") => `<article><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong>${note ? `<small>${escapeHtml(note)}</small>` : ""}</article>`;
  return [
    stat("Highlighted", selected?.["Dimension Value"] || "None", selected ? `${metric} ${formatDataPoint(Number(selected[metric]))} | Vol ${Math.round(Number(selected.Volume) || 0).toLocaleString()}` : "Showing the selected dimension"),
    stat("Best Segment", best?.["Dimension Value"] || "N/A", best ? `${metric} ${formatDataPoint(Number(best[metric]))}` : ""),
    stat("Needs Focus", lowest?.["Dimension Value"] || "N/A", lowest ? `${metric} ${formatDataPoint(Number(lowest[metric]))}` : ""),
    stat("Highest Volume", volumeLead?.["Dimension Value"] || "N/A", volumeLead ? `${Math.round(Number(volumeLead.Volume) || 0).toLocaleString()} rows` : ""),
    stat(`Avg ${metric}`, Number.isFinite(meanScore) ? formatDataPoint(meanScore) : "N/A"),
    stat("Consistency", consistency, Number.isFinite(volatility) ? `SD ${formatDataPoint(volatility)}` : "Needs more segments"),
    stat("Best vs Focus Gap", Number.isFinite(gap) ? `${formatDataPoint(gap)} pts` : "N/A"),
    stat("Focus Opportunity", opportunity?.["Dimension Value"] || "N/A", opportunity ? `Vol ${Math.round(Number(opportunity.Volume) || 0).toLocaleString()}` : ""),
    stat("Target Hit", `${targetHits}/${scored.length}`, `Target ${formatDataPoint(Number(summary.target))}`),
    stat("Above / Below Avg", `${aboveAvg} / ${belowAvg}`),
    stat("Volume Concentration", Number.isFinite(concentration) ? `${formatDataPoint(concentration)}%` : "N/A", volumeLead?.["Dimension Value"] || ""),
    stat("Reliability", reliability, `${Math.round(totalVolume).toLocaleString()} total rows`),
    stat("Total Volume", Math.round(totalVolume).toLocaleString()),
    stat("Actionable", actionable.toLocaleString(), "Segments requiring review"),
    stat("Top Theme", topTheme),
  ].join("");
}

function openResultDimensionChart(row = {}, rows = []) {
  const metric = resultScoreName(state.analysis || {});
  const dimension = String(row.Dimension || "Dimension");
  const selectedValue = String(row["Dimension Value"] || "");
  const dimensionRows = rows.filter((item) => String(item.Dimension || "") === dimension);
  document.querySelector(".dimension-chart-overlay")?.remove();
  const chartId = "resultDimensionInsightChart";
  const overlay = document.createElement("div");
  overlay.className = "dimension-chart-overlay period-chart-overlay";
  overlay.innerHTML = `<div class="period-chart-dialog dimension-chart-dialog" role="dialog" aria-modal="true">
    <button class="period-chart-close" type="button" aria-label="Close">x</button>
    <div class="period-chart-header">
      <div>
        <span>Dimension Insight</span>
        <h3>${escapeHtml(dimension)}</h3>
      </div>
      <p>Compare generated dimension values by ${escapeHtml(metric)}, volume, decision signal, and opportunity context.</p>
    </div>
    <div class="dimension-chart-strip">${escapeHtml(resultDimensionInsightStrip(dimensionRows, metric, selectedValue))}</div>
    <div class="period-chart-maximized-body dimension-chart-body">
      <section class="period-chart-panel dimension-chart-panel">
        <svg id="${chartId}" viewBox="0 0 760 340"></svg>
        <div class="dimension-chart-note">${escapeHtml(selectedValue ? `${selectedValue} is highlighted for reference.` : "Values are ranked by score; rings identify best, focus, and opportunity segments.")}</div>
      </section>
      <aside class="period-chart-stats dimension-chart-stats">${resultDimensionChartStatsHtml(dimensionRows, metric, selectedValue)}</aside>
    </div>
    <div class="dimension-chart-insight-box">
      <strong>Insight read:</strong> ${escapeHtml(row.Insight || "Use the strongest negative gaps, high volume, and actionable decisions to prioritize leadership review.")}
    </div>
    <div class="dimension-chart-insight-box dimension-chart-explain-box">
      <strong>What this is saying:</strong> ${escapeHtml(resultDimensionChartExplanation(dimensionRows, metric, selectedValue))}
    </div>
  </div>`;
  document.body.appendChild(overlay);
  renderResultDimensionChartSvg(chartId, dimensionRows, metric, selectedValue);
  const close = () => overlay.remove();
  overlay.querySelector(".period-chart-close")?.addEventListener("click", close);
  overlay.addEventListener("click", (event) => { if (event.target === overlay) close(); });
}

function renderResultDimensionInsightTable(rows = [], current = "All") {
  const table = $("resultDimensionTable");
  if (!table) return;
  if (!rows.length) {
    table.innerHTML = "<tbody><tr><td>No data available yet.</td></tr></tbody>";
    return;
  }
  const displayRows = rows.slice(0, tableDisplayLimit("resultDimensionTable"));
  const showDimension = current === "All";
  const columns = [
    ...(showDimension ? ["Dimension"] : []),
    "Dimension Value",
    "Volume",
    "Volume Share %",
    resultScoreName(state.analysis || {}),
    "Gap to Overall",
    "Gap to Target",
    "Negative Sentiment %",
    "Top Theme",
    "Opportunity Size",
    "Confidence",
    "Decision",
    "Insight",
  ].filter((column) => displayRows.some((row) => Object.prototype.hasOwnProperty.call(row, column)));
  const notice = rows.length > displayRows.length
    ? `<caption class="table-preview-caption">Showing ${displayRows.length.toLocaleString()} of ${rows.length.toLocaleString()} rows to keep the browser smooth. The chart uses the visible dimension group.</caption>`
    : "";
  table.innerHTML = `${notice}<thead><tr>${columns.map((column) => `<th class="${tableHeaderClass("resultDimensionTable", column)}" title="${escapeHtml(column)}">${escapeHtml(column)}</th>`).join("")}</tr></thead>
    <tbody>${displayRows.map((row) => `<tr>${columns.map((column) => `<td class="${cellClass(row[column])} ${tableHeaderClass("resultDimensionTable", column)}" title="${escapeHtml(column)}: ${escapeHtml(displayCellValue(row[column]))}"><span class="cell-value">${escapeHtml(displayCellValue(row[column]))}</span></td>`).join("")}</tr>`).join("")}</tbody>`;
}

function openResultDimensionChartForCurrent(rows = []) {
  const select = $("resultDimensionSelect");
  const current = select?.value || "All";
  const dimension = current === "All"
    ? String(rows.find((row) => row.Dimension)?.Dimension || "")
    : current;
  const dimensionRows = rows.filter((row) => String(row.Dimension || "") === dimension);
  if (!dimensionRows.length) {
    alert("Select a dimension with generated rows before opening the chart.");
    return;
  }
  openResultDimensionChart({ Dimension: dimension }, rows);
}

function renderResultDimensionTable(rows = []) {
  const select = $("resultDimensionSelect");
  const dimensions = ["All", ...Array.from(new Set(rows.map((row) => String(row.Dimension || "").trim()).filter(Boolean))).sort()];
  const current = select && dimensions.includes(select.value) ? select.value : "All";
  if (select) {
    select.innerHTML = dimensions.map((item) => `<option value="${escapeHtml(item)}">${escapeHtml(item === "All" ? "All Dimensions" : item)}</option>`).join("");
    select.value = current;
    if (select.dataset.boundResultDimensionSelect !== "1") {
      select.dataset.boundResultDimensionSelect = "1";
      select.addEventListener("change", () => renderResultDimensionTable(resultDimensionRows(state.analysis || {})));
    }
  }
  const filtered = current === "All" ? rows : rows.filter((row) => String(row.Dimension || "") === current);
  const chartButton = $("resultDimensionChartButton");
  if (chartButton && chartButton.dataset.boundDimensionChart !== "1") {
    chartButton.dataset.boundDimensionChart = "1";
    chartButton.addEventListener("click", () => openResultDimensionChartForCurrent(resultDimensionRows(state.analysis || {})));
  }
  if (chartButton) chartButton.disabled = !rows.length;
  if ($("resultDimensionsStatus")) {
    $("resultDimensionsStatus").textContent = rows.length
      ? `${filtered.length.toLocaleString()} of ${rows.length.toLocaleString()} dimension rows shown across ${Math.max(dimensions.length - 1, 0).toLocaleString()} dimensions.`
      : "Run analysis to populate this result.";
  }
  renderResultDimensionCards(filtered);
  renderResultDimensionInsightTable(filtered, current);
}

function resultDimensionQuartile(values = [], percentile = 0.25) {
  const sorted = values.map(Number).filter(Number.isFinite).sort((a, b) => a - b);
  if (!sorted.length) return NaN;
  const position = (sorted.length - 1) * percentile;
  const lower = Math.floor(position);
  const upper = Math.ceil(position);
  if (lower === upper) return sorted[lower];
  return sorted[lower] + (sorted[upper] - sorted[lower]) * (position - lower);
}

function resultDimensionMiniGraphHtml(item, metric = "NPS") {
  const scaleMin = metric === "NPS" ? -100 : 0;
  const scaleMax = 100;
  const clamp = (value) => Math.max(scaleMin, Math.min(scaleMax, Number(value) || 0));
  const percent = (value) => ((clamp(value) - scaleMin) / (scaleMax - scaleMin)) * 100;
  const bestScore = Number(item.best?.[metric]);
  const focusScore = Number(item.focus?.[metric]);
  const q1 = Number(item.q1);
  const q2 = Number(item.q2);
  const q3 = Number(item.q3);
  const min = Number(item.min);
  const max = Number(item.max);
  const avg = Number(item.avg);
  const iqrLeft = Number.isFinite(q1) ? percent(q1) : 0;
  const iqrRight = Number.isFinite(q3) ? percent(q3) : 0;
  const iqrWidth = Math.max(3, iqrRight - iqrLeft);
  const bestLeft = Number.isFinite(bestScore) ? percent(bestScore) : 0;
  const focusLeft = Number.isFinite(focusScore) ? percent(focusScore) : 0;
  const avgLeft = Number.isFinite(avg) ? percent(avg) : 0;
  const inspect = [
    item.dimension,
    item.best ? `Best ${item.best["Dimension Value"]} ${formatDataPoint(bestScore)}` : "",
    item.focus ? `Focus ${item.focus["Dimension Value"]} ${formatDataPoint(focusScore)}` : "",
    Number.isFinite(item.iqr) ? `IQR ${formatDataPoint(item.iqr)} pts` : "",
    Number.isFinite(min) && Number.isFinite(q1) && Number.isFinite(q2) && Number.isFinite(q3) && Number.isFinite(max)
      ? `Q1 ${formatDataPoint(min)}-${formatDataPoint(q1)} | Q2 ${formatDataPoint(q1)}-${formatDataPoint(q2)} | Q3 ${formatDataPoint(q2)}-${formatDataPoint(q3)} | Q4 ${formatDataPoint(q3)}-${formatDataPoint(max)}`
      : "",
    `Vol ${Math.round(item.volume).toLocaleString()}`,
  ].filter(Boolean).join(" | ");
  return `<article class="dimension-mini-graph" tabindex="0" data-inspect="${escapeHtml(inspect)}">
    <div class="dimension-mini-graph-head">
      <span>${escapeHtml(item.dimension)}</span>
      <strong>${Number.isFinite(item.iqr) ? `${formatDataPoint(item.iqr)} pts` : "N/A"} <em>IQR</em></strong>
    </div>
    <div class="dimension-mini-graph-body" aria-label="${escapeHtml(item.dimension)} ${escapeHtml(metric)} summary">
      <i class="dimension-mini-iqr" style="left:${iqrLeft.toFixed(2)}%;width:${iqrWidth.toFixed(2)}%"></i>
      ${Number.isFinite(avg) ? `<i class="dimension-mini-avg" style="left:${avgLeft.toFixed(2)}%"></i>` : ""}
      ${Number.isFinite(bestScore) ? `<b class="dimension-mini-dot best" style="left:${bestLeft.toFixed(2)}%" title="Best: ${escapeHtml(item.best["Dimension Value"])} ${formatDataPoint(bestScore)}"></b>` : ""}
      ${Number.isFinite(focusScore) ? `<b class="dimension-mini-dot focus" style="left:${focusLeft.toFixed(2)}%" title="Focus: ${escapeHtml(item.focus["Dimension Value"])} ${formatDataPoint(focusScore)}"></b>` : ""}
    </div>
    <div class="dimension-mini-labels">
      <span>Focus ${escapeHtml(item.focus?.["Dimension Value"] || "N/A")} ${Number.isFinite(focusScore) ? formatDataPoint(focusScore) : ""}</span>
      <span>Best ${escapeHtml(item.best?.["Dimension Value"] || "N/A")} ${Number.isFinite(bestScore) ? formatDataPoint(bestScore) : ""}</span>
    </div>
    <div class="dimension-mini-inspect">${escapeHtml(inspect)}</div>
  </article>`;
}

function renderResultDimensionCards(rows = []) {
  const container = $("resultDimensionCards");
  if (!container) return;
  const metric = resultScoreName(state.analysis || {});
  if (!rows.length) {
    container.innerHTML = "";
    return;
  }
  const groups = new Map();
  rows.forEach((row) => {
    const key = String(row.Dimension || "Dimension");
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(row);
  });
  const summaries = [...groups.entries()].map(([dimension, items]) => {
    const scored = items.filter((row) => Number.isFinite(Number(row[metric])));
    const scores = scored.map((row) => Number(row[metric]));
    const best = scored.slice().sort((a, b) => Number(b[metric]) - Number(a[metric]))[0];
    const focus = scored.slice().sort((a, b) => Number(a[metric]) - Number(b[metric]))[0];
    const volume = items.reduce((sum, row) => sum + (Number(row.Volume) || 0), 0);
    const q1 = resultDimensionQuartile(scores, 0.25);
    const q2 = resultDimensionQuartile(scores, 0.5);
    const q3 = resultDimensionQuartile(scores, 0.75);
    const min = scores.length ? Math.min(...scores) : NaN;
    const max = scores.length ? Math.max(...scores) : NaN;
    const avg = scores.length ? average(scores) : NaN;
    const iqr = Number.isFinite(q1) && Number.isFinite(q3) ? q3 - q1 : NaN;
    return { dimension, count: items.length, best, focus, volume, q1, q2, q3, min, max, avg, iqr };
  }).sort((a, b) => b.volume - a.volume || a.dimension.localeCompare(b.dimension));
  const top = summaries;
  container.classList.add("dimension-card-grid", "dimension-graph-grid");
  container.innerHTML = top.map((item) => resultDimensionMiniGraphHtml(item, metric)).join("");
}

function resultQuestionCategory(question = {}) {
  const text = `${question.category || ""} ${question.question || ""} ${question.logic || ""} ${question.text || ""}`.toLowerCase();
  if (/target|gap|above|below|met|miss/.test(text)) return "Target";
  if (/trend|movement|improv|declin|change|period|week|month|recover/.test(text)) return "Momentum";
  if (/risk|attention|detractor|dissatisfied|negative|weak|outlier|complaint/.test(text)) return "Risk";
  if (/stable|stability|consistent|volatile|variation|fluctuat|standard deviation|confidence/.test(text)) return "Stability";
  if (/agent|manager|team|people|coach|tl|supervisor/.test(text)) return "People";
  if (/driver|theme|reason|root|issue|voc|sentiment/.test(text)) return "Drivers";
  if (/correlation|relationship|influence|regression|r-squared|chi-square|significant/.test(text)) return "Correlation";
  if (/volume|sample|response|participation|count|rows|survey/.test(text)) return "Volume";
  return "General";
}

function resultStatusTone(status = "") {
  const text = String(status || "").toLowerCase();
  if (/action|review|required|investigate|attention/.test(text)) return "attention";
  if (/no action|no evidence|monitor|directional/.test(text)) return "monitor";
  return "pass";
}

function resultDecisionFocusBucket(status = "") {
  const text = String(status || "").toLowerCase();
  if (/no action|informational/.test(text)) {
    return { key: "noaction", label: "No Action Required", tone: "neutral", description: "Informational checks only." };
  }
  if (/favorable|healthy|pass|lower-risk|low risk/.test(text)) {
    return { key: "favorable", label: "Favorable", tone: "pass", description: "Healthy signals to maintain." };
  }
  if (/monitor|watch|directional|no evidence/.test(text)) {
    return { key: "monitor", label: "Monitor", tone: "monitor", description: "Watch before acting." };
  }
  return { key: "actionable", label: "Actionable", tone: "attention", description: "Needs follow-up or review." };
}

function resultDecisionShortResponse(question = {}) {
  const text = `${question.text || ""} ${question.answer || ""} ${question.status || ""}`.toLowerCase();
  if (/below target|target gap|miss|below/.test(text)) return "Below target";
  if (/above target|met target|at target|above/.test(text)) return "Above target";
  if (/declin|drop|down|worsen|negative momentum/.test(text)) return "Declining";
  if (/improv|increase|up|positive momentum|recover/.test(text)) return "Improving";
  if (/stable|flat|unchanged|consistent/.test(text)) return "Stable";
  if (/highest|best|top reliable|leads/.test(text)) return "Top segment";
  if (/lowest|weakest|needs focus|bottom/.test(text)) return "Needs focus";
  if (/negative sentiment|risk|review|required|actionable|investigate/.test(text)) return "Needs review";
  if (/monitor|directional|watch/.test(text)) return "Monitor";
  if (/favorable|healthy|controlled|low risk/.test(text)) return "Healthy";
  if (/no action|informational/.test(text)) return "No action";
  return resultDecisionFocusBucket(question.status || "Monitor").label;
}

function showResultDecisionFocusDetail(questions = [], bucketKey = "actionable", title = "Decision Checks") {
  const modal = $("summaryModal");
  const body = $("summaryBody");
  if (!modal || !body) return;
  const rows = questions.filter((question) => resultDecisionFocusBucket(question.status || "Monitor").key === bucketKey);
  body.innerHTML = `<div class="lens-question-popup decision-focus-detail">
    <p class="eyebrow">Decision Focus</p>
    <h2>${escapeHtml(title)}</h2>
    <p class="modal-subtitle">${rows.length.toLocaleString()} check${rows.length === 1 ? "" : "s"} in this decision group.</p>
    <div class="table-wrap fit-table compact-report-table">
      <table class="decision-question-table decision-focus-detail-table">
        <thead><tr><th>S.No</th><th>Category</th><th>Check</th><th>Response</th><th>Status</th></tr></thead>
        <tbody>${rows.length ? rows.map((question, index) => {
          const status = question.status || "Monitor";
          const tone = resultStatusTone(status);
          return `<tr>
            <td>${index + 1}</td>
            <td><strong>${escapeHtml(resultQuestionCategory(question))}</strong></td>
            <td>${escapeHtml(question.question || "Decision check")}</td>
            <td><span class="decision-short-response">${escapeHtml(resultDecisionShortResponse(question))}</span></td>
            <td><span class="decision-status-pill ${tone}">${escapeHtml(status)}</span></td>
          </tr>`;
        }).join("") : `<tr><td colspan="5">No checks are available in this group.</td></tr>`}</tbody>
      </table>
    </div>
  </div>`;
  modal.classList.remove("hidden");
}

function renderResultDecisionFocusCards(questions = [], selectedCategory = "All") {
  const container = $("resultDecisionFocusCards");
  if (!container) return;
  const categoryQuestions = questions.filter((question) => selectedCategory === "All" || resultQuestionCategory(question) === selectedCategory);
  const buckets = [
    resultDecisionFocusBucket("Actionable"),
    resultDecisionFocusBucket("Monitor"),
    resultDecisionFocusBucket("Favorable"),
    resultDecisionFocusBucket("No Action Required"),
  ];
  const grouped = new Map(buckets.map((bucket) => [bucket.key, { ...bucket, items: [] }]));
  categoryQuestions.forEach((question) => {
    const bucket = resultDecisionFocusBucket(question.status || "Monitor");
    grouped.get(bucket.key)?.items.push(question);
  });
  container.innerHTML = buckets.map((bucket) => {
    const group = grouped.get(bucket.key) || { ...bucket, items: [] };
    const checks = group.items.slice(0, 3).map((question) => `<li>${escapeHtml(question.question || "Decision check")}</li>`).join("");
    const more = group.items.length > 3 ? `<li class="decision-focus-more">+${group.items.length - 3} more checks</li>` : "";
    const empty = group.items.length ? "" : `<li class="decision-focus-empty">No checks in this group</li>`;
    return `<article class="decision-focus-card ${bucket.tone}" data-decision-focus-card="${escapeHtml(bucket.key)}" title="Double-click to view all ${escapeHtml(bucket.label)} checks">
      <div class="decision-focus-card-head">
        <span class="decision-status-pill ${bucket.tone}">${escapeHtml(bucket.label)}</span>
        <strong>${group.items.length}</strong>
      </div>
      <p>${escapeHtml(bucket.description)}</p>
      <ul>${checks}${more}${empty}</ul>
    </article>`;
  }).join("");
  container.querySelectorAll("[data-decision-focus-card]").forEach((card) => {
    card.addEventListener("dblclick", () => {
      const bucket = buckets.find((item) => item.key === card.dataset.decisionFocusCard) || buckets[0];
      showResultDecisionFocusDetail(categoryQuestions, bucket.key, bucket.label);
    });
  });
}

function renderResultDecisionQuestions(questions = [], selectedCategory = "All", selectedDecision = "All") {
  const container = $("resultDecisionGuide");
  const select = $("resultDecisionCategory");
  const decisionSelect = $("resultDecisionDecision");
  if (!container) return;
  const categories = ["All", ...Array.from(new Set(questions.map(resultQuestionCategory))).filter(Boolean).sort()];
  const decisions = ["All", ...Array.from(new Set(questions.map((question) => question.status || "Monitor"))).filter(Boolean).sort()];
  if (select) {
    const current = categories.includes(selectedCategory) ? selectedCategory : "All";
    select.innerHTML = categories.map((category) => `<option value="${escapeHtml(category)}"${category === current ? " selected" : ""}>${escapeHtml(category)}</option>`).join("");
    select.onchange = () => renderResultDecisionQuestions(questions, select.value || "All", decisionSelect?.value || "All");
    selectedCategory = current;
  }
  if (decisionSelect) {
    const currentDecision = decisions.includes(selectedDecision) ? selectedDecision : "All";
    decisionSelect.innerHTML = decisions.map((decision) => `<option value="${escapeHtml(decision)}"${decision === currentDecision ? " selected" : ""}>${escapeHtml(decision)}</option>`).join("");
    decisionSelect.onchange = () => renderResultDecisionQuestions(questions, select?.value || "All", decisionSelect.value || "All");
    selectedDecision = currentDecision;
  }
  renderResultDecisionFocusCards(questions, selectedCategory);
  const filtered = questions.filter((question) => {
    const categoryMatch = selectedCategory === "All" || resultQuestionCategory(question) === selectedCategory;
    const decisionMatch = selectedDecision === "All" || (question.status || "Monitor") === selectedDecision;
    return categoryMatch && decisionMatch;
  });
  container.classList.remove("driver-list");
  container.innerHTML = filtered.length ? `
    <div class="table-wrap fit-table compact-report-table">
      <table class="decision-question-table decision-check-table">
        <thead><tr><th>S.No</th><th>Category</th><th>Check</th><th>Response</th><th>Status</th><th>Info</th></tr></thead>
        <tbody>
          ${filtered.map((question, index) => {
            const originalIndex = Math.max(0, questions.indexOf(question));
            const status = question.status || "Monitor";
            const tone = resultStatusTone(status);
            const answer = question.text || question.answer || "Answered after the completed analysis is available.";
            const info = question.method || question.logic || question.statistics || question.guardrail || question.text || "";
            return `<tr>
              <td>${index + 1}</td>
              <td><strong>${escapeHtml(resultQuestionCategory(question))}</strong></td>
              <td>${escapeHtml(question.question || "Decision check")}</td>
              <td class="decision-response-cell" title="${escapeHtml(answer)}"><span>${escapeHtml(answer)}</span></td>
              <td><span class="decision-status-pill ${tone}">${escapeHtml(status)}</span></td>
              <td><button class="mini-info-button" type="button" data-result-question-info="${originalIndex}" title="${escapeHtml(info)}">i</button></td>
            </tr>`;
          }).join("")}
        </tbody>
      </table>
    </div>` : `<p class="insight-text">Run analysis to generate decision checks.</p>`;
  bindResultQuestionDetails(container);
}

