function resultEvidenceTable(rows = []) {
  const safeRows = Array.isArray(rows) ? rows.slice(0, 12) : [];
  if (!safeRows.length) return `<p class="insight-text">No row-level evidence is available for this question.</p>`;
  const columns = Array.from(new Set(safeRows.flatMap((row) => Object.keys(row || {})))).slice(0, 8);
  if (!columns.length) return `<p class="insight-text">No row-level evidence is available for this question.</p>`;
  return `<div class="table-wrap fit-table compact-report-table"><table class="decision-question-table">
    <thead><tr>${columns.map((column) => `<th>${escapeHtml(column)}</th>`).join("")}</tr></thead>
    <tbody>${safeRows.map((row) => `<tr>${columns.map((column) => `<td>${escapeHtml(displayCellValue(row?.[column]))}</td>`).join("")}</tr>`).join("")}</tbody>
  </table></div>`;
}

