function bindResultQuestionDetails(root = document) {
  root.querySelectorAll?.("[data-result-question-info]").forEach((button) => {
    if (button.dataset.boundQuestionInfo === "1") return;
    button.dataset.boundQuestionInfo = "1";
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      showResultQuestionDetail(button.dataset.resultQuestionInfo);
    });
  });
  root.querySelectorAll?.("[data-result-question-card]").forEach((card) => {
    if (card.dataset.boundQuestionCard === "1") return;
    card.dataset.boundQuestionCard = "1";
    card.addEventListener("dblclick", () => showResultQuestionDetail(card.dataset.resultQuestionCard));
  });
}

function resultSentimentQuestionAnswers(analysis = state.analysis || {}) {
  const sentiment = analysis.sentiment || {};
  const rows = resultAllRows(analysis);
  const outputRows = analysis.feedbackRows || analysis.feedbackTableRows || analysis.preview || rows || [];
  const total = Number(analysis.summary?.total || analysis.summary?.Total || outputRows.length || 0);
  const positive = Number(sentiment.Positive || sentiment.positive || 0);
  const neutral = Number(sentiment.Neutral || sentiment.neutral || 0);
  const negative = Number(sentiment.Negative || sentiment.negative || 0);
  const topTheme = (analysis.themeRows || analysis.themes || [])[0]?.Theme || (analysis.themeRows || analysis.themes || [])[0]?.Driver || "top available theme";
  const driverRows = analysis.drivers || analysis.reasons || analysis.themeRows || [];
  const topDriver = driverRows[0]?.Driver || driverRows[0]?.Reason || driverRows[0]?.Theme || topTheme;
  const enoughRows = total >= 100 ? "Strong" : total >= 30 ? "Directional" : "Limited";
  const answerFor = (question) => {
    const text = question.toLowerCase();
    if (/positive|promoter|satisfied|strength|replicate|working/.test(text)) return `Positive sentiment is ${formatMetric(positive)}% across ${total.toLocaleString()} analyzed rows. Use the strongest positive themes to identify what can be repeated.`;
    if (/negative|complaint|dissatisfied|risk|friction|pain|fix|recover/.test(text)) return `Negative sentiment is ${formatMetric(negative)}%. Start with ${topDriver || "the highest-volume negative driver"} where volume and dissatisfaction overlap.`;
    if (/neutral|passive|convert|opportunity/.test(text)) return `Neutral sentiment is ${formatMetric(neutral)}%. Treat neutral/passive feedback as a conversion opportunity when it clusters around fixable drivers.`;
    if (/theme|driver|root|reason|topic|issue/.test(text)) return `The leading available driver/theme is ${topDriver || topTheme}. Validate it against volume, sentiment, and score movement before assigning ownership.`;
    if (/volume|sample|coverage|representative|confidence/.test(text)) return `${enoughRows} evidence strength from ${total.toLocaleString()} rows. Segment-level answers should be read with volume and confidence checks.`;
    if (/trend|emerging|change|movement|week|period/.test(text)) return `Use the dated trend views with sentiment mix to confirm whether the signal is sustained or only a short-term movement.`;
    if (/agent|manager|team|owner|coaching/.test(text)) return `Use the agent and manager dashboards to assign ownership only where the sentiment signal has enough row volume and repeated evidence.`;
    return `This VOC question is answered from the completed analysis: ${formatMetric(positive)}% positive, ${formatMetric(neutral)}% neutral, ${formatMetric(negative)}% negative across ${total.toLocaleString()} rows.`;
  };
  const questions = [
    "What are customers saying most positively?",
    "What are customers saying most negatively?",
    "Which negative themes need immediate attention?",
    "Which positive themes should be replicated?",
    "Is negative sentiment concentrated or spread out?",
    "Is neutral feedback creating a conversion opportunity?",
    "Which issue is the clearest root-cause candidate?",
    "Which driver is most connected to dissatisfied records?",
    "Which driver is most connected to satisfied records?",
    "Are complaint themes increasing?",
    "Are positive themes increasing?",
    "Are there emerging VOC risks?",
    "Which customer comments need leadership attention?",
    "Which sentiment signal should be reviewed first?",
    "Is sentiment aligned with the score movement?",
    "Is the sentiment read strong enough to act on?",
    "Where should managers focus coaching?",
    "Which teams need VOC review?",
    "Which agents need verbatim review?",
    "Which themes are likely process issues?",
    "Which themes are likely knowledge or coaching issues?",
    "Which themes are likely customer expectation issues?",
    "Which issues appear preventable?",
    "Which issues are high-volume but lower-risk?",
    "Which issues are lower-volume but high-risk?",
    "What is the primary recovery opportunity?",
    "What is the primary sustainment opportunity?",
    "What should be escalated outside operations?",
    "What can be handled through coaching?",
    "What should be monitored rather than acted on now?",
    "Which comments explain the score gap?",
    "Which comments explain the latest movement?",
    "Which sentiment pattern supports the executive readout?",
    "Which VOC signal is most useful for clients?",
    "Which VOC signal is most useful for QA?",
    "Which VOC signal is most useful for operations?",
    "Which VOC signal is most useful for training?",
    "Which issue needs owner assignment?",
    "Which issue needs more evidence before action?",
    "Where is the no-comment or weak-comment blind spot?",
    "Are negative comments tied to specific groups?",
    "Are positive comments tied to specific groups?",
    "Which driver should be tracked next period?",
    "Which driver should be added to the action plan?",
    "Which sentiment read has the highest confidence?",
    "Which sentiment read has the lowest confidence?",
    "What should leadership communicate first?",
    "What should frontline leaders inspect first?",
    "What should be included in the next business review?",
    "What is the overall VOC conclusion?",
  ];
  return questions.map((question, index) => ({
    number: 51 + index,
    category: "Voice of Customer",
    question,
    text: answerFor(question),
    method: "Sentiment mix, analyzed feedback rows, available drivers/themes, and volume guardrails",
    status: negative >= 30 && /negative|risk|complaint|recover|immediate|escalat/i.test(question) ? "Actionable" : "Monitor",
  }));
}

async function renderLeadershipResultQuestions(analysis = state.analysis || {}) {
  const total = Number(analysis.summary?.total || analysis.summary?.Total || analysis.counts?.total || analysis.counts?.Total || resultAllRows(analysis).length || 0);
  if (!total) {
    renderResultDecisionQuestions([]);
    renderResultQuestionCards([]);
    return;
  }
  const scoreName = resultScoreName(analysis).toLowerCase();
  const isNps = scoreName === "nps";
  const targetValue = isNps ? (typeof guidedNpsTargetValue === "function" ? guidedNpsTargetValue() : 85) : (typeof guidedCsatTargetValue === "function" ? guidedCsatTargetValue() : 85);
  const payload = {
    mode: isNps ? "nps" : "csat",
    target: Number.isFinite(targetValue) ? targetValue : 85,
    minimumSample: 10,
    satisfiedMin: Number($("guidedCsatSatisfiedMin")?.value || $("csatSatisfiedMin")?.value || 4),
    neutralMin: Number($("guidedCsatNeutralMin")?.value || $("csatNeutralMin")?.value || 3),
    promoterMin: Number($("guidedNpsPromoterMin")?.value || $("npsPromoterMin")?.value || 9),
    passiveMin: Number($("guidedNpsPassiveMin")?.value || $("npsPassiveMin")?.value || 7),
    calendar: state.calendar || analysis.calendar || {},
    dateFilter: analysis.dateFilter || {},
  };
  try {
    if ($("resultDecisionStatus")) $("resultDecisionStatus").textContent = "Preparing decision checks...";
    if ($("resultRowsStatus")) $("resultRowsStatus").textContent = "Preparing answered questions...";
    const response = await fetch("/api/leadership-statistics", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const data = await response.json();
    if (!response.ok || data.ok === false) throw new Error(data.error || "Leadership question results are not available.");
    const questions = [...(Array.isArray(data.questions) ? data.questions : []), ...resultSentimentQuestionAnswers(analysis)];
    state.leadershipQuestions = questions;
    renderResultDecisionQuestions(questions);
    renderResultQuestionCards(questions);
    if ($("resultDecisionStatus")) $("resultDecisionStatus").textContent = `${questions.length.toLocaleString()} decision checks generated.`;
    if ($("resultRowsStatus")) $("resultRowsStatus").textContent = `${questions.length.toLocaleString()} answered leadership questions generated.`;
  } catch (error) {
    renderResultDecisionQuestions([]);
    renderResultQuestionCards([]);
    if ($("resultDecisionStatus")) $("resultDecisionStatus").textContent = error.message || "Decision checks are not available.";
    if ($("resultRowsStatus")) $("resultRowsStatus").textContent = error.message || "Answered questions are not available.";
  }
}

function resultTopNameShare(rows = [], nameKeys = [], valueKeys = []) {
  const source = Array.isArray(rows) ? rows : [];
  const first = source.find((row) => row && Object.keys(row).length);
  if (!first) return "";
  const name = resultFirstValue(first, nameKeys, first.Name || first.Driver || first.Theme || first.Reason || "General");
  const value = Number(resultFirstValue(first, valueKeys, first.Share || first.Percent || first.Count || first.Rows || NaN));
  return Number.isFinite(value) ? `${name} (${formatDataPoint(value)}%)` : String(name || "");
}

function resultDateWindowText(analysis = {}, rows = []) {
  const filter = analysis.dateFilter || {};
  if (filter.mode && filter.mode !== "All Time") {
    if (filter.mode === "Custom Range" && (filter.start || filter.end)) return `${filter.start || "start"} and ${filter.end || "latest"}`;
    return filter.mode;
  }
  const dates = (Array.isArray(rows) ? rows : [])
    .map((row) => row?.["Feedback Date"] || row?.Date || row?.Period || row?.Week)
    .map((value) => String(value || "").slice(0, 10))
    .filter((value) => /^\d{4}-\d{2}-\d{2}$/.test(value))
    .sort();
  if (dates.length) return `${dates[0]} and ${dates[dates.length - 1]}`;
  const weekly = Array.isArray(analysis.weekly) ? analysis.weekly : [];
  const periods = weekly.map((row) => String(row.Period || row.Week || row.Date || "").slice(0, 10)).filter(Boolean).sort();
  return periods.length ? `${periods[0]} and ${periods[periods.length - 1]}` : "the selected reporting period";
}

function resultPeriodDateValue(row = {}) {
  return String(row.Period || row.Week || row.Date || row.Month || "").slice(0, 10);
}

function resultPeriodVolumeValue(row = {}) {
  return Number(resultFirstValue(row, ["Responses", "Response Count", "Total", "Count", "Volume", "N", "Records"], NaN));
}

function resultPeriodScoreValue(row = {}, metric = "NPS") {
  return Number(resultFirstValue(row, [metric, "NPS", "CSAT", "Score"], NaN));
}

function resultMonthLabel(monthKey = "") {
  const [year, month] = String(monthKey).split("-").map(Number);
  if (!year || !month) return monthKey || "Month";
  return new Date(Date.UTC(year, month - 1, 1)).toLocaleString(undefined, { month: "short", year: "numeric" });
}

function resultWeeklyPeriodRows(analysis = {}, metric = "NPS") {
  return (Array.isArray(analysis.weekly) ? analysis.weekly : [])
    .map((row, index) => ({
      period: resultPeriodDateValue(row) || `Week ${index + 1}`,
      score: resultPeriodScoreValue(row, metric),
      volume: resultPeriodVolumeValue(row),
    }))
    .filter((row) => row.period && (Number.isFinite(row.score) || Number.isFinite(row.volume)));
}

function resultMonthlyPeriodRows(weeklyRows = []) {
  const buckets = new Map();
  weeklyRows.forEach((row) => {
    const key = /^\d{4}-\d{2}/.test(row.period) ? row.period.slice(0, 7) : "";
    if (!key) return;
    const bucket = buckets.get(key) || { period: resultMonthLabel(key), sortKey: key, scoreWeight: 0, weight: 0, volume: 0 };
    const weight = Number.isFinite(row.volume) && row.volume > 0 ? row.volume : 1;
    if (Number.isFinite(row.score)) {
      bucket.scoreWeight += row.score * weight;
      bucket.weight += weight;
    }
    if (Number.isFinite(row.volume)) bucket.volume += row.volume;
    buckets.set(key, bucket);
  });
  return [...buckets.values()]
    .sort((a, b) => a.sortKey.localeCompare(b.sortKey))
    .map((row) => ({
      period: row.period,
      key: row.sortKey,
      score: row.weight ? row.scoreWeight / row.weight : NaN,
      volume: row.volume,
    }));
}

function resultCalendarWeekStartIndex() {
  const label = String((state.analysis?.calendar || selectedCalendarConfig()).weekStartDay || "Monday").toLowerCase();
  return ["sunday", "monday", "tuesday", "wednesday", "thursday", "friday", "saturday"].indexOf(label) >= 0
    ? ["sunday", "monday", "tuesday", "wednesday", "thursday", "friday", "saturday"].indexOf(label)
    : 1;
}

function resultDateFromRow(row = {}) {
  const mapped = $("dateCol")?.value || "";
  const value = resultFirstValue(row, [mapped, "Feedback Date", "Response Date", "Conversation Date", "Survey Date", "Created Date", "Date", "Week", "Period"], "");
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function resultLocalDateKey(date) {
  if (!date || Number.isNaN(date.getTime())) return "";
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`;
}

function resultWeekKeyForDate(date) {
  if (!date) return "";
  const startDay = resultCalendarWeekStartIndex();
  const normalized = new Date(date.getFullYear(), date.getMonth(), date.getDate());
  const diff = (normalized.getDay() - startDay + 7) % 7;
  normalized.setDate(normalized.getDate() - diff);
  return resultLocalDateKey(normalized);
}

function resultMonthKeyForDate(date) {
  return date ? `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}` : "";
}

function resultPeriodDetailRows(kind, key) {
  const rows = allFeedbackRows();
  if (!rows.length || !key) return [];
  return rows.filter((row) => {
    const date = resultDateFromRow(row);
    if (!date) return false;
    return kind === "month" ? resultMonthKeyForDate(date) === key : resultWeekKeyForDate(date) === key;
  });
}

function resultRawScore(row = {}, metric = "NPS") {
  const type = String(resultFirstValue(row, [metric === "NPS" ? "NPS Type" : "CSAT Type", "Satisfaction Level", "Category"], "")).toLowerCase();
  if (metric === "NPS") {
    if (type.includes("promoter")) return 100;
    if (type.includes("passive")) return 0;
    if (type.includes("detractor")) return -100;
  } else {
    if (type.includes("dissatisfied")) return 0;
    if (type.includes("satisfied")) return 100;
    if (type.includes("neutral")) return 50;
  }
  const mapped = $("scoreCol")?.value || "";
  const numeric = parseMetricNumber(resultFirstValue(row, [mapped, metric, `${metric} Score`, "Score", "Rating"], ""));
  if (!Number.isNaN(numeric)) return numeric;
  return NaN;
}

function resultGroupStats(rows = [], metric = "NPS", nameFn = agentName) {
  const groups = new Map();
  rows.forEach((row) => {
    const name = nameFn(row) || "Unknown";
    if (!name || name === "Unknown") return;
    const score = resultRawScore(row, metric);
    const group = groups.get(name) || { name, scores: [], volume: 0 };
    group.volume += 1;
    if (Number.isFinite(score)) group.scores.push(score);
    groups.set(name, group);
  });
  return [...groups.values()]
    .map((group) => ({ ...group, score: group.scores.length ? average(group.scores) : NaN }))
    .filter((group) => Number.isFinite(group.score))
    .sort((a, b) => b.score - a.score || b.volume - a.volume);
}

function resultQuartileAverages(rows = [], metric = "NPS") {
  const scores = rows.map((row) => resultRawScore(row, metric)).filter(Number.isFinite).sort((a, b) => b - a);
  if (!scores.length) return [];
  const labels = ["Q1", "Q2", "Q3", "Q4"];
  return labels.map((label, index) => {
    const start = Math.floor(index * scores.length / 4);
    const end = Math.floor((index + 1) * scores.length / 4);
    const chunk = scores.slice(start, Math.max(end, start + 1));
    return { label, score: average(chunk), volume: chunk.length };
  });
}

function showResultPeriodDetail(kind, row = {}, metric = "NPS") {
  const key = row.key || row.period;
  const rows = resultPeriodDetailRows(kind, key);
  const quartiles = resultQuartileAverages(rows, metric);
  const agents = resultGroupStats(rows, metric, agentName);
  const managers = resultGroupStats(rows, metric, managerName);
  const bestAgent = agents[0];
  const bestManager = managers[0];
  const focusAgent = agents[agents.length - 1];
  const focusManager = managers[managers.length - 1];
  const scoreText = Number.isFinite(row.score) ? formatDataPoint(row.score) : "N/A";
  const volumeText = Number.isFinite(row.volume) ? Math.round(row.volume).toLocaleString() : rows.length.toLocaleString();
  const overlay = document.createElement("div");
  document.querySelector(".performance-logic-overlay")?.remove();
  overlay.className = "performance-logic-overlay";
  overlay.innerHTML = `<div class="performance-logic-dialog result-period-dialog" role="dialog" aria-modal="true">
    <button class="performance-logic-close" type="button" aria-label="Close">×</button>
    <span>Period Detail</span>
    <h3>${escapeHtml(kind === "month" ? "Monthly" : "Weekly")} detail: ${escapeHtml(row.period || key)}</h3>
    <div class="result-period-summary">
      <article><span>${escapeHtml(metric)}</span><strong>${escapeHtml(scoreText)}</strong><small>Period score</small></article>
      <article><span>Volume</span><strong>${escapeHtml(volumeText)}</strong><small>Rows in this period</small></article>
      <article><span>Best Agent</span><strong>${escapeHtml(bestAgent ? bestAgent.name : "N/A")}</strong><small>${bestAgent ? `${formatDataPoint(bestAgent.score)} | ${bestAgent.volume.toLocaleString()} rows` : "Not available"}</small></article>
      <article><span>Best Manager</span><strong>${escapeHtml(bestManager ? bestManager.name : "N/A")}</strong><small>${bestManager ? `${formatDataPoint(bestManager.score)} | ${bestManager.volume.toLocaleString()} rows` : "Not available"}</small></article>
      <article class="focus"><span>Agent Needing Focus</span><strong>${escapeHtml(focusAgent ? focusAgent.name : "N/A")}</strong><small>${focusAgent ? `${formatDataPoint(focusAgent.score)} | ${focusAgent.volume.toLocaleString()} rows` : "Not available"}</small></article>
      <article class="focus"><span>Manager Needing Focus</span><strong>${escapeHtml(focusManager ? focusManager.name : "N/A")}</strong><small>${focusManager ? `${formatDataPoint(focusManager.score)} | ${focusManager.volume.toLocaleString()} rows` : "Not available"}</small></article>
    </div>
    <h4>Q1-Q4 averages</h4>
    <div class="result-period-quartiles">${quartiles.length ? quartiles.map((item) => `<article><span>${item.label}</span><strong>${formatDataPoint(item.score)}</strong><small>${item.volume.toLocaleString()} rows</small></article>`).join("") : "<p>No score rows available for quartile averages.</p>"}</div>
    <h4>Top period performers</h4>
    <div class="result-period-tables">
      <table><thead><tr><th>Agent</th><th>${escapeHtml(metric)}</th><th>Volume</th></tr></thead><tbody>${agents.slice(0, 5).map((item) => `<tr><td>${escapeHtml(item.name)}</td><td>${formatDataPoint(item.score)}</td><td>${item.volume.toLocaleString()}</td></tr>`).join("") || '<tr><td colspan="3">No agent detail available.</td></tr>'}</tbody></table>
      <table><thead><tr><th>Manager</th><th>${escapeHtml(metric)}</th><th>Volume</th></tr></thead><tbody>${managers.slice(0, 5).map((item) => `<tr><td>${escapeHtml(item.name)}</td><td>${formatDataPoint(item.score)}</td><td>${item.volume.toLocaleString()}</td></tr>`).join("") || '<tr><td colspan="3">No manager detail available.</td></tr>'}</tbody></table>
    </div>
    <h4>Needs focus</h4>
    <div class="result-period-tables">
      <table><thead><tr><th>Agent</th><th>${escapeHtml(metric)}</th><th>Volume</th></tr></thead><tbody>${agents.slice(-5).reverse().map((item) => `<tr><td>${escapeHtml(item.name)}</td><td>${formatDataPoint(item.score)}</td><td>${item.volume.toLocaleString()}</td></tr>`).join("") || '<tr><td colspan="3">No agent focus detail available.</td></tr>'}</tbody></table>
      <table><thead><tr><th>Manager</th><th>${escapeHtml(metric)}</th><th>Volume</th></tr></thead><tbody>${managers.slice(-5).reverse().map((item) => `<tr><td>${escapeHtml(item.name)}</td><td>${formatDataPoint(item.score)}</td><td>${item.volume.toLocaleString()}</td></tr>`).join("") || '<tr><td colspan="3">No manager focus detail available.</td></tr>'}</tbody></table>
    </div>
  </div>`;
  document.body.appendChild(overlay);
  const close = () => overlay.remove();
  overlay.querySelector(".performance-logic-close")?.addEventListener("click", close);
  overlay.addEventListener("click", (event) => { if (event.target === overlay) close(); });
}

function resultPeriodTrendBadge(current, previous, { volume = false } = {}) {
  if (!Number.isFinite(current) || !Number.isFinite(previous)) return '<span class="period-indicator na">First</span>';
  const delta = current - previous;
  const direction = Math.abs(delta) < 0.005 ? "flat" : delta > 0 ? "up" : "down";
  const label = direction === "up" ? "Up" : direction === "down" ? "Down" : "Flat";
  const value = volume ? Math.round(Math.abs(delta)).toLocaleString() : formatDataPoint(Math.abs(delta));
  return `<span class="period-indicator ${direction}">${label} ${direction === "flat" ? value : `${delta > 0 ? "+" : "-"}${value}`}</span>`;
}

function renderPerformancePeriodTable(tableId, rows = [], periodLabel = "Period", metric = "NPS", kind = "week") {
  const table = $(tableId);
  if (!table) return;
  table.classList.add("performance-period-table");
  if (!rows.length) {
    table.innerHTML = `<thead><tr><th>${periodLabel}</th><th>${metric}</th><th>Volume</th></tr></thead><tbody><tr><td colspan="3">Run analysis with a mapped date field to populate period movement.</td></tr></tbody>`;
    return;
  }
  const displayRows = rows.map((row, index) => ({ ...row, previous: rows[index - 1] || {} })).slice().reverse();
  table.innerHTML = `<thead><tr><th>${periodLabel}</th><th>${metric}</th><th>Volume</th></tr></thead><tbody>${displayRows.map((row) => {
    const previous = row.previous || {};
    const scoreText = Number.isFinite(row.score) ? formatDataPoint(row.score) : "N/A";
    const volumeText = Number.isFinite(row.volume) ? Math.round(row.volume).toLocaleString() : "N/A";
    return `<tr data-period-detail="${escapeHtml(row.key || row.period)}" title="Double-click for ${escapeHtml(periodLabel.toLowerCase())} details" tabindex="0">
      <td><strong>${escapeHtml(row.period)}</strong></td>
      <td><div class="period-cell"><strong>${scoreText}</strong>${resultPeriodTrendBadge(row.score, previous.score)}</div></td>
      <td><div class="period-cell"><strong>${volumeText}</strong>${resultPeriodTrendBadge(row.volume, previous.volume, { volume: true })}</div></td>
    </tr>`;
  }).join("")}</tbody>`;
  const byKey = new Map(rows.map((row) => [String(row.key || row.period), row]));
  table.querySelectorAll("tbody tr[data-period-detail]").forEach((tr) => {
    const open = () => showResultPeriodDetail(kind, byKey.get(tr.dataset.periodDetail) || { period: tr.dataset.periodDetail, key: tr.dataset.periodDetail }, metric);
    tr.addEventListener("dblclick", open);
    tr.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        open();
      }
    });
  });
}

function resultPeriodChartStats(rows = []) {
  const scored = rows.filter((row) => Number.isFinite(row.score));
  const volumes = rows.map((row) => Number(row.volume)).filter(Number.isFinite);
  const scores = scored.map((row) => row.score).sort((a, b) => a - b);
  const best = scored.slice().sort((a, b) => b.score - a.score)[0];
  const lowest = scored.slice().sort((a, b) => a.score - b.score)[0];
  const latest = rows[rows.length - 1] || {};
  const previous = rows[rows.length - 2] || {};
  const movement = Number.isFinite(latest.score) && Number.isFinite(previous.score) ? latest.score - previous.score : NaN;
  const median = scores.length ? (scores.length % 2 ? scores[(scores.length - 1) / 2] : average([scores[(scores.length / 2) - 1], scores[scores.length / 2]])) : NaN;
  const range = scores.length ? scores[scores.length - 1] - scores[0] : NaN;
  return {
    best,
    lowest,
    mean: scored.length ? average(scored.map((row) => row.score)) : NaN,
    median,
    volatility: scored.length > 1 ? stdDev(scored.map((row) => row.score)) : NaN,
    range,
    totalVolume: volumes.reduce((sum, value) => sum + value, 0),
    avgVolume: volumes.length ? average(volumes) : NaN,
    latest,
    movement,
  };
}

function resultPeriodChartStatHtml(rows = [], metric = "NPS", label = "Period") {
  const stats = resultPeriodChartStats(rows);
  const stat = (name, value, note = "") => `<article><span>${escapeHtml(name)}</span><strong>${escapeHtml(value)}</strong>${note ? `<small>${escapeHtml(note)}</small>` : ""}</article>`;
  return [
    stat(`Best ${label}`, stats.best?.period || "N/A", stats.best ? `${metric} ${formatDataPoint(stats.best.score)} | Vol ${Math.round(stats.best.volume || 0).toLocaleString()}` : ""),
    stat(`Lowest ${label}`, stats.lowest?.period || "N/A", stats.lowest ? `${metric} ${formatDataPoint(stats.lowest.score)} | Vol ${Math.round(stats.lowest.volume || 0).toLocaleString()}` : ""),
    stat(`Mean ${metric}`, Number.isFinite(stats.mean) ? formatDataPoint(stats.mean) : "N/A"),
    stat(`Median ${metric}`, Number.isFinite(stats.median) ? formatDataPoint(stats.median) : "N/A"),
    stat("Volatility", Number.isFinite(stats.volatility) ? formatDataPoint(stats.volatility) : "N/A", "Std dev"),
    stat(`${metric} Range`, Number.isFinite(stats.range) ? formatDataPoint(stats.range) : "N/A"),
    stat("Total Volume", Math.round(stats.totalVolume || 0).toLocaleString()),
    stat("Avg Volume", Number.isFinite(stats.avgVolume) ? Math.round(stats.avgVolume).toLocaleString() : "N/A"),
    stat("Latest", stats.latest?.period || "N/A", Number.isFinite(stats.latest?.score) ? `${metric} ${formatDataPoint(stats.latest.score)}` : ""),
    stat("Latest Movement", Number.isFinite(stats.movement) ? `${stats.movement >= 0 ? "+" : ""}${formatDataPoint(stats.movement)} pts` : "N/A"),
  ].join("");
}

function resultPeriodChartInsightHtml(rows = [], metric = "NPS", target = 0) {
  const scored = rows.filter((row) => Number.isFinite(row.score));
  const scores = scored.map((row) => row.score);
  const volumes = rows.map((row) => Number(row.volume)).filter(Number.isFinite);
  const latest = rows[rows.length - 1] || {};
  const first = scored[0] || {};
  const mean = scores.length ? average(scores) : NaN;
  const volatility = scores.length > 1 ? stdDev(scores) : NaN;
  const movement = Number.isFinite(latest.score) && Number.isFinite(first.score) ? latest.score - first.score : NaN;
  const avgVolume = volumes.length ? average(volumes) : NaN;
  const latestVolume = Number(latest.volume);
  const direction = !Number.isFinite(movement) || Math.abs(movement) < 1 ? "Stable" : movement > 0 ? "Improving" : "Declining";
  const volatilityText = Number.isFinite(volatility) && Number.isFinite(mean) && Math.abs(volatility) > Math.max(5, Math.abs(mean) * 0.16) ? "Volatile" : "Controlled";
  const confidence = Number.isFinite(latestVolume) && Number.isFinite(avgVolume)
    ? latestVolume >= avgVolume * 0.8 ? "Volume quality is healthy" : "Latest period is lower volume"
    : "Volume quality pending";
  const targetGap = Number.isFinite(latest.score) && Number.isFinite(Number(target)) ? latest.score - Number(target) : NaN;
  const insight = Number.isFinite(targetGap)
    ? `${metric} is ${targetGap >= 0 ? "above" : "below"} target by ${formatDataPoint(Math.abs(targetGap))} pts.`
    : "Target comparison is not available.";
  return `<div class="period-chart-insights">
    <article><span>Trend interpretation</span><strong>${escapeHtml(direction)}</strong><small>${Number.isFinite(movement) ? `${movement >= 0 ? "+" : ""}${formatDataPoint(movement)} pts across the shown range` : "Movement pending"}</small></article>
    <article><span>Stability read</span><strong>${escapeHtml(volatilityText)}</strong><small>${Number.isFinite(volatility) ? `Volatility ${formatDataPoint(volatility)}` : "Volatility pending"}</small></article>
    <article><span>Volume quality note</span><strong>${escapeHtml(confidence)}</strong><small>${Number.isFinite(latestVolume) ? `Latest volume ${Math.round(latestVolume).toLocaleString()}` : "Latest volume pending"}</small></article>
    <article><span>Target read</span><strong>${escapeHtml(insight)}</strong><small>Target ${formatDataPoint(Number(target))}</small></article>
  </div>`;
}

function resultPeriodWindowOptions(kind = "weekly") {
  return kind === "monthly"
    ? [
      ["all", "All months"],
      ["1", "Past 1 month"],
      ["2", "Past 2 months"],
      ["3", "Past 3 months"],
      ["6", "Past 6 months"],
      ["12", "Past 12 months"],
    ]
    : [
      ["all", "All weeks"],
      ["1", "Past 1 week"],
      ["2", "Past 2 weeks"],
      ["4", "Past 4 weeks"],
      ["8", "Past 8 weeks"],
      ["12", "Past 12 weeks"],
      ["26", "Past 26 weeks"],
    ];
}

function resultPeriodDefaultWindow(kind = "weekly", rowCount = 0) {
  if (kind === "weekly") return rowCount > 12 ? "12" : "all";
  return rowCount > 12 ? "12" : "all";
}

function resultPeriodWindowRows(rows = [], windowValue = "all") {
  const count = windowValue === "all" ? rows.length : Number(windowValue);
  if (!Number.isFinite(count) || count <= 0 || count >= rows.length) return rows;
  return rows.slice(-count);
}

function openResultPeriodChartOverlay(kind = "weekly") {
  const config = state.resultPeriodChartData?.[kind];
  if (!config || !config.rows?.length) {
    alert("Run analysis to populate this chart first.");
    return;
  }
  document.querySelector(".period-chart-overlay")?.remove();
  const chartId = `maximized${kind === "monthly" ? "Monthly" : "Weekly"}PerformanceTrend`;
  const defaultWindow = resultPeriodDefaultWindow(kind, config.rows.length);
  const scopedRows = resultPeriodWindowRows(config.rows, defaultWindow);
  const targetValue = config.metric === "NPS"
    ? (typeof guidedNpsTargetValue === "function" ? guidedNpsTargetValue() : 0)
    : (typeof guidedCsatTargetValue === "function" ? guidedCsatTargetValue() : 85);
  const overlay = document.createElement("div");
  overlay.className = "period-chart-overlay";
  overlay.innerHTML = `<div class="period-chart-dialog" role="dialog" aria-modal="true">
    <button class="period-chart-close" type="button" aria-label="Close">x</button>
    <div class="period-chart-header">
      <div>
        <span>Performance Trend</span>
        <h3>${escapeHtml(config.title)}</h3>
      </div>
      <p>Hover anywhere on the chart to inspect period movement, rank, target gap, and volume share.</p>
    </div>
    <div class="period-chart-insight-slot">${resultPeriodChartInsightHtml(scopedRows, config.metric, targetValue)}</div>
    <div class="period-chart-maximized-body">
      <section class="period-chart-panel">
        <svg id="${chartId}" viewBox="0 0 760 260"></svg>
        <div class="period-chart-window-control">
          <label for="${chartId}Window">Show me</label>
          <select id="${chartId}Window">
            ${resultPeriodWindowOptions(kind).map(([value, label]) => `<option value="${value}"${value === defaultWindow ? " selected" : ""}>${label}</option>`).join("")}
          </select>
        </div>
      </section>
      <aside class="period-chart-stats">${resultPeriodChartStatHtml(scopedRows, config.metric, config.label)}</aside>
    </div>
  </div>`;
  document.body.appendChild(overlay);
  const renderScopedChart = () => {
    const selectedWindow = overlay.querySelector(`#${chartId}Window`)?.value || defaultWindow;
    const rows = resultPeriodWindowRows(config.rows, selectedWindow);
    overlay.querySelector(".period-chart-insight-slot").innerHTML = resultPeriodChartInsightHtml(rows, config.metric, targetValue);
    overlay.querySelector(".period-chart-stats").innerHTML = resultPeriodChartStatHtml(rows, config.metric, config.label);
    renderScoreVolumeLineChart(chartId, rows.map((row) => ({ Week: row.period, [config.metric]: row.score, Volume: row.volume })), config.metric, `Run analysis to view ${config.label.toLowerCase()} ${config.metric} and volume trend.`, "#006d86", "#14b8a6", { maximized: true, target: targetValue, valueLabelSize: 8 });
  };
  renderScopedChart();
  overlay.querySelector(`#${chartId}Window`)?.addEventListener("change", renderScopedChart);
  const close = () => overlay.remove();
  overlay.querySelector(".period-chart-close")?.addEventListener("click", close);
  overlay.addEventListener("click", (event) => { if (event.target === overlay) close(); });
}

function bindResultPeriodChartExpanders() {
  document.querySelectorAll("[data-period-chart]").forEach((button) => {
    if (button.dataset.boundPeriodChart === "1") return;
    button.dataset.boundPeriodChart = "1";
    button.addEventListener("click", () => openResultPeriodChartOverlay(button.dataset.periodChart || "weekly"));
  });
}

function renderPerformancePeriodTables(analysis = {}, context = {}) {
  const metric = context.scoreName || resultScoreName(analysis);
  const weeklyRows = resultWeeklyPeriodRows(analysis, metric);
  const monthlyRows = resultMonthlyPeriodRows(weeklyRows);
  state.resultPeriodChartData = {
    monthly: { title: "Monthly Performance Trend", rows: monthlyRows, metric, label: "Month" },
    weekly: { title: "Weekly Performance Trend", rows: weeklyRows, metric, label: "Week" },
  };
  renderScoreVolumeLineChart("resultMonthlyPerformanceTrend", monthlyRows.map((row) => ({ Week: row.period, [metric]: row.score, Volume: row.volume })), metric, `Run analysis to view monthly ${metric} and volume trend.`, "#006d86", "#14b8a6");
  renderScoreVolumeLineChart("resultWeeklyPerformanceTrend", weeklyRows.map((row) => ({ Week: row.period, [metric]: row.score, Volume: row.volume })), metric, `Run analysis to view weekly ${metric} and volume trend.`, "#006d86", "#14b8a6");
  bindResultPeriodChartExpanders();
  renderPerformancePeriodTable("resultMonthlyPerformanceTable", monthlyRows, "Month", metric, "month");
  renderPerformancePeriodTable("resultWeeklyPerformanceTable", weeklyRows, "Week", metric, "week");
  const status = $("resultPeriodStatus");
  if (status) {
    const calendar = analysis.calendar || selectedCalendarConfig();
    status.textContent = weeklyRows.length
      ? `${monthlyRows.length.toLocaleString()} month(s), ${weeklyRows.length.toLocaleString()} week(s). Week starts ${calendar.weekStartDay || "Monday"}; fiscal year starts ${calendar.fiscalStartMonth || "January"}.`
      : "Run analysis to populate period movement.";
  }
}

function renderPerformanceExecutiveSummary(analysis = {}, context = {}) {
  const container = $(context.containerId || "resultPerformanceReadout");
  if (!container) return;
  const metric = context.scoreName || resultScoreName(analysis);
  const score = Number(context.score || 0);
  const total = Number(context.total || 0);
  const movement = Number(context.movement);
  const sentiment = analysis.sentiment || {};
  const targetValue = metric === "NPS"
    ? (typeof guidedNpsTargetValue === "function" ? guidedNpsTargetValue() : 85)
    : (typeof guidedCsatTargetValue === "function" ? guidedCsatTargetValue() : 85);
  const target = Number.isFinite(Number(targetValue)) ? Number(targetValue) : 85;
  const gap = score - target;
  const weekly = Array.isArray(analysis.weekly) ? analysis.weekly : [];
  const weeklyRows = resultWeeklyPeriodRows(analysis, metric);
  const monthlyRows = resultMonthlyPeriodRows(weeklyRows);
  const latestVolume = Number(weekly.at(-1)?.Responses || weekly.at(-1)?.Count || weekly.at(-1)?.Total || 0);
  const previousVolume = Number(weekly.at(-2)?.Responses || weekly.at(-2)?.Count || weekly.at(-2)?.Total || 0);
  const volumeChange = previousVolume ? ((latestVolume - previousVolume) / previousVolume) * 100 : NaN;
  const weeklyValues = weekly.map((row) => Number(resultFirstValue(row, [metric, "CSAT", "NPS", "Score"], NaN))).filter(Number.isFinite);
  const weeklyMean = weeklyValues.length ? weeklyValues.reduce((sum, value) => sum + value, 0) / weeklyValues.length : NaN;
  const previousScore = Number(weeklyRows.at(-2)?.score);
  const volatility = weeklyValues.length > 1 ? Math.sqrt(weeklyValues.reduce((sum, value) => sum + ((value - weeklyMean) ** 2), 0) / (weeklyValues.length - 1)) : NaN;
  const quartiles = analysis.quartiles || analysis.quartileRollup || [];
  const quartileScores = quartiles.map((row) => Number(resultFirstValue(row, [metric, "CSAT", "NPS", "Score"], NaN))).filter(Number.isFinite);
  const quartileVariance = quartileScores.length ? Math.max(...quartileScores) - Math.min(...quartileScores) : NaN;
  const topDriver = resultTopNameShare(analysis.reasons || analysis.drivers || analysis.themeRows || [], ["Reason", "Driver", "Theme", "Name"], ["Share", "Percent", "Count", "Rows"]);
  const topTheme = resultTopNameShare(analysis.themes || analysis.themeRows || [], ["Theme", "Driver", "Name"], ["Share", "Percent", "Count", "Rows"]);
  const painPoint = resultTopNameShare(analysis.painPoints || analysis.negativeReasons || analysis.reasons || analysis.drivers || [], ["Reason", "Driver", "Theme", "Name"], ["Negative", "Dissatisfied", "Share", "Percent", "Count", "Rows"]);
  const secondaryPainPoint = resultTopNameShare(analysis.riskRows || analysis.acptRows || analysis.themeRows || [], ["Risk", "ACPT", "Theme", "Name"], ["Share", "Percent", "Count", "Rows"]);
  const negativeShare = Number(sentiment.Negative || 0);
  const outlook = gap < -25 || negativeShare >= 40 ? "Critical" : gap < -10 || negativeShare >= 30 ? "Needs Attention" : gap < 0 || Number.isFinite(movement) && movement < 0 ? "Watchlist" : "On Track";
  const periodText = resultDateWindowText(analysis, context.outputRows || []);
  const trendWord = Number.isFinite(movement) ? (movement >= 0 ? "Improved" : "Declined") : "Requires more dated periods";
  const volumeWord = Number.isFinite(volumeChange) ? (Math.abs(volumeChange) < 2 ? "Stable" : volumeChange >= 0 ? "Increasing" : "Declining") : "Not available";
  const momentum = Number.isFinite(movement) && movement < 0 ? "Negative" : Number.isFinite(movement) && movement > 0 ? "Positive" : "Stable";
  const stability = Number.isFinite(volatility) && volatility > 8 ? "Low" : Number.isFinite(volatility) && volatility > 4 ? "Moderate" : Number.isFinite(volatility) ? "High" : "Not available";
  const volatilityLabel = Number.isFinite(volatility) && volatility > 8 ? "Volatile" : Number.isFinite(volatility) && volatility > 4 ? "Moderately Stable" : Number.isFinite(volatility) ? "Stable" : "Not available";
  const experienceVariability = Number.isFinite(quartileVariance) && quartileVariance >= 10 ? "High" : Number.isFinite(quartileVariance) && quartileVariance >= 4 ? "Moderate" : Number.isFinite(quartileVariance) ? "Low" : "Not available";
  const opportunity = Number.isFinite(quartileVariance) && quartileVariance >= 10 ? "High" : Number.isFinite(quartileVariance) && quartileVariance >= 4 ? "Moderate" : Number.isFinite(quartileVariance) ? "Limited" : "X";
  const sentimentAssessment = negativeShare >= 30 ? "At Risk" : Number(sentiment.Positive || 0) >= 70 ? "Excellent" : "Stable";
  const fmt = (value, suffix = "") => Number.isFinite(value) ? `${formatDataPoint(value)}${suffix}` : `X${suffix}`;
  const scoreSuffix = metric === "CSAT" ? "%" : "";
  const totalText = total ? total.toLocaleString() : "X";
  const startDate = resultFirstValue(weeklyRows[0] || {}, ["period", "Week", "Month", "Date"], "");
  const endDate = resultFirstValue(weeklyRows.at(-1) || {}, ["period", "Week", "Month", "Date"], "");
  const targetHitWeeks = weeklyRows.filter((row) => Number(row.score) >= target).length;
  const targetHitPct = weeklyRows.length ? (targetHitWeeks / weeklyRows.length) * 100 : NaN;
  const targetAttainment = targetHitPct >= 75 ? "Consistent" : targetHitPct >= 45 ? "Moderately consistent" : "Inconsistent";
  const currentWeekScore = Number(weeklyRows.at(-1)?.score);
  const currentWeekVsAvg = Number.isFinite(currentWeekScore) && Number.isFinite(weeklyMean) ? currentWeekScore - weeklyMean : NaN;
  const currentWeekVsAvgPct = Number.isFinite(currentWeekVsAvg) && weeklyMean ? (currentWeekVsAvg / Math.abs(weeklyMean)) * 100 : NaN;
  const monthlyValues = monthlyRows.map((row) => Number(row.score)).filter(Number.isFinite);
  const monthlyMean = monthlyValues.length ? monthlyValues.reduce((sum, value) => sum + value, 0) / monthlyValues.length : NaN;
  const currentMonthScore = Number(monthlyRows.at(-1)?.score);
  const currentMonthVsAvg = Number.isFinite(currentMonthScore) && Number.isFinite(monthlyMean) ? currentMonthScore - monthlyMean : NaN;
  const currentMonthVsAvgPct = Number.isFinite(currentMonthVsAvg) && monthlyMean ? (currentMonthVsAvg / Math.abs(monthlyMean)) * 100 : NaN;
  const avgWeeklyVolume = weeklyRows.length ? weeklyRows.reduce((sum, row) => sum + Number(row.volume || 0), 0) / weeklyRows.length : NaN;
  const avgMonthlyVolume = monthlyRows.length ? monthlyRows.reduce((sum, row) => sum + Number(row.volume || 0), 0) / monthlyRows.length : NaN;
  const currentMonthVolume = Number(monthlyRows.at(-1)?.volume || 0);
  const currentWeekVolumeGap = Number.isFinite(avgWeeklyVolume) && avgWeeklyVolume ? ((latestVolume - avgWeeklyVolume) / avgWeeklyVolume) * 100 : NaN;
  const currentMonthVolumeGap = Number.isFinite(avgMonthlyVolume) && avgMonthlyVolume ? ((currentMonthVolume - avgMonthlyVolume) / avgMonthlyVolume) * 100 : NaN;
  const movementPct = Number.isFinite(movement) && previousScore ? (movement / Math.abs(previousScore)) * 100 : NaN;
  let improvedWeeks = 0;
  let declinedWeeks = 0;
  let unchangedWeeks = 0;
  weeklyRows.forEach((row, index) => {
    if (!index) return;
    const delta = Number(row.score) - Number(weeklyRows[index - 1].score);
    if (delta > 0.005) improvedWeeks += 1;
    else if (delta < -0.005) declinedWeeks += 1;
    else unchangedWeeks += 1;
  });
  const sortedScores = weeklyValues.slice().sort((a, b) => a - b);
  const quartileAt = (p) => {
    if (!sortedScores.length) return NaN;
    const index = (sortedScores.length - 1) * p;
    const lower = Math.floor(index);
    const upper = Math.ceil(index);
    return lower === upper ? sortedScores[lower] : sortedScores[lower] + (sortedScores[upper] - sortedScores[lower]) * (index - lower);
  };
  const q1 = quartileAt(0.25);
  const q2 = quartileAt(0.5);
  const q3 = quartileAt(0.75);
  const q4 = sortedScores.length ? sortedScores.at(-1) : NaN;
  const topQuartileAvg = sortedScores.length ? sortedScores.slice(Math.floor(sortedScores.length * 0.75)).reduce((sum, value) => sum + value, 0) / Math.max(sortedScores.slice(Math.floor(sortedScores.length * 0.75)).length, 1) : NaN;
  const bottomQuartileAvg = sortedScores.length ? sortedScores.slice(0, Math.max(1, Math.ceil(sortedScores.length * 0.25))).reduce((sum, value) => sum + value, 0) / Math.max(sortedScores.slice(0, Math.max(1, Math.ceil(sortedScores.length * 0.25))).length, 1) : NaN;
  const iqr = Number.isFinite(q1) && Number.isFinite(q3) ? q3 - q1 : quartileVariance;
  const interquartileGap = Number.isFinite(topQuartileAvg) && Number.isFinite(bottomQuartileAvg) ? topQuartileAvg - bottomQuartileAvg : iqr;
  const driverText = topDriver || "X";
  const painText = [painPoint, secondaryPainPoint].filter(Boolean).slice(0, 2).join(", ") || "X";
  const themeText = [topTheme, topDriver].filter(Boolean).slice(0, 3).join(", ") || "X";
  const priority = painPoint || topDriver || topTheme || "X";
  const operationalShare = Number.isFinite(negativeShare) ? negativeShare : NaN;
  const impactPoints = Number.isFinite(interquartileGap) ? interquartileGap / 2 : NaN;
  const consistencyRead = stability === "High" ? "Good" : stability === "Low" ? "Poor" : stability === "Moderate" ? "Moderate" : "Not available";
  const executiveRows = (context.outputRows && context.outputRows.length ? context.outputRows : allFeedbackRows()).filter(Boolean);
  const baseRows = executiveRows.length ? executiveRows : (analysis.feedbackRows || analysis.feedbackTableRows || analysis.preview || []);
  const validVerbatimRows = baseRows.filter((row) => feedbackText(row).trim().length > 0);
  const validVerbatimCount = validVerbatimRows.length;
  const missingVerbatimCount = Math.max(total - validVerbatimCount, 0);
  const verbatimParticipation = total ? (validVerbatimCount / total) * 100 : NaN;
  const currentWeekKey = String(weeklyRows.at(-1)?.period || "");
  const currentWeekRows = currentWeekKey ? baseRows.filter((row) => feedbackWeek(row) === currentWeekKey) : [];
  const currentWeekVerbatimRows = currentWeekRows.filter((row) => feedbackText(row).trim().length > 0);
  const currentWeekVerbatimPct = currentWeekRows.length ? (currentWeekVerbatimRows.length / currentWeekRows.length) * 100 : NaN;
  const currentWeekVerbatimGap = Number.isFinite(currentWeekVerbatimPct) && Number.isFinite(verbatimParticipation) ? currentWeekVerbatimPct - verbatimParticipation : NaN;
  const npsTypeForSummary = (row) => String(npsDashboardType(row) || rowNpsType(row) || "").trim().toLowerCase();
  const segmentCounts = { promoter: 0, passive: 0, detractor: 0 };
  const segmentVerbatims = { promoter: 0, passive: 0, detractor: 0 };
  baseRows.forEach((row) => {
    const type = npsTypeForSummary(row);
    if (!Object.prototype.hasOwnProperty.call(segmentCounts, type)) return;
    segmentCounts[type] += 1;
    if (feedbackText(row).trim()) segmentVerbatims[type] += 1;
  });
  const passiveDetractorCount = segmentCounts.passive + segmentCounts.detractor;
  const passiveDetractorBlindSpots = passiveDetractorCount - segmentVerbatims.passive - segmentVerbatims.detractor;
  const segmentParticipationRows = ["promoter", "passive", "detractor"].map((key) => ({
    key,
    label: key === "promoter" ? "Promoters" : key === "passive" ? "Passives" : "Detractors",
    count: segmentCounts[key],
    verbatims: segmentVerbatims[key],
    pct: segmentCounts[key] ? (segmentVerbatims[key] / segmentCounts[key]) * 100 : NaN,
  })).filter((row) => row.count > 0);
  const highestSegmentParticipation = segmentParticipationRows.slice().sort((a, b) => (b.pct || 0) - (a.pct || 0))[0]?.label || "X";
  const lowestSegmentParticipation = segmentParticipationRows.slice().sort((a, b) => (a.pct || 0) - (b.pct || 0))[0]?.label || "X";
  const segmentCoverageText = segmentParticipationRows.length
    ? segmentParticipationRows.map((row) => `${row.label}: <strong>${row.verbatims.toLocaleString()}</strong> of <strong>${row.count.toLocaleString()}</strong> (<strong>${fmt(row.pct, "%")}</strong>)`).join(", ")
    : "Promoters: <strong>X</strong> of <strong>Y</strong> (<strong>X%</strong>), Passives: <strong>X</strong> of <strong>Y</strong> (<strong>X%</strong>), and Detractors: <strong>X</strong> of <strong>Y</strong> (<strong>X%</strong>)";
  const verbatimThemeNames = ["Primary Reason", "Owl Primary Driver", "Primary Theme", "Theme", "Predicted Theme", "Owl Theme", "Driver", "Reason"];
  const themeCounts = new Map();
  validVerbatimRows.forEach((row) => {
    const value = String(resultFirstValue(row, verbatimThemeNames, "") || "").trim();
    if (!value) return;
    themeCounts.set(value, (themeCounts.get(value) || 0) + 1);
  });
  const themeDistribution = [...themeCounts.entries()].map(([label, count]) => ({ label, count })).sort((a, b) => b.count - a.count || a.label.localeCompare(b.label));
  const distinctThemeCount = themeDistribution.length;
  const topThemeLimit = Math.min(5, themeDistribution.length);
  const topThemeShare = validVerbatimCount && topThemeLimit ? (themeDistribution.slice(0, topThemeLimit).reduce((sum, row) => sum + row.count, 0) / validVerbatimCount) * 100 : NaN;
  const meaningfulWordsForSummary = (text) => String(text || "").toLowerCase().replace(/[^a-z0-9\s]/g, " ").split(/\s+/).map((word) => word.trim()).filter((word) => word.length > 2 && !WORD_CLOUD_STOP_WORDS.has(word) && !/^\d+$/.test(word));
  const verbatimWordLists = validVerbatimRows.map((row) => meaningfulWordsForSummary(feedbackText(row)));
  const totalMeaningfulWords = verbatimWordLists.reduce((sum, words) => sum + words.length, 0);
  const avgMeaningfulWords = validVerbatimCount ? totalMeaningfulWords / validVerbatimCount : NaN;
  const currentWeekWordLists = currentWeekVerbatimRows.map((row) => meaningfulWordsForSummary(feedbackText(row)));
  const currentWeekWordTotal = currentWeekWordLists.reduce((sum, words) => sum + words.length, 0);
  const currentWeekAvgWords = currentWeekVerbatimRows.length ? currentWeekWordTotal / currentWeekVerbatimRows.length : NaN;
  const currentWeekWordGap = Number.isFinite(currentWeekAvgWords) && Number.isFinite(avgMeaningfulWords) ? currentWeekAvgWords - avgMeaningfulWords : NaN;
  const uniqueMeaningfulWords = new Set(verbatimWordLists.flat()).size;
  const actionableRows = validVerbatimRows.filter((row) => {
    const sentimentText = String(row.Sentiment || row.sentiment || "").toLowerCase();
    const type = npsTypeForSummary(row);
    const hasTheme = verbatimThemeNames.some((name) => String(row[name] || "").trim());
    return /negative|review|required|actionable|risk/.test(sentimentText) || ["passive", "detractor"].includes(type) || hasTheme;
  }).length;
  const actionablePct = validVerbatimCount ? (actionableRows / validVerbatimCount) * 100 : NaN;
  const phraseCounts = new Map();
  verbatimWordLists.forEach((words) => {
    for (let size = 2; size <= 3; size += 1) {
      for (let index = 0; index <= words.length - size; index += 1) {
        const phrase = words.slice(index, index + size).join(" ");
        if (!phrase) continue;
        phraseCounts.set(phrase, (phraseCounts.get(phrase) || 0) + 1);
      }
    }
  });
  const recurringPhrases = [...phraseCounts.entries()].filter(([, count]) => count > 1).map(([phrase, count]) => ({ phrase, count })).sort((a, b) => b.count - a.count || a.phrase.localeCompare(b.phrase)).slice(0, 5);
  const totalPhraseOccurrences = [...phraseCounts.values()].reduce((sum, count) => sum + count, 0);
  const topPhraseShare = totalPhraseOccurrences && recurringPhrases.length ? (recurringPhrases.reduce((sum, row) => sum + row.count, 0) / totalPhraseOccurrences) * 100 : NaN;
  const phraseText = recurringPhrases.length ? recurringPhrases.map((row) => `"${escapeHtml(row.phrase)}"`).join(", ") : "\"X\", \"X\", \"X\", \"X\", and \"X\"";
  const verbatimSentimentAssessment = negativeShare >= 30 ? "Needs Improvement" : negativeShare >= 20 ? "Fair" : Number(sentiment.Positive || 0) >= 70 ? "Excellent" : "Good";
  const acptThemeCategoryNames = ["ACPT Primary Category", "ACPT", "Predicted ACPT", "Owl ACPT", "Ownership", "Accountability", "Bucket Category", "Owl Customer Impact"];
  const countDistribution = (sourceRows, names) => {
    const counts = new Map();
    sourceRows.forEach((row) => {
      const value = String(resultFirstValue(row, names, "") || "").trim();
      if (!value) return;
      counts.set(value, (counts.get(value) || 0) + 1);
    });
    return [...counts.entries()].map(([label, count]) => ({ label, count })).sort((a, b) => b.count - a.count || a.label.localeCompare(b.label));
  };
  const acptDistribution = countDistribution(validVerbatimRows, acptThemeCategoryNames);
  const classifiedThemeAcptRows = validVerbatimRows.filter((row) => resultFirstValue(row, verbatimThemeNames, "") || resultFirstValue(row, acptThemeCategoryNames, ""));
  const topAcptLimit = Math.min(5, acptDistribution.length);
  const topAcptText = acptDistribution.length ? acptDistribution.slice(0, 5).map((row) => `<strong>${escapeHtml(row.label)}</strong>`).join(", ") : "<strong>X</strong>, <strong>X</strong>, <strong>X</strong>, <strong>X</strong>, and <strong>X</strong>";
  const topThemeText = themeDistribution.length ? themeDistribution.slice(0, 5).map((row) => `<strong>${escapeHtml(row.label)}</strong>`).join(", ") : "<strong>X</strong>, <strong>X</strong>, <strong>X</strong>, <strong>X</strong>, and <strong>X</strong>";
  const combinedDistribution = [...themeDistribution.map((row) => ({ ...row, family: "theme" })), ...acptDistribution.map((row) => ({ ...row, family: "ACPT" }))].sort((a, b) => b.count - a.count || a.label.localeCompare(b.label));
  const combinedTopLimit = Math.min(5, combinedDistribution.length);
  const combinedTopShare = validVerbatimCount && combinedTopLimit ? Math.min(100, (combinedDistribution.slice(0, combinedTopLimit).reduce((sum, row) => sum + row.count, 0) / validVerbatimCount) * 100) : NaN;
  const combinedSentiment = new Map();
  const addCombinedSentiment = (label, sentimentKey) => {
    if (!label || !sentimentKey) return;
    if (!combinedSentiment.has(label)) combinedSentiment.set(label, { Positive: 0, Neutral: 0, Negative: 0, total: 0 });
    const bucket = combinedSentiment.get(label);
    bucket[sentimentKey] += 1;
    bucket.total += 1;
  };
  classifiedThemeAcptRows.forEach((row) => {
    const sentimentValue = String(row.Sentiment || row.sentiment || row["Sentiment Label"] || "").trim().toLowerCase();
    const sentimentKey = sentimentValue === "positive" ? "Positive" : sentimentValue === "neutral" ? "Neutral" : sentimentValue === "negative" ? "Negative" : "";
    addCombinedSentiment(String(resultFirstValue(row, verbatimThemeNames, "") || "").trim(), sentimentKey);
    addCombinedSentiment(String(resultFirstValue(row, acptThemeCategoryNames, "") || "").trim(), sentimentKey);
  });
  const combinedSentimentRows = [...combinedSentiment.entries()].map(([label, counts]) => ({
    label,
    positivePct: counts.total ? (counts.Positive / counts.total) * 100 : NaN,
    negativeCount: counts.Negative || 0,
  }));
  const topPositiveThemeAcpt = combinedSentimentRows.slice().sort((a, b) => (b.positivePct || 0) - (a.positivePct || 0))[0]?.label || "X";
  const topNegativeThemeAcpt = combinedSentimentRows.slice().sort((a, b) => (b.negativeCount || 0) - (a.negativeCount || 0))[0]?.label || "X";
  const weekKeysForThemes = [...new Set(classifiedThemeAcptRows.map((row) => feedbackWeek(row)).filter(Boolean))].sort();
  const currentThemeWeek = weekKeysForThemes.at(-1) || "";
  const combinedWeekCounts = new Map();
  classifiedThemeAcptRows.forEach((row) => {
    const week = feedbackWeek(row);
    if (!week) return;
    [resultFirstValue(row, verbatimThemeNames, ""), resultFirstValue(row, acptThemeCategoryNames, "")].forEach((value) => {
      const label = String(value || "").trim();
      if (!label) return;
      const key = `${label}|||${week}`;
      combinedWeekCounts.set(key, (combinedWeekCounts.get(key) || 0) + 1);
    });
  });
  const fastestThemeAcpt = combinedDistribution.map((row) => {
    const current = currentThemeWeek ? Number(combinedWeekCounts.get(`${row.label}|||${currentThemeWeek}`) || 0) : 0;
    const average = weekKeysForThemes.length ? row.count / weekKeysForThemes.length : NaN;
    const changePct = average ? ((current - average) / average) * 100 : NaN;
    return { ...row, current, average, changePct };
  }).filter((row) => Number.isFinite(row.changePct)).sort((a, b) => Math.abs(b.changePct) - Math.abs(a.changePct))[0];
  const passiveDetractorClassified = classifiedThemeAcptRows.filter((row) => ["passive", "detractor"].includes(npsTypeForSummary(row)));
  const passiveDetractorDrivers = countDistribution(passiveDetractorClassified, [...verbatimThemeNames, ...acptThemeCategoryNames]);
  const topPassiveDetractorDriver = passiveDetractorDrivers[0];
  const passiveDetractorDriverShare = passiveDetractorClassified.length && topPassiveDetractorDriver ? (topPassiveDetractorDriver.count / passiveDetractorClassified.length) * 100 : NaN;
  container.classList.remove("driver-list");
  container.innerHTML = `<section class="result-executive-summary">
    <h4>Executive Performance Summary</h4>
    <ul class="executive-bullet-list">
      <li>A total of <strong>${escapeHtml(totalText)}</strong> customer surveys were analyzed across <strong>${weeklyRows.length || "X"}</strong> weeks covering the period <strong>${escapeHtml(startDate || periodText)}</strong> to <strong>${escapeHtml(endDate || periodText)}</strong>.</li>
      <li>The average weekly ${escapeHtml(metric)} for the analysis period is <strong>${fmt(weeklyMean, scoreSuffix)}</strong>, while the current week recorded <strong>${fmt(currentWeekScore, scoreSuffix)}</strong>, which is <strong>${fmt(Math.abs(currentWeekVsAvg))}</strong> points (<strong>${fmt(Math.abs(currentWeekVsAvgPct), "%")}</strong>) ${currentWeekVsAvg >= 0 ? "Above" : "Below"} the period average. The average monthly ${escapeHtml(metric)} for the analysis period is <strong>${fmt(monthlyMean, scoreSuffix)}</strong>, while the current month recorded <strong>${fmt(currentMonthScore, scoreSuffix)}</strong>, which is <strong>${fmt(Math.abs(currentMonthVsAvg))}</strong> points (<strong>${fmt(Math.abs(currentMonthVsAvgPct), "%")}</strong>) ${currentMonthVsAvg >= 0 ? "Above" : "Below"} the period average.</li>
      <li>The average weekly survey volume is <strong>${fmt(avgWeeklyVolume)}</strong>, while the current week recorded <strong>${fmt(latestVolume)}</strong> surveys (<strong>${fmt(Math.abs(currentWeekVolumeGap), "%")}</strong> ${currentWeekVolumeGap >= 0 ? "Up" : "Down"}). The average monthly survey volume is <strong>${fmt(avgMonthlyVolume)}</strong>, while the current month recorded <strong>${fmt(currentMonthVolume)}</strong> surveys (<strong>${fmt(Math.abs(currentMonthVolumeGap), "%")}</strong> ${currentMonthVolumeGap >= 0 ? "Up" : "Down"}), indicating a <strong>${volumeWord === "Increasing" ? "rise" : volumeWord === "Declining" ? "decline" : "stable pattern"}</strong> in survey participation.</li>
      <li>Across the analysis period, target was met in <strong>${targetHitWeeks}</strong> of <strong>${weeklyRows.length || "X"}</strong> weeks (<strong>${fmt(targetHitPct, "%")}</strong>). Performance improved in <strong>${improvedWeeks}</strong> weeks, declined in <strong>${declinedWeeks}</strong> weeks, and remained unchanged in <strong>${unchangedWeeks}</strong> weeks, reflecting <strong>${escapeHtml(consistencyRead)}</strong> consistency. The overall volatility score is <strong>${fmt(volatility)}</strong>, calculated as the standard deviation of weekly ${escapeHtml(metric)} scores, indicating <strong>${escapeHtml(volatilityLabel)}</strong> performance.</li>
      <li>The Interquartile Range (IQR) is <strong>${fmt(iqr)}</strong> points, with the top quartile averaging <strong>${fmt(topQuartileAvg, scoreSuffix)}</strong> and the bottom quartile averaging <strong>${fmt(bottomQuartileAvg, scoreSuffix)}</strong>, resulting in an interquartile gap of <strong>${fmt(interquartileGap)}</strong> points. The middle 50% of observations fall between <strong>${fmt(q1, scoreSuffix)}</strong> and <strong>${fmt(q3, scoreSuffix)}</strong>, suggesting <strong>${escapeHtml(experienceVariability)}</strong> variability in customer experience.</li>
    </ul>
    <h4>AI Verbatim Insights</h4>
    <ul class="executive-bullet-list">
      <li>A total of <strong>${escapeHtml(totalText)}</strong> customer surveys were collected across <strong>${weeklyRows.length || "X"}</strong> weeks, covering the period <strong>${escapeHtml(startDate || periodText)}</strong> to <strong>${escapeHtml(endDate || periodText)}</strong>. Of these, <strong>${validVerbatimCount.toLocaleString()}</strong> surveys (<strong>${fmt(verbatimParticipation, "%")}</strong>) contained valid customer verbatims, while <strong>${missingVerbatimCount.toLocaleString()}</strong> surveys (<strong>${fmt(total ? (missingVerbatimCount / total) * 100 : NaN, "%")}</strong>) did not include written feedback. Overall verbatim participation was <strong>${fmt(verbatimParticipation, "%")}</strong>, compared with <strong>${fmt(currentWeekVerbatimPct, "%")}</strong> in the current week (${Number.isFinite(currentWeekVerbatimGap) ? `${currentWeekVerbatimGap >= 0 ? "Above" : "Below"} the reporting period average by <strong>${fmt(Math.abs(currentWeekVerbatimGap))}</strong> percentage points` : "X"}).</li>
      <li>Detractors and Passives account for <strong>${passiveDetractorCount.toLocaleString()}</strong> surveys (<strong>${fmt(total ? (passiveDetractorCount / total) * 100 : NaN, "%")}</strong>) of the total responses, of which <strong>${passiveDetractorBlindSpots.toLocaleString()}</strong> surveys (<strong>${fmt(passiveDetractorCount ? (passiveDetractorBlindSpots / passiveDetractorCount) * 100 : NaN, "%")}</strong>) are blind spots due to missing verbatims. Verbatim participation by customer segment was ${segmentCoverageText}, with <strong>${escapeHtml(highestSegmentParticipation)}</strong> recording the highest participation rate and <strong>${escapeHtml(lowestSegmentParticipation)}</strong> the lowest.</li>
      <li>AI-based analysis identified <strong>${fmt(Number(sentiment.Positive), "%")}</strong> Positive, <strong>${fmt(Number(sentiment.Neutral), "%")}</strong> Neutral, and <strong>${fmt(Number(sentiment.Negative), "%")}</strong> Negative sentiment, indicating an overall customer experience that is <strong>${escapeHtml(verbatimSentimentAssessment)}</strong>. AI also identified <strong>${distinctThemeCount || "X"}</strong> distinct themes, with the Top <strong>${topThemeLimit || "X"}</strong> themes contributing <strong>${fmt(topThemeShare, "%")}</strong> of all verbatims and representing the primary drivers of customer experience.</li>
      <li>Customers used an average of <strong>${fmt(avgMeaningfulWords)}</strong> meaningful words per verbatim (excluding stop words), compared with <strong>${fmt(currentWeekAvgWords)}</strong> in the current week (${Number.isFinite(currentWeekWordGap) ? `${currentWeekWordGap >= 0 ? "Above" : "Below"} the reporting period average by <strong>${fmt(Math.abs(currentWeekWordGap))}</strong> words` : "X"}). A total of <strong>${uniqueMeaningfulWords ? uniqueMeaningfulWords.toLocaleString() : "X"}</strong> unique meaningful words were identified, while <strong>${fmt(actionablePct, "%")}</strong> of verbatims contained actionable feedback, demonstrating the depth and usefulness of customer feedback for improvement initiatives.</li>
      <li>The Top 5 recurring customer phrases were ${phraseText}, accounting for <strong>${fmt(topPhraseShare, "%")}</strong> of all meaningful phrase occurrences and providing a concise summary of the dominant topics influencing customer experience during the reporting period.</li>
    </ul>
    <h4>ACPT and Theme Analysis</h4>
    <ul class="executive-bullet-list">
      <li>AI analyzed <strong>${validVerbatimCount.toLocaleString()}</strong> valid customer verbatims and identified <strong>${distinctThemeCount || "X"}</strong> distinct themes, classifying them into <strong>${acptDistribution.length || "X"}</strong> ACPT categories. The Top <strong>${combinedTopLimit || "X"}</strong> themes/categories accounted for <strong>${fmt(combinedTopShare, "%")}</strong> of all customer feedback, indicating that a small number of topics drive the majority of customer conversations.</li>
      <li>The most frequently discussed themes were ${topThemeText}, while the leading ACPT categories were ${topAcptText}, representing the primary drivers of customer experience during the reporting period.</li>
      <li>Compared with the reporting period average, mentions of <strong>${escapeHtml(fastestThemeAcpt?.label || "X")}</strong> ${fastestThemeAcpt ? (fastestThemeAcpt.changePct >= 0 ? "increased" : "decreased") : "increased/decreased"} by <strong>${fastestThemeAcpt ? fmt(Math.abs(fastestThemeAcpt.changePct), "%") : "X%"}</strong> in the current week, making it the fastest-moving customer theme/category.</li>
      <li>Sentiment analysis across identified themes and ACPT categories shows that <strong>${escapeHtml(topPositiveThemeAcpt)}</strong> contributed the highest proportion of positive customer experiences, whereas <strong>${escapeHtml(topNegativeThemeAcpt)}</strong> accounted for the largest share of negative customer feedback, highlighting the strongest strengths and improvement opportunities.</li>
      <li>Among Detractor and Passive customers, <strong>${fmt(passiveDetractorDriverShare, "%")}</strong> of all classified feedback was attributed to <strong>${escapeHtml(topPassiveDetractorDriver?.label || "X")}</strong>, making it the single largest driver of customer dissatisfaction and the highest-priority improvement area. The Top 5 recurring customer topics were ${phraseText}, collectively contributing <strong>${fmt(topPhraseShare, "%")}</strong> of all classified feedback.</li>
    </ul>
    <h4>Business Impact & Recommendations</h4>
    <ul class="executive-bullet-list">
      <li>Addressing <strong>${escapeHtml(driverText)}</strong> is expected to improve overall ${escapeHtml(metric)} by approximately <strong>${fmt(impactPoints)}</strong> points based on current trend analysis.</li>
      <li>The largest performance gap exists within <strong>${escapeHtml(priority)}</strong>, contributing <strong>${fmt(operationalShare, "%")}</strong> of all negative customer feedback and representing the highest ROI improvement opportunity.</li>
      <li>Prioritize improvements in <strong>${escapeHtml(priority)}</strong>, replicate best practices from the top-performing segments, and focus coaching on the bottom-performing quartile to reduce performance variation.</li>
      <li>Based on statistical analysis, AI insights, sentiment, ACPT findings, theme distribution, and recent performance trends, overall performance is assessed as <strong>${escapeHtml(outlook)}</strong>, with <strong>${escapeHtml(priority)}</strong> identified as the highest-priority initiative for the next reporting period.</li>
    </ul>
  </section>`;
}

function executiveSummaryExportName(extension) {
  const metric = resultScoreName(state.analysis || {}) || "NPS";
  return `${metric}_Executive_Summary_${new Date().toISOString().slice(0, 10)}.${extension}`;
}

function executiveSummaryHtmlDocument({ printMode = false } = {}) {
  const summary = $("resultExecutiveSummaryBox");
  if (!summary || !summary.textContent.trim()) return "";
  const metric = resultScoreName(state.analysis || {}) || "NPS";
  const generatedAt = new Date().toLocaleString();
  return `<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${escapeHtml(metric)} Executive Summary</title>
    <style>
      * { box-sizing: border-box; }
      body { margin: 0; background: #f4f8fb; color: #062a45; font-family: Arial, Helvetica, sans-serif; }
      .report-topbar { background: #004762; color: #fff; border-bottom: 4px solid #22d3c7; padding: 18px 28px; display: flex; align-items: center; justify-content: space-between; gap: 16px; }
      .report-brand { letter-spacing: 2px; text-transform: uppercase; font-size: 13px; }
      .report-shell { max-width: 1120px; margin: 28px auto; padding: 0 20px 36px; }
      .report-card { background: #fff; border: 1px solid #cfe1ec; border-radius: 8px; box-shadow: 0 14px 34px rgba(7, 43, 66, .08); padding: 28px; }
      .report-card h1 { margin: 0 0 16px; font-size: 30px; }
      .report-meta { color: #52677b; font-size: 12px; margin-bottom: 22px; }
      .result-executive-summary { color: #173b56; font-size: 14px; line-height: 1.58; }
      .result-executive-summary h4 { margin: 20px 0 8px; color: #008b8b; font-size: 13px; letter-spacing: .08em; text-transform: uppercase; }
      .result-executive-summary p { margin: 0 0 11px; }
      @media print { body { background: #fff; } .report-topbar { color: #062a45; background: #fff; border-bottom: 2px solid #22d3c7; } .report-shell { margin: 0; max-width: none; } .report-card { box-shadow: none; border: 0; } }
    </style>
  </head>
  <body>
    <div class="report-topbar"><div class="report-brand">CX Intelligence Suite</div><div>${escapeHtml(metric)} Executive Summary</div></div>
    <main class="report-shell">
      <section class="report-card">
        <h1>Executive Summary</h1>
        <div class="report-meta">Generated ${escapeHtml(generatedAt)}</div>
        ${summary.innerHTML}
      </section>
    </main>
    ${printMode ? "<script>window.addEventListener('load', () => setTimeout(() => window.print(), 350));<\/script>" : ""}
  </body>
</html>`;
}

function exportExecutiveSummaryTxt() {
  const summary = $("resultExecutiveSummaryBox");
  const text = summary?.innerText?.trim() || "";
  if (!text) {
    alert("Run or import an analysis before exporting the Executive Summary.");
    return;
  }
  triggerBlobDownload(new Blob([`Executive Summary\n\n${text}`], { type: "text/plain;charset=utf-8" }), executiveSummaryExportName("txt"));
}

function exportExecutiveSummaryHtml() {
  const html = executiveSummaryHtmlDocument();
  if (!html) {
    alert("Run or import an analysis before exporting the Executive Summary.");
    return;
  }
  triggerBlobDownload(new Blob([html], { type: "text/html;charset=utf-8" }), executiveSummaryExportName("html"));
}

function exportExecutiveSummaryPdf() {
  const html = executiveSummaryHtmlDocument({ printMode: true });
  if (!html) {
    alert("Run or import an analysis before exporting the Executive Summary.");
    return;
  }
  const reportWindow = window.open("", "_blank");
  if (!reportWindow) {
    alert("The PDF window was blocked. Please allow pop-ups for this local app.");
    return;
  }
  reportWindow.document.open();
  reportWindow.document.write(html);
  reportWindow.document.close();
}

function renderAnalysisResultViews(analysis = state.analysis || {}) {
  const summary = analysis.summary || {};
  const counts = analysis.counts || {};
  const sentiment = analysis.sentiment || {};
  const weekly = analysis.weekly || [];
  const rows = resultAllRows(analysis);
  const scoreName = resultScoreName(analysis);
  const populationRows = Number(analysis.population?.rows || 0);
  const scoredTotal = Number(summary.total || summary.Total || counts.Total || counts.total || rows.length || 0);
  const total = Number(populationRows || scoredTotal || rows.length || 0);
  const score = Number(summary[scoreName] ?? summary[scoreName.toLowerCase()] ?? summary.nps ?? 0);
  const latest = weekly[weekly.length - 1] || {};
  const previous = weekly[weekly.length - 2] || {};
  const latestScore = Number(resultFirstValue(latest, [scoreName, "CSAT", "NPS", "Score"], NaN));
  const previousScore = Number(resultFirstValue(previous, [scoreName, "CSAT", "NPS", "Score"], NaN));
  const movement = Number.isFinite(latestScore) && Number.isFinite(previousScore) ? latestScore - previousScore : NaN;
  const sentimentRows = [
    { Sentiment: "Positive", Share: Number(sentiment.Positive || 0) },
    { Sentiment: "Neutral", Share: Number(sentiment.Neutral || 0) },
    { Sentiment: "Negative", Share: Number(sentiment.Negative || 0) },
  ];
  const dimensions = resultDimensionRows(analysis);
  const outputRows = analysis.feedbackTableRows || analysis.feedbackRows || analysis.preview || [];
  const evidenceReturned = Number(analysis.population?.evidenceRowsReturned || outputRows.length || 0);
  const previewLimit = Number(analysis.population?.evidenceLimit || 0);
  const outputCount = populationRows || total || outputRows.length;
  const previewNote = previewLimit && evidenceReturned < outputCount
    ? `${evidenceReturned.toLocaleString()} row browser preview; full output has ${outputCount.toLocaleString()} rows`
    : "Generated result records";
  const insightCards = typeof buildGuidedCompletionInsights === "function" ? buildGuidedCompletionInsights(analysis) : [];

  ["resultDatasetStatus", "resultPerformanceStatus", "resultExecutiveSummaryStatus", "resultDecisionStatus", "resultDimensionsStatus", "resultRowsStatus", "resultSentimentStatus", "resultInsightsStatus"].forEach((id) => {
    if ($(id)) $(id).textContent = total ? `Generated from ${total.toLocaleString()} analyzed rows.` : "Run analysis to populate this result.";
  });

  resultMetricCards("resultDatasetCards", [
    { label: "Analyzed Rows", value: total.toLocaleString(), note: "Rows included in the completed run" },
    { label: "Base Columns", value: String((state.baseColumns || []).length || Object.keys(state.baseColumnStats || {}).length || "-"), note: "Uploaded source fields" },
    { label: "Lookup Columns", value: String((state.lookupColumns || []).length || Object.keys(state.lookupColumnStats || {}).length || "0"), note: "Optional lookup fields" },
    { label: "Output Rows", value: outputCount.toLocaleString(), note: previewNote },
    { label: "Dimension Rows", value: dimensions.length.toLocaleString(), note: "Generated segment outputs" },
    { label: "Weekly Periods", value: weekly.length.toLocaleString(), note: "Available trend periods" },
  ]);
  renderAnyTable("resultDatasetTable", [
    { Section: "Base file", Status: state.baseUploadComplete ? "Uploaded" : "Available after upload", Count: (state.baseColumns || []).length, Detail: "Source fields used by setup and mapping" },
    { Section: "Lookup file", Status: (state.lookupColumns || []).length ? "Uploaded" : "Not used", Count: (state.lookupColumns || []).length, Detail: "Optional enrichment fields" },
    { Section: "Analysis output", Status: total ? "Generated" : "Waiting", Count: outputCount, Detail: previewLimit && evidenceReturned < outputCount ? `${evidenceReturned.toLocaleString()} rows returned to this screen for preview and details` : "Rows available for result views" },
    { Section: "Dimensions", Status: dimensions.length ? "Generated" : "No dimension output", Count: dimensions.length, Detail: "Agent, manager, quartile, wave, tenure, and custom outputs where available" },
  ], 6);

  resultMetricCards("resultPerformanceCards", [
    { label: scoreName, value: formatMetric(score), note: `${scoreName} from the completed analysis` },
    { label: "Responses", value: total.toLocaleString(), note: "Analyzed response count" },
    { label: "Latest Movement", value: Number.isFinite(movement) ? `${movement >= 0 ? "+" : ""}${formatMetric(movement)} pts` : "N/A", note: "Latest period vs prior period", tone: Number.isFinite(movement) && movement < 0 ? "negative" : "positive" },
    { label: "Positive Sentiment", value: `${formatMetric(sentiment.Positive || 0)}%`, note: "Sparrow positive share" },
  ]);
  renderPerformancePeriodTables(analysis, { scoreName });
  renderPerformanceExecutiveSummary(analysis, { scoreName, score, total, movement, outputRows, containerId: "resultExecutiveSummaryBox" });

  resultMetricCards("resultDecisionCards", [
    { label: "Primary Decision", value: Number.isFinite(movement) && movement < 0 ? "Recover" : "Sustain", note: Number.isFinite(movement) ? "Based on latest movement and current score." : "Based on current score until trend is available." },
    { label: "Evidence Strength", value: total >= 1000 ? "Strong" : total >= 100 ? "Directional" : "Limited", note: `${total.toLocaleString()} analyzed rows` },
    { label: "Sentiment Risk", value: Number(sentiment.Negative || 0) >= 30 ? "Elevated" : "Controlled", note: `${formatMetric(sentiment.Negative || 0)}% negative sentiment` },
  ]);
  resultReadoutList("resultDecisionGuide", [
    { label: "Start here", value: Number(sentiment.Negative || 0) >= 30 ? "Negative sentiment" : "Performance trend", note: "Use this as the first review path after analysis." },
    { label: "Next view", value: dimensions.length ? "Dimensions" : "Results", note: dimensions.length ? "Compare segment rows for concentration." : "Review generated result rows for evidence." },
    { label: "Leadership read", value: analysis.insights ? "Available" : "Generated metrics only", note: analysis.insights || "Use the score, sentiment, volume, and generated tables to form the readout." },
  ]);

  renderResultDimensionCards(dimensions);
  renderResultDimensionTable(dimensions);

  renderAnyTable("resultRowsTable", outputRows, 10);

  resultMetricCards("resultSentimentCards", [
    { label: "Positive", value: `${formatMetric(sentiment.Positive || 0)}%`, note: "Positive sentiment share", tone: "positive" },
    { label: "Neutral", value: `${formatMetric(sentiment.Neutral || 0)}%`, note: "Neutral sentiment share" },
    { label: "Negative", value: `${formatMetric(sentiment.Negative || 0)}%`, note: "Negative sentiment share", tone: Number(sentiment.Negative || 0) >= 30 ? "negative" : "" },
  ]);
  renderSimpleBar("resultSentimentChart", sentimentRows, "Sentiment", "Share", "#009b9b");
  if ($("resultSentimentInsight")) $("resultSentimentInsight").textContent = `Positive sentiment is ${formatMetric(sentiment.Positive || 0)}%; negative sentiment is ${formatMetric(sentiment.Negative || 0)}%.`;
  resultReadoutList("resultSentimentReadout", [
    { label: "Sentiment posture", value: Number(sentiment.Positive || 0) >= Number(sentiment.Negative || 0) ? "Favorable" : "Watch", note: "Compares positive and negative shares." },
    { label: "Review focus", value: Number(sentiment.Negative || 0) >= 30 ? "Negative verbatims" : "Top drivers", note: "Use representative rows below as evidence." },
  ]);
  renderAnyTable("resultSentimentTable", outputRows.filter((row) => String(row.Sentiment || "").trim()).slice(0, 500), 8);

  resultMetricCards("resultInsightsGrid", insightCards.slice(0, 6).map((item, index) => ({
    label: item.phase || `Insight ${index + 1}`,
    value: item.title || "Generated insight",
    note: item.text || "",
  })));
  resultReadoutList("resultInsightsReadout", insightCards.slice(0, 10).map((item, index) => ({
    label: item.phase || `Insight ${index + 1}`,
    value: item.title || "",
    note: item.text || "",
  })));
  renderLeadershipResultQuestions(analysis);
}

function renderAnalysis(analysis, options = {}) {
  analysis = normalizeBlankCommentSentiment(analysis || {});
  state.analysis = analysis;
  updateAnalysisAccessUi();
  const statusEl = $("analysisStatus");
  if (statusEl) statusEl.textContent = analysis.status || "Local NPS analysis complete. Dashboards ready.";
  $("analysisCompleteBanner")?.classList.add("hidden");
  const filter = analysis.dateFilter || { mode: "All Time" };
  const custom = filter.mode === "Custom Range" && (filter.start || filter.end) ? ` (${filter.start || "..."} to ${filter.end || "..."})` : "";
  const dateText = `${filter.mode || "All Time"}${custom}`;
  if ($("dateLabel")) $("dateLabel").textContent = dateText;
  updateDateToggleLabel(dateText);
  syncDateFilterControls(filter);
  if (options.showCompletionSummary && typeof showAnalysisCompleteSummary === "function") {
    setTimeout(() => showAnalysisCompleteSummary(analysis, options.summaryReason || "Analysis complete"), 120);
  }
  const analysisOutputCount = Number(analysis.population?.rows || analysis.feedbackTableRows?.length || analysis.feedbackRows?.length || analysis.preview?.length || 0);
  renderMetrics(analysis.summary || {}, analysis.counts || {}, analysis.segmentSentiments || {}, analysis.executiveDashboard?.intelligence || [], { ...analysis, outputCount: analysisOutputCount });
  renderTrend(analysis.weekly || []);
  renderGauge(analysis.summary || {});
  renderComposition(analysis.counts || {}, analysis.summary || {});
  renderVolumeTrend(analysis.weekly || []);
  renderSentimentTrend(analysis.weekly || []);
  renderSentiment(analysis.sentiment || {});
  renderDrivers(analysis.reasons || []);
  renderOwlOverviewViews(analysis);
  renderAlerts(analysis.alerts || []);
  renderFeedbackSummary(analysis.sentiment || {});
  if (typeof renderFeedbackTable === "function") renderFeedbackTable();
  renderSentimentComparison();
  if (typeof renderDataViews === "function") renderDataViews(analysis);
  renderPerformanceLens(analysis);
  renderMovingAveragesView(analysis);
  renderAgentDashboard();
  renderManagerDashboard();
  renderQuartileDashboard();
  renderRootCauseClouds();
  renderPromoterDna();
  renderStatsDashboard(analysis);
  renderCustomStatsShell();
  refreshSummaryBuilder();
  renderSummaryBuilderDashboard();
  renderColumnExplorer();
  renderAnalysisRawDataPage();
  if (typeof renderExecutiveLens === "function") renderExecutiveLens(analysis);
  if (typeof renderThemeBuilder === "function") renderThemeBuilder();
  if (typeof renderAnalysisSnapshot === "function") renderAnalysisSnapshot(analysis);
  renderAnalysisResultViews(analysis);
  if ($("insightsText")) $("insightsText").textContent = analysis.insights || "No insights generated yet.";
  const hasExecutiveDashboardData = executiveDashboardHasData(analysis);
  const isExecutiveDashboardHandoff = requestedDashboardHandoffView() === "executive";
  setExecutiveDashboardLoading(isExecutiveDashboardHandoff && !hasExecutiveDashboardData, hasExecutiveDashboardData ? "" : "Waiting for analysis data...");
  if (isExecutiveDashboardHandoff && hasExecutiveDashboardData && dashboardGuideShouldRun()) setTimeout(runDashboardGuideTour, 450);
}

function owlOutputRows(analysis = state.analysis || {}) {
  const sources = [analysis.feedbackRows, analysis.feedbackTableRows, analysis.preview, state.statsData?.analyzedRows, state.statsData?.baseRows].filter((rows) => Array.isArray(rows) && rows.length);
  if (!sources.length) return [];
  const outputNames = ["Primary Reason", "Owl Primary Driver", "Primary Theme", "Theme", "Predicted Theme", "Owl Theme", "ACPT Primary Category", "ACPT", "Predicted ACPT", "Owl ACPT", "Owl Resolution Status", "Resolution Status"];
  return sources
    .map((rows, index) => ({ rows, index, score: rows.reduce((sum, row) => sum + (outputNames.some((name) => row?.[name] !== undefined && row?.[name] !== null && String(row?.[name]).trim()) ? 1 : 0), 0) }))
    .sort((a, b) => b.score - a.score || a.index - b.index)[0].rows;
}

function owlOutputValue(row, names) {
  if (!row) return "";
  for (const name of names) {
    const value = row[name];
    if (value !== undefined && value !== null && String(value).trim()) return String(value).trim();
  }
  const lookup = Object.fromEntries(Object.keys(row || {}).map((key) => [key.toLowerCase(), key]));
  for (const name of names) {
    const key = lookup[String(name).toLowerCase()];
    const value = key ? row[key] : "";
    if (value !== undefined && value !== null && String(value).trim()) return String(value).trim();
  }
  return "";
}

function owlDistribution(rows, names) {
  const counts = new Map();
  rows.forEach((row) => {
    const value = owlOutputValue(row, names);
    if (!value) return;
    counts.set(value, (counts.get(value) || 0) + 1);
  });
  return [...counts.entries()].map(([label, count]) => ({ label, count })).sort((a, b) => b.count - a.count || a.label.localeCompare(b.label));
}

function owlOverviewCards(containerId, cards) {
  const container = $(containerId);
  if (!container) return;
  container.innerHTML = cards.map((card) => `<article class="metric-card performance-executive-card owl-kpi-card ${card.tone || ""}"><span>${escapeHtml(card.label)}</span><strong>${escapeHtml(card.value)}</strong><small>${escapeHtml(card.note || "")}</small></article>`).join("");
}

function owlTopCards(prefix, dist, total, limit = 8) {
  return dist.slice(0, limit).map((item, index) => ({
    label: `${prefix} ${index + 1}`,
    value: item.label,
    note: `${item.count.toLocaleString()} rows${total ? ` (${formatMetric((item.count / total) * 100)}%)` : ""}`,
    tone: index === 0 ? "" : "neutral",
  }));
}

function owlEvidenceRows(rows) {
  const themeNames = ["Primary Reason", "Owl Primary Driver", "Primary Theme", "Theme", "Predicted Theme", "Owl Theme", "Driver", "Reason"];
  const acptNames = ["ACPT Primary Category", "ACPT", "Predicted ACPT", "Owl ACPT", "Ownership", "Accountability", "Bucket Category", "Owl Customer Impact"];
  const resolutionNames = ["Owl Resolution Status", "Resolution Status", "Predicted Resolution", "Resolution"];
  const confidenceNames = ["ACPT Confidence", "Theme Confidence", "Confidence", "confidence", "Probability", "probability"];
  const feedbackNames = ["Verbatim Feedback", "Customer Comments", "Feedback", "Comments", "Comment", "Customer Feedback", "Text"];
  const sourceNames = ["ACPT Evidence", "Owl Analysis Source", "Classification Source", "Source"];
  return rows.map((row) => ({
    Theme: owlOutputValue(row, themeNames) || "Not classified",
    ACPT: owlOutputValue(row, acptNames) || "Not classified",
    "Resolution Status": owlOutputValue(row, resolutionNames) || "Not mentioned",
    Confidence: owlOutputValue(row, confidenceNames) || "",
    Evidence: owlOutputValue(row, sourceNames) || "",
    Feedback: owlOutputValue(row, feedbackNames) || "",
  })).filter((row) => row.Theme !== "Not classified" || row.ACPT !== "Not classified" || row["Resolution Status"] !== "Not mentioned");
}

function polarPoint(cx, cy, radius, angleDegrees) {
  const angle = (angleDegrees - 90) * Math.PI / 180;
  return {
    x: cx + radius * Math.cos(angle),
    y: cy + radius * Math.sin(angle),
  };
}

function renderOwlDistributionChart(svgId, dist = [], emptyMessage = "Run Owl theme classification to view this chart.") {
  const svg = $(svgId);
  if (!svg) return;
  const top = (dist || []).slice(0, 4);
  const other = (dist || []).slice(4).reduce((sum, item) => sum + Number(item.count || 0), 0);
  const data = other > 0 ? [...top, { label: "Other", count: other }] : top;
  if (!data.length) {
    svg.innerHTML = `<text x="380" y="130" text-anchor="middle" fill="#728399" font-size="13">${escapeHtml(emptyMessage)}</text>`;
    return;
  }
  const cx = 380, cy = 140, radius = 112;
  const total = data.reduce((sum, item) => sum + Number(item.count || 0), 0) || 1;
  const palette = ["#1f7fd1", "#34c98f", "#ffb252", "#7c5cff", "#d9e6ee"];
  let start = -90;
  const slices = data.map((item, index) => {
    const value = Number(item.count || 0);
    const angle = (value / total) * 360;
    const end = start + angle;
    const large = angle > 180 ? 1 : 0;
    const startPoint = polarPoint(cx, cy, radius, start);
    const endPoint = polarPoint(cx, cy, radius, end);
    const mid = polarPoint(cx, cy, radius + 30, start + angle / 2);
    const labelX = mid.x < cx ? mid.x - 88 : mid.x + 14;
    const labelAnchor = mid.x < cx ? "end" : "start";
    const label = String(item.label || "Unknown").slice(0, 18);
    const pct = (value / total) * 100;
    start = end;
    const shape = angle >= 359.99
      ? `<circle cx="${cx}" cy="${cy}" r="${radius}" fill="${palette[index % palette.length]}" stroke="#fff" stroke-width="2"></circle>`
      : `<path d="M ${cx} ${cy} L ${startPoint.x} ${startPoint.y} A ${radius} ${radius} 0 ${large} 1 ${endPoint.x} ${endPoint.y} Z" fill="${palette[index % palette.length]}" stroke="#fff" stroke-width="2"></path>`;
    return `
      ${shape}
      <line x1="${mid.x}" y1="${mid.y}" x2="${labelAnchor === "end" ? labelX + 8 : labelX - 8}" y2="${mid.y}" stroke="${palette[index % palette.length]}" stroke-width="2"></line>
      <text x="${labelX}" y="${mid.y - 4}" text-anchor="${labelAnchor}" fill="#0c2340" font-size="11">${escapeHtml(label)}</text>
      <text x="${labelX}" y="${mid.y + 11}" text-anchor="${labelAnchor}" fill="#50647a" font-size="10">${formatMetric(pct)}% | ${value.toLocaleString()}</text>
    `;
  }).join("");
  const center = data[0] ? `${formatMetric((Number(data[0].count || 0) / total) * 100)}%` : "-";
  svg.innerHTML = `${slices}<circle cx="${cx}" cy="${cy}" r="50" fill="#fff" opacity="0.94"></circle><text x="${cx}" y="${cy - 5}" text-anchor="middle" fill="#0c2340" font-size="24" font-weight="500">${center}</text><text x="${cx}" y="${cy + 18}" text-anchor="middle" fill="#607487" font-size="11">top share</text>`;
}

function renderOwlOverviewViews(analysis = state.analysis || {}) {
  const rows = owlOutputRows(analysis);
  const declaredTotal = Math.round(Number(analysis.summary?.total || analysis.summary?.Total || state.setupBaseRowCount || rows.length)) || rows.length;
  const checkedTotal = Math.max(rows.length, declaredTotal);
  const themeDist = owlDistribution(rows, ["Primary Reason", "Owl Primary Driver", "Primary Theme", "Theme", "Predicted Theme", "Owl Theme", "Driver", "Reason"]);
  const acptDist = owlDistribution(rows, ["ACPT Primary Category", "ACPT", "Predicted ACPT", "Owl ACPT", "Ownership", "Accountability", "Bucket Category", "Owl Customer Impact"]);
  const resolutionDist = owlDistribution(rows, ["Owl Resolution Status", "Resolution Status", "Predicted Resolution", "Resolution"]);
  const themeCount = themeDist.reduce((sum, item) => sum + item.count, 0);
  const acptCount = acptDist.reduce((sum, item) => sum + item.count, 0);
  const resolutionCount = resolutionDist.reduce((sum, item) => sum + item.count, 0);
  const evidence = owlEvidenceRows(rows);
  renderOwlThemeSummary(rows, evidence, themeDist, checkedTotal, analysis);
  renderAcptOverviewSummary(rows, evidence, acptDist, checkedTotal);
  owlOverviewCards("themesOverviewMetricGrid", [
    { label: "Rows Classified", value: checkedTotal.toLocaleString(), note: "Rows checked for Owl evidence" },
    { label: "Theme Coverage", value: checkedTotal ? `${formatMetric((themeCount / checkedTotal) * 100)}%` : "-", note: `${themeCount.toLocaleString()} rows with theme output` },
    { label: "Top Theme", value: themeDist[0]?.label || "-", note: themeDist[0] ? `${themeDist[0].count.toLocaleString()} rows` : "No output" },
    { label: "Resolution Coverage", value: checkedTotal ? `${formatMetric((resolutionCount / checkedTotal) * 100)}%` : "-", note: resolutionDist[0] ? `${resolutionDist[0].label} leads` : "No resolution output" },
  ]);
  owlOverviewCards("acptOverviewMetricGrid", [
    { label: "Rows Checked", value: checkedTotal.toLocaleString(), note: "Analyzed row output" },
    { label: "Rows With ACPT", value: acptCount.toLocaleString(), note: "Rows with ownership output" },
    { label: "ACPT Coverage", value: checkedTotal ? `${formatMetric((acptCount / checkedTotal) * 100)}%` : "-", note: "Share with ACPT output" },
    { label: "Top ACPT", value: acptDist[0]?.label || "-", note: acptDist[0] ? `${acptDist[0].count.toLocaleString()} rows` : "No output" },
    ...owlTopCards("ACPT", acptDist, checkedTotal, 8),
  ]);
  renderOwlDistributionChart("owlThemeTopChart", themeDist, "No Owl theme output is available yet.");
  renderOwlDistributionChart("owlThemeAcptChart", acptDist, "No Owl ACPT output is available yet.");
  renderOwlDistributionChart("owlThemeResolutionChart", resolutionDist, "No Owl resolution output is available yet.");
  renderAcptOwnershipMix("acptOverviewList", acptDist, checkedTotal);
  if ($("themesOverviewMeta")) $("themesOverviewMeta").textContent = evidence.length ? `${evidence.length.toLocaleString()} row(s) with Owl or local theme evidence.` : "No theme evidence is available yet.";
  if ($("acptOverviewMeta")) $("acptOverviewMeta").textContent = evidence.length ? `${evidence.length.toLocaleString()} row(s) with Owl or local ACPT evidence.` : "No ACPT evidence is available yet.";
  renderAnyTable("themesOverviewTable", evidence, 8);
  renderAnyTable("acptOverviewTable", evidence.map((row) => ({ ACPT: row.ACPT, Theme: row.Theme, "Resolution Status": row["Resolution Status"], Confidence: row.Confidence, Evidence: row.Evidence, Feedback: row.Feedback })), 8);
}

function renderAcptOverviewSummary(rows = [], evidence = [], acptDist = [], checkedTotal = 0) {
  const host = $("acptOverviewSummary");
  if (!host) return;
  const acptNames = ["ACPT Primary Category", "ACPT", "Predicted ACPT", "Owl ACPT", "Ownership", "Accountability", "Bucket Category", "Owl Customer Impact"];
  const validVerbatims = rows.filter((row) => feedbackText(row).trim());
  const analyzedVerbatims = validVerbatims.length || evidence.length || rows.length;
  const normalizedOther = (value) => /^(other|unclassified|uncategorized|not classified|unknown|n\/a|-|none)$/i.test(String(value || "").trim());
  const acptRows = rows.map((row) => ({
    row,
    acpt: String(resultFirstValue(row, acptNames, "") || "").trim(),
    sentiment: String(row.Sentiment || row.sentiment || row["Sentiment Label"] || "").trim().toLowerCase(),
    week: feedbackWeek(row),
    type: npsTypeForSummary(row),
  })).filter((item) => item.acpt);
  const classifiedRows = acptRows.filter((item) => !normalizedOther(item.acpt));
  const classifiedPct = analyzedVerbatims ? (classifiedRows.length / analyzedVerbatims) * 100 : NaN;
  const unclassifiedPct = analyzedVerbatims ? ((analyzedVerbatims - classifiedRows.length) / analyzedVerbatims) * 100 : NaN;
  const totalClassified = classifiedRows.length || acptDist.reduce((sum, item) => sum + Number(item.count || 0), 0);
  const topCategories = acptDist.filter((item) => item && item.label && !normalizedOther(item.label)).slice(0, 5);
  const topCategoryShare = totalClassified && topCategories.length ? (topCategories.reduce((sum, item) => sum + Number(item.count || 0), 0) / totalClassified) * 100 : NaN;
  const topCategoryText = topCategories.length
    ? topCategories.map((item) => `<strong>${escapeHtml(item.label)}</strong> (${formatMetric(totalClassified ? (Number(item.count || 0) / totalClassified) * 100 : NaN)}%)`).join(", ")
    : "<strong>X</strong> (X%), <strong>X</strong> (X%), <strong>X</strong> (X%), <strong>X</strong> (X%), and <strong>X</strong> (X%)";
  const sentimentByAcpt = new Map();
  classifiedRows.forEach((item) => {
    if (!sentimentByAcpt.has(item.acpt)) sentimentByAcpt.set(item.acpt, { Positive: 0, Neutral: 0, Negative: 0, total: 0 });
    const bucket = sentimentByAcpt.get(item.acpt);
    const key = item.sentiment === "positive" ? "Positive" : item.sentiment === "neutral" ? "Neutral" : item.sentiment === "negative" ? "Negative" : "";
    if (key) bucket[key] += 1;
    bucket.total += 1;
  });
  const sentimentRows = [...sentimentByAcpt.entries()].map(([label, counts]) => ({
    label,
    positivePct: counts.total ? (counts.Positive / counts.total) * 100 : NaN,
    negativePct: counts.total ? (counts.Negative / counts.total) * 100 : NaN,
    negativeCount: counts.Negative || 0,
  }));
  const positiveCategory = sentimentRows.slice().sort((a, b) => (b.positivePct || 0) - (a.positivePct || 0))[0]?.label || "X";
  const negativeCategory = sentimentRows.slice().sort((a, b) => (b.negativeCount || 0) - (a.negativeCount || 0))[0]?.label || "X";
  const weekKeys = [...new Set(classifiedRows.map((item) => item.week).filter(Boolean))].sort();
  const currentWeek = weekKeys.at(-1) || "";
  const weekTotals = new Map();
  const acptWeekCounts = new Map();
  classifiedRows.forEach((item) => {
    if (!item.week) return;
    weekTotals.set(item.week, (weekTotals.get(item.week) || 0) + 1);
    const key = `${item.acpt}|||${item.week}`;
    acptWeekCounts.set(key, (acptWeekCounts.get(key) || 0) + 1);
  });
  const movementRows = topCategories.map((item) => {
    const currentCount = currentWeek ? Number(acptWeekCounts.get(`${item.label}|||${currentWeek}`) || 0) : 0;
    const currentTotal = currentWeek ? Number(weekTotals.get(currentWeek) || 0) : 0;
    const currentShare = currentTotal ? (currentCount / currentTotal) * 100 : NaN;
    const periodShare = totalClassified ? (Number(item.count || 0) / totalClassified) * 100 : NaN;
    const gap = Number.isFinite(currentShare) && Number.isFinite(periodShare) ? currentShare - periodShare : NaN;
    return { label: item.label, currentShare, periodShare, gap };
  }).filter((item) => Number.isFinite(item.gap));
  const movement = movementRows.slice().sort((a, b) => Math.abs(b.gap) - Math.abs(a.gap))[0];
  const trendDirection = !movement ? "Rising / Stable / Declining" : Math.abs(movement.gap) < 1 ? "Stable" : movement.gap > 0 ? "Rising" : "Declining";
  const passiveDetractorRows = classifiedRows.filter((item) => ["passive", "detractor"].includes(item.type));
  const pdCounts = new Map();
  passiveDetractorRows.forEach((item) => pdCounts.set(item.acpt, (pdCounts.get(item.acpt) || 0) + 1));
  const pdTop = [...pdCounts.entries()].map(([label, count]) => ({ label, count })).sort((a, b) => b.count - a.count || a.label.localeCompare(b.label))[0];
  const pdShare = passiveDetractorRows.length && pdTop ? (pdTop.count / passiveDetractorRows.length) * 100 : NaN;
  host.innerHTML = `<section class="owl-theme-summary-card">
    <div class="owl-theme-summary-head">
      <div>
        <p class="eyebrow">ACPT Summary</p>
        <h2>ACPT Analysis</h2>
      </div>
      <span>${analyzedVerbatims ? analyzedVerbatims.toLocaleString() : "X"} analyzed verbatims</span>
    </div>
    <ul>
      <li>A total of <strong>${analyzedVerbatims ? analyzedVerbatims.toLocaleString() : "X"}</strong> customer verbatims were analyzed across <strong>${acptDist.length || "X"}</strong> ACPT categories. <strong>${Number.isFinite(classifiedPct) ? `${formatMetric(classifiedPct)}%` : "X%"}</strong> of verbatims were successfully classified, while <strong>${Number.isFinite(unclassifiedPct) ? `${formatMetric(unclassifiedPct)}%` : "X%"}</strong> remained unclassified or fell into the Other category.</li>
      <li>The most frequently occurring ACPT categories were ${topCategoryText}, collectively accounting for <strong>${Number.isFinite(topCategoryShare) ? `${formatMetric(topCategoryShare)}%` : "X%"}</strong> of all classified feedback.</li>
      <li>Positive sentiment was primarily associated with <strong>${escapeHtml(positiveCategory)}</strong>, while Negative sentiment was predominantly linked to <strong>${escapeHtml(negativeCategory)}</strong>, highlighting the strongest drivers of customer satisfaction and dissatisfaction.</li>
      <li>The current week recorded <strong>${movement ? `${formatMetric(movement.currentShare)}%` : "X%"}</strong> of feedback related to <strong>${escapeHtml(movement?.label || "X")}</strong>, compared with a reporting period average of <strong>${movement ? `${formatMetric(movement.periodShare)}%` : "X%"}</strong> (${movement ? `${movement.gap >= 0 ? "Above" : "Below"} average by <strong>${formatMetric(Math.abs(movement.gap))}</strong> percentage points` : "Above / Below average by X percentage points"}), indicating a <strong>${escapeHtml(trendDirection)}</strong> trend.</li>
      <li>Among Detractor and Passive customers, <strong>${Number.isFinite(pdShare) ? `${formatMetric(pdShare)}%` : "X%"}</strong> of all classified feedback was attributed to <strong>${escapeHtml(pdTop?.label || "X")}</strong>, representing the largest opportunity for operational improvement.</li>
    </ul>
  </section>`;
}

function renderAcptOwnershipMix(targetId, dist = [], totalRows = 0) {
  const host = $(targetId);
  if (!host) return;
  const total = Number(totalRows || 0) || dist.reduce((sum, item) => sum + Number(item.count || 0), 0);
  const rows = (dist || []).filter((item) => item && item.label && Number(item.count || 0) > 0).slice(0, 8);
  if (!rows.length) {
    host.innerHTML = `<p class="insight-text">No ACPT ownership output is available yet.</p>`;
    return;
  }
  const max = Math.max(...rows.map((item) => Number(item.count || 0)), 1);
  host.innerHTML = rows.map((item, index) => {
    const count = Number(item.count || 0);
    const share = total ? (count / total) * 100 : 0;
    const width = Math.max(4, (count / max) * 100);
    return `<div class="acpt-mix-row">
      <div class="acpt-mix-rank">${String(index + 1).padStart(2, "0")}</div>
      <div class="acpt-mix-main">
        <div class="acpt-mix-label"><strong>${escapeHtml(item.label)}</strong><span>${count.toLocaleString()} rows | ${formatMetric(share)}%</span></div>
        <div class="acpt-mix-track"><span style="width:${width}%"></span></div>
      </div>
    </div>`;
  }).join("");
}

function renderOwlThemeSummary(rows = [], evidence = [], themeDist = [], checkedTotal = 0, analysis = state.analysis || {}) {
  const host = $("owlThemeSummary");
  if (!host) return;
  const analyzedVerbatims = evidence.length || rows.filter((row) => feedbackText(row).trim()).length || rows.length;
  const themeTotal = themeDist.reduce((sum, item) => sum + Number(item.count || 0), 0);
  const topLimit = Math.min(5, themeDist.length);
  const topThemes = themeDist.slice(0, topLimit);
  const topThemeShare = themeTotal && topThemes.length ? (topThemes.reduce((sum, item) => sum + Number(item.count || 0), 0) / themeTotal) * 100 : NaN;
  const topThemeNames = topThemes.map((item) => item.label).filter(Boolean);
  const dominantTheme = topThemeNames[0] || "X";
  const sentimentCounts = { Positive: 0, Neutral: 0, Negative: 0 };
  const themeSentiment = new Map();
  const themeNames = ["Primary Reason", "Owl Primary Driver", "Primary Theme", "Theme", "Predicted Theme", "Owl Theme", "Driver", "Reason"];
  rows.forEach((row) => {
    const theme = String(resultFirstValue(row, themeNames, "") || "").trim();
    const sentiment = String(row.Sentiment || row.sentiment || row["Sentiment Label"] || "").trim().toLowerCase();
    const sentimentKey = sentiment === "positive" ? "Positive" : sentiment === "neutral" ? "Neutral" : sentiment === "negative" ? "Negative" : "";
    if (sentimentKey) sentimentCounts[sentimentKey] += 1;
    if (!theme || !sentimentKey) return;
    if (!themeSentiment.has(theme)) themeSentiment.set(theme, { Positive: 0, Neutral: 0, Negative: 0, total: 0 });
    const bucket = themeSentiment.get(theme);
    bucket[sentimentKey] += 1;
    bucket.total += 1;
  });
  const sentimentTotal = sentimentCounts.Positive + sentimentCounts.Neutral + sentimentCounts.Negative;
  const analysisSentiment = analysis.sentiment || {};
  const positivePct = sentimentTotal ? (sentimentCounts.Positive / sentimentTotal) * 100 : Number(analysisSentiment.Positive);
  const neutralPct = sentimentTotal ? (sentimentCounts.Neutral / sentimentTotal) * 100 : Number(analysisSentiment.Neutral);
  const negativePct = sentimentTotal ? (sentimentCounts.Negative / sentimentTotal) * 100 : Number(analysisSentiment.Negative);
  const sentimentRows = [...themeSentiment.entries()].map(([theme, counts]) => ({
    theme,
    positivePct: counts.total ? (counts.Positive / counts.total) * 100 : NaN,
    negativeCount: counts.Negative || 0,
  }));
  const highestPositiveTheme = sentimentRows.slice().sort((a, b) => (b.positivePct || 0) - (a.positivePct || 0))[0]?.theme || "X";
  const highestNegativeTheme = sentimentRows.slice().sort((a, b) => (b.negativeCount || 0) - (a.negativeCount || 0))[0]?.theme || "X";
  const weekKeys = [...new Set(rows.map((row) => feedbackWeek(row)).filter(Boolean))].sort();
  const currentWeek = weekKeys.at(-1) || "";
  const weekThemeCounts = new Map();
  rows.forEach((row) => {
    const week = feedbackWeek(row);
    const theme = String(resultFirstValue(row, themeNames, "") || "").trim();
    if (!week || !theme) return;
    const key = `${theme}|||${week}`;
    weekThemeCounts.set(key, (weekThemeCounts.get(key) || 0) + 1);
  });
  const movementRows = themeDist.map((item) => {
    const current = currentWeek ? Number(weekThemeCounts.get(`${item.label}|||${currentWeek}`) || 0) : 0;
    const average = weekKeys.length ? Number(item.count || 0) / weekKeys.length : NaN;
    const changePct = average ? ((current - average) / average) * 100 : NaN;
    return { label: item.label, current, average, changePct };
  }).filter((item) => Number.isFinite(item.changePct));
  const fastestTheme = movementRows.slice().sort((a, b) => b.changePct - a.changePct)[0];
  const trendTheme = fastestTheme?.label || dominantTheme;
  const trendDirection = fastestTheme ? (fastestTheme.changePct >= 0 ? "increased" : "decreased") : "increased/decreased";
  const trendPct = fastestTheme ? formatMetric(Math.abs(fastestTheme.changePct)) : "X";
  const negativeThemeTotal = [...themeSentiment.values()].reduce((sum, item) => sum + Number(item.Negative || 0), 0);
  const topThemeSet = new Set(topThemes.map((item) => item.label));
  let topThemeNegative = 0;
  themeSentiment.forEach((counts, theme) => {
    if (topThemeSet.has(theme)) topThemeNegative += Number(counts.Negative || 0);
  });
  const negativeConcentration = negativeThemeTotal ? (topThemeNegative / negativeThemeTotal) * 100 : NaN;
  const listNames = topThemeNames.length ? topThemeNames.map((name) => `<strong>${escapeHtml(name)}</strong>`).join(", ") : "<strong>X</strong>, <strong>X</strong>, <strong>X</strong>, <strong>X</strong>, and <strong>X</strong>";
  host.innerHTML = `<section class="owl-theme-summary-card">
    <div class="owl-theme-summary-head">
      <div>
        <p class="eyebrow">Theme Summary</p>
        <h2>Theme Analysis</h2>
      </div>
      <span>${analyzedVerbatims ? analyzedVerbatims.toLocaleString() : "X"} analyzed verbatims</span>
    </div>
    <ul>
      <li>AI identified <strong>${themeDist.length || "X"}</strong> distinct customer themes across <strong>${analyzedVerbatims ? analyzedVerbatims.toLocaleString() : "X"}</strong> analyzed verbatims. The Top <strong>${topLimit || "X"}</strong> themes contributed <strong>${Number.isFinite(topThemeShare) ? `${formatMetric(topThemeShare)}%` : "X%"}</strong> of all customer feedback, indicating that a relatively small number of topics drive the majority of customer conversations.</li>
      <li>The most frequently discussed themes were ${listNames}, with <strong>${escapeHtml(dominantTheme)}</strong> emerging as the dominant customer concern during the reporting period.</li>
      <li>Theme sentiment analysis shows <strong>${Number.isFinite(positivePct) ? `${formatMetric(positivePct)}%` : "X%"}</strong> Positive, <strong>${Number.isFinite(neutralPct) ? `${formatMetric(neutralPct)}%` : "X%"}</strong> Neutral, and <strong>${Number.isFinite(negativePct) ? `${formatMetric(negativePct)}%` : "X%"}</strong> Negative theme occurrences, with <strong>${escapeHtml(highestPositiveTheme)}</strong> demonstrating the highest positive perception and <strong>${escapeHtml(highestNegativeTheme)}</strong> contributing the largest share of negative customer experiences.</li>
      <li>Compared with the reporting period average, mentions of <strong>${escapeHtml(trendTheme)}</strong> ${trendDirection} by <strong>${trendPct}%</strong> during the current week, while <strong>${escapeHtml(fastestTheme?.label || "X")}</strong> emerged as the fastest-growing customer theme.</li>
      <li><strong>${Number.isFinite(negativeConcentration) ? `${formatMetric(negativeConcentration)}%` : "X%"}</strong> of negative customer feedback was concentrated within the Top <strong>${topLimit || "X"}</strong> themes, suggesting that addressing these key areas has the potential to improve a significant proportion of the overall customer experience.</li>
    </ul>
  </section>`;
}

async function analyze(options = {}) {
  const guidedRun = options.guided === true || document.body.classList.contains("nps-onboarding-active");
  state.activeAnalysisEngines = {
    sentiment: (guidedRun ? $("guidedSentimentEngine")?.value : "") || $("sentimentEngine")?.value || "local",
    theme: (guidedRun ? $("guidedThemeEngine")?.value : "") || $("themeEngine")?.value || "local",
  };
  if ($("sentimentEngine")) $("sentimentEngine").value = state.activeAnalysisEngines.sentiment;
  if ($("themeEngine")) $("themeEngine").value = state.activeAnalysisEngines.theme;
  const sentimentLabel = state.activeAnalysisEngines.sentiment === "local" ? "Local Rules" : "Sparrow";
  const themeLabel = state.activeAnalysisEngines.theme === "local" ? "Local Rules" : "Owl";
  showLoading(`Starting local NPS analysis. Sentiment: ${sentimentLabel}. Themes: ${themeLabel}.`, 1);
  try {
    const feedbackSelect = $("feedbackCol");
    if (feedbackSelect && !state.baseColumns.includes(feedbackSelect.value)) {
      feedbackSelect.value = pickFeedbackColumn(state.baseColumns, state.guesses.feedback || "");
    }
    const payload = {
      mode: "nps",
      mapping: {
        feedback: feedbackSelect?.value || "",
        score: $("scoreCol")?.value || "",
        satisfaction: $("npsTypeCol")?.value || "",
        agent: $("agentCol")?.value || "",
        manager: $("managerCol")?.value || "",
        date: $("dateCol")?.value || "",
        wave: $("waveCol")?.value || "",
        tenure: $("tenureCol")?.value || "",
      },
      engines: {
        sentiment: state.activeAnalysisEngines.sentiment,
        theme: state.activeAnalysisEngines.theme,
      },
      modelPaths: {
        sparrow: $("sparrowModelPath")?.value || "",
        vulture: $("vultureModelPath")?.value || "",
      },
      dynamicDimensions: state.dynamicDimensions,
      calendar: selectedCalendarConfig(),
      baseKey: $("baseKey")?.value || "",
      lookupKey: $("lookupKey")?.value || "",
    };
    const response = await fetch("/api/analyze", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    const data = await response.json();
    if (!data.ok) throw new Error(data.error || "Analysis failed");
    const analysis = await waitForAnalysisCompletion(data.analysisId || data.analysis?.analysisId || "");
    analysis.calendar = payload.calendar;
    updateProgress("Browser preparation: loading supporting statistics and column profiles...", 98.5);
    await loadStatisticsData();
    updateProgress("Browser preparation: rendering dashboard views and analysis tables...", 99);
    renderAnalysis(analysis, { showCompletionSummary: !guidedRun, summaryReason: "New analysis complete" });
    if (guidedRun) {
      updateProgress("Browser preparation: building the guided insight briefing...", 99.5);
      state.guidedAnalysisComplete = true;
      window.sessionStorage.setItem("npsGuidedAnalysisId", String(analysis.analysisId || data.analysisId || ""));
      state.guidedSetupStage = "complete";
      state.guidedInsightIndex = 0;
      state.guidedCompletionInsights = buildGuidedCompletionInsights(analysis);
      closeGuidedDiveRail({ reset: true });
      $("guidedAnalysisComplete")?.classList.remove("briefing-started");
      $("guidedFieldDive")?.classList.remove("expanded");
      if ($("guidedFieldDive")) $("guidedFieldDive").hidden = true;
      if ($("guidedInsightDeck")) $("guidedInsightDeck").hidden = false;
      if ($("guidedStoryChooser")) $("guidedStoryChooser").hidden = true;
      if ($("guidedCompletionIntro")) $("guidedCompletionIntro").textContent = "Before we open the dashboards, let me quickly walk you through what I found.";
      renderGuidedInsightDeck();
      if ($("guidedAnalysisComplete")) $("guidedAnalysisComplete").hidden = false;
      updateGuidedSetupState();
      $("guidedAnalysisComplete")?.scrollIntoView({ behavior: "smooth", block: "center" });
      showCoachTipSoon("guidedStartBriefing", "Click here when you are ready for the guided readout.", { key: "show-insights", position: "top" });
      updateProgress("Complete: Executive Summary is ready.", 100);
      state.guidedReleaseToApp = true;
      activateView("executivesummary");
      showCoachTipSoon("exportExecutiveSummaryHtml", "Analysis is complete. Start with this Executive Summary for the leadership read, then use Help Me to review Data Set Summary, Performance Overview, Decision Guide, Results, and dashboards.", { key: "analysis-complete-executive-summary", position: "top", force: true, duration: 6200 });
    } else {
      updateProgress("Complete: dashboard is ready.", 100);
      state.guidedReleaseToApp = true;
      activateView("executivesummary");
      showCoachTipSoon("exportExecutiveSummaryHtml", "Analysis is complete. Start with this Executive Summary, then export it or continue into the detailed result views and dashboards.", { key: "analysis-complete-executive-summary", position: "top", force: true, duration: 6200 });
    }
  } finally {
    hideLoading();
  }
}

async function validateModel(kind) {
  const input = kind === "sparrow" ? $("sparrowModelPath") : $("vultureModelPath");
  const status = kind === "sparrow" ? $("sparrowModelStatus") : $("vultureModelStatus");
  if (status) status.textContent = `Validating ${kind} model...`;
  const response = await fetch("/api/model/validate", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ kind, path: input?.value || "" }),
  });
  const payload = await response.json().catch(() => ({ ok: false, error: "Validation failed." }));
  if (!payload.ok) {
    if (status) status.textContent = payload.error || `${kind} model is invalid.`;
    throw new Error(payload.error || `${kind} model is invalid.`);
  }
  if (input) input.value = payload.path || input.value;
  if (status) status.textContent = `${payload.message || "Model is valid"} Active path: ${payload.resolved_path || payload.path}`;
  return payload;
}

async function browseModel(kind) {
  const input = kind === "sparrow" ? $("sparrowModelPath") : $("vultureModelPath");
  const response = await fetch("/api/model/browse", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ initialPath: input?.value || "" }),
  });
  const payload = await response.json().catch(() => ({ ok: false, error: "Folder picker failed." }));
  if (!payload.ok) throw new Error(payload.error || "Folder picker failed.");
  if (payload.path && input) {
    input.value = payload.path;
    await validateModel(kind);
  }
}

async function openTrainingTool(kind) {
  const response = await fetch("/api/train/open", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ kind }),
  });
  const payload = await response.json().catch(() => ({ ok: false, error: "Training launcher did not respond." }));
  if (!response.ok || !payload.ok) {
    const urls = { sparrow: "/apps/sparrow-training/index.html?login=1", vulture: "/apps/theme-model-training/index.html", theme: "/apps/theme-model-training/index.html" };
    const fallbackUrl = urls[kind];
    if (fallbackUrl) {
      const opened = window.open(fallbackUrl, "_blank", "noopener");
      if (opened) return payload;
    }
    throw new Error(payload.error || "Training tool could not be opened.");
  }
  if (payload.message) showToastMessage(payload.message);
  if (kind === "sparrow") window.open("/apps/sparrow-training/index.html?login=1", "_blank", "noopener");
  if (kind === "theme" || kind === "vulture") window.open("/apps/theme-model-training/index.html", "_blank", "noopener");
  return payload;
}

function openSuiteTool(url) {
  if (url) window.location.href = url;
}

function setTrainPanelOpen(open) {
  const panel = $("trainPanel");
  const toggle = $("trainToggle");
  if (!panel || !toggle) return;
  panel.classList.toggle("hidden", !open);
  toggle.classList.toggle("active", open);
  toggle.setAttribute("aria-expanded", open ? "true" : "false");
}

function showToastMessage(message) {
  const text = String(message || "").trim();
  if (!text) return;
  const existing = $("appToastMessage");
  if (existing) existing.remove();
  const toast = document.createElement("div");
  toast.id = "appToastMessage";
  toast.className = "app-toast-message";
  toast.textContent = text;
  document.body.appendChild(toast);
  setTimeout(() => toast.classList.add("show"), 20);
  setTimeout(() => {
    toast.classList.remove("show");
    setTimeout(() => toast.remove(), 250);
  }, 3200);
}

async function loadStatus() {
  const initialRequestedView = requestedDashboardHandoffView();
  const initialDashboardHandoff = Boolean(initialRequestedView);
  if (initialDashboardHandoff) {
    state.guidedReleaseToApp = true;
    clearCoachTips();
    showLoading("Dashboard handoff: opening the saved analysis package...", 8);
  }
  try {
  if (initialDashboardHandoff) updateProgress("Dashboard handoff: contacting the local analyzer for the completed result package...", 14);
  const response = await fetch("/api/status");
  if (initialDashboardHandoff) updateProgress("Dashboard handoff: result package received. Validating workbook, rows, and dashboard context...", 28);
  const payload = await response.json();
  const setupCache = readSetupCache();
  const queryParams = new URLSearchParams(window.location.search);
  const restartRequested = queryParams.get("restart") === "1";
  const requestedView = initialRequestedView || requestedDashboardHandoffView();
  const dashboardHandoff = Boolean(requestedView);
  const cachedBaseColumns = normalizeColumnList(setupCache.baseColumns);
  const cachedLookupColumns = normalizeColumnList(setupCache.lookupColumns);
  const serverBaseColumns = normalizeColumnList(payload.base_columns || payload.baseColumns);
  const serverLookupColumns = normalizeColumnList(payload.lookup_columns || payload.lookupColumns);
  const hasSavedBase = serverBaseColumns.length > 0;
  if (!hasSavedBase) clearSetupCache();
  const savedAnalysis = payload.analysis || {};
  const savedBaseName = String(payload.files?.base || "");
  const savedAnalysisId = String(savedAnalysis.analysisId || "");
  if (restartRequested) {
    window.sessionStorage.removeItem("npsGuidedBaseFile");
    window.sessionStorage.removeItem("npsGuidedAnalysisId");
  }
  const baseSessionMatches = (Boolean(savedBaseName)
    && window.sessionStorage.getItem("npsGuidedBaseFile") === savedBaseName);
  const analysisSessionMatches = Boolean(savedAnalysisId)
    && window.sessionStorage.getItem("npsGuidedAnalysisId") === savedAnalysisId;
  const analysisComplete = !restartRequested
    && baseSessionMatches
    && analysisSessionMatches
    && savedAnalysis.running !== true
    && Number(savedAnalysis.progress || 0) >= 100
    && Number(savedAnalysis.summary?.total || savedAnalysis.summary?.Total || 0) > 0;
  const forceGuidedStart = !dashboardHandoff && (restartRequested || !hasSavedBase || !baseSessionMatches);
  state.guidedReleaseToApp = dashboardHandoff === true;
  state.guidedAnalysisComplete = analysisComplete;
  state.guidedMappingConfirmed = analysisComplete;
  state.guidedStoryActive = false;
  state.guidedStoryView = "";
  state.guidedInsightIndex = 0;
  state.guidedCompletionInsights = [];
  state.guidedSetupStage = analysisComplete ? "complete" : (hasSavedBase && !forceGuidedStart ? "coverage" : "upload");
  state.setupCoverageChoice = analysisComplete ? ((payload.lookup_columns || []).length ? "lookup" : "complete") : "";
  state.setupBaseRowCount = analysisComplete
    ? Number(savedAnalysis.summary?.total || savedAnalysis.summary?.Total || payload.row_counts?.base || payload.base_rows || setupCache.baseRows || 0)
    : Number(setupCache.baseRows || 0);
  state.baseUploadComplete = hasSavedBase && !forceGuidedStart;
  state.baseColumns = forceGuidedStart ? [] : (serverBaseColumns.length ? serverBaseColumns : cachedBaseColumns);
  state.lookupColumns = forceGuidedStart ? [] : (serverLookupColumns.length ? serverLookupColumns : cachedLookupColumns);
  state.guesses = forceGuidedStart ? {} : (Object.keys(payload.guesses || {}).some((key) => payload.guesses[key]) ? payload.guesses : (setupCache.guesses || {}));
  if (!forceGuidedStart && setupCache.baseColumnStats) state.baseColumnStats = setupCache.baseColumnStats;
  if (!forceGuidedStart && setupCache.lookupColumnStats) state.lookupColumnStats = setupCache.lookupColumnStats;
  if (forceGuidedStart) activateView("setup");
  if (dashboardHandoff) {
    const rows = Number(savedAnalysis.summary?.total || savedAnalysis.summary?.Total || payload.row_counts?.base || payload.base_rows || 0);
    const rowText = Number.isFinite(rows) && rows > 0 ? ` for ${rows.toLocaleString()} rows` : "";
    updateProgress(`Dashboard handoff: mapped file context loaded${rowText}. Preparing model and engine status...`, 42);
  }
  if (payload.analysis?.modelPaths) state.modelPaths = payload.analysis.modelPaths;
  if ($("sparrowModelPath") && !$("sparrowModelPath").value) $("sparrowModelPath").value = state.modelPaths.sparrow || payload.model_status?.sparrow?.path || "";
  if ($("vultureModelPath") && !$("vultureModelPath").value) $("vultureModelPath").value = state.modelPaths.vulture || payload.model_status?.vulture?.path || "";
  if (payload.analysis?.analysisEngines) {
    state.activeAnalysisEngines = {
      sentiment: payload.analysis.analysisEngines.sentiment || "local",
      theme: payload.analysis.analysisEngines.theme || "local",
    };
    if ($("sentimentEngine")) $("sentimentEngine").value = state.activeAnalysisEngines.sentiment;
    if ($("themeEngine")) $("themeEngine").value = state.activeAnalysisEngines.theme;
  }
  const sparrowReady = payload.model_status?.sparrow?.ready;
  const vultureReady = payload.model_status?.vulture?.ready;
  const themeUsesLocalRules = (state.activeAnalysisEngines?.theme || "local") === "local";
  if ($("sparrowDot")) $("sparrowDot").className = `dot ${sparrowReady ? "ready" : "missing"}`;
  if ($("vultureDot")) $("vultureDot").className = `dot ${themeUsesLocalRules || vultureReady ? "ready" : "missing"}`;
  if ($("sparrowText")) $("sparrowText").textContent = sparrowReady ? "Ready" : "Missing";
  if ($("vultureText")) $("vultureText").textContent = themeUsesLocalRules ? "Local Rules" : (vultureReady ? "Ready" : "Missing");
  if (!forceGuidedStart && (state.lookupColumns || []).length && !state.setupCoverageChoice) state.setupCoverageChoice = "lookup";
  if (!analysisComplete && !forceGuidedStart && (state.baseColumns || []).length && !state.setupBaseRowCount) {
    state.setupBaseRowCount = Number(payload.row_counts?.base || payload.base_rows || 0);
    state.guidedSetupStage = "coverage";
  }
  if (dashboardHandoff) updateProgress("Dashboard handoff: refreshing mappings and preparing dashboard filters...", 58);
  refreshMapping();
  if (dashboardHandoff) updateProgress("Dashboard handoff: rendering dashboard cards, trends, gauges, and evidence tables...", 78);
  renderAnalysis(savedAnalysis);
  if (dashboardHandoff) updateProgress("Dashboard handoff: dashboard views rendered. Preparing guided context and next-step tour...", 88);
  if (analysisComplete) {
    state.guidedInsightIndex = 0;
    state.guidedAttackChooserVisible = false;
    state.guidedCompletionInsights = buildGuidedCompletionInsights(savedAnalysis);
    $("guidedAnalysisComplete")?.classList.add("briefing-started");
    if ($("guidedAnalysisComplete")) $("guidedAnalysisComplete").hidden = false;
    if ($("guidedInsightDeck")) $("guidedInsightDeck").hidden = false;
    if ($("guidedAttackDeck")) $("guidedAttackDeck").hidden = true;
    if ($("guidedStoryChooser")) $("guidedStoryChooser").hidden = true;
    if ($("guidedStoryPanel")) $("guidedStoryPanel").hidden = true;
    if ($("guidedFieldDive")) $("guidedFieldDive").hidden = true;
    renderGuidedInsightDeck();
  }
  updateGuidedSetupState();
  if (dashboardHandoff) {
    updateProgress("Dashboard handoff: moving you to the requested dashboard view...", 96);
    applyDashboardHandoffView(requestedView);
    updateProgress("Dashboard ready: cards, charts, trends, and executive views are populated.", 100);
  }
  } finally {
    if (initialDashboardHandoff) {
      setTimeout(() => hideLoading(), 650);
    }
  }
}

