function movingAveragesViewContext() {
  const targetScore = parseMetricNumber($("perfTargetScore")?.value);
  const start = Number.isFinite(parseMetricNumber($("movingWeekStartDay")?.value))
    ? parseMetricNumber($("movingWeekStartDay")?.value)
    : parseMetricNumber($("perfWeekStartDay")?.value || 1);
  const end = Number.isFinite(parseMetricNumber($("movingWeekEndDay")?.value))
    ? parseMetricNumber($("movingWeekEndDay")?.value)
    : parseMetricNumber($("perfWeekEndDay")?.value || 6);
  return {
    currentStart: $("perfCurrentStart")?.value || "",
    currentEnd: $("perfCurrentEnd")?.value || "",
    previousStart: $("perfPreviousStart")?.value || "",
    previousEnd: $("perfPreviousEnd")?.value || "",
    targetScore: Number.isFinite(targetScore) ? targetScore : 85,
    weekStartDay: Number.isFinite(start) ? start : 1,
    weekEndDay: Number.isFinite(end) ? end : 6,
  };
}

function syncMovingAverageWeekWindow(changedId = "") {
  const startSelect = $("movingWeekStartDay");
  const endSelect = $("movingWeekEndDay");
  if (!startSelect || !endSelect) return;
  const start = parseMetricNumber(startSelect.value);
  const end = parseMetricNumber(endSelect.value);
  if (changedId === "movingWeekEndDay" && Number.isFinite(end)) {
    startSelect.value = String((end + 1) % 7);
  } else if (Number.isFinite(start)) {
    endSelect.value = String((start + 6) % 7);
  }
}

function handleMovingAverageWeekWindowChange(event) {
  syncMovingAverageWeekWindow(event?.target?.id || "");
  state.movingAverageTab = "weekly";
  renderMovingAveragesView(state.analysis || {});
}

function movingAverageInsightCard(item, index) {
  const tone = item?.[3] || performanceQuestionTone(item?.[0], item?.[1]);
  const verdict = tone === "positive" ? "Favorable" : tone === "negative" ? "Watch" : "Monitor";
  const title = item?.[0] || "Moving average insight";
  const body = item?.[1] || "Run analysis to populate this insight.";
  const detail = item?.[2] || "Double-click to review the logic.";
  const logic = item?.[4] || `${title}\n\n${body}\n\n${detail}`;
  return `<article class="moving-average-insight-card ${tone}" tabindex="0" data-info="${escapeHtml(logic)}">
    <span>${String(index + 1).padStart(2, "0")} / ${escapeHtml(verdict)}</span>
    <strong>${escapeHtml(title)}</strong>
    <p>${escapeHtml(body)}</p>
    <small>${escapeHtml(detail)}</small>
    <em>Double-click for logic</em>
    <button type="button" class="moving-average-info" aria-label="Open moving average logic">i</button>
  </article>`;
}

