function wireUploadInputs() {
  const dashboardHandoff = Boolean(requestedDashboardHandoffView());
  if (dashboardHandoff) {
    state.guidedReleaseToApp = true;
    clearCoachTips();
  }
  const baseInput = $("baseFile");
  if (baseInput && baseInput.dataset.boundUpload !== "1") {
    baseInput.dataset.boundUpload = "1";
    baseInput.addEventListener("change", (event) => {
      const file = event.target.files?.[0];
      if (!file) return;
      uploadFile("base", file).catch((err) => {
        hideLoading();
        alert(err.message || "Base file upload failed.");
      });
    });
  }
  const lookupInput = $("lookupFile");
  if (lookupInput && lookupInput.dataset.boundUpload !== "1") {
    lookupInput.dataset.boundUpload = "1";
    lookupInput.addEventListener("change", (event) => {
      const file = event.target.files?.[0];
      if (!file) return;
      uploadFile("lookup", file).catch((err) => {
        hideLoading();
        alert(err.message || "Lookup file upload failed.");
      });
    });
  }
  document.querySelectorAll("[data-coverage-choice]").forEach((button) => {
    if (button.dataset.boundCoverageChoice === "1") return;
    button.dataset.boundCoverageChoice = "1";
    button.addEventListener("click", () => setGuidedCoverageChoice(button.dataset.coverageChoice || "complete"));
  });
  wireBaseInfoPanel();
  wireGuidedSuccessContinue();
  wireConfirmMapping();
  wireGuidedRunAnalysis();
  wireGuidedNextActions();
  updateGuidedSetupState();
  if (!dashboardHandoff) {
    showCoachTipSoon("baseUploadButton", "Start here. Upload the Base File and I will guide the rest.", { key: "start-upload-base", position: "top", delay: 700 });
  }
}
